window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-015.json"] = [{"name":"黑嘴长尾蜂鸟","english_name":"Black-billed Streamertail","scientific_name":"Trochilus scitulus","overview":"黑嘴长尾蜂鸟（英文名：Black-billed Streamertail，学名：Trochilus scitulus），是雨燕目蜂鸟科牙买加长尾蜂鸟属的鸟类。特有种于牙买加东部。与红嘴长尾蜂鸟相区隔，两物种在狭窄接触带可能杂交。","appearance":"雄性黑嘴长尾蜂鸟身长22至24厘米，含10至13厘米的尾流苏，体重介于4.0至5.8克之间。雌鸟长约10.5厘米，体重3.5至5.5克。雄鸟具黑色至蓝黑色冠羽，上体呈亮绿色，尾部黑色带绿至青铜光泽。雌鸟上体金属青铜绿色，尾部中央羽毛亮青铜绿色，其余黑色，外侧尾羽具宽白尖，下体白色，胸及胁部有金属青铜绿斑点。","call":"其鸣声包括响亮的金属音‘ting’或‘teet’，以及逐渐降调的‘twink-twink-twink’。","habits":"栖息于牙买加的常绿山地森林、低地热带森林及次生林，避免红树林和干旱高地，海拔跨度从海平面至1500米。以花蜜为主食，偏好Besleria lutea，也会从曲嘴森莺造成的花孔中吸取花蜜，同时捕食小型昆虫。","breeding":"繁殖行为全年皆可见，主要集中在1月至5月，每年可能抚育三窝。巢为细纤维和蜘蛛网构成的杯状，通常建于地面1至3米高的细枝上，由雌鸟独自孵化为期17至19天的两枚蛋，幼鸟19至24天后离巢。","identification":"雄鸟以其独特的尾流苏与红嘴长尾蜂鸟区分，而雌鸟则通过全黑的喙与红嘴长尾蜂鸟雌鸟及 vervain 蜂鸟区别。","protection":"IUCN：LC（无危）","distribution":"仅分布于牙买加的东部地区。","other":"该物种对人造环境的适应性表明，栖息地丧失不大可能是其面临的主要威胁。"},{"name":"蓝颏青蜂鸟","english_name":"Blue-chinned Sapphire","scientific_name":"Chlorestes notata","overview":"蓝颏青蜂鸟（英文名：Blue-chinned Sapphire，学名：Chlorestes notata），是雨燕目蜂鸟科蓝颏青蜂鸟属的鸟类。广泛分布于南美的蜂鸟，从哥伦比亚至巴西东部，遍及亚马逊雨林区域。其主要特征为绿色羽毛，雄鸟拥有深蓝色尾羽和蓝颏，雌鸟腹部有绿色斑点。","appearance":"蓝颏青蜂鸟体型小，雄鸟长8.9厘米，重约3.8克。喙短而直，上颚黑色，下颚红褐色。雄鸟上部羽毛呈闪亮的青铜绿，下巴虹彩蓝，下部虹彩绿，尾羽叉状，钢蓝色。雌鸟上部和喙类似雄鸟，下部白色带闪光圆斑，尾羽钢蓝色。","call":"鸣声单调，持续重复“tsip, tsip, tsip...”。","habits":"常见于草原、种植园、城镇花园、田野、树篱及落叶林边缘，高度低至中等，1-6米。以花园植物花蜜为主食，如Russelia、Salvia、Hibiscus等，也摄食蜘蛛、昆虫和昆虫蜜露，通过空中捕食昆虫。雄鸟建立并保卫喂食领地。","breeding":"繁殖期为8月至11月或10月至次年1月。杯形巢置于小树细枝或离地面约1米的暴露根部，由细纤维、叶条和树皮条构成，内部铺软质材料如绒毛种子或种子纤维，外部装饰苔藓、叶片碎片和树枝。产卵2枚，尺寸14-14.2毫米×8-8.5毫米，重量0.5克，由雌鸟孵卵14-16天，雏鸟暗灰色，背部有两排灰色绒毛，20-22天离巢，有时可达28天。","identification":"雄鸟与蓝尾翠蜂鸟雄鸟相似，但体型更大，尾羽非叉状，下部呈蓝绿色调。雌鸟与辉喉蜂鸟相似，但胸斑均匀。","protection":"IUCN：LC（无危）；CITES: II级。在分布范围内常见，适应人类创造的环境如种植园和公园。","distribution":"分布于南美，自哥伦比亚向东南至圭亚那、特立尼达和多巴哥、秘鲁及巴西。在巴西，沿亚马逊主河盆地和东北部的大西洋森林，以及东南沿海地带。","other":"蓝颏青蜂鸟有时被归入Chlorostilbon属。"},{"name":"紫腹蜂鸟","english_name":"Violet-bellied Hummingbird","scientific_name":"Chlorestes julie","overview":"紫腹蜂鸟（英文名：Violet-bellied Hummingbird，学名：Chlorestes julie），是雨燕目蜂鸟科蓝颏青蜂鸟属的鸟类。分布于中美洲的巴拿马到南美洲西北部的秘鲁。雄鸟以亮紫色腹部为显著特征，雌鸟腹部呈淡灰色，全身闪烁着金属绿光泽。此物种常见于森林和边缘地带，适应湿润及半干旱环境。","appearance":"紫腹蜂鸟体型小巧，雄鸟上身呈金属绿色，最引人注目的是其明亮的紫色腹部，而雌鸟的腹部为淡灰色。雄鸟的喉咙和头部下方呈亮丽的金属绿色，腹部和两侧为金属紫色。雌鸟上身金属青铜绿色，腹部为淡灰色，略带白色。幼鸟似雌鸟，但前颈可能带有闪亮的蓝绿色斑点。","habits":"紫腹蜂鸟栖息于森林和森林边缘，偏好湿润及半干旱区域。它们以各种开花灌木和树木的花蜜为食，同时捕食空中昆虫。经常在较低至中层的花丛中觅食，也会光顾人工喂食器。","breeding":"紫腹蜂鸟的繁殖习性为多配偶制，雄鸟通过在高约1-10米的枝头歌唱吸引雌鸟。雌鸟独自筑巢，巢由植物纤维、动物毛发和羽毛构成，建于距地面约1.2至4.2米的树或灌木上。每窝产两枚白色卵，尺寸约为8x13毫米，孵化期约15天，雏鸟需20-22天才能离巢。雏鸟出生时无助，依赖母鸟喂养和保护。","identification":"紫腹蜂鸟与木精灵蜂鸟（Thalurania）相似，但体型较小，背部为绿色而非紫色，尾巴圆形而非凹陷。雄性紫腹蜂鸟与蓝顶妍蜂鸟和青喉蜂鸟有颜色上的相似性，但可通过尾型、喉部和腹部颜色加以区分。","protection":"IUCN：LC（无危）","distribution":"紫腹蜂鸟分布于中美洲巴拿马至南美洲西北部的秘鲁，包括巴拿马、哥伦比亚和厄瓜多尔等地。"},{"name":"蓝喉红嘴蜂鸟","english_name":"Blue-throated Sapphire","scientific_name":"Chlorestes eliciae","overview":"蓝喉红嘴蜂鸟（英文名：Blue-throated Sapphire，学名：Chlorestes eliciae），是雨燕目蜂鸟科蓝颏青蜂鸟属的鸟类。分布于中美洲至南美洲北部的蜂鸟。生活在墨西哥南部至哥伦比亚西北部的热带低地森林边缘、种植园和林地中，偏好湿润至半湿润环境。雄鸟具有独特的蓝色喉咙和金色尾巴，雌鸟则颜色稍淡，喉部带灰蓝斑点。","appearance":"蓝喉红嘴蜂鸟体型中等，总长8-9厘米，雄鸟略大于雌鸟。雄鸟头部、背部呈金属绿色，尾羽金绿闪耀，喉部为蓝紫色，腹部为淡黄褐色，侧胸和胁部有绿色斑纹。雌鸟相似，但色彩较暗淡，喉部灰蓝混杂。喙直而红，尖端黑色，基部宽大。","call":"雄鸟在群体中发出多种不同的鸣叫声，包含一系列单音或双音节，或短颤音的组合，叫声高亢，带有嗡嗡声。","habits":"栖息于低海拔森林、次生林、种植园和花园等环境，活动于树冠层。主要以花蜜为食，偶尔捕食小昆虫。在繁殖季节，雄鸟会聚集在特定地点鸣叫和展示。","breeding":"繁殖期可能在旱季，从十二月至七月。巢呈杯状，由植物材料和蜘蛛网构建，通常位于林缘、次生植被或花园的小枝上，高度约2-4米。每窝产卵2枚。","identification":"与棕尾蜂鸟和蓝头红嘴蜂鸟相似，但蓝喉红嘴蜂鸟的喙更直，尾羽金色，喉部蓝紫色，而非绿色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲北部，具体包括墨西哥南部至哥伦比亚西北部，以及中美洲国家如危地马拉、洪都拉斯、萨尔瓦多、尼加拉瓜、哥斯达黎加、巴拿马等地。","other":"曾归类于Hylocharis属，后基因研究将其调整至Chlorestes属。"},{"name":"白颊红嘴蜂鸟","english_name":"White-chinned Sapphire","scientific_name":"Chlorestes cyanus","overview":"白颊红嘴蜂鸟（英文名：White-chinned Sapphire，学名：Chlorestes cyanus），是雨燕目蜂鸟科蓝颏青蜂鸟属的鸟类。小型蜂鸟，以直喙、绿色颈背和铜色臀部、深色尾巴为显著特征。雄鸟在特定光线下展现紫蓝色头部和模糊的白色颊部，喙红黑相间。雌鸟头部绿色，喉部有斑点，腹部偏白色。常见于热带湿润森林内部及边缘。","appearance":"体型小，约8至9厘米，体重2.8至3.5克。雄鸟喙直而中等长度，珊瑚红色，尖端暗色；头部、脸颊、喉部呈现明亮的紫蓝色，背部金色绿，臀部铜色；下巴基部白色；腹部和胁部金绿色，中心更显灰；上尾覆羽深铜至紫色；尾羽钢蓝至蓝黑色，中间尾羽有时呈深青铜绿。雌鸟头部绿色，喉部有斑点，腹部偏白色；下腹及尾下覆羽白色，外侧尾羽具灰色端带。幼鸟头部和喉部部分蓝绿色，腹部较灰，尾下覆羽暗灰色。","call":"雄鸟的鸣唱类似Amazilia sapphirina，自孤立的高枝发出虫鸣般的连续短语，如‘ca-seek’或‘tweeh-chit’，频率每秒2至3次，持续数分钟。","habits":"栖息于热带低地常绿森林边缘、河岸林木、种植园等地，高度从低地到亚山地，海拔200至1250米。觅食花蜜和蜘蛛、甲虫、苍蝇等昆虫，从地面至树顶均可见其觅食，有时与其他蜂鸟聚集于喂食树。","breeding":"几乎全年繁殖，如在巴西东南部9月至11月，在亚马逊北部11月至2月，在南部12月至3月。巢杯状，由植物纤维构成，建于离地1.5至4米的水平枝上，外部附有蛛网和苔藓。每窝产卵2枚，卵长14至14.3毫米×宽8.5至9毫米，重0.42至0.43克，由雌鸟孵化14至15天，小鸟20至26天后离巢。","identification":"雄鸟头部紫蓝，雌鸟喉部有斑点，腹部偏白色，与其他蜂鸟区别明显。亚种viridiventris、rostrata、conversa和griseiventris在喙长、腹部颜色和尾下覆羽上有细微差异。","protection":"IUCN：LC（无危）。CITES II。在较为湿润的森林边界和河岸林地普遍，但在较干旱生境较少见。适应人类改造的环境，如果树林和公园。在多个保护区出现。","distribution":"主要分布在南美洲的亚马逊雨林及东南部，包括哥伦比亚的阿马卡尤国家公园、委内瑞拉的伊马塔卡森林保护区、巴西的Mata dos Godoy州立公园和秘鲁的坦博帕塔保护区。","other":"曾被归类于Hylocharis属，2014年分子系统学研究发现Hylocharis多系群，故将其移至Chlorestes属。"},{"name":"白腹绿蜂鸟","english_name":"White-bellied Emerald","scientific_name":"Chlorestes candida","overview":"白腹绿蜂鸟（英文名：White-bellied Emerald，学名：Chlorestes candida），是雨燕目蜂鸟科蓝颏青蜂鸟属的鸟类。体型较小的蜂鸟，其上部为绿色，腹部为白色，与红嘴蜂鸟相似，但体形更小，腹部全白。该物种广泛分布于热带雨林和边缘地带，包括墨西哥东部至尼加拉瓜的低地常绿和半落叶森林。","appearance":"白腹绿蜂鸟具有典型的性别二态性，但外观上雌雄相似，上体金属青铜色到青铜绿色，背部通常更绿，腹部纯白，带有金属青铜绿色斑点从脸颊延伸至两侧。尾羽为金属青铜色，除中央一对外，其余尾羽近端有一条宽的暗紫色或黑色带，最外侧两对尾羽末端呈暗褐色。成鸟与幼鸟的区别在于幼鸟的冠羽、臀羽和尾上覆羽的羽毛顶端有微弱的棕色尖端。","call":"白腹绿蜂鸟的鸣声被描述为高音、尖锐的‘chipping’声，有时表现为单调的、高音的吱吱声，如‘tssi-ip tssi-ip’或‘tsip tsip’等。","habits":"白腹绿蜂鸟栖息于低地常绿和半落叶森林的内部和边缘地带，从海平面到海拔1,600米的高度都有分布。它们在觅食时会低飞至地面，同时也会在树冠层觅食，以花蜜为主食，来自各种开花植物，同时也会在树叶中寻找昆虫。它们受到体型更大的棕尾蜂鸟的支配。","breeding":"白腹绿蜂鸟的繁殖季节从2月持续到5月。雄鸟在lek中唱歌，暗示其可能采取一雄多雌制。雌鸟用植物材料和蜘蛛网筑杯状巢，外部装饰有苔藓和地衣，每窝产2枚蛋。","identification":"与红嘴蜂鸟相比，白腹绿蜂鸟体型更小，尾羽缺乏明显的白色角，且头部和侧面无蓝色。C. c. genini亚种具有较长和较宽的喙，而C. c. pacifica亚种的喙更粗壮，背部的绿色延伸至两侧和腹部。","protection":"IUCN：LC（无危）","distribution":"白腹绿蜂鸟分布于中美洲，从墨西哥东部至尼加拉瓜的低地常绿和半落叶森林，以及部分地区的河岸树林、空旷地带和种植园。","other":"白腹绿蜂鸟在热带加勒比低地较为常见，但在较高海拔或太平洋斜坡上则较少见。"},{"name":"金冠翠蜂鸟","english_name":"Golden-crowned Emerald","scientific_name":"Cynanthus auriceps","overview":"金冠翠蜂鸟（英文名：Golden-crowned Emerald，学名：Cynanthus auriceps），是雨燕目蜂鸟科阔嘴蜂鸟属的鸟类。体型小巧的蜂鸟，仅分布于墨西哥西部。其最显著的外部特征是雄鸟的金绿色冠羽和极深的叉尾，以及红褐色的喙尖。雌鸟则具有斑纹脸庞和相似的喙色。该物种曾被认为是卡氏翠蜂鸟的一个亚种，现已被确认为独立物种。","appearance":"雄性金冠翠蜂鸟拥有完全的翡翠绿色羽毛，其中冠羽呈金绿色，尾巴长而深叉，黑色基底带紫蓝色光泽，中央三对尾羽顶端呈棕灰色。喙部红色，尖端黑色。雌鸟上体同样为绿色至青铜绿色，下面部灰暗，腹部较浅，脸颊处有灰白色条纹，尾部略短，但依然叉开，中央尾羽蓝绿色至青铜绿色，多数带有黑色环带和灰尖。喙部颜色与雄鸟相似。","call":"金冠翠蜂鸟发出干燥、咔嚓作响的叫声。","habits":"金冠翠蜂鸟偏好干旱至半湿润地带的灌木林地、森林边缘和花丛，常在较低和中层区域觅食花蜜或昆虫。它们在觅食时会摆动尾巴。这种蜂鸟主要居住在墨西哥西部，从锡那罗亚州南至瓦哈卡州东部，以及内陆沿巴尔萨斯河盆地至莫雷洛斯州南部，海拔高度从海平面至1,800米。","breeding":"繁殖季节从2月持续到7月。金冠翠蜂鸟会在靠近地面的细枝梢端建造一个小杯状巢穴，巢底部有时会有一个小平台，由木片构成，巢身由木棉种子纤维制成，外侧覆盖草、木屑和地衣。每次产卵数量为两枚，幼鸟在孵化后约24至25天离巢。","identification":"雄性金冠翠蜂鸟的长而深叉的尾巴是其显著特征，可轻易与同类其他物种区分。雌鸟与阔嘴蜂鸟雌鸟类似，但体型更小，喙更短更直。","protection":"IUCN：LC（无危）","distribution":"金冠翠蜂鸟主要分布在墨西哥西部，从锡那罗亚州南至瓦哈卡州东部，以及内陆沿巴尔萨斯河盆地至莫雷洛斯州南部。"},{"name":"科苏梅尔翠蜂鸟","english_name":"Cozumel Emerald","scientific_name":"Cynanthus forficatus","overview":"科苏梅尔翠蜂鸟（英文名：Cozumel Emerald，学名：Cynanthus forficatus），是雨燕目蜂鸟科阔嘴蜂鸟属的鸟类。仅见于墨西哥尤卡坦半岛附近的科苏梅尔岛。为岛上最常见的蜂鸟种类。","appearance":"雄性科苏梅尔翠蜂鸟身长9至10.5厘米，拥有醒目的金绿色冠羽和略暗的上体羽毛，其下体呈现耀眼的金属金绿色，尾羽深蓝黑色，末端有棕色灰色尖端，尾部深叉状。雌鸟体型稍小，长约8至9.1厘米，上体亮绿至青铜绿色，下体淡灰色，尾羽较短，深叉程度不如雄鸟显著。两者均有分叉的尾羽，但雄鸟的更长更深叉。","call":"其鸣叫声被描述为干燥、颤动和叽喳声，类似于近缘物种的叫声。","habits":"科苏梅尔翠蜂鸟栖息于灌木丛生的林地或次生植被区，主要在较低层和中层寻找花蜜或昆虫为食。它们被认为是全年居住于科苏梅尔岛上的。","identification":"雄性科苏梅尔翠蜂鸟最明显的特征是其长而深叉的尾羽，而雌鸟则与属内的其他成员相似。与邻近的卡氏翠蜂鸟相比，科苏梅尔翠蜂鸟雄鸟的尾羽更长、更深叉，雌鸟的尾羽也有类似差异，但较为细微。此外，与西部墨西哥的金冠翠蜂鸟相比，科苏梅尔翠蜂鸟的尾羽更为宽大且尖锐。","protection":"IUCN：LC（无危）","distribution":"科苏梅尔翠蜂鸟主要分布在墨西哥的科苏梅尔岛，偶尔会访问约90公里以北的穆赫雷斯岛。"},{"name":"卡氏翠蜂鸟","english_name":"Canivet's Emerald","scientific_name":"Cynanthus canivetii","overview":"卡氏翠蜂鸟（英文名：Canivet's Emerald，学名：Cynanthus canivetii），是雨燕目蜂鸟科阔嘴蜂鸟属的鸟类。热带低地的小型蜂鸟。在森林边缘和半开阔地带活动频繁，偏好较为干燥的生境。卡氏翠蜂鸟的显著特征是其闪烁的绿宝石色外观，雄鸟的尾部呈叉状，而雌鸟的白眉纹和宽黑面具使其易于识别。这种蜂鸟广泛分布于中美洲，自墨西哥东南部至哥斯达黎加。","appearance":"雄性卡氏翠蜂鸟体长7.8至9.3厘米，体重约2.1至2.8克，上身闪耀着金绿色光泽，下身同样呈金绿色，尾部蓝黑色带蓝色光泽，叉状。雌鸟体型略小，体长7.5至8.6厘米，体重约2.3克，上身金属绿色至青铜绿色，下身淡灰色，脸颊暗色，眼后有一条灰白色纹路，尾部中央羽毛蓝绿色，末端有白色尖端。雌雄两性均会在悬停时摇摆叉状尾羽。","call":"卡氏翠蜂鸟的鸣叫被描述为干涩、沙哑的'chut'或'chit'声，有时连成一串软弱的断音颤鸣，这与红冠戴菊的叫声有些相似。","habits":"卡氏翠蜂鸟栖息于从海平面至1,900米海拔的半开放至开放景观，如常绿林边缘、次生林、灌木草原和花园。它们采取陷阱线觅食策略，不保卫领地，而是沿着一系列开花植物采食花蜜，同时也会捕食小型节肢动物。","breeding":"繁殖季节随分布区域而异，从2月至5月在墨西哥东部，12月至次年2月在萨尔瓦多，11月至次年3月或4月在哥斯达黎加，可能包括5月在洪都拉斯。巢由植物纤维和绒毛制成，外部覆盖树皮碎片，通常建在地面1至3米的高度。关于孵化期和雏鸟离巢时间的信息尚不清楚。","identification":"卡氏翠蜂鸟与同属的金冠翠蜂鸟和科苏梅尔翠蜂鸟在分布上互不重叠，但若相遇，可通过尾羽形状、颜色和雌鸟的面部特征进行区分。金冠翠蜂鸟和科苏梅尔翠蜂鸟雄鸟尾羽更长且分叉更深，雌鸟尾羽也较长且分叉，基部白色更多。","protection":"IUCN：LC（无危）","distribution":"卡氏翠蜂鸟遍布中美洲，从墨西哥东南部的塔毛利帕斯至尤卡坦半岛，经伯利兹、危地马拉北部，直至洪都拉斯（包括其离岸岛屿），向南延伸至尼加拉瓜西部和哥斯达黎加西北部的太平洋沿岸。","other":"卡氏翠蜂鸟有两个主要群体，一个位于墨西哥东南部、危地马拉北部和伯利兹，另一个在从墨西哥南部至哥斯达黎加西北部的太平洋沿岸，这两个群体有时也被认为是独立的物种。"},{"name":"阔嘴蜂鸟","english_name":"Broad-billed Hummingbird","scientific_name":"Cynanthus latirostris","overview":"阔嘴蜂鸟（英文名：Broad-billed Hummingbird，学名：Cynanthus latirostris），是雨燕目蜂鸟科阔嘴蜂鸟属的鸟类。色彩斑斓的小型蜂鸟，以其独特的宽红嘴而著称。主要分布在墨西哥，但在美国西南部局部地区也有发现。性别差异显著，雄鸟体色更为鲜艳，雌鸟则较暗淡。广泛分布于美国西南部至墨西哥中部。","appearance":"雄性阔嘴蜂鸟拥有明亮的蓝喉，黑色尾羽带蓝色光泽，白腹下覆羽。雌鸟上体呈金属青铜绿色，下体灰暗，具白色眼纹，尾羽末端白色。幼鸟类似雌鸟，但逐渐显现雄鸟特征，如蓝色喉部斑块。","call":"发出类似红冠戴菊的急速'chi-dit'声，以及雄鸟特有的'zing'声。","habits":"栖息于溪边灌木丛、橡木林地、低山峡谷等生境。以花蜜为主食，也会捕食空中昆虫。偏好红或红黄相间的花朵。分布范围包括北美西南部至墨西哥中部。","breeding":"繁殖季节在春季至夏季，选择靠近水源的林地筑巢，雌鸟独自建巢，巢距地面约2米，通常在4月到8月间尝试两次繁殖。","identification":"与白耳蜂鸟区分在于雌性阔嘴蜂鸟具有更明显的灰色喉部，而非圆点状，且耳斑为灰色。雄鸟幼鸟开始换羽时，喉部显现大块蓝色斑块，不同于白耳蜂鸟的圆形绿斑。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要在美国西南部（亚利桑那州东南部、新墨西哥州西南部、德克萨斯州西南部）和墨西哥中部。非繁殖季节可能迁徙至墨西哥更南部地区。","other":"在某些地区，如索诺拉州，阔嘴蜂鸟是最常见的蜂鸟种类之一。"},{"name":"青绿阔嘴蜂鸟","english_name":"Turquoise-crowned Hummingbird","scientific_name":"Cynanthus doubledayi","overview":"青绿阔嘴蜂鸟（英文名：Turquoise-crowned Hummingbird，学名：Cynanthus doubledayi），是雨燕目蜂鸟科阔嘴蜂鸟属的独特蜂鸟，以青绿色的头部和宽阔的红色喙著称。分布于墨西哥南部，主要栖息于太平洋沿岸的瓜纳华托至瓦哈卡一带。雄鸟在适当光线下呈现钴蓝色光泽，雌鸟则色泽较为暗淡，灰褐色腹部带有一条明显的淡色眼纹。","appearance":"体型小巧（3-4克），外观修长，背部呈金属青铜绿色，头部色彩较淡。成年雄鸟下部深绿色，带有耀眼的蓝宝石色喉部，尾羽宽大，末端呈蓝黑色，翼羽棕色，尾侧有白色羽毛簇。雌鸟上体颜色较雄鸟暗淡，下体灰色。下喙基部常为红色，逐渐变为黑色尖端；具有一条可辨识的白色眼纹，衬托着模糊的暗灰色耳斑。尾羽方尖，基部青铜绿色，末端转为蓝黑或绿黑色，最外两根尾羽有白色尖端。幼鸟雌鸟与成年雌鸟难以区分，幼雄鸟尾羽蓝绿至灰褐色，尾部无白色，下体灰色，混杂少量闪光蓝或深绿色羽毛。","call":"青绿阔嘴蜂鸟的叫声独特，类似红冠戴菊的je-dit声，与紫冠蜂鸟的叫声相似，明显不同于白耳蜂鸟的金属音。","habits":"在墨西哥南部的多个景观中定居，包括干旱灌木丛、热带落叶林、河岸林和次生森林。偶尔可见于松栎林和草地山坡。活动范围通常在海拔0到2200米之间，最高可达3000米。以多种开花植物的花蜜和小型节肢动物为食，采用陷阱线的方式在河岸林中觅食花蜜。","breeding":"繁殖季节未知，但似乎全年都有筑巢活动。雄鸟通过一系列频率从2到13kHz的短促chip音开始鸣唱。","identification":"与白耳蜂鸟相比，青绿阔嘴蜂鸟的耳斑几乎总是黑色，而白耳蜂鸟的耳斑为灰色。白耳蜂鸟的喉咙有圆形的暗斑点，而青绿阔嘴蜂鸟雌鸟的喉咙中心明显为灰色。幼雄鸟开始换羽时，喉咙颜色显示大的蓝色斑块，而非白耳蜂鸟幼雄鸟的圆形绿色斑点。与暗色蜂鸟的区别在于，青绿阔嘴蜂鸟的尾羽为蓝黑色，而暗色蜂鸟的尾羽为暗橄榄绿色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的墨西哥南部，包括太平洋沿岸的瓜纳华托至瓦哈卡一带。","other":"青绿阔嘴蜂鸟是墨西哥的特有种，其种群可能受到栖息地丧失的影响，但具体影响程度尚未研究清楚。"},{"name":"三圣岛蜂鸟","english_name":"Tres Marias Hummingbird","scientific_name":"Cynanthus lawrencei","overview":"三圣岛蜂鸟（英文名：Tres Marias Hummingbird，学名：Cynanthus lawrencei），是雨燕目蜂鸟科阔嘴蜂鸟属的鸟类。体型小巧，全身闪烁着金属绿光泽，雄鸟拥有璀璨的绿色羽毛和虹彩喉部，喙部鲜红亮丽。雌鸟则呈现出较不显眼的灰底色，头顶至背部为金属绿色，下体灰色，喙基部带红色。本物种仅在墨西哥中部太平洋沿岸约60英里外的马利亚斯群岛中发现，该群岛上唯一的另一种蜂鸟是桂红蜂鸟。三圣岛蜂鸟栖息于灌木丛、林地和花园。","appearance":"三圣岛蜂鸟为小型蜂鸟，体重3-4克，外观纤细，具有宽大的红色喙尖。成年雄鸟上体呈金属青铜绿色，虹彩喉部为蓝绿色，下体金属青铜绿色，尾羽暗灰色，翼下覆羽暗灰色，中央尾羽蓝黑色并带有灰色尖端，翼羽褐色。雌鸟上体金属绿色较暗淡，面部由白色眉纹和灰褐色耳羽主导，下体灰色，尾羽基部为青铜绿色并逐渐过渡到蓝色，最外侧两到三根尾羽尖端白色。幼鸟的描述不详，但可能与近缘的阔嘴蜂鸟相似。","call":"关于三圣岛蜂鸟的鸣叫特征，现有资料并未提供详细信息。","habits":"三圣岛蜂鸟居住在马利亚斯群岛的所有四个岛屿上的灌木丛、林地和花园。它们以花蜜和小昆虫为食，如同近缘的阔嘴蜂鸟和其他许多蜂鸟一样，通过悬停摄食。在繁殖季节，它们可能会表现出一定的领地行为。","breeding":"三圣岛蜂鸟的繁殖期为4月至7月。关于其繁殖生态的具体细节，如求偶、筑巢、交配、产卵、孵化和育雏过程，目前资料有限。","identification":"雄性三圣岛蜂鸟与阔嘴蜂鸟的区别在于喉部颜色（蓝绿色对比紫蓝色）、下体颜色（较深的灰色）和喙长（较短）。雌性三圣岛蜂鸟的额部和下体颜色亦较暗，喙长同样较短。此外，尾部长度和形状也有差异，雄性三圣岛蜂鸟的尾部更长且分叉更深。","protection":"IUCN：NT（近危）","distribution":"三圣岛蜂鸟仅限于墨西哥西部海域的马利亚斯群岛繁殖。该群岛位于墨西哥中部太平洋沿岸约60英里处。","other":"2022年，基于与阔嘴蜂鸟和其他种群显著的遗传和形态差异，三圣岛蜂鸟被提升为独立物种。"},{"name":"花园翠蜂鸟","english_name":"Garden Emerald","scientific_name":"Chlorostilbon assimilis","overview":"花园翠蜂鸟（英文名：Garden Emerald，学名：Chlorostilbon assimilis），是雨燕目蜂鸟科翠蜂鸟属的小型鸟类。以全身闪烁的绿色羽毛而著称，分布于中美洲的哥斯达黎加西南部和巴拿马的太平洋沿岸，包括科伊巴岛和珍珠群岛。该鸟种的雄鸟通体呈深金属绿色，雌鸟上身则为明亮的金属绿至青铜绿色。","appearance":"成年雄鸟上体为深金属绿色，翼部暗淡带紫色光泽，下体颜色更亮，有时带有淡蓝色光泽，两腿白色毛丛。雌鸟上体为明亮的金属绿至青铜绿色，下体淡灰色，眼后有白色或灰白色斑点。幼鸟似雌鸟，但下体较暗。体长7.8至8.5厘米，体重约3至4.1克。","call":"关于其鸣叫特征的信息尚不充分，可能与卡氏翠蜂鸟相似。","habits":"花园翠蜂鸟栖息于开阔地带，如林地边缘、树篱、溪边灌木丛、灌木地和花园。它们主要以花蜜为食，通过访问一系列开花的树木、灌木和其他植物进行觅食，也会在枝叶间寻找小昆虫。生活在低地，海拔高度从海平面到1500米左右。","breeding":"繁殖季节尚未完全确定，但在巴拿马似乎至少从11月持续到3月。其筑巢、孵化期、离巢时间等繁殖生态细节尚未记录，但可能与其他Chlorostilbon属蜂鸟类似。","identification":"雄鸟与雌鸟的明显差异在于雄鸟的全绿色外观和蓝黑色分叉尾羽，雌鸟具有独特的暗色面罩，后面有白色的眉纹。在巴拿马西部，雌鸟是唯一具有明确暗色面罩和眼后白色眉纹的小型蜂鸟。","protection":"IUCN：LC（无危）。花园翠蜂鸟拥有广阔的分布范围，估计成熟个体数量至少为50,000只，且被认为数量稳定，无立即威胁。","distribution":"分布于中美洲的哥斯达黎加西南部和巴拿马的太平洋沿岸，包括科伊巴岛和珍珠群岛。在哥斯达黎加，分布可达1500米的海拔高度，在巴拿马则为1200米。","other":"花园翠蜂鸟曾被视为蓝尾翠蜂鸟的一个亚种，现在作为一个独立物种，其种内没有其他亚种。"},{"name":"蓝尾翠蜂鸟","english_name":"Blue-tailed Emerald","scientific_name":"Chlorostilbon mellisugus","overview":"蓝尾翠蜂鸟（英文名：Blue-tailed Emerald，学名：Chlorostilbon mellisugus），是雨燕目蜂鸟科翠蜂鸟属的鸟类。广泛分布于南美洲北部的常见小型翠蜂鸟，喜栖潮湿低地及林缘，雄鸟通体闪金属翠绿，尾羽深蓝且叉状，雌鸟下体灰、尾羽稍短。","appearance":"雄鸟体长7.5–9.5厘米，雌鸟6.5–7.5厘米。雄鸟额与头顶呈金绿虹彩，上体青铜绿，下体闪烁翠绿并具白色股羽，尾钢蓝且深叉；光线不足时看似全暗绿。雌鸟上体金属草绿，耳羽具黑色宽带，上方以苍白纹相隔，下体淡灰，尾蓝黑、末端灰白、分叉浅。幼鸟似雌鸟，但冠较暗橄榄绿，下体浅褐，股羽及尾下覆羽白。嘴直而全黑；跗跖及趾暗褐至近黑；虹膜黑。","call":"鸣唱微弱，为连续“tsip”或“chwep”的单音重复，间或带颤音。叫声中包括较响亮的粗哑“chirrrt”。歌声常被形容为相机高速快门声，节奏每秒3–4音，偶以几声前导音开始。","habits":"留鸟，局部或有海拔迁移。栖热带至亚热带，自海平面至2200米，常见于森林边缘、次生灌丛、种植园、花园、稀树草原及林隙。觅食时快速直飞至花丛，有时悬停取食，亦记录盗蜜行为；以花蜜为主，兼食小型节肢动物及树汁。捕虫方式主要为空中掠食。","breeding":"在委内瑞拉北部及特立尼达几乎全年繁殖，高峰期在雨季末至旱季初。巢建于0.8–0.9米高的倾斜细枝上，杯状，由植物绒与蛛丝黏合，外覆树皮及地衣。每窝2枚白色卵，11.3–12.75 × 7.4–8.25毫米，重约0.4克。仅雌鸟孵卵，13–19天；雏鸟18–20天出飞。","identification":"同属内，可通过雄鸟全黑嘴、翠绿体羽及深蓝叉尾，雌鸟灰下体与蓝黑尾羽相区分。亚种间差异细微：caribaeus喉部无蓝辉；duidae头与上体呈铜橙；subfurcatus喉及尾上覆羽更蓝绿；phoeopygus尾叉略深。","protection":"IUCN: LC（无危）。CITES附录II。整体数量稳定，广泛且常见，能适应人造环境，唯特立尼达及厄瓜多尔东部较为稀少。","distribution":"繁殖区覆盖南加勒比海岛屿（阿鲁巴、库拉索、博内尔、特立尼达、玛格丽塔）及委内瑞拉、圭亚那、苏里南、法属圭亚那，并沿安第斯山东麓经哥伦比亚、厄瓜多尔、秘鲁至玻利维亚北部，再东入巴西西部与西北部。非繁殖区与其繁殖区基本重合，局部有季节性海拔移动。","other":"历史上曾被视为包含多达17个亚种的大复合体，现已拆分成7个独立种。现存7个亚种的有效性仍待进一步研究。"},{"name":"西翠蜂鸟","english_name":"Western Emerald","scientific_name":"Chlorostilbon melanorhynchus","overview":"西翠蜂鸟（英文名：Western Emerald，学名：Chlorostilbon melanorhynchus），是雨燕目蜂鸟科翠蜂鸟属的鸟类。分布于南美的哥伦比亚西部和厄瓜多尔西部、中部。体型较小，羽毛以闪烁的翡翠绿为主，雄鸟全身覆盖着金属光泽的绿色，尾部呈深蓝色；雌鸟上身绿色，下身淡灰色，眼后有一白色线条。广泛出现在花园、半开放或灌木地带，适应力强。","appearance":"西翠蜂鸟体长10.9至11.4厘米，体重约2.6克。雄鸟拥有完全闪耀的翡翠绿色羽毛，头部和颈部带有金色到橙色反光，下体呈现出蓝绿色调的强烈光泽。雌鸟上身绿色，下身淡灰至白色，喉部和腹部带有微黄色彩，尾部蓝黑，尖端略白。喙短而直，黑色。","call":"其鸣唱是一系列连续的低沉刮擦声和嘶哑音符，速率约为每秒3至4个音符，有时前有几声引子，如“witsitsitsi...chirr..chirr..chirr..chirr..”或“tsit-trr, tsit-trr, tsit-trr, tsit-trr...”。叫声包括轻微的“tsip”，“pit”，和“chwep”。","habits":"西翠蜂鸟主要栖息于开阔或半开阔的环境，如成熟森林边缘、种植园、农田、花园等。飞行模式较为直线，通常单独觅食于较低层或中层，偏好花蜜，常访问花园中的花卉和人工喂食器。","breeding":"繁殖季节在哥伦比亚可能从1月持续到6月，但具体繁殖细节如巢的描述等尚未被充分记录。雌雄鸟在繁殖期的生理状态已得到确认。","identification":"与蓝尾翠蜂鸟极为相似，但两者不存在地理重叠。不同亚种之间的差异不大，主要体现在喙的长度和冠羽的亮度上。","protection":"IUCN：NR（未评估），但在其分布范围内相当常见，能够适应人类创造的生境。","distribution":"分布于南美洲的哥伦比亚西部以及厄瓜多尔的西部和中部，从热带至温带区域，海拔高度从600米至1800米，局部可达3050米。","other":"曾被视为蓝尾翠蜂鸟的一个亚种，近年来被重新分类为独立物种。"},{"name":"红嘴翠蜂鸟","english_name":"Red-billed Emerald","scientific_name":"Chlorostilbon gibsoni","overview":"红嘴翠蜂鸟（英文名：Red-billed Emerald，学名：Chlorostilbon gibsoni），是雨燕目蜂鸟科翠蜂鸟属的鸟类。小型蜂鸟，主要分布在南美的哥伦比亚和委内瑞拉西北部。以其独特的红嘴和绿宝石般的羽毛而闻名。","appearance":"体长约7.6至9厘米，体重约2.8克。雄鸟全身呈现深青铜绿色，头部和下体闪烁着绿至金绿色光泽，尾巴深蓝黑色且深叉。雌鸟上身发光绿，下身灰白，脸颊暗淡，眼后有一短白色线。喙直，雄鸟下颚大多红色，雌鸟基部红色。","call":"发出连续的金属颤音，节奏约为每秒3个音符，同时伴有高音穿透性的“tseeee”和芦苇似的“tzreee”叫声。","habits":"偏好干燥至荒漠地带，包括沙漠灌木丛、干燥林地、农田和公园花园。通常在低处觅食花蜜，偶尔飞得更高，偏爱小花。其活动范围在哥伦比亚海拔500米以下，但在上马格达莱纳谷地可高达2,300米，在委内瑞拉可达1,300米。","breeding":"繁殖季节尚不明确，但在委内瑞拉可能从3月持续到8月，在哥伦比亚至少部分区域包括11月。已知会筑下绒毛杯状巢，外表粘附苔藓，固定在蕨类植物叶片上。","identification":"与蓝尾翠蜂鸟的雌鸟在野外难以区分，但红嘴翠蜂鸟的背部更铜色，外侧尾羽基部浅灰色。与Amazilia saucerottei相比，体型较小，无铜色臀部，下体覆羽绿色而非蓝色。","protection":"IUCN：LC（无危）","distribution":"主要分布于哥伦比亚中部的马格达莱纳河谷，北部科尔多瓦和桑坦德北部之间，以及哥伦比亚瓜希拉半岛和委内瑞拉西北部邻接地区。","other":"历史上曾被视为蓝尾翠蜂鸟的亚种，现已被多数分类学家视为独立物种。"},{"name":"奇里翠蜂鸟","english_name":"Chiribiquete Emerald","scientific_name":"Chlorostilbon olivaresi","overview":"奇里翠蜂鸟（英文名：Chiribiquete Emerald，学名：Chlorostilbon olivaresi），是雨燕目蜂鸟科翠蜂鸟属的鸟类，仅分布于南美洲哥伦比亚东南部的偏远奇里比奎特山脉，远离安第斯山脉。","appearance":"雄性奇里翠蜂鸟体型长约8.5至9厘米，体重约3.8克，上体呈现金属绿色光泽，尾羽深钢蓝色，头颈两侧反射金色绿光，喉部与上胸闪耀蓝绿色，其余下体亮金属绿色。雌鸟体长约相同，体重约3.6克，上体金属青铜绿色，下体淡灰色，脸部暗色，眼后有一白色条纹，尾羽大部分蓝绿色，外侧羽毛基部灰色，末端有白色尖端。","call":"奇里翠蜂鸟在觅食时会发出尖锐、干燥、刮擦声的'cht'叫声，声音较同属其他物种稍大。","habits":"奇里翠蜂鸟主要栖息于奇里比奎特山脉中高海拔的开阔灌木丛和草原，偶尔出现在较低海拔的森林地带，但避免低地。它似乎不守卫采食领地，通过穿梭于植被空隙捕捉小昆虫，同时也会从花朵和树叶上采集昆虫。","breeding":"奇里翠蜂鸟的繁殖季节可能是在12月至5月的旱季，其筑巢细节和繁殖生态尚未被描述。","identification":"奇里翠蜂鸟与广泛分布的蓝尾翠蜂鸟极为相似，但体型更大，喙更长。雌鸟的特征，如淡色下体、黑色面罩和眼后白纹，有助于区分。","protection":"IUCN：LC（无危）","distribution":"奇里翠蜂鸟分布于南美洲哥伦比亚东南部的奇里比奎特山脉，包括瓜维亚雷和卡奎塔部门。","other":"奇里翠蜂鸟主要依赖低矮灌木Decagonocarpus cornutus的花蜜作为食物来源，同时也从其他灌木和树木的花朵中摄取花蜜。"},{"name":"辉腹翠蜂鸟","english_name":"Glittering-bellied Emerald","scientific_name":"Chlorostilbon lucidus","overview":"辉腹翠蜂鸟（英文名：Glittering-bellied Emerald，学名：Chlorostilbon lucidus），是雨燕目蜂鸟科翠蜂鸟属的鸟类。体型较小，以绿色为主色调，分布于南美洲东部、东南部至中南部，包括阿根廷、玻利维亚、巴西、巴拉圭和乌拉圭等地。该鸟种常见于多种开放和半开放生境，如森林边缘、沙漠、草原和花园。","appearance":"雄性辉腹翠蜂鸟身长9.5-10.5厘米，体重3-3.8克；雌鸟略小，身长7.5-8.5厘米，体重3-4.5克。雄鸟具有黑色尖端的红色喙，蓝色喉咙，上体呈暗青铜绿色，下体具虹彩青铜至青铜绿色，腹部至胸部颜色渐变为蓝绿色。雌鸟喙外半部黑色，内半部红色，额头、冠羽和背部稍带金绿色，腹部白色，向胸腹部渐变为淡棕色。幼鸟似雌鸟，但喙部可能有更多黑色。","call":"发出高音调、类似蟋蟀的颤音，持续1-4秒，频率约9-10千赫兹，间隔重复。主要叫声为短促、干涩、沙哑的颤音，如“trrrr”或“krrr”，在觅食或悬停时重复发出。激斗时发出快速下降的一系列“tsee-tsee-tsee-tsu-tsew-tsew-tsew”音符。","habits":"辉腹翠蜂鸟主要栖息于半干旱至湿润的开放或半开放环境，如灌木地、草原、森林边缘、公园和花园。它在海拔500至3500米之间最为常见，主要通过陷阱线觅食，访问各种开花植物获取花蜜，同时也会捕捉空中飞虫。偏好Lantana camara、Duranta arboreus、Citrus sinensis、Abutilon striatus和Eucalytus robusta等植物。","breeding":"繁殖季节至少从8月持续到2月。巢杯状，由细植物纤维、叶碎片和树皮条组成，内部以柔软材料如绒毛种子或Typha dominguensis种子纤维衬里，外饰以苔藓、叶碎片、树皮和树枝伪装。巢通常建于小树的细枝上或离地面约1米的暴露根部。每窝产卵两枚，卵孵化期约为14天，由雌鸟承担，雏鸟在20至22天后离巢。","identification":"与同属其他种类相比，辉腹翠蜂鸟的上体和下体色彩更纯正的绿色而非金绿色。C. l. igneus亚种的腹部点缀着闪烁的橙金色斑点。","protection":"IUCN：LC（无危）","distribution":"辉腹翠蜂鸟广泛分布于南美洲东部至东南部，具体包括阿根廷、玻利维亚、巴西、巴拉圭和乌拉圭。在阿根廷部分地区，它是最常见的蜂鸟种类，出现在多个保护区，如巴西的Serra dos Orgãos、Serra da Capivara和Chapada dos Guimarães国家公园，以及阿根廷的Costanera Sur生态保护区。","other":"辉腹翠蜂鸟适应性强，能接受人为环境，如花园、公园和种植园。"},{"name":"铜色翠蜂鸟","english_name":"Coppery Emerald","scientific_name":"Chlorostilbon russatus","overview":"铜色翠蜂鸟（英文名：Coppery Emerald，学名：Chlorostilbon russatus），是雨燕目蜂鸟科翠蜂鸟属的小型鸟类，体型紧凑，喙和尾均短小，尾羽呈红色调。雄鸟全身闪耀铜绿色光泽；雌鸟上体铜绿色，下体灰色，颊部深色，眼线白色。分布于南美洲东北部的哥伦比亚和委内瑞拉西北部山区。","appearance":"雄性铜色翠蜂鸟长约8至8.5厘米，雌鸟约7至7.5厘米，体重介于3.2至3.6克之间。其特征为短而直的黑色喙。雄鸟头部、背部及上体金绿发光，尾覆羽铜绿色，尾羽略呈叉状，金色带铜色。雌鸟头部、背部、侧翼和尾覆羽铜绿色，下体烟灰色，尾羽同样略呈叉状，羽端淡色，具铜紫带。幼鸟与雌鸟相似，头部羽毛边缘呈淡黄色。","call":"在觅食时，会发出重复的短促‘tsik’或‘trk’声。","habits":"栖息于半开放和开放的景观，如灌木丛、森林边缘和耕作区。常见于海拔500至1700米间，有时可达2600米。以花蜜为主食，常通过巡视多种开花植物（如豆科、茜草科、旅人蕉科和苦苣苔科）来获取，同时捕食小型昆虫。","breeding":"繁殖期在5月至6月。筑杯状巢，内衬柔软植物材料，通常位于离地面约0.8米的倾斜枝条上。雌鸟孵卵15至16天，雏鸟约20天后离巢。","identification":"在其极为有限的分布范围内，无类似物种，特征明显，易于识别。","protection":"IUCN：LC（无危）","distribution":"分布于哥伦比亚东北部，包括下马格达莱纳河谷和圣塔玛尔塔地区，以及哥伦比亚西北部与委内瑞拉西部边境的Serranía del Perijá山脉。"},{"name":"狭尾翠蜂鸟","english_name":"Narrow-tailed Emerald","scientific_name":"Chlorostilbon stenurus","overview":"狭尾翠蜂鸟（英文名：Narrow-tailed Emerald，学名：Chlorostilbon stenurus），是雨燕目蜂鸟科翠蜂鸟属的鸟类。小型的蜂鸟，雄鸟全身闪耀着绿色光泽，而雌鸟上部绿色，下部灰色，具深色脸颊、白色眼纹及尾尖。分布于南美洲的委内瑞拉、哥伦比亚和厄瓜多尔东北部，常栖息于高海拔森林边缘。","appearance":"雄鸟长约8.5至9厘米，雌鸟稍小，约7.5至8厘米，体重介于3.2至3.6克之间。雄鸟喙短直呈黑色，头顶及背部闪烁绿色，下体及两侧呈现绿色金属光泽，尾羽叉状，深绿色。雌鸟喙微曲，冠部暗绿色带青铜色，喉部白色，下体淡白色，尾羽叉状，内侧羽毛蓝绿色，外侧灰色基部渐变为宽白尖端。","habits":"栖息于海拔1000至3000米的湿润森林、灌木丛和次生林，偏好在较开阔地带活动，低飞觅食，以花蜜为主食，同时捕捉小型昆虫。通常单独活动，季节性地在一定范围内移动。","breeding":"繁殖季在9月至11月间，雌鸟用苔藓筑杯状巢，外饰地衣，通常位于树或灌木的1至2米高度处。每窝产两枚卵，孵化期约为15至16天，雏鸟约在20天后离巢。","identification":"与其它翠蜂鸟种类相比较，可通过尾羽长度及形态进行区分，特别是与绿尾翠蜂鸟的区别在于尾羽的不规则长度。","protection":"IUCN：LC（无危）","distribution":"分布于南美的委内瑞拉、哥伦比亚和厄瓜多尔东北部，包括安第斯山脉北段和沿海山脉。","other":"系统学历史上，曾有作者提议将绿尾翠蜂鸟视为其亚种或包含于其中的一个群体。"},{"name":"绿尾翠蜂鸟","english_name":"Green-tailed Emerald","scientific_name":"Chlorostilbon alice","overview":"绿尾翠蜂鸟（英文名：Green-tailed Emerald，学名：Chlorostilbon alice），是雨燕目蜂鸟科翠蜂鸟属的鸟类。体型小巧、结构紧凑的蜂鸟，拥有绿色的尾巴。雄鸟通体闪烁着耀眼的绿色，雌鸟背部绿色，腹部灰白，颊部深色，眼线白色，尾端带有灰色尖。该物种分布于委内瑞拉的安第斯山脉和沿海山脉，常见于海拔2500米以下的干燥至湿润森林边缘，尤其喜欢花园和耕作区。","appearance":"雄性绿尾翠蜂鸟体长7.5至8.5厘米，体重3至4克，喙短而直，头部和冠部呈现闪亮的深绿色，上身和翼覆羽青铜绿色，尾羽闪烁着青铜绿色，下体草绿色。雌鸟相似，但下体呈淡灰色，尾羽基部绿色，末端黑色，尖端灰色。幼鸟外观与雌鸟相似，头羽边缘有淡黄色边。","call":"鸣叫声为轻微高音的细碎颤音，具体描述较为缺乏。","habits":"绿尾翠蜂鸟栖息于半开放的森林边缘，包括半湿润雨林、云雾林、次生林、种植园，偶尔在干林中可见。它们在700至1800米的海拔范围内活动，以花蜜为主食，同时捕食空中飞虫。飞行和活动范围通常在植被较低处，高度在1至6米之间。","breeding":"繁殖季节为1月至3月。雌鸟会在离地面约1米高的树枝上搭建杯状巢，使用植物纤维、叶片碎片和树皮，内部铺垫柔软的种子绒毛，外部装饰有叶片和小枝。每窝产卵2枚，由雌鸟孵化约14天，雏鸟在20至22天后离巢。","identification":"与狭尾翠蜂鸟相比，绿尾翠蜂鸟的雄鸟和雌鸟尾羽正常，而非逐渐变窄，且雌鸟的尾羽外侧为铜绿色，尖端白色较小。与蓝尾翠蜂鸟区别在于尾羽颜色，绿尾翠蜂鸟的尾羽为绿色而非蓝色。","protection":"IUCN：LC（无危）","distribution":"绿尾翠蜂鸟是委内瑞拉北部地区的特有种，分布于从法尔孔州南部至拉腊州和苏克雷州，向东延伸至莫纳加斯州北部。","other":"绿尾翠蜂鸟能适应人类创造的环境，如种植园、公园、花园和路边，其中散落着灌木和树木。"},{"name":"短尾翠蜂鸟","english_name":"Short-tailed Emerald","scientific_name":"Chlorostilbon poortmani","overview":"短尾翠蜂鸟（英文名：Short-tailed Emerald，学名：Chlorostilbon poortmani），是雨燕目蜂鸟科翠蜂鸟属的鸟类。分布于南美的哥伦比亚和委内瑞拉西北部。体型小巧，色彩斑斓，雄鸟全身闪耀着翡翠绿，尾部短小；雌鸟上身绿色略显暗淡，下身灰色，尾部中央羽毛绿色，其余基部淡绿渐变为深蓝，尖端灰白。该物种在南美洲的特定区域常见。","appearance":"雄性短尾翠蜂鸟长6.9至8.5厘米，体重3至4克。头部前额闪烁着翠绿光泽，冠部及背部青铜绿，全身覆以亮丽的绿色羽毛，尾部短小且叉开，呈青铜绿色。雌鸟相似，但前额颜色较暗，下身呈灰色，尾部特征明显。幼鸟类似雌鸟，但头部羽毛边缘泛黄，雄鸟幼鸟尾部末端有蓝色带，身体两侧和喉侧有绿色斑点。","call":"可能的鸣唱为一连串高音调的“tseep”音符，速率为每秒约1.5个音符，推测仅在雨季时歌唱。叫声包括重复的短促“tsip”声和较长的下滑音“tsew...tsew..”。","habits":"栖息于湿润森林、林缘、开阔林地、次生林、咖啡和香蕉种植园及树丛覆盖的牧场，通常在低矮的花丛中觅食，高度在0.6至5米之间，偏好开放地带如路边和小片空地。以非下垂花朵如Elleanthus、Guzmania和Phaseolus的花蜜为主食，也会在空中捕捉昆虫。","breeding":"繁殖季节在哥伦比亚东部安第斯山脉从至少五月到六月，西部则始于二月。筑杯状巢于灌木或低树上，约1米高，由棉质或纤维制成，外饰叶碎片、苔藓等。产白色蛋两枚，孵化期14至16天，仅雌鸟负责。幼鸟20至22天后离巢。","identification":"与铜色翠蜂鸟和狭尾翠蜂鸟雌鸟相似，但尾部无蓝色。与狭尾翠蜂鸟非常接近，但飞行模式更为波浪状。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的哥伦比亚和委内瑞拉西北部，包括梅里达和塔奇拉州的安第斯山脉西部，以及哥伦比亚东部安第斯山脉的东部斜坡。","other":"短尾翠蜂鸟在人类创造的环境如花园和种植园中较为常见，只要周围有树木和灌木即可。"},{"name":"古尔德翠蜂鸟","english_name":"Gould's Emerald","scientific_name":"Riccordia elegans","overview":"古尔德翠蜂鸟（英文名：Gould's Emerald，学名：Riccordia elegans），是雨燕目蜂鸟科 Riccordia 属的鸟类。已灭绝的Riccordia属的一员。基于1860年采集的唯一标本描述，其起源未知，但可能源自巴哈马北部或尤以牙买加可能性较大。","appearance":"由于仅存单一标本，古尔德翠蜂鸟的具体外形特征细节无法详尽描述。该标本显示了蜂鸟科典型的细小身材和鲜艳羽毛，但具体色彩和尺寸信息缺失。","habits":"关于古尔德翠蜂鸟的生活习性信息缺失，但考虑到它属于蜂鸟科，可以推测它可能栖息于森林环境，偏好花蜜作为主要食物来源。","identification":"由于缺乏多个标本，古尔德翠蜂鸟与其他蜂鸟种类之间的辨识要点无法确定。","protection":"IUCN：EX（已灭绝）","distribution":"其确切分布地不明，但推测可能存在于巴哈马北部或牙买加。","other":"国际鸟类学委员会在2023年将其从物种清单中移除，待遗传分析和/或稳定同位素分析提供更多关于其状态的信息。"},{"name":"布雷氏翠蜂鸟","english_name":"Brace's Emerald","scientific_name":"Riccordia bracei","overview":"布雷氏翠蜂鸟（英文名：Brace's Emerald，学名：Riccordia bracei），是雨燕目蜂鸟科 Riccordia 属的已灭绝鸟类。这种蜂鸟仅见于巴哈马群岛的新普罗维登斯岛，以其独特的外观和历史地位而闻名。","appearance":"布雷氏翠蜂鸟体长约9.5厘米，翼展宽约9.25英寸（约23.5厘米），尾长2.5英寸（约6.4厘米）。其黑色喙部稍曲，末端呈圆锥形，双脚同样呈黑色。背部显现出铜绿色，带有金光，头部色彩与背部相似，但无金色光泽。眼睛后方有一显著的白点，喉咙呈现蓝黑色，腹部羽毛为绿色，带灰色尖端。翅膀呈现出紫色，飞羽绿色，围肛羽为灰色，边缘略带淡桂色。","protection":"IUCN：EX （已灭绝）","distribution":"北美：布雷氏翠蜂鸟的分布限于巴哈马群岛中的新普罗维登斯岛。"},{"name":"古巴翠蜂鸟","english_name":"Cuban Emerald","scientific_name":"Riccordia ricordii","overview":"古巴翠蜂鸟（英文名：Cuban Emerald，学名：Riccordia ricordii），是雨燕目蜂鸟科 Riccordia 属的鸟类。分布于古巴主岛、大松树岛（Isla de la Juventud）和若干离岸小岛，以及巴哈马群岛的多个岛屿。好斗的蜂鸟，以花蜜和昆虫为食，偶尔也会捕食空中飞虫。雄鸟翠绿色的羽毛和红色的喙基部是其显著特征。","appearance":"雄性古巴翠蜂鸟体长10.5至11.5厘米，体重2.5至5克，拥有略向下弯曲的短喙，上喙呈暗黑色，下喙红色，仅尖端为黑色。头部前方为暗褐色，眼后有一小块灰白色斑点。背部深绿带青铜色光泽，腹部为金属绿色，尾下覆羽白色，尾羽深叉，中央四对尾羽呈金属青铜色至绿青铜色。雌鸟相似，但体型略小，腹部为灰褐色，两侧至尾下覆羽为白色，尾羽较不深叉。幼鸟背部颜色较暗淡。","call":"雄鸟的鸣唱为一系列高音调的滚音和金属声，例如\"zzi zzi zzi-zzi zzih\"，而雌鸟则发出独特的高音调\"seeeee\"飞行叫声，有时重复2至5次。","habits":"古巴翠蜂鸟广泛分布于多种森林环境，从海平面到海拔至少1300米，偶尔高达约1975米。它们主要在低地活动，栖息于湿润和干旱的开阔森林。在大巴哈马岛上，它们常见于开放松树林下的灌木丛、沿海灌木林、花园、公园和种植园。觅食高度通常在1至6米之间。","breeding":"全年均可繁殖，但在古巴主要集中在4月至7月。它们会在像仙人掌一样的Euphorbia nivulia上密集筑巢，巢间距平均约为30厘米，巢呈杯状，由苔藓和植物纤维构成，外面缠绕着树皮和蜘蛛网的细丝。每次产卵两枚，孵化期为15至16天，仅由雌鸟承担。雏鸟背部有两行淡黄色绒毛，离巢时间为19至22天。首次繁殖发生在第二年。","identification":"古巴翠蜂鸟与较小的吸蜜蜂鸟雌鸟相似，但后者尾羽更短，尾端蓝色且带有白色尖端。与红喉北蜂鸟雌鸟相比，古巴翠蜂鸟的尾羽更长且分叉，尾尖无白色。","protection":"IUCN：LC（无危）；被列入《濒危野生动植物种国际贸易公约》附录二。古巴翠蜂鸟在大部分分布范围内常见，能够适应人类创造的生境。","distribution":"古巴翠蜂鸟分布在古巴主岛、大松树岛（Isla de la Juventud）和若干离岸小岛，以及巴哈马群岛的多个岛屿，包括大巴哈马岛、大阿巴科岛、安德罗斯岛和格林岛。偶尔作为迷鸟出现在美国佛罗里达州。","other":"历史上曾被认为与C. swainsonii和C. maugaeus关系密切，这三个物种以前被归类在Riccordia属中。† C. bracei曾被认为是古巴翠蜂鸟的一个已灭绝亚种，但现在认为它可能是一个独立的物种。"},{"name":"中美翠蜂鸟","english_name":"Hispaniolan Emerald","scientific_name":"Riccordia swainsonii","appearance":"雄性伊岛翠蜂鸟全身呈金属绿色光泽，上喙黑色，下喙红色，尾部深褐色且显著分叉。雌鸟上身金属绿色，下身灰色，腹部颜色较暗，尾羽基部灰白色，端部具宽幅的暗棕色带纹。幼鸟外观与雌鸟相似。","call":"伊岛翠蜂鸟发出尖锐的金属质感的‘tic’声，通常以每秒五次的频率连续发出。","habits":"它们栖息在海拔300至2500米的密集山地雨林，偶尔降至海平面高度。以花蜜为食，常在Inga vera、Heliconia bihai等植物上觅食，同时也会在空中捕捉昆虫。一般在地面以上3至18米的高度觅食。","breeding":"繁殖季节从1月持续到6月，有时延续至8月。巢穴由苔藓、蕨类纤维和其他植物材料制成，装饰有苔藓，用蛛网固定，通常建在离地面0.5至2米的低树或灌木丛中。一窝产两枚白色蛋，孵化期为15至16天，幼鸟大约在20至22天后离巢。","identification":"与Antillean Mango相比，伊岛翠蜂鸟尾部更长，翅膀与尾尖大致齐平；与小吸蜜蜂鸟相比，体型更大，喙更长。雌鸟与小吸蜜蜂鸟雌鸟相比，具有更长的喙；与红喉北蜂鸟雌鸟相比，更黑的喙和更小的眼后白斑。","protection":"IUCN：LC（无危）；CITES II级；在多米尼加共和国的La Visite国家公园和Pic Macaya生物圈保护区中得到保护。","distribution":"主要分布在多米尼加共和国和海地的Hispaniola岛，包括内陆密集的山地雨林、边缘地带、灌木丛和咖啡种植园。","other":"尽管面临森林砍伐的威胁，特别是在海地，伊岛翠蜂鸟仍能适应人类制造的环境，只要周围有残留的森林斑块。"},{"name":"波多翠蜂鸟","english_name":"Puerto Rican Emerald","scientific_name":"Riccordia maugaeus","appearance":"雄性波多黎各翠蜂鸟全身羽毛呈现出迷人的虹彩绿色，某些角度和光照下会显现出蓝色光泽。其体型较小，尾部较长。与之相比，绿喉蜂鸟和绿芒果蜂鸟虽然也有绿色外观，但体型更大，喙部更长且呈明显弯曲。雌性波多黎各翠蜂鸟背部金属绿色，腹部暗淡白色，尾部相对较长且分叉，面部黑色带有小块白色斑点位于眼后。","call":"波多黎各翠蜂鸟的鸣唱是一连串快速的颤音，常见叫声为高音清脆的‘tsip’声，可单独发出或连续鸣叫。","habits":"波多黎各翠蜂鸟栖息于波多黎各的各种林地环境，包括咖啡种植园和花园。它们以花蜜为食，同时也会捕食昆虫。","breeding":"关于波多黎各翠蜂鸟的繁殖信息目前较为有限。","identification":"与凤头蜂鸟相比，波多黎各翠蜂鸟具有更长的喙，面部黑色部分以及眼后的小白点，尾部形状也有所不同。","protection":"IUCN：LC（无危）","distribution":"波多黎各翠蜂鸟仅分布于北美地区的波多黎各。","other":"在中国全境没有分布，偶尔被误认的可能是某些大型天蛾，如蜂鸟鹰蛾。"},{"name":"蓝头蜂鸟","english_name":"Blue-headed Hummingbird","scientific_name":"Riccordia bicolor","overview":"蓝头蜂鸟（英文名：Blue-headed Hummingbird，学名：Riccordia bicolor），是雨燕目蜂鸟科 Riccordia 属的鸟类。而雌鸟则以绿色为主，头顶和尾部带有蓝色光泽。分布于小安的列斯群岛中的多米尼克和马提尼克岛，栖息于森林边缘和内部。","appearance":"雄性蓝头蜂鸟体长约9至11厘米，体重约4.7克，具有笔直的黑色喙，下颌基部呈粉红色。头部为金属光泽的紫蓝色，背部闪烁着绿色，尾上覆羽深蓝色，尾巴叉状，钢蓝色。雌鸟喙全黑，头部绿色闪亮，脸颊暗淡，耳区有灰色斑点，背部和侧翼青铜绿色，腹部淡棕色灰色。","call":"鸣叫声包括一系列快速下降的尖锐金属音符，以及金属质感的‘tic-tic-tic’声。","habits":"蓝头蜂鸟生活在未受干扰的森林边缘和内部，偶尔出现在次生林沿河地带。它们在森林各层寻找花蜜，同时捕食停驻在枝叶上的节肢动物。","breeding":"繁殖季节为3月至5月，雌鸟用植物纤维筑杯形巢，高度位于1至4米之间，通常装饰有枯死的树叶。每窝产两枚白色卵，孵化期16至18天，由雌鸟单独承担，雏鸟20至23天离巢。","identification":"与雌鸟相比，雄鸟的金属光泽更为显著，而雌鸟与凤头蜂鸟相似，但后者常有冠羽，喙较短，尾部较短，缺乏蓝头蜂鸟特有的蓝色尾部。","protection":"IUCN：NT（近危）","distribution":"分布于小安的列斯群岛中的多米尼克和马提尼克岛，主要栖息于海拔800至1000米的森林地带。","other":"蓝头蜂鸟的种群在1980年代因飓风影响而大幅减少，目前仅缓慢恢复。"},{"name":"火喉蜂鸟","english_name":"Fiery-throated Hummingbird","scientific_name":"Panterpe insignis","overview":"火喉蜂鸟（英文名：Fiery-throated Hummingbird，学名：Panterpe insignis），是雨燕目蜂鸟科火喉蜂鸟属的鸟类。体型小巧而色彩斑斓的蜂鸟，以彩虹般绚丽的喉部羽毛著称。其分布于中美洲的哥斯达黎加和巴拿马西部的山区森林中。","appearance":"火喉蜂鸟长10.5至11厘米，雄鸟体重5.9至6.2克，雌鸟4.9至5.2克。性别相似，拥有黑色喙基带粉色，脚呈暗灰色。头部顶部闪烁着皇家蓝，侧面和颈背为黑色，后背绿金属光泽，逐渐变为蓝绿色，尾羽深蓝至黑色。最引人注目的是中央喉咙部位的金绿至亮铜橙色，胸部中心有紫色斑块，腹部和腹下侧为鲜绿至蓝绿色。幼鸟的面部和颈背羽毛边缘呈锈色。eisenmanni亚种略小，胸腹部蓝紫延伸，颈背黑色延伸至背部，上尾覆羽多为蓝色，喙较短。","call":"火喉蜂鸟似乎没有真正的歌曲，但会发出重复的鼻音、尖锐的“kek...kek...”声，快速连串，兴奋时尤为明显。还有复杂快速的液态鸣叫，伴有突然的尖锐音调上升。","habits":"栖息于高山森林、云雾林、矮林，以及靠近森林的开阔地带和次生林。活动范围从海拔1500米至树线，有时会降至1400至1600米，罕见至700米。繁殖季节结束后部分个体迁至较低海拔。以多种植物花朵中的花蜜为食，如附生植物、灌木和小树，也会捕食飞行中的小型昆虫。","breeding":"繁殖期从8月至次年1月，雄鸟在繁殖季捍卫富含花蜜的花朵领地，允许雌鸟进入并交配。巢由树蕨鳞片、植物绒毛和蜘蛛网构成，外部装饰有绿色苔藓和地衣，通常建于森林内的竹茎末端或道路悬垂银行下的垂根处，离地面2至4米。每窝产两枚白色卵，孵化和育雏细节未知。","identification":"与其他较大蜂鸟如高地大蜂鸟区分，可通过其深蓝黑色尾羽、中等长度喙基部粉红色、蓝色臀部识别，或等待它转动头部以展现独特喉部色彩。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加和巴拿马西部，包括北部和北中部哥斯达黎加的山地，以及南至巴拿马西部的Bocas del Toro和Chiriquí省。在较高山脉中，分布于2200至3200米之间；在哥斯达黎加北部和北中部较低山脉中，高度范围为1600至1800米至山顶。"},{"name":"白尾丽蜂鸟","english_name":"White-tailed Emerald","scientific_name":"Microchera chionura","overview":"白尾丽蜂鸟（英文名：White-tailed Emerald，学名：Microchera chionura），是雨燕目蜂鸟科白顶蜂鸟属的鸟类。分布于中美洲的哥斯达黎加和巴拿马。体型较小，主要特征为闪耀的绿宝石色羽毛，雄鸟有明亮的白色下腹和尾羽末端。分布于太平洋斜坡的山地森林地带。","appearance":"白尾丽蜂鸟长约7.5至8厘米，体重约3.1至3.3克。雄鸟拥有青铜绿色的上体，逐渐变为深铜色的尾羽覆羽，中央两对尾羽呈铜色，其余三对尾羽为白色带黑尖。腹部、臀部和尾下覆羽为白色。雌鸟与雄鸟相似，但白色向上延伸至喉部，下体颜色较暗，有灰绿色的胁部。幼鸟比成鸟下体更暗淡，带有灰黄色边缘。","call":"其鸣唱为持续的细薄刮擦声，混杂着嗡嗡声或咕噜声，音调起伏不定。觅食时发出柔和的刮擦声，追逐时发出高音的嗡嗡声。","habits":"栖息于海拔750至2000米的湿润山地森林，偏好森林边缘和内部，偶尔出现在次生林、种植园和花园中。在非繁殖季节，部分个体会进行上下坡迁移。","breeding":"繁殖季节从6月延续到11月。雄鸟在小群体中以领地方式吸引雌鸟，具体繁殖生态细节未知，巢穴尚未被描述。","identification":"与雪胸蜂鸟区别明显，后者肩部和臀部为铜色，尾羽无白色。白尾丽蜂鸟的尾部特征和鸣声是辨识关键。","protection":"IUCN：LC（无危）","distribution":"分布于哥斯达黎加西南部至巴拿马中部的太平洋斜坡，局部地区延伸至巴拿马的加勒比斜坡。","other":"曾归类于Elvira属，现置于Microchera属，为单型种。"},{"name":"铜头丽蜂鸟","english_name":"Coppery-headed Emerald","scientific_name":"Microchera cupreiceps","overview":"铜头丽蜂鸟（英文名：Coppery-headed Emerald，学名：Microchera cupreiceps），是雨燕目蜂鸟科白顶蜂鸟属的小型蜂鸟。其最显著的特征是雄鸟的铜色头顶和亮白色尾羽边缘。该物种分布于哥斯达黎加的高海拔地区，偏好凉爽湿润的高地森林。","appearance":"雄性铜头丽蜂鸟主要呈闪烁的绿色，头顶铜色，尾羽外侧明亮的白色，喙部明显弯曲。雌鸟相似，但下体为白色，饰以绿色斑点。体长约7.5厘米，体重约3至3.3克。雄鸟在极北端的Cordillera de Guanacaste区域还具有胸部中央的紫色斑点。","call":"鸣声被描述为高而细的颤音和婉转声，叫声则是高而清脆的quip或quit声，追逐时发出快速的高音嘶嘶声。","habits":"栖息于湿润至潮湿的高山森林边缘和内部，通常单独活动，但在繁殖季节，雄鸟会聚集在展示区。主要以多种开花植物、灌木和树木的花蜜为食，也会捕食小昆虫。活动高度随环境而变，森林内部雄鸟多在树冠层，雌鸟在林下层，边缘地带则在所有高度上觅食。","breeding":"繁殖期从十月持续到三月，雄鸟在小型群组中通过唱歌和追逐其他雄鸟来求偶。雌鸟用植物绒毛、树蕨鳞片和蜘蛛网搭建杯状巢，外部装饰苔藓和地衣，巢位一般位于地面1至3米处。每窝产两枚卵，孵化期和雏鸟离巢时间未知。","identification":"铜头丽蜂鸟的体型较小，尾羽大部分白色，铜色臀部，与其他蜂鸟物种易于区分。雄鸟与白顶蜂鸟雄鸟区别在于后者头部主要为紫色，雌性白顶蜂鸟下体白色。","protection":"IUCN：LC（无危）","distribution":"铜头丽蜂鸟主要分布在哥斯达黎加北部和中部的高海拔地区，多数在加勒比海斜坡，但在最北端也出现在太平洋斜坡，海拔高度从300米到1500米，太平洋侧低于约1200米较少见。","other":"无"},{"name":"白顶蜂鸟","english_name":"Snowcap","scientific_name":"Microchera albocoronata","overview":"白顶蜂鸟（英文名：Snowcap，学名：Microchera albocoronata），是雨燕目蜂鸟科白顶蜂鸟属的鸟类。体型小巧、色彩绚丽的蜂鸟，分布于中美洲云雾森林，自洪都拉斯南至巴拿马。雄鸟以红葡萄酒般的深紫色身躯和醒目的白色顶冠而著称，而雌鸟则呈现较小的尺寸，上体绿色，下体洁白，尾羽外侧显著的白色与尾端的黑色形成鲜明对比。","appearance":"雄鸟全身深紫色，带有金属光泽，头顶部为纯白色，尾羽中央呈青铜色，其余部分基部白色，末端黑色。雌鸟背部金属绿色，下体灰白色，尾羽外侧白色，末端黑色，尖端带白。幼鸟类似雌鸟，但眼上方有一条细白线，下体逐渐变为暗紫黑色。","call":"雄鸟的歌声为柔和的、嘶嘶作响的旋律：tsitsup tsitsup tsitsup tsew ttttt-tsew 或 tsip-tsee tsippy tsippy tsippy tsip-tick tsew。叫声包括柔和、高音、干燥的 tsip 声，以及在争斗中的嗡嗡声和叽叽喳喳声。","habits":"白顶蜂鸟栖息于潮湿的低地和山地森林、半开放的林地和次生林，偏好林间空地和较开阔的环境。它们在所有植被层中觅食花蜜，同时捕食树叶上的节肢动物，雄鸟会从栖木上捕捉小型昆虫。","breeding":"繁殖季节在哥斯达黎加为1月至5月，雄鸟在松散的群组中进行求偶展示，追逐其他雄鸟。雌鸟用树蕨鳞片和植物绒毛筑巢，外部装饰苔藓和地衣，巢通常位于离地面1.7至3米的树枝或悬垂藤蔓上。一窝产两枚蛋，孵化期和雏鸟离巢时间未知。","identification":"雄性白顶蜂鸟的白色顶冠和金属光泽的深紫色羽毛使其独一无二。雌鸟的小巧体型、洁白下体和尾羽外侧的白色与尾端黑色形成对比，易于识别。与相似物种如白尾翡翠（Elvira chionura）的雌鸟相比，白顶蜂鸟的下体为纯白色，无绿色斑点。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从洪都拉斯南部至巴拿马中部，主要栖息在潮湿的低地和山地森林。","other":"在哥斯达黎加，繁殖后白顶蜂鸟会降至较低海拔，少数个体可能游荡至高于繁殖区约1,400米的高度。"},{"name":"蓝顶蜂鸟","english_name":"Oaxaca Hummingbird","scientific_name":"Eupherusa cyanophrys","overview":"蓝顶蜂鸟（英文名：Oaxaca Hummingbird，学名：Eupherusa cyanophrys），是雨燕目蜂鸟科蓝顶蜂鸟属的鸟类。其独特的蓝色顶冠是显著特征。仅分布于墨西哥南部奥阿哈卡州的Sierra Madre del Sur山脉，偏好湿润的常绿森林和阴凉咖啡种植园。该物种因栖息地丧失而面临严重威胁。","appearance":"雄性蓝顶蜂鸟通体呈闪亮的翡翠绿色，头顶有醒目的紫蓝色，翼上有鲜明的红褐色斑块；中央一对尾羽为绿色，其余尾羽为白色或近白色。雌鸟腹部呈淡灰色，尾部外侧有灰绿色边缘。雌雄差异明显，雌鸟翼上的红褐色斑块不如雄鸟显眼，腹面颜色较浅。","call":"蓝顶蜂鸟的歌声为高音、快速的颤音，与白尾蜂鸟相似，但更为急促，不那么匆忙。叫声细节不详，但似乎与白尾蜂鸟的清脆、略带嗡嗡声的‘chip’声类似。","habits":"蓝顶蜂鸟在森林的低层至中层活动，快速穿梭于花朵间，展露其白色尾羽。栖息于云雾林、半落叶林、松树常绿林和河岸林，海拔范围在700至2,600米之间，常见于1,800米以下。以花蜜为食，已知会访问Inga、Lobelia、Malvaviscus和Psittacanthus等植物的花朵，同时也可能摄取小型节肢动物。","breeding":"繁殖习性知之甚少，但在5月、10月和11月观察到活跃的巢穴。巢为苔藓制成的杯状，内衬植物绒毛，外覆地衣，置于离地面1.2至5.4米高的位置。一窝产两枚卵，孵化期和雏鸟离巢时间未知。","identification":"与白尾蜂鸟极为相似，尤其是雌鸟和幼鸟几乎无法区分。雄性蓝顶蜂鸟通过其蓝色顶冠与白尾蜂鸟区分开来。与绿蜂鸟有表面相似性，但后者有红褐色尾巴，腹部颜色（雄鸟为土黄色，雌鸟为白色），且喙部分为红色。","protection":"IUCN：EN（濒危）","distribution":"仅分布于墨西哥中南部的Sierra Madre del Sur山脉的太平洋斜坡，包括Sierra de Miahuatlán。","other":"蓝顶蜂鸟曾被视为白尾蜂鸟的亚种，或两者共同被视为纹尾蜂鸟的亚种。"},{"name":"白尾蜂鸟","english_name":"White-tailed Hummingbird","scientific_name":"Eupherusa poliocerca","overview":"白尾蜂鸟（英文名：White-tailed Hummingbird，学名：Eupherusa poliocerca），是雨燕目蜂鸟科蓝顶蜂鸟属的鸟类。体型中等，主要特征是雄鸟全身闪耀着翠绿色光泽，尾部中央羽毛呈金属青铜绿色，两侧尾羽大部分为灰白色。分布于墨西哥西南部，偏好湿润的常绿森林环境，其数量正在减少，被列为近危物种。","appearance":"雄性白尾蜂鸟整体呈现鲜艳的金属青铜绿色，翼上有醒目的红褐色斑块，尾羽中央对称的羽毛为金属青铜绿色，其余尾羽大多为灰白色。雌鸟蜂鸟下腹部呈淡灰色，尾羽边缘带暗绿色。两性均有明显的白色尾羽和红褐色翼斑。雌鸟和雄鸟在色彩上存在差异，雌鸟下腹及脸侧为淡灰色，尾羽末端较白。","call":"鸣声被描述为高亢、快速、略带水滴状至吱吱声的颤音。叫声则是一种流动到略微嗡嗡作响、滚动的chip声，经常演变成颤音。","habits":"白尾蜂鸟栖息于墨西哥西南部的湿润常绿森林、半落叶林及松栎林中，偶尔出现在种植园。它们在森林的各个层次觅食花蜜，从林下层至树冠层，以多种花朵的花蜜为食，同时也会摄取小型节肢动物。","breeding":"关于繁殖生态的信息有限，但根据标本分析，推测有两个繁殖高峰期，分别为2月至5月和9月至10月。巢穴尚未被详细描述。","identification":"雄性白尾蜂鸟与蓝顶蜂鸟极为相似，但可通过蓝顶蜂鸟的蓝色头部来区分。雌鸟两物种几乎无法区分。此外，白尾蜂鸟与绿蜂鸟外观相似，但后者尾巴为红褐色，腹部颜色不同，喙部部分红色。","protection":"IUCN：NT（近危）","distribution":"白尾蜂鸟分布于中美洲墨西哥的西南部，具体位于格雷罗州的太平洋斜坡地区，略微延伸至奥阿哈卡西部。海拔高度介于800至2440米之间。","other":"过去，一些分类学家将蓝顶蜂鸟视为白尾蜂鸟的亚种，而另一些则将白尾蜂鸟视为条纹尾蜂鸟的亚种。"},{"name":"纹尾蜂鸟","english_name":"Stripe-tailed Hummingbird","scientific_name":"Eupherusa eximia","overview":"纹尾蜂鸟（英文名：Stripe-tailed Hummingbird，学名：Eupherusa eximia），是雨燕目蜂鸟科蓝顶蜂鸟属的鸟类。是中美地区特有的一种蜂鸟，主要分布在墨西哥南部至巴拿马西部。其最显著的特征是雄鸟的亮绿色羽毛和雌鸟的淡灰色腹部，以及独特的锈色翼斑。纹尾蜂鸟偏好潮湿的常绿森林和遮阴咖啡种植园，活跃于低至中层林区。","appearance":"纹尾蜂鸟体型中等，总长度约9至10.5厘米，平均体重4至4.5克。雄鸟拥有明亮的金属草绿色上体，逐渐变为青铜色，特别是在上尾覆羽处。翅膀上的第二级飞羽呈锈红色，形成明显的翼斑。尾羽内侧三对为深青铜绿色，外侧两对具有黑色外缘和白色内缘，尖端带有黑色，这是纹尾蜂鸟名称的由来。雌鸟的下体为淡棕色灰色，两侧带有金属绿色斑点。雌雄两性均具有直而黑的喙。","call":"纹尾蜂鸟的鸣唱包含1到3个尖锐的、有时带金属质感的音符，接着是一段低沉、干燥、类似昆虫的颤音，随后再次发出1到3个尖锐的音符。其叫声包括流利的、咔嗒声的颤音、尖锐的、刺耳的‘peet’或‘bzeet’声，以及尖锐的嗡嗡声。","habits":"纹尾蜂鸟栖息在湿润的高山、半落叶和松栎树林边缘及内部，以及种植园。它们在森林各层觅食花蜜，尤其偏爱Inga树、Acanthaceae和Rubiaceae灌木、附生植物以及Clusia、Besleria和Salvia的花朵。雄鸟通常会积极保卫花丛。它们在繁殖季节后会进行季节性的海拔迁移，从较高地区移动到较低地带。","breeding":"纹尾蜂鸟在墨西哥的繁殖期为4月至8月，在哥斯达黎加则为9月至次年4月，其它地区的繁殖季节尚未确定。它们筑杯状巢，使用植物绒毛并以苔藓（尤其是红色苔藓）装饰外部，巢一般位于地面以上1至3米处，靠近溪流。每窝产卵2枚，孵化期和雏鸟离巢时间未知。","identification":"纹尾蜂鸟与绿蜂鸟容易混淆，后者同样具有锈色翼斑，但绿蜂鸟的尾羽全为锈色，雄鸟腹部为黄褐色，雌鸟腹部为白色，且喙部分为红色。在哥斯达黎加和巴拿马，纹尾蜂鸟可能与黑腹蜂鸟混淆，雄性黑腹蜂鸟头部两侧和下体为黑色，雌性黑腹蜂鸟比纹尾蜂鸟小，其锈色翼斑不那么显眼。","protection":"IUCN：LC（无危）。纹尾蜂鸟被评估为无危物种，尽管其确切的种群数量和趋势不明。然而，它在南部墨西哥可能因栖息地丧失而受到潜在威胁。","distribution":"纹尾蜂鸟分布于中美洲，从墨西哥南部至巴拿马西部，具体包括墨西哥东部、奥哈卡、奇瓦瓦、洪都拉斯、萨尔瓦多、尼加拉瓜、哥斯达黎加和巴拿马西部。在墨西哥，它们的分布海拔从近海平面至1,800米，在洪都拉斯为300至1,800米，在哥斯达黎加为300至2,450米。","other":"纹尾蜂鸟有三个亚种，即指名亚种E. e. eximia、E. e. nelsoni和E. e. egregia。"},{"name":"黑腹蜂鸟","english_name":"Black-bellied Hummingbird","scientific_name":"Eupherusa nigriventris","overview":"黑腹蜂鸟（英文名：Black-bellied Hummingbird，学名：Eupherusa nigriventris），是雨燕目蜂鸟科蓝顶蜂鸟属的鸟类。小型蜂鸟，雄鸟拥有独特的黑色腹部，延伸至脸部前额，而雌鸟则为浅灰色腹部。主要分布在中美洲的哥斯达黎加和巴拿马西部的高海拔森林地带。","appearance":"雄性黑腹蜂鸟上体呈青铜绿色，头部侧面和整个腹部为黑色，翅膀第二枚飞羽为赤褐色，尾羽内侧有白色。雌鸟的腹部为灰白色，尾羽下方为白色，上体金属青铜绿色，尾羽覆羽更显青铜色。两者均在繁殖后换羽，雄鸟比雌鸟早一到两个月开始。","call":"其鸣唱为高音、细薄的喷射式颤音，通常从森林空隙边缘的栖木发出。叫声包括尖锐的高音‘tseep’或‘peet’声以及追逐中的高音‘tsittering’。","habits":"黑腹蜂鸟主要栖息在湿润的高山森林边缘和内部，海拔约600至2000米。雄鸟通常在树冠层觅食花蜜，而雌鸟则更常在林下层和边缘活动。它们会守卫开花树木，即使有体型更大的蜂鸟种类存在。食物来源包括Inga和Pithecellobium树、附生植物、Psychotria、Witheringia和Besleria等。","breeding":"繁殖季节主要在哥斯达黎加的10月至3月间，可能最早始于7月。雌鸟用树蕨鳞片和蜘蛛网筑杯状巢，外部装饰苔藓和地衣，通常离地面2至4米高。每窝产两枚卵，孵化期和雏鸟离巢时间未知。","identification":"雄性黑腹蜂鸟的黑色腹部和明亮的白色尾羽边缘组合独一无二，与任何其他蜂鸟种类不同。雌鸟与纹尾蜂鸟的雌鸟相似，但纹尾蜂鸟雌鸟体型略大，次级飞羽上的赤褐色斑块对比更明显，胸部两侧和腹部有更多绿色斑点。","protection":"IUCN：LC（无危）","distribution":"黑腹蜂鸟的分布限于中美洲，主要在哥斯达黎加和巴拿马西部的高海拔地区。在哥斯达黎加，该物种被认为是少见至局部丰富的。"},{"name":"墨西哥妍蜂鸟","english_name":"Mexican Woodnymph","scientific_name":"Eupherusa ridgwayi","overview":"墨西哥妍蜂鸟（英文名：Mexican Woodnymph，学名：Eupherusa ridgwayi），是雨燕目蜂鸟科蓝顶蜂鸟属的鸟类。特有种于墨西哥西部的热带丘陵地带。主要栖息于橡树林和荫蔽咖啡种植园，偏好低海拔地区，尤其在阴暗的沟壑中活动频繁。","appearance":"雄性墨西哥妍蜂鸟整体显得黑亮，喙黑色，尾羽深蓝色，胸前有一抹翡翠绿，头顶呈深蓝色，偶尔反射出光泽。雌鸟外观较朴素，灰脸和下体，喙同样黑色，全身以绿色为主调，缺乏雄鸟的鲜艳色彩。","call":"它们特有的鸣叫声为连续的、略带湿润感的颤音“tsip”，通常在短暂快速的2至4声系列中发出，形成一种液体般的响动，通常在悬停时发出。","habits":"墨西哥妍蜂鸟居住在墨西哥西部的北山脉，不迁徙，全年留守其狭窄的生活范围。它们生活在海拔250至1200米的湿润森林、峡谷和丘陵地带，也能在某些咖啡种植园中找到踪迹。","breeding":"繁殖季节集中在2月至3月，雄鸟通过独特的羽毛排列和颜色吸引配偶，进行繁殖活动。","identification":"雄鸟与雌鸟在色彩上差异明显，雄鸟的蓝黑色尾羽和翡翠色喉部是辨识的关键，而雌鸟则以其灰色面庞和朴素的体色区别于其他种类。","protection":"IUCN：VU（易危）；CITES II；墨西哥西北斜坡EBA。由于栖息地森林受到严重威胁，保护规划难以精确实施，需紧急研究其生态需求。","distribution":"分布于墨西哥西部，包括南纳亚里特、哈利斯科和科利马的太平洋斜坡。","other":"墨西哥妍蜂鸟曾被归类于Thalurania属，现已基于分子系统发育研究调整至Eupherusa属，该物种为单型种，无已知亚种。"},{"name":"棕颊蜂鸟","english_name":"Pirre Hummingbird","scientific_name":"Goldmania bella","overview":"棕颊蜂鸟（英文名：Pirre Hummingbird，学名：Goldmania bella），是雨燕目蜂鸟科紫顶蜂鸟属的鸟类。生活在巴拿马东部及哥伦比亚西北部近边界的稀有蜂鸟。其最显著特征为两性均具有的浅红褐色尾羽边缘，雄鸟拥有闪烁蓝绿色喉部，而雌鸟则下部较淡，喉部带有肉桂色。此物种仅限于特定的高海拔森林地带。","appearance":"棕颊蜂鸟体型中等，雄鸟头部前额及眼周为红褐色，上体及翼覆羽呈现金属绿色，尾羽中央为青铜绿色基部并以黑色尖端结束，外侧尾羽大面积红褐色并带黑色尖端。雌鸟上体全绿，无雄鸟的红褐色前额，下体为淡肉桂色。两性翼部均有一小块肉桂色斑点。","call":"关于棕颊蜂鸟的鸣叫特征记录较少，已知会发出一系列锐利的单音调，其具体功能尚不清楚。","habits":"此蜂鸟栖息于潮湿的山地森林边缘与内部的林下层，活动范围在海拔600至1650米之间。它们觅食时会从地面到森林中层寻找花蜜，已观察到它们在Cephalus灌木上觅食。除花蜜外，也假设它们像其他蜂鸟一样摄食小型节肢动物。","breeding":"关于棕颊蜂鸟的繁殖信息知之甚少，其筑巢及繁殖周期尚未被详细记录。","identification":"棕颊蜂鸟在有限的地理范围内具有独特性，其明显的肉桂色翼斑和尾羽使其在同类中易于辨认，尤其是在巴拿马东部及相邻哥伦比亚的区域。","protection":"IUCN：NT（近危）","distribution":"棕颊蜂鸟分布于巴拿马东部和哥伦比亚西北部的几处孤立山脉，主要栖息于相对原始的高海拔森林中。","other":"此蜂鸟因栖息地偏远且受到正式保护，大部分高山森林仍保持较为原始的状态。"},{"name":"紫顶蜂鸟","english_name":"Violet-capped Hummingbird","scientific_name":"Goldmania violiceps","overview":"紫顶蜂鸟（英文名：Violet-capped Hummingbird，学名：Goldmania violiceps），是雨燕目蜂鸟科紫顶蜂鸟属的鸟类。一种中等体型的蜂鸟。雄鸟以亮绿色体羽搭配闪耀的紫色头顶和青铜紫色尾巴而独具特色；雌鸟则拥有绿上体和白下体，侧边带有绿色斑点。主要分布于巴拿马中部至哥伦比亚西北极区的山地森林地带，活动于海拔约600-1200米之间。","appearance":"紫顶蜂鸟体长8.5至9.5厘米，雄鸟体重3.8至4.4克，雌鸟体重3.4至3.9克。雄鸟的喙笔直呈黑色，基部略带粉色；其头顶呈现出耀眼的紫蓝色光泽，全身大部分覆盖着金属质感的绿色羽毛，尾羽略呈叉状，深红色并边缘泛青铜色；雌鸟上体绿色，下体白色，喉部点缀灰色斑点，侧面有绿色斑块，尾羽与雄鸟相似，末端带有白色尖端。","call":"发出一系列不规则重复的、鼻音较重且音调较低的‘kyek...kyek-kyek-kyek...kyek...’声，通常在悬停或觅食时发出。其歌声被描述为低沉快速的啾啾声。","habits":"紫顶蜂鸟全年居住在其分布范围内，主要在密集的灌木丛中寻找花蜜，偏爱如鼠尾草、Pachystachis、Palicourea和Psammisia等低矮开花植物。","breeding":"繁殖季节从12月持续至至少4月，但关于其繁殖生态的详细信息尚不明了。已知其巢穴尚未被描述。","identification":"紫顶蜂鸟在雄鸟头部的显著紫蓝色和尾部的特殊色彩上易于识别，与同属的Pirre蜂鸟相比，具有明显的区别。","protection":"IUCN：NT（近危）","distribution":"紫顶蜂鸟分布于巴拿马东部和哥伦比亚西北部的若干非连续山地地区，主要栖息于海拔600至1200米的湿润森林边缘和内部。"},{"name":"暗阔嘴蜂鸟","english_name":"Dusky Hummingbird","scientific_name":"Phaeoptila sordida","overview":"暗阔嘴蜂鸟（英文名：Dusky Hummingbird，学名：Phaeoptila sordida），是雨燕目蜂鸟科 Phaeoptila 属的鸟类。体型中等的蜂鸟，分布于墨西哥西南部的干燥灌木丛生地带，包括花园和开放林地。其最显著的外部特征为灰褐色的上体与淡灰色的下体，以及雄鸟特有的红黑相间喙。与之相似的雌性阔嘴蜂鸟分布区域极少重叠。","appearance":"暗阔嘴蜂鸟拥有略显暗淡的青铜绿色上体，下体呈灰褐色或灰棕色。雄鸟具有独特的红色喙，顶端黑色，雌鸟喙色更深，下体颜色较淡，尾羽边缘有白色。成年个体全长约9至10.6厘米，雄鸟体重约为4.3克，雌鸟约为3.4克。眼后有一条灰白色的条纹，脸颊暗色，喉咙深灰色，带有绿色斑点。腿毛白色。","call":"暗阔嘴蜂鸟发出的鸣叫声被描述为柔和、干涩的叽叽喳喳声，与阔嘴蜂鸟类似，但更为柔和和液化。","habits":"暗阔嘴蜂鸟在树的中上层觅食花蜜，偏好柱状仙人掌和龙舌兰的花朵。它们在觅食时会展开并摆动尾巴。除了花蜜，它们还会捕食小型节肢动物。活动范围从900米至2200米海拔高度的半开放至开放景观。","breeding":"繁殖季节在3月、5月、8月、11月和12月均有观察记录。巢由植物纤维制成的小杯状，内部衬以柔软的植物绒毛，外表覆盖着叶片和树皮碎片。巢位高度通常在1.2至2米之间，位于灌木丛中。孵化期和离巢时间未知。","identification":"与雌性阔嘴蜂鸟相似，但后者上体更鲜亮的绿色，尾羽末端有更蓝黑色的亚端带，以及更白色、对比更鲜明的尾羽尖端。","protection":"IUCN：LC（无危）","distribution":"暗阔嘴蜂鸟主要分布在墨西哥南部，从Michoacán和Morelos到Oaxaca。"},{"name":"蓝顶妍蜂鸟","english_name":"Crowned Woodnymph","scientific_name":"Thalurania colombica","overview":"蓝顶妍蜂鸟（英文名：Crowned Woodnymph，学名：Thalurania colombica），是雨燕目蜂鸟科妍蜂鸟属的鸟类。广泛分布于中美洲至南美洲北部，从危地马拉延伸至厄瓜多尔和秘鲁西北部。雄鸟外观令人印象深刻，但常因深色外表而显得暗淡，其拥有较长且深叉的尾巴和璀璨的翡翠与紫色羽毛。雌鸟较为朴素，具有黑色喙，绿斑点的侧腹，以及蓝黑带白色角的尾巴。","appearance":"雄性蓝顶妍蜂鸟长9.5至11.5厘米，重4至5.5克，雌鸟略小，长8.5至9.2厘米，重3.5至4.2克。喙黑色，脚深灰色。雄鸟的额部、头顶、腹部和上背部为紫色，喉部和胸部闪烁着绿色光泽，颈背为深青铜绿色，下背和臀部为深蓝绿色，尾羽蓝黑且深叉。雌鸟上体鲜绿色，喉部和胸部淡灰色，腹部更深的灰色；尾羽末端半部分蓝黑，最外侧三根尾羽尖端白色。幼年雄鸟的头顶、喉部和下体呈灰暗色，点缀着25根或更少的紫色虹彩羽毛，外侧尾羽黑色带紫色，无白色尖端，尾叉小于12毫米；幼年雌鸟头顶绿色，上体均匀暗绿色，喉部和下体淡灰色，外侧尾羽有白色尖端，尾叉小于4.5毫米。","call":"可能的歌曲是一连串单调、哀婉的吱吱声，如“ksit...ksit...ksit..”，每秒约1.5音符（colombica群）或单调重复的单音吱吱声，如“tsip...tsip...tsip..”，每秒约1.2至2音符（fannyae群）。叫声包括短促干燥的吱吱声，有时快速连续发出，形成干涩的颤音或喋喋不休，例如刮擦的“chut-t-t”。","habits":"偏好热带低地的常绿森林及其边缘，通常靠近溪流。主要在阴暗的下层林间较低至中层觅食，但也到林缘和空旷地带的喂食器处觅食。在哥斯达黎加，栖息地海拔从海平面至900米，繁殖季节后可移动至高达1200米；在巴拿马，栖息地海拔可达130米；在哥伦比亚和委内瑞拉，栖息地海拔在1600至2000米之间；在秘鲁，栖息地海拔不超过950米。主要在覆盖或半开放区域而非开阔地带觅食。雄鸟倾向于在繁殖季节在树冠层觅食，雌鸟在下层林间觅食，但在繁殖季节之外，两者都在所有层次觅食。","breeding":"主要繁殖季节在旱季，哥斯达黎加为2月至6月，巴拿马为3月，北哥伦比亚和中哥伦比亚为3月至至少8月，西南哥伦比亚几乎全年都可繁殖。雄鸟可能通过保卫丰富的花朵吸引雌鸟。巢为紧凑的杯状，由树蕨鳞片、植物绒毛和蜘蛛网构成，外表面装饰有苔藓和地衣，位于灌木的水平枝条下，通常在森林中，常位于小缺口或路径边缘，距地面1至5米（偶尔可达8米）。一窝产两枚白色蛋。孵化期长度和离巢时间未知。","identification":"雄鸟与雌鸟在色彩上有明显区别，雄鸟色彩鲜艳，雌鸟较为暗淡。与其他同属物种相比，蓝顶妍蜂鸟的雄鸟具有独特的深叉尾和紫色头部特征。亚种之间也有细微差异，如在体型、色彩和尾羽形状上的变化。","protection":"IUCN：LC（无危）。蓝顶妍蜂鸟在其分布范围内是最常见的森林蜂鸟之一，但在许多地区，由于森林砍伐导致栖息地大量丧失，尤其是中美洲和北哥伦比亚的部分地区。严重砍伐可能威胁到西厄瓜多尔低地特有的hypochlora亚种，迫切需要更多关于这一亚种的信息。在一些保护区中发现，如哥斯达黎加的卡拉拉生物保护区、戈尔菲托国家野生动物庇护所、科科瓦多和布拉里奥卡里略国家公园，厄瓜多尔的布埃纳文图拉保护区（hypochlora亚种）以及秘鲁的西北生物圈保护区（hypochlora亚种）。","distribution":"分布于中美洲和南美洲，从危地马拉至厄瓜多尔和秘鲁西北部。","other":"蓝顶妍蜂鸟曾被分为多个独立物种，如绿冠木灵蜂鸟（T. c. fannyae）和翡翠腹木灵蜂鸟（T. c. hypochlora），但目前被视为同一物种的不同亚种。"},{"name":"叉尾妍蜂鸟","english_name":"Fork-tailed Woodnymph","scientific_name":"Thalurania furcata","overview":"叉尾妍蜂鸟（英文名：Fork-tailed Woodnymph，学名：Thalurania furcata），是雨燕目蜂鸟科妍蜂鸟属的鸟类。体型较小的叉尾蜂鸟，常见于低地亚马逊森林中。雄鸟头部和胸部呈闪光绿色，腹部紫色，但在光线不佳时整体显得较暗。雌鸟上部绿色，下部浅灰色。在亚马逊低地极为常见，栖息于各种开阔林地环境。","appearance":"雄鸟体长9.5至12.9厘米，体重3.6至6克；雌鸟体长8至10.7厘米，体重3至5克。两者均有直而中等长度的黑色喙。雄鸟上部大部分为深绿铜色，头顶和颈背暗铜色，喉部闪烁绿色，腹部和背部上方有紫色带，尾部蓝黑且叉开，尾下覆羽蓝钢色边缘泛白。雌鸟上部鲜绿色，冠部略暗更偏铜色，下部淡灰色；尾端蓝钢色，外侧三对尾羽尖端白色。幼鸟上下体色较为暗淡。","call":"发出连续的高音双音节、细薄金属音‘see-tseet...see-tseet....see-tseet...’，或重复3至7个昆虫般的脉冲音‘tsee-see-see....tsee-see-see-see-see...tsee-see-see...’。","habits":"栖息于湿润森林，包括亚马逊地区的高地森林和水边森林，偏好光照充足的林间空地。以多种开花植物的花蜜为食，如附生植物、藤蔓、树和灌木。通过捕飞和偶尔的叶面觅食获取小昆虫。在密集的森林环境中，利用所有层次进行觅食。","breeding":"繁殖季节各地不一，从4月至10月在安第斯山脉东坡，8月至10月在哥伦比亚东部的viridipectus亚种，以及12月至翌年3月在北巴西。巢为小巧杯状，由至少两种类型的种子绒毛构成，外壁粘贴少量苔藓，高度1.5至2.5米，宽约40至46毫米，内部直径19至23毫米，深18至20毫米。每窝产两枚纯白蛋。","identification":"与同类物种相比，雄鸟的尾下覆羽颜色、体型大小、上部体色等特征可作为辨识依据。雌鸟的下部灰度和尾下覆羽颜色也有差异。","protection":"IUCN：LC（无危）","distribution":"广泛分布于南美洲大陆，包括亚马逊流域的各国，从海平面至约2,000米海拔高度。","other":"在巴西多个保护区可见，如巴西利亚国家公园。"},{"name":"长尾妍蜂鸟","english_name":"Long-tailed Woodnymph","scientific_name":"Thalurania watertonii","overview":"长尾妍蜂鸟（英文名：Long-tailed Woodnymph，学名：Thalurania watertonii），是雨燕目蜂鸟科妍蜂鸟属的鸟类。体型较为大型、身姿苗条的蜂鸟，拥有略呈叉状的尾巴和笔直的喙。雄鸟羽毛呈现出金属光泽的绿色和紫蓝色，而雌鸟上部为绿色，下部为白色。该物种分布受限，主要栖息于巴西东北部的沿海森林、种植园以及一些树木繁茂的城市花园中。雄性叉尾妍蜂鸟的尾巴较短，背部更绿，但两者的分布区域并不重叠。","appearance":"雄鸟长约11.8至13厘米（含6厘米长的尾巴），雌鸟约10至11厘米（尾巴约3.5厘米）。雄鸟具有中等大小的笔直黑色喙，头顶和下颈为绿色，背部呈现虹彩的紫蓝色，腹部为闪耀的草绿色，两侧为紫蓝色；尾巴长且深叉，钢蓝色。雌鸟头顶和颈后为金绿色，下背为蓝绿色；下部均匀灰白色；尾巴不延长，轻微叉开，中央一对尾羽为蓝绿色，其余为绿色，有宽阔的钢蓝色亚端带和白色尖端。幼鸟类似成年雌鸟，但下部更暗淡的灰色，头部羽毛边缘带有黄褐色。","call":"文献中尚未详细描述其声音，但已记录到硬而响亮的‘chipping’叫声，以不同速度发出，经常持续较长一段时间，似乎是在领地防卫中发出。","habits":"栖息于沿海雨林、半开放的空地、种植园和公园，海拔从海平面至550米。觅食高度较低至中等，通常在植被边缘活动。以开花藤蔓、仙人掌、附生植物、灌木和树木的花蜜为食，如西番莲科、仙人掌科、凤梨科、桑寄生科、唇形科、茜草科、豆科等。偶尔在空中捕捉昆虫。雄鸟建立并积极捍卫其领地，防止同类和异类入侵。","breeding":"繁殖季节为11月至次年2月。巢由细根和苔藓构成，用蛛丝粘合，建于灌木或小树的水平枝上，通常被悬垂的叶子保护，离地面1.5至2.5米。每窝产2枚卵，大小约为14.5毫米×9.3毫米，重量0.5克，孵化期14至15天，由雌鸟承担。雏鸟暗色，背部有两排淡黄灰色绒毛；大约20天后离巢。首次繁殖发生在第二年。","identification":"雄性长尾妍蜂鸟与叉尾妍蜂鸟雄鸟的主要区别在于前者尾巴更长，背部颜色更加紫蓝；雌鸟辨识较为困难，但两者的分布区并不重叠。","protection":"IUCN：EN（濒危）","distribution":"分布于巴西东北部（伯南布哥州、阿拉戈阿斯州、塞尔希培州和巴伊亚州北部）；在帕拉州东部的报道几乎肯定是错误的。可能也在圭亚那存在，但仅知一型标本，其真实来源可能不确定。主要栖息于大西洋森林，包括沿海雨林、种植园和公园。"},{"name":"紫顶妍蜂鸟","english_name":"Violet-capped Woodnymph","scientific_name":"Thalurania glaucopis","overview":"紫顶妍蜂鸟（英文名：Violet-capped Woodnymph，学名：Thalurania glaucopis），是雨燕目蜂鸟科妍蜂鸟属的鸟类。主要分布在南美洲，从巴西东南部到里奥格兰德杜斯，再到阿根廷东北部的米西奥内斯省、巴拉圭东部及乌拉圭北部。常见的森林及郊区环境中的蜂鸟。","appearance":"紫顶妍蜂鸟体型介于8至11厘米，雄鸟体重4至6.1克，雌鸟4至5克。雄鸟具有蓝紫色的额头和冠羽，金色绿色的上体，以及深蓝色的叉状尾巴。雌鸟全身绿色，下体呈脏白色或淡黄色，尾巴略带叉状，内部羽毛金属绿色，外部深蓝色带白尖。亚成年雄鸟的冠羽为蓝绿色，带有零散的蓝紫色羽毛，下体有灰褐色区域。","call":"可能的鸣唱是一系列单调快速的金属质感的‘chip..chip..chip...’声，以每秒约5至10个音符的速度发出，偶尔加速成颤音。飞行中会发出短促干燥的‘chip’声，常以快速连续的颤音或叽喳声呈现。","habits":"紫顶妍蜂鸟栖息于原始森林、森林边缘、灌木丛，也出现在城市公园和花园。海拔分布范围从海平面至850米。它是一种短距离迁徙的鸟类，以各种本土和引入的植物花蜜为食，从林下层至树冠层都有觅食活动，也会捕食小昆虫。","breeding":"繁殖季节从9月至翌年2月。巢为碗状，由柔软的植物纤维构成，外部装饰有蕨类鳞片和苔藓。巢置于树上水平枝条或细枝分叉处，离地面1.5至3米。每窝产两枚白色卵，孵化期约15天，由雌鸟独自承担，雏鸟孵化后20至25天离巢。","identification":"雄性紫顶妍蜂鸟的蓝紫色冠羽和深蓝色的叉状尾巴是显著特征，而雌鸟和亚成年雄鸟的外观较为相似，主要通过冠羽颜色和下体色调进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于巴西东南部至里奥格兰德杜斯，阿根廷东北部的米西奥内斯省，巴拉圭东部，以及乌拉圭北部。","other":"紫顶妍蜂鸟在巴西东南部是最常见的Trochilidae之一，在许多受保护的区域中都可以找到，例如Serra dos Órgãos和Itatiaia国家公园。"},{"name":"青喉蜂鸟","english_name":"Sapphire-throated Hummingbird","scientific_name":"Chrysuronia coeruleogularis","overview":"青喉蜂鸟（英文名：Sapphire-throated Hummingbird，学名：Chrysuronia coeruleogularis），是雨燕目蜂鸟科金尾蜂鸟属的鸟类。中等体型的蜂鸟，分布于巴拿马、哥伦比亚，近期在哥斯达黎加也有发现。其以金属光泽的绿宝石色羽毛著称，雄鸟拥有深紫蓝到黑色变化的喉部，雌鸟下部为灰白色，两侧点缀绿色斑点，尾部呈明显的叉状。","appearance":"成年青喉蜂鸟长约8.5至9.5厘米，重3.9至4.3克。雄鸟喙短而直，上喙黑，下喙粉红，尖端黑；上体闪烁绿光，臀部铜色；喉部及胸部为虹彩般的蓝紫色，其余下体部分绿光闪耀；尾羽叉状，中央尾羽铜金色，其余蓝黑色。雌鸟与雄鸟相似，但下部灰白，两侧有蓝绿色斑点，外侧尾羽尖端白色。幼鸟似雌鸟，头羽边缘淡黄。","call":"鸣声为高音金属颤音，起始于单独音符，随后为一系列快速下降的颤音，持续约3秒，重复间隔不规则。叫声为短促流利的颤音。","habits":"栖息于干燥林地、灌木丛和红树林，偏好花树环境。以花蜜为食，偏爱豆科和桃金娘科等高糖分花朵，同时捕食枝叶上的节肢动物，偶尔捕飞虫。飞行速度快，能倒飞，适应力强。","breeding":"繁殖期在1月至3月（巴拿马、北哥伦比亚），筑巢于低矮灌木分叉处，巢杯状，由干植物纤维构成，外表装饰苔藓和枯叶碎片，离地面高度约0.7至1.5米。每窝产两枚白色卵，孵化期15至16天，仅由雌鸟承担。雏鸟粉色，背部长有两排肉桂色绒毛，离巢期19至22天。","identification":"雄鸟的蓝紫色喉部和叉状尾羽是显著特征，雌鸟下部灰白色，两侧有绿色斑点，区别于其他类似体型和颜色的蜂鸟。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的巴拿马，南美洲的哥伦比亚，近年在哥斯达黎加也有记录。主要栖息于沿海森林、次生林、灌木丛和红树林地带，最高海拔可达100米。","other":"青喉蜂鸟分为三个亚种： coeruleogularis、 coelina、 conifis。"},{"name":"青腹蜂鸟","english_name":"Sapphire-bellied Hummingbird","scientific_name":"Chrysuronia lilliae","overview":"青腹蜂鸟（英文名：Sapphire-bellied Hummingbird，学名：Chrysuronia lilliae），是雨燕目蜂鸟科金尾蜂鸟属的鸟类。仅分布于哥伦比亚中北部沿海的红树林及周边灌木丛中。雄鸟拥有闪耀蓝绿色上体，腹部至喉咙呈现出璀璨的蓝宝石色光泽，尾部呈深蓝黑色且分叉。","appearance":"雄性青腹蜂鸟上体闪耀着绿光，下体至喉咙覆盖着绚丽的蓝宝石色，尾羽蓝黑且分叉明显，喙几乎笔直，上喙黑色，下喙粉红色带黑色尖端。雌鸟及幼鸟的羽毛特征尚未详细描述，可能与雄鸟相似但下体颜色更淡。","call":"其叫声被描述为一系列短暂的叽喳声，具体细节记录有限。","habits":"青腹蜂鸟偏好茶红树的花蜜，同时也会摄食昆虫，栖息于红树林及相邻的干旱灌木丛中。","breeding":"关于青腹蜂鸟的繁殖习性，目前尚无确切信息。","identification":"与之相似的青喉蜂鸟（学名：）在同一生境中出现，但缺乏青腹蜂鸟特有的下胸及腹部的闪光蓝色。","protection":"IUCN：EN（濒危）","distribution":"青腹蜂鸟仅限于哥伦比亚中北部的Ciénaga Grande de Santa Marta红树林及周边干旱灌木丛中，属于南美洲特有种。","other":"青腹蜂鸟曾被视为青喉蜂鸟的亚种，现已确认为独立物种。"},{"name":"辉绿蜂鸟","english_name":"Shining-green Hummingbird","scientific_name":"Chrysuronia goudoti","overview":"辉绿蜂鸟（英文名：Shining-green Hummingbird，学名：Chrysuronia goudoti），是雨燕目蜂鸟科金尾蜂鸟属的鸟类。辉绿蜂鸟，蜂鸟科的一种，主要分布于南美洲的哥伦比亚和委内瑞拉西北部。其全身闪烁着绿色光泽，头部和腹部带有蓝色调，尾巴相对较长且呈明显缺口状。","appearance":"辉绿蜂鸟长约9至9.5厘米，雄鸟体重约4.1克，雌鸟约3.7克。雄鸟上体为绿色，下体闪耀蓝绿色，腹部白色，尾羽中央为青铜黑色，外侧为蓝黑色。雌鸟下体羽毛基部和边缘白色，形成斑点状外观，腹部几乎纯白，尾羽较雄鸟少分叉，颜色更偏青铜或绿色。幼鸟上体比成鸟暗淡，下体为灰白色，腹部灰白色。","call":"鸣叫包括清脆的‘pee-rrrr..pee-rrrr..peer-rrrr..’式薄而快速重复的颤音，以及高音下降的颤鸣和尖锐的鸣叫声。","habits":"栖息于开放地带，如灌木丛、带散生树木的区域、干燥到湿润的灌木地、画廊森林边缘、咖啡种植园和花园。海拔分布从海平面至最高1,600米。以多种植物的花蜜为食，偶尔群集于开花树上争斗，同时捕食昆虫。","breeding":"繁殖季节大约从十月持续到三月。巢为小型杯状，由植物绒毛和蛛丝构成，外表覆盖苔藓，通常位于树或灌木的外围枝条上，距地面1至1.5米。关于繁殖生态学的其他信息未知。","identification":"与近缘种相比，辉绿蜂鸟的雄鸟上体更加绿色，下体蓝绿色更显著，尾羽中央为青铜黑色，外侧为蓝黑色。雌鸟腹部几乎纯白，尾羽较雄鸟少分叉。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的哥伦比亚和委内瑞拉西北部，主要栖息于海拔1,000米以下的地区。"},{"name":"蓝头红嘴蜂鸟","english_name":"Blue-headed Sapphire","scientific_name":"Chrysuronia grayi","overview":"蓝头红嘴蜂鸟（英文名：Blue-headed Sapphire，学名：Chrysuronia grayi），是雨燕目蜂鸟科金尾蜂鸟属的鸟类。引人注目的蜂鸟，以其深蓝色头部、闪烁的绿色身体和红色喙尖为显著特征。主要分布于南美洲的哥伦比亚西部至厄瓜多尔北部的安第斯山谷地带。","appearance":"蓝头红嘴蜂鸟体型小，长度9至11厘米，雄鸟体重约6.2至6.8克，雌鸟略轻，约4.6至5.6克。雄鸟喙大部分珊瑚红色，末端黑色；雌鸟喙基部红色，其余部分粉红色，末端黑色。雄鸟头部上部、面部和冠部深蓝色并闪耀光泽，颈背暗蓝绿色，背部金属绿色，尾部深钢蓝色；下喉、胸部和上腹部翡翠绿色，下腹有一小块灰白色，覆尾羽金属绿色边缘暗灰色。雌鸟上体金属绿到青铜绿色，尾部基部暗青铜绿，余部蓝黑色，外侧尾羽尖端灰白色；下体主要灰白至淡白色，喉咙和胸部两侧青铜绿色，下喉有亮绿色斑点。幼鸟头部和下体色泽较暗，缺乏金属光泽。","call":"鸣唱为重复的短促颤音，起始于吱吱声“tee”，随后是“tee…teetlitlitsee-chup… teetlitlitsee-chup”，最后一音较低，通常从2至4米高的栖木发出。叫声包括短促的‘chip’音和高音下降的咔哒声。","habits":"栖息于海拔500至2000米的干灌木林地、林缘和高大的森林边缘，偶尔可见于海拔2600米。蓝头红嘴蜂鸟在繁殖季节会进行显著的季节性迁移，具体细节尚不清楚。以花蜜为食，常在各种开花的灌木和树木上觅食，有时会保卫领地，尤其在聚集于开花树冠时表现出攻击性。除花蜜外，还通过从栖木上猎捕或从植被中拣拾的方式捕食昆虫。","breeding":"繁殖期记录在11月至次年4月间，但具体繁殖生态学信息未知，其巢穴尚未被描述。","identification":"与洪氏红嘴蜂鸟极为相似，但后者分布于海岸低海拔地区。","protection":"IUCN：LC（无危）","distribution":"分布于哥伦比亚西部（Valle del Cauca）向南延伸至厄瓜多尔北部（Pichincha省）的安第斯山谷。"},{"name":"洪氏红嘴蜂鸟","english_name":"Humboldt's Sapphire","scientific_name":"Chrysuronia humboldtii","overview":"洪氏红嘴蜂鸟（英文名：Humboldt's Sapphire，学名：Chrysuronia humboldtii），是雨燕目蜂鸟科金尾蜂鸟属的鸟类。小型蜂鸟，主要分布在中美洲巴拿马东南部至南美洲厄瓜多尔西北部的狭窄太平洋沿岸地带。其最显著的特征是雄鸟的蓝绿色冠羽和喉咙，以及明亮的珊瑚红色喙，喙尖呈黑色。","appearance":"雄性洪氏红嘴蜂鸟长约9至12.5厘米，重6.3至6.6克，喙大部分为珊瑚红色，仅尖端黑色。头部特征明显，额头及喉咙中心深蓝色，颈侧及脸颊闪烁着蓝绿色至绿色光泽，腹部中心及尾下覆羽白色，白纹常延展至胸部下方形成宽条纹。雌鸟体型略小，下体偏白，喉及胸侧点缀以鲜绿色斑点。幼鸟腹部白色较多，喉部及胸部灰褐色带有青铜色斑点，冠羽及面部暗蓝绿色。雌雄两性皆具黑色脚趾。","call":"鸣唱特征尚不完全清楚，但已知的可能的歌声为一系列高音的嘶嘶声和颤音组成的重复短语，如“tee-tsee-see-tsee-see-trtrt-tsee-see-trtrt”。还发出下降的吱吱声或哨音。","habits":"栖息于沿海低地的灌木丛生的次生林和红树林，偏好茶红树的花朵，也会访问其他开花的树木、灌木和大草本植物。捕食飞行中的昆虫，从靠近开阔地或水面的栖息处猎捕，也会从植物上捡食小型节肢动物。","breeding":"繁殖行为部分了解，雄鸟会在1月到5月期间聚集在展示场向雌鸟展示，但具体繁殖细节未知，巢穴尚未被描述。","identification":"与之前被认为是同种的格氏漠百灵相比，洪氏红嘴蜂鸟的喙较短，翅膀和尾巴较长。雄鸟的蓝色限于额头和喉咙中央，而雌鸟下体更白，喉及胸侧有明显的绿色斑点。","protection":"IUCN：LC（无危）。全球估计数量在20,000至50,000只成熟个体之间，但种群被认为正在减少。在巴拿马较为常见，在哥伦比亚非常局部，在厄瓜多尔极为罕见。","distribution":"分布于巴拿马东南部至厄瓜多尔西北部的太平洋沿岸带，包括哥伦比亚西部。主要栖息在红树林和邻近的湿性次生林，海拔通常低于50米。","other":"曾一度被视为蓝头红嘴蜂鸟的亚种。"},{"name":"金尾蜂鸟","english_name":"Golden-tailed Sapphire","scientific_name":"Chrysuronia oenone","overview":"金尾蜂鸟（英文名：Golden-tailed Sapphire，学名：Chrysuronia oenone），是雨燕目蜂鸟科金尾蜂鸟属的鸟类。体型小巧，雄鸟拥有蓝紫色头部，绿色胸部，铜色腹部和尾部，以及鲜艳的红臀部和尾羽；雌鸟相似但蓝色面颊缺失，腹部颜色更淡。分布于南美北部，尤其是亚马逊雨林西部，常见于森林边缘和牛轭湖附近。","appearance":"金尾蜂鸟体长9.5至10厘米，雄鸟体重4.7至6.3克，雌鸟体重4.3至5.3克。雄鸟具有完整的蓝紫色头部和喉咙，胸部闪耀着绿色，腹部逐渐变为青铜绿色，尾下覆羽带白色边缘；背部亮绿色，通过青铜绿色过渡到明亮的铜色上尾羽和铜青铜色尾巴。雌鸟头部顶部蓝色，背部绿色，上尾羽和尾巴铜青铜色；下方大部分白色，喉侧和颈侧带有蓝绿色斑点，侧面和胸前绿色，两胁青铜绿色；尾下覆羽带有青铜色中心。幼鸟的冠部暗绿，喉咙灰暗，胸色较暗；首次换羽后的头和喉咙羽毛比成年雄鸟的更蓝，少紫；雌鸟幼鸟的斑点下方较暗，更青铜色，少蓝色。","call":"金尾蜂鸟的鸣声多变，常表现为重复的节奏性短语，通常以沙哑音开始，接着是几个非常尖锐或刺耳的音符，以连续的咔嚓声结束。叫声包括拉长的金属颤音和较短的咔嚓声。","habits":"金尾蜂鸟主要在湿润低地活动，偏爱森林边缘和牛轭湖环境。它们频繁造访开花树木（如红花刺槐、印加树）和灌木（如彩叶草、帕里库拉）以吸食花蜜；雄鸟偶尔会在花朵处建立领地，当更有攻击性的物种如叉尾蜂鸟不在场时。它们也会在森林边缘或空隙处捕食昆虫，或从树叶上获取节肢动物。","breeding":"金尾蜂鸟的繁殖季节在东哥伦比亚为6月至11月，但在巴西西部则为1月至4月。繁殖期间，雄鸟通常聚集在由5至10个个体组成的lek群中展示给雌鸟看，有时独自展示。每窝产卵2枚，大小约为14至14.3毫米×9毫米，重量约0.47克；孵化期大约14天，幼鸟离巢时间约为28天。","identification":"金尾蜂鸟与其他蜂鸟的区别在于其独特的尾羽色彩和雄鸟的蓝紫色头部。亚种C. o. josephinae的雄鸟喉部主要是绿色，臀部绿色，与铜色尾羽形成鲜明对比；而C. o. alleni的喉部全部绿色，脸颊上的蓝色较少，两性的臀部均为铜色。","protection":"IUCN：LC（无危）；被列入《濒危野生动植物种国际贸易公约》（CITES）附录II。在哥伦比亚和委内瑞拉的部分地区较为常见，但在远离安第斯山脉的亚马逊低地较为罕见。","distribution":"金尾蜂鸟广泛分布于南美洲北部，包括哥伦比亚/委内瑞拉边境的佩里贾山脉，委内瑞拉东部和北部，哥伦比亚东部中部，厄瓜多尔东部，巴西西部极区以及秘鲁东北部。在玻利维亚北部也有分布。它栖息于半开放景观，如湿润森林的边缘和空隙，成熟的次生林，河岸森林，阴凉的可可和咖啡种植园以及花园。在哥伦比亚和委内瑞拉，海拔范围从海平面至1,500米，在厄瓜多尔则在400至1,200米之间。","other":"曾被归入Amazilia属，但基于分子系统发育研究，现在分类至Chrysuronia属。"},{"name":"纯腹蜂鸟","english_name":"Plain-bellied Emerald","scientific_name":"Chrysuronia leucogaster","overview":"纯腹蜂鸟（英文名：Plain-bellied Emerald，学名：Chrysuronia leucogaster），是雨燕目蜂鸟科金尾蜂鸟属的鸟类。这种蜂鸟以绿色和白色为主色调，拥有纯白的腹部和带有红基的喙，活跃于南美洲的多种半开放至开放生境，包括沿海地带的红树林、次生林、城市公园和花园等。在东北部委内瑞拉至巴西皮奥伊州以及巴西东部至埃斯皮里图圣多州之间分布。","appearance":"纯腹蜂鸟体长约9-10厘米，体重4-4.5克（雄鸟）和约4.3克（雌鸟）。雄鸟具有一根略向下弯曲的黑色喙，基部呈红色，头部和颈侧闪烁着金色绿光，其余上身、侧腹和喉侧呈金至青铜绿色，中心喉部、腹部及下覆羽为白色。尾内侧羽青铜色至青铜绿，外侧羽蓝黑色，尾微叉状。雌鸟与雄鸟相似，但喉侧有更多绿色斑点，尾尖灰绿色。幼鸟背部边缘呈棕色。巴西亚种（bahiae）喙较长（23毫米），翅膀更长（55毫米），颜色较淡。","call":"其推测的歌曲是一连串重复的单一‘pseeee’音符。鸣叫包括细薄的‘tsink’声和高音的颤音系列。","habits":"纯腹蜂鸟在各种花卉、灌木和树木中觅食花蜜，偏好豆科、沃克希科科、芭蕉科、马鞭草科、鹤望兰科、紫葳科、锦葵科、凤梨科、漆树科、唇形科和西番莲科植物。通过悬停捕食空中小昆虫。","breeding":"繁殖季节在圭亚那地区为7月至8月，在东北巴西为10月至翌年2月。巢呈杯状，由植物绒毛制成，有时包含凤梨科植物材料，外部装饰有苔藓，置于离地面不超过5米的水平枝或小树丛叉中。每窝产两枚卵，大小约为13.4-14毫米×9毫米，重0.42-0.44克。孵化期14天，仅由雌鸟承担；幼鸟在20-25天后离巢。","identification":"与白胸蜂鸟极为相似，可能仅在良好观察下才能安全区分开；纯腹蜂鸟具有较长的喙，基部带红色。巴西亚种（bahiae）喙更长，翅膀更大，颜色较淡。","protection":"IUCN：LC（无危）","distribution":"纯腹蜂鸟主要分布在南美洲东北部，从东北委内瑞拉经圭亚那、苏里南、法属圭亚那至巴西东北部皮奥伊州；在巴西东部，自伯南布哥向南至巴伊亚，略微延伸至埃斯皮里图圣多州。通常栖息于海平面附近，但在委内瑞拉可达海拔250米。","other":"纯腹蜂鸟的系统学历史中，曾被归入Agyrtria和Amazilia属，后因分子系统发育研究被移至Chrysuronia属。"},{"name":"虹彩蜂鸟","english_name":"Versicolored Emerald","scientific_name":"Chrysuronia versicolor","overview":"虹彩蜂鸟（英文名：Versicolored Emerald，学名：Chrysuronia versicolor），是雨燕目蜂鸟科金尾蜂鸟属的鸟类。广泛分布在南美洲的中南部、东南部及亚马逊雨林的部分地区，常见于多种生境，从森林边缘到沙漠、红树林至城市地带。具有多个亚种，羽毛色彩差异显著，但共同特征为闪耀的绿色身体，橙色下喙基部，以及可变的白色腹部。","appearance":"虹彩蜂鸟体型小，长度8-10厘米，体重3-4克，喙直而中等长度（约1.8厘米），上喙黑色，下喙除尖端外呈红色。头部、脸颊、背部呈现青铜绿至金绿色光泽，下体中央白色，胸侧、胁部和尾下覆羽为青铜绿色，边缘带白色。尾巴为青铜绿色，外侧尾羽有暗色亚端斑。雌鸟外侧尾羽尖端呈灰色。幼鸟冠羽、背下部和臀部边缘呈锈色，腹部棕色。不同亚种在喉部颜色（蓝、绿或白）、腹部白色斑块大小以及冠羽颜色（蓝绿至金色光泽）上存在差异。","call":"发出一系列单音节的‘pseee’或‘tsew’或‘tsidit’，速度约为每秒1.5-2个音符。另有短促的‘trr’叫声。","habits":"虹彩蜂鸟偏好半开放的生境，包括灌木丛、Caatinga（干旱灌木林）、Campo cerrado（热带草原）和城市公园花园，一般不进入湿润原始森林内部。主要在低海拔活动，高度范围从亚马逊盆地的50米至安第斯山脉东坡下山地带的1250米，但在南美Pantepui地区很少见于1000米以上，最高可达1700米。以花蜜和节肢动物为食，偏好短管或无管的花朵，如Buddleja、Piptocarpa、Tillandsia等，也会在果园或城市区域的Heliconia、Eucalyptus、Citrus等开花植物上觅食。","breeding":"繁殖季节几乎全年，东部巴西为10月至翌年3月。巢呈杯状，由植物绒毛和种子构成，外部装饰有灰红色苔藓碎片，通常置于离地面1-6米的水平枝上，偶尔高达10米。巢高33毫米，外径43毫米，内径14毫米。每窝产两枚蛋，尺寸约为14毫米×9毫米，重0.43克，由雌鸟孵化14天，雏鸟20-26天离巢，有时可达32天。","identification":"与其他蜂鸟区分的关键在于其绿色至青铜绿色的上体、白色的腹部中心、橙色下喙基部以及变化多端的喉部颜色。亚种间差异体现在喉部颜色、冠羽色泽及腹部白色斑块的大小。其他亚种与亚种rondoniae相比，后者头部呈现蓝色，但两者生态需求相似，可能难以在野外区分。","protection":"IUCN：LC（无危）。《华盛顿公约》CITES II级保护。在巴西南部，如圣卡塔琳娜州，某些亚种数量稀少。荷兰亚种（hollandi）和库布特切基亚种（kubtchecki）的分布和状态需要进一步研究，尤其是rondoniae亚种，由于森林砍伐威胁，其巴西种群可能处于危险之中。","distribution":"虹彩蜂鸟分布于南美洲北部玻利维亚、东部巴拉圭、东北阿根廷、巴西东部、南部和中部，以及亚马逊盆地的部分地区，如沿亚马逊河和黑河。在远西北巴西、委内瑞拉南部、圭亚那西部和哥伦比亚东部也有零星分布。","other":"虹彩蜂鸟的分类复杂，涉及多个亚种，部分曾被视为独立物种，如亚种rondoniae，现已重新归类为虹彩蜂鸟的亚种。"},{"name":"白胸蜂鸟","english_name":"White-chested Emerald","scientific_name":"Chrysuronia brevirostris","overview":"白胸蜂鸟（英文名：White-chested Emerald，学名：Chrysuronia brevirostris），是雨燕目蜂鸟科金尾蜂鸟属的鸟类。体型较小，具有完全白色的下体，常见于热带草原、干林和受干扰的生境。其历史分类复杂，曾先后被称为Amazilia chionopectus, Agyrtria brevirostris和Amazilia brevirostris。","appearance":"体型约9至10厘米，重量介于3至5克之间。雄鸟具有一根直而短的几乎黑色的喙；头部上方和脸颊呈现闪光的蓝绿色；背部呈闪亮的青铜绿色，向臀部逐渐变为铜色；中央腹部白色；侧腹和胸部侧面青铜绿色；下尾羽覆羽带有金色绿心和白色边缘；外侧尾羽铜至青铜色，下方有黑色亚端斑。雌鸟外侧尾羽尖端灰白色。幼鸟似雌鸟，但下颌基部黄至红色。三个亚种中，emchionopectus/em体型显著较大；orienticola上体和侧腹颜色更深，更呈青铜色。","call":"鸣声变化多端，但始终具有难以描述的鼻音和尖锐特性，常重复短语如“tsri-lee … tsri-lee ... tsri-lee”，“tee-tink-tink-tink .. tsee-tink ... tee-tink-tink-tink … tsee-tink ...”或“teee-tjitjitjitjitji ..... teee-tjitjitjitjitji...”。","habits":"栖息于雨林、半落叶林、画廊林、次生林、灌木丛、大草原和半耕作土地。偏好开放山谷中的可可树种植园。觅食花蜜于大树如Erythrina和Samanea，小树如Calliandra，草本植物如Pachystachys，以及多种Malvaceae、Leguminosae、Lorantaceae、Bignoniaceae、Vochysiaceae和Verbenaceae科植物。在植被中或空中捕捉小型昆虫。","breeding":"筑杯状巢，由植物纤维构成，外部覆盖苔藓，通常置于离地面1至7米的水平枝条上。繁殖季节至少包含12月至4月。雌鸟孵化两枚蛋，孵化期未知；小鸟出壳后约20天离巢。","identification":"与Plain-bellied和Versicolored Emeralds最相似，但具有较短的全黑喙；在共同分布区，若观察不够细致，则难以与它们区分。","protection":"IUCN：LC（无危）。CITES II。在半开放沿海地区普遍常见，但在一些大陆种群的状况近期未被研究，缺乏关于当前数量或潜在威胁的信息。","distribution":"分布于巴西、圭亚那、特立尼达和委内瑞拉北部。在特立尼达岛，偏好开放的山谷地带。orienticola亚种仅限于法属圭亚那沿海地区。","other":"在特立尼达岛上是最常见的Trochilidae之一，能迅速适应人造环境。然而，orienticola亚种自1987年以来仅有两次标本记录和少数目击，被认为是极其罕见。"},{"name":"棕喉红嘴蜂鸟","english_name":"Rufous-throated Sapphire","scientific_name":"Hylocharis sapphirina","overview":"棕喉红嘴蜂鸟（英文名：Rufous-throated Sapphire，学名：Hylocharis sapphirina），是雨燕目蜂鸟科红嘴蜂鸟属的鸟类。属于蜂鸟科，主要分布在南美洲的亚马孙雨林区域，包括哥伦比亚东部、委内瑞拉南部、圭亚那地区、巴西北部至海岸线，以及玻利维亚东北部、巴拉圭东南部、阿根廷东北部和巴西东南部的巴伊亚州至帕拉纳州北部。其最显著的特征是雄鸟的鲜艳色彩，拥有绿色背部、紫色蓝光泽的腹部、铜色尾巴和白色的腹底，以及独特的棕色喉咙。","appearance":"雄性棕喉红嘴蜂鸟长约8.4至9.1厘米，重4.1至4.5克，具有中等长度、笔直的珊瑚红色喙，尖端黑色；上身深绿色，尾羽覆羽呈铜色紫光；喉咙、胸部及腹部具金属光泽的紫蓝色，下尾覆羽为栗色；中央尾羽铜色带紫色，其余尾羽栗色，尖端暗灰色。雌鸟相似，但下身灰白色，带有较大的蓝绿色斑点于喉部和胸部，下尾覆羽为淡黄色。幼鸟与成年雌鸟相似，但雄鸟幼鸟下巴有更丰富的棕色。","call":"在委内瑞拉，其叫声为一系列明亮高音的音符，以约每两秒四音节的速度重复，声音类似'sping...sping...sping...'或更双音节'sping...spewee...spewee...spewee'。在亚马逊地区和巴西东部，叫声完全不同，是一种不规则重复的、延长的、高音下滑音'seeeeee'，持续约0.5至0.8秒。","habits":"栖息于低地森林边缘、灌木丛生的草原、岩石露头附近的空地、咖啡种植园及罕见的沿海开阔植被。主要在海拔200至500米处最多，有时可达1850米。以花蜜为主食，采食多种开花植物，包括豆科、芸香科、茜草科、桃金娘科、桑寄生科、西番莲科和凤梨科。偶尔在亚马逊地区的树顶聚集，与其它蜂鸟共饮花蜜。也会在某些地区访问人工喂食器。通过空中捕捉昆虫和蜘蛛网上的蜘蛛来补充饮食。","breeding":"繁殖季节在圭亚那地区为7月至1月，在巴西（含大西洋森林）为8月至2月。筑巢于灌木或树木的水平枝条上，高度通常在4至6米之间，巢由植物纤维构成，内部铺有柔软的种子绒毛，有时外壁装饰有苔藓和叶片碎片。每次产卵两个，卵大小约为14.5至15毫米×9至9.3毫米，重量0.48至0.5克。孵化期为14至16天，由雌鸟单独孵化。雏鸟黑色，背部有稀疏的黄白色绒毛。离巢时间为22至27天，之后雌鸟会继续喂养一段时间。","identification":"雌雄差异明显，雄鸟具有醒目的颜色，尤其是其独特的棕色喉咙，而雌鸟下体较灰暗。与白颊红嘴蜂鸟和金尾蜂鸟在外观上有一定相似性，但可通过观察下巴的棕色特征加以区分。","protection":"IUCN：LC（无危）；CITES II（濒危野生动植物种国际贸易公约二级）。","distribution":"广泛分布于南美亚马孙雨林区域，包括哥伦比亚东部、委内瑞拉南部、圭亚那、苏里南、法属圭亚那、巴西北部至海岸线，以及玻利维亚东北部、巴拉圭东南部、阿根廷东北部和巴西东南部的巴伊亚州至帕拉纳州北部。","other":"在巴西东南部的隆德里纳城市中心附近，该物种数量合理，适应了人类创造的环境，如咖啡种植园，前提是周边有自然的半开放生境。"},{"name":"金红嘴蜂鸟","english_name":"Gilded Sapphire","scientific_name":"Hylocharis chrysura","overview":"金红嘴蜂鸟（英文名：Gilded Sapphire，学名：Hylocharis chrysura），是雨燕目蜂鸟科红嘴蜂鸟属的鸟类。中型蜂鸟，分布于南美洲的玻利维亚至巴西东南部，乌拉圭和阿根廷北部。在森林边缘、轻木林、种植园及喂食器附近可见。","appearance":"金红嘴蜂鸟长约8至10厘米，重4至5克。其特征为中等长度的直喙，珊瑚红色并带有黑色尖端。雄鸟全身大部分呈现金属光泽的金色绿色，下颌淡赤褐色，尾羽闪耀着金色青铜色。雌鸟相似，但总体上较暗淡，腹部下方呈灰色。幼鸟与成年雌鸟相似，头部羽毛边缘泛黄。","call":"其歌声为反复的高音调、类似蟋蟀的颤音，长度变化不定，频率在8至10千赫兹。叫声为短暂干燥的‘trrrt’声。","habits":"金红嘴蜂鸟栖息于花园、种植园、有散落灌木和树木的草原、森林边缘，海拔从200米到1000米，局部地区可达更高。它在植被外围觅食，从低处到树顶的开阔地带都有它的身影，数量最多在海拔400至800米之间。","breeding":"繁殖季节在巴西为9月至2月。小杯状的巢由马利筋、Chorisis和各种凤梨科植物种子纤维以及蜘蛛网构成，外部装饰有苔藓和碎叶。巢通常建在4至6米高的细水平枝或小树叉上，偶尔高达12米。每窝产两枚蛋，大小约为15毫米×9.3毫米，重量约0.5克，由雌鸟孵化14至15天。雏鸟黑色，背部有两行淡黄色绒毛，离巢期为20至28天。","identification":"金红嘴蜂鸟与同属的其他物种相比，其独特的金色绿色羽毛和珊瑚红色喙是辨识的关键。雌雄差异不大，但雌鸟整体更暗淡，腹部下方灰色，而雄鸟下颌赤褐色。","protection":"IUCN：LC（无危）","distribution":"金红嘴蜂鸟分布于玻利维亚东北部至南部、巴西中部和东南部、乌拉圭及阿根廷北部。","other":"金红嘴蜂鸟在人类制造的环境中如花园和种植园中非常常见，由于其对环境要求的广泛性，预计其分布范围会继续扩大。"},{"name":"白喉蜂鸟","english_name":"White-throated Hummingbird","scientific_name":"Leucochloris albicollis","overview":"白喉蜂鸟（英文名：White-throated Hummingbird，学名：Leucochloris albicollis），是雨燕目蜂鸟科白喉蜂鸟属的鸟类。是南美洲特有的一种珍贵鸟类，分布于巴西东南部、巴拉圭东部、乌拉圭和阿根廷东北部。其最显著的特征是拥有绿色的身躯和醒目的白色喉部。","appearance":"白喉蜂鸟体型小巧，长约10至11.5厘米，雄鸟体重5至8克，雌鸟约4.5克。成年个体拥有中等长度、笔直的喙，上颚黑色，下颚红色带黑尖。雄鸟背部呈金色到青铜绿色，尾羽内侧金绿至亮绿，外侧黑绿带白边。喉部白色，脸颊和胸部金绿至亮绿色，腹部中央白色，两侧金色至青铜色。雌鸟相似但光泽较弱，幼鸟下体偏灰褐色。","call":"鸣唱为一系列4至10个高音、嗡嗡的音符，重音在第一个音符，'bzeeeee-bzee-bzee-bzee-bzee'。还有更复杂的组合声，包括干涩的吱吱声和高音下降的金属颤音。","habits":"栖息于森林边缘、沼泽环境、开阔地带的灌木丛、公园和花园，海拔从近海平面至1000米，偶尔高达2100米。以各种本土和引进植物的花蜜为食，常访花的植物包括豆科、茜草科、苦苣苔科等。也会捕捉昆虫。偏好纯花蜜或含维生素和矿物质的花蜜。","breeding":"繁殖期为10月至3月。巢呈杯状，由植物绒毛和苔藓构成，外饰地衣，位于小树或灌木的水平枝上。巢高50毫米，外径40毫米，内径32毫米。每窝产两枚白色卵，卵长16毫米×宽9毫米，重0.65克。孵化期14天，由雌鸟承担。雏鸟离巢期20至25天。","identification":"白喉蜂鸟的白色喉部和绿色体羽是识别的关键特征。与同属物种相比，白喉蜂鸟具有独特的双色喙和明显的白色喉斑。","protection":"IUCN：LC（无危）","distribution":"分布于巴西东南部（从米纳斯吉拉斯州和圣埃斯皮里图州向南）、巴拉圭东部、乌拉圭和阿根廷东北部。在接近海平面至1000米的海拔范围内广泛分布，偶见于更高海拔。","other":"白喉蜂鸟适应人类环境的能力强，常见于城市周边地区。"},{"name":"白尾金喉蜂鸟","english_name":"White-tailed Goldenthroat","scientific_name":"Polytmus guainumbi","overview":"白尾金喉蜂鸟（英文名：White-tailed Goldenthroat，学名：Polytmus guainumbi），是雨燕目蜂鸟科金喉蜂鸟属的鸟类。是南美洲特有的一种小型蜂鸟，主要特征为绿色光泽的体羽，雄鸟具白色下腹部和尾下覆羽，以及对比鲜明的黑色面罩，周围环绕着白色线条。雌鸟较雄鸟色泽淡，胸部带绿斑点。常见于南美北部、东北部及东南部的草甸和沼泽地带。","appearance":"白尾金喉蜂鸟体长介于9.7至11.8厘米，体重4.4至5克。雄鸟拥有弯曲的长喙，上嘴暗红至黑色，下嘴红色，尖端黑色。背部闪耀金色至青铜绿色，尾羽呈圆形，绿色为主，尾端及外侧三对尾羽边缘为白色。眼周暗灰色，上下皆有白色条纹。雌鸟面部带有淡色条纹，颏部白色，其余下体淡色，喉部及胸部有绿色斑点。幼鸟头部羽毛边缘呈淡色。亚种andinus和thaumantias与指名亚种相似，但前者内侧尾羽有更多白色，后者上体呈红金色，外侧尾羽上的白色较少。","call":"白尾金喉蜂鸟在觅食时会发出快速连串的响亮、激动的‘spit’音节，或在栖息时发出一连串三个尖锐的音符，飞行中还会发出干燥的‘tsip-tsip’声。","habits":"白尾金喉蜂鸟栖息于水草丛生的草地、灌木草原、cerrado及淡水沼泽，海拔高度从海平面到600米。它们倾向于贴近地面单独觅食，偏好花园花卉、低矮灌木及树木的花蜜，如Lagerstroemia、Russelia equisetiformis、Calliandra surinamensis等。同时，它们也会在空中捕捉昆虫，或从植被表面获取蜘蛛。","breeding":"繁殖季节因地区而异，从2月至8月（特立尼达岛、苏里南）、2月至4月及7月至9月（法属圭亚那）、10月至11月（委内瑞拉）、10月至3月（巴西）以及10月（阿根廷东北部）。雌鸟独自筑巢，通常在小灌木的叉枝上，离地面0.5至1米，巢由植物绒毛制成，外饰苔藓或种子，形状类似白腹紫耳蜂鸟的巢。每窝产卵两枚，孵化期约14至15天，由雌鸟独自孵化。雏鸟黑色，背部长有稀疏的淡色绒毛，离巢期为20至22天。","identification":"白尾金喉蜂鸟与同属其他物种的区别在于其独特的白色尾羽和面部特征，以及栖息地的选择。亚种间主要通过尾羽颜色差异和体型大小进行区分。","protection":"IUCN：LC（无危）","distribution":"白尾金喉蜂鸟广泛分布于南美洲，包括阿根廷、玻利维亚、巴西、哥伦比亚、法属圭亚那、圭亚那、巴拉圭、秘鲁、苏里南、特立尼达和多巴哥以及委内瑞拉。在巴西，从马拉尼昂州向南延伸至帕拉纳州北部。在阿根廷，主要见于恩特雷里奥斯省、科连特斯省、米西奥内斯省、福尔摩萨省、查科省、圣菲省，并有一次记录于圣地亚哥德尔埃斯特罗省。"},{"name":"黑嘴金喉蜂鸟","english_name":"Tepui Goldenthroat","scientific_name":"Polytmus milleri","overview":"黑嘴金喉蜂鸟（英文名：Tepui Goldenthroat，学名：Polytmus milleri），是雨燕目蜂鸟科金喉蜂鸟属的鸟类。仅见于委内瑞拉和圭亚那的特普伊山脉，以独特的黑色弯喙和白尖尾羽著称。常见于干燥至湿润的草地、小树丛、森林边缘等生境。","appearance":"雄鸟长约11-12厘米，重4.5-6.1克，上体呈青铜绿色，下体闪烁着绿光，尾羽中央对带有青铜绿色光泽，其余尾羽基部宽幅白色，尖端略窄。雌鸟较雄鸟小，体重约4.1-5克，下体主要为暗淡白色，密集点缀金色绿点，尤其在胸部。幼鸟与成鸟相似，头部羽毛边缘呈淡黄色。","call":"发出一系列响亮高音的‘tsit’或‘tizzie’声，通常在觅食时发出。","habits":"栖息于特普伊山脉的云雾林边缘和灌木地带，海拔介于1300至2200米之间。以花蜜为食，同时捕捉飞行中的昆虫，也会从植被和岩石缝隙中觅得蜘蛛。","breeding":"繁殖期在5月至6月，筑杯状巢，内部铺垫细纤维，外表装饰苔藓，通常位于灌木枝叉处，离地面0.5至1米。每窝产两枚卵，孵化期15至16天。","identification":"与Polytmus属其他种类相比，雄鸟无眼周白色，喙长而稍弯，雌鸟下体密集金色绿点，易于区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲特普伊山脉，包括委内瑞拉南部和东南部、圭亚那西部及巴西极北部。"},{"name":"绿尾金喉蜂鸟","english_name":"Green-tailed Goldenthroat","scientific_name":"Polytmus theresiae","overview":"绿尾金喉蜂鸟（英文名：Green-tailed Goldenthroat，学名：Polytmus theresiae），是雨燕目蜂鸟科金喉蜂鸟属的鸟类。主要分布在南美洲亚马逊雨林东北部和西部地区。这种蜂鸟具有独特的绿色羽毛，尾羽尤为突出，其脸部图案包括眼睛后方的小白点。绿尾金喉蜂鸟栖息于森林边缘、沙质草原，常在低矮灌木丛中活动。","appearance":"绿尾金喉蜂鸟体型中等，长度约为8.9至9.9厘米，体重介于3.0至3.9克。雄鸟拥有较长的微弯喙，上颚黑色，下颚粉红色，末端黑色；全身羽毛闪耀着绿色光泽，眼周灰暗，带有白色斑点；尾羽圆形，中央羽毛绿色，其余绿色，基部白色。雌鸟与雄鸟相似，但体型较小，喉咙和胸部为灰白色，密集点缀以绿色斑点，最外侧尾羽尖端有白色。幼鸟类似成年雌鸟，但头部羽毛边缘呈淡黄色。亚种leucorrhous与指名亚种基本相同，但腹下部和尾下覆羽广泛白色，绿色仅限于羽毛盘状部分。","call":"绿尾金喉蜂鸟的歌曲是一系列连续的20至25个音符，起初上升随后轻微下降，最后逐渐减弱，通常以单个起始音符开始，持续时间约2至3秒。孤立的秘鲁种群的歌声类似，但速度更快，几乎带有颤音，音符更多。此外，还会发出单个‘tsit’声。","habits":"绿尾金喉蜂鸟偏好森林边缘和沙质草原，高度在100至300米之间，以梅洛斯托马科植物花蜜为主食，同时捕食叶子上的节肢动物或空中猎获。雄鸟偶尔会占据喂食领地，而两性通常通过陷阱线路觅食。","breeding":"繁殖季节在圭亚那地区为3月至4月和8月至10月，在委内瑞拉为10月至11月，在巴西为11月至3月。巢由细小、淡色的植物纤维和蜘蛛网构成，建于低矮灌木的分叉处，高度42毫米，外部直径37毫米，内部直径33毫米。每窝产卵2枚，尺寸为15毫米×9.1毫米，重量0.54至0.58克。孵化期为14天，由雌鸟单独完成；雏鸟黑色，背部有两行淡黄色绒毛；离巢期为20天，有时长达28天。","identification":"绿尾金喉蜂鸟与辉喉蜂鸟相似，但缺乏下腹部的白色，面部和喉咙的对比度较低。","protection":"IUCN：LC（无危）","distribution":"绿尾金喉蜂鸟的分布范围包括玻利维亚、巴西、哥伦比亚、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉，可能还存在于厄瓜多尔。在南美洲东北部亚马逊雨林和西部地区有记录，包括低地沙土森林边缘和沙质草原。"},{"name":"淡黄蜂鸟","english_name":"Buffy Hummingbird","scientific_name":"Leucippus fallax","overview":"淡黄蜂鸟（英文名：Buffy Hummingbird，学名：Leucippus fallax），是雨燕目蜂鸟科留基伯蜂鸟属的鸟类。留基伯蜂鸟属下的唯一物种。分布于南美洲北部，主要栖息于干燥森林和灌木丛地带。","appearance":"淡黄蜂鸟的雄鸟和雌鸟外观相似，但雌鸟色彩较为暗淡。背部和上半身呈淡绿色，下半身则为温暖的肉桂色，腹部和下尾羽为白色。尾部呈圆钝状，带有灰色横纹。眼睛后方有一小白斑，喙细长且直，上喙黑色，下喙浅色带黑尖。体型介于8.5至9厘米之间。","call":"鸣叫声为重复的短语，通常由2至4个音符组成，最简单的形式是两个鼻音似的吱吱声，'tsik-tslee...tsi..tslee..'，但通常包含3至4个不同的音符，大多带有鼻音，例如'tsik-tsuk-chlee-tsee...'，雄鸟会在单独或松散的求偶场中唱歌。","habits":"栖息于沙漠灌木丛、干燥森林边缘和红树林中，高度可达500米。它以昆虫和仙人掌果实的肉和汁液为食，同时在花朵间采蜜，扮演着重要的授粉角色。它会保护自己喂食的花区，且能进行空中捕虫。","breeding":"淡黄蜂鸟在5月至11月期间筑巢，巢杯状，位于低枝或灌木分叉处，由树棉的柔软纤维构成，外饰以树皮碎片、苔藓和叶子。每窝产两枚卵。雄鸟通过弧线俯冲展示求偶。","identification":"与红顶绿蜂鸟的雌鸟相比，淡黄蜂鸟具有锈红色尾巴和较短的喙。","protection":"IUCN：LC（无危）","distribution":"分布于南美东北部的哥伦比亚和委内瑞拉西北部及北部，包括近岸岛屿。","other":"淡黄蜂鸟在12月至4月干旱季节倾向于出现在密集的荆棘树群中。"},{"name":"秘鲁蜂鸟","english_name":"Tumbes Hummingbird","scientific_name":"Thaumasius baeri","overview":"秘鲁蜂鸟（英文名：Tumbes Hummingbird，学名：Thaumasius baeri），是雨燕目蜂鸟科 Thaumasius 属的鸟类。体型较小的蜂鸟，主要分布在南美洲的厄瓜多尔西南部及秘鲁西北部，栖息于干旱灌丛、干燥森林边缘以及偶尔出现在落叶林。其颜色较为暗淡，上体呈淡金色绿色，下体灰白色，羽毛无光泽。","appearance":"秘鲁蜂鸟的外观特征为：体长8至11厘米，体重约4.5克。两性相似，具有几乎笔直的黑色喙。上体为淡金色绿色，下体为灰白色，腹部逐渐变为白色。尾羽为淡绿色，内侧尾羽带有青铜色尖端，而外侧尾羽近末端有一条灰褐色带，雄鸟的尾羽尖端为白色，雌鸟为灰色。","call":"其鸣唱复杂，由一系列的啾声和嘶哑的电子颤音组成。叫声被描述为粗犷的‘dzi’声和啾啾声。","habits":"秘鲁蜂鸟主要在旱生灌木丛和落叶林边缘活动，栖息于Tumbes生态区。它通常为留鸟，但在季节性迁徙中可能有所移动。觅食时，它会从下层植被到中层寻找花蜜，具体偏好哪些开花植物尚不清楚。除花蜜外，它还以小型节肢动物为食。","identification":"与斑喉蜂鸟相似，但斑喉蜂鸟的喉部密集地覆盖着小绿点，且体型较大。二者在地理分布上有区别，秘鲁蜂鸟仅限于安第斯山脉西侧，不进入Marañon流域。","protection":"IUCN：LC（无危）。尽管其分布范围有限，且确切的种群数量和趋势未知，但目前没有识别到紧迫威胁。然而，由于其分布范围狭窄，任何增加的栖息地丧失、退化或碎片化都可能使其处于潜在的脆弱状态。","distribution":"秘鲁蜂鸟的分布范围涵盖了厄瓜多尔西南部的El Oro和Loja省，向南延伸至秘鲁西北部，最南可达Lambayeque省。在海拔高度上，它在厄瓜多尔的分布范围从海平面至1,000米，在秘鲁则可达1,275米。","other":"秘鲁蜂鸟曾被归类于Leucippus属，但基于2014年发表的一项分子系统发育研究，该属被发现为多系群，因此将其和点斑蜂鸟一同移至复生的Thaumasius属。"},{"name":"斑喉蜂鸟","english_name":"Spot-throated Hummingbird","scientific_name":"Thaumasius taczanowskii","overview":"斑喉蜂鸟（英文名：Spot-throated Hummingbird，学名：Thaumasius taczanowskii），是雨燕目蜂鸟科 Thaumasius 属的鸟类。主要分布于秘鲁北部至中部，接近厄瓜多尔边境，几乎特有于秘鲁。斑喉蜂鸟栖息于干燥灌木丛或干燥森林边缘，以龙舌兰或香蕉等植物的花蜜为食。","appearance":"斑喉蜂鸟外观暗淡，上体呈暗绿色，下体为污白色，喉部有小而闪亮的绿色斑点。头部冠羽青铜色，背部和翼覆羽灰金绿至青铜绿，尾巴内部羽毛灰绿至青铜绿，外侧逐渐变为灰色，尾端有青铜色带。下体呈苍白的灰褐色，下巴、喉咙和两胁点缀着金色绿斑点。下尾覆羽羽毛中心淡棕色，边缘白色。喙黑色，有时上颚呈灰棕色或深黄色带黑尖。","call":"发出一系列复杂的啾啾声和嘶哑的电颤音，以及干涩的喋喋声和尖锐的音符。","habits":"斑喉蜂鸟在灌木层到中层林间觅食花蜜，已知在印加树、龙舌兰和香蕉中采食。它还捕食空中飞行的小型节肢动物。","breeding":"繁殖生态学尚未被描述。","identification":"与秘鲁蜂鸟相似，但秘鲁蜂鸟体型较小，喉咙无斑点，局限于较低海拔。也可与白腹蜂鸟混淆，后者在更湿润的灌木丛和森林边缘取代斑喉蜂鸟，下体更白，喉咙无斑点，下颚基部红色，尾羽基部白色。","protection":"IUCN：LC（无危）","distribution":"分布于秘鲁北部至中部，包括安卡什省，可能出现在厄瓜多尔极南部，但未得到证实。","other":"虽然斑喉蜂鸟广泛分布且常见，但其自然历史的细节仍知之甚少。"},{"name":"绿斑蜂鸟","english_name":"Olive-spotted Hummingbird","scientific_name":"Talaphorus chlorocercus","overview":"绿斑蜂鸟（英文名：Olive-spotted Hummingbird，学名：Talaphorus chlorocercus），是雨燕目蜂鸟科 Talaphorus 属的鸟类。珍贵的蜂鸟科鸟类，分布于南美洲的亚马逊雨林西部。体长约12厘米，体重约6克，拥有灰绿色至青铜绿色的上体，喉部橄榄绿色，有时带有金色斑点，下体呈白色。性别相似，但雌鸟下体更偏灰褐色。","appearance":"绿斑蜂鸟体长约12厘米，重约6克。全身被覆灰绿色至青铜绿色羽毛，喉部橄榄绿色，有时在特定角度下呈现出金色光泽。尾羽淡灰绿至橄榄绿，有灰色尖端和暗色次末端条纹。雌雄相似，但雌鸟下体更偏灰褐色，且喙稍长。","call":"其鸣唱为单调的一系列多音节音符，如'cliCHEW cliCHEW cliCHEW...'，叫声包括尖锐的'seek'声、金属般的'seeuee'声、丰富的啾啾声和硬朗的'tcht'声。","habits":"绿斑蜂鸟主要栖息于亚马逊盆地的年轻河岛，偏好开放的灌木林和早期演替植被，偶尔出现在相邻的陆地牧场。分布于海拔400米以下。以多种植物家族的花蜜为食，同时从叶面捕获昆虫。","breeding":"繁殖季节未知。巢为杯状，由柔软的植物材料、纤维和蛛网构成，外饰苔藓，通常位于2至10米高的水平枝条上。一窝产两枚卵，孵化期14至15天，仅由雌鸟承担，雏鸟约20天离巢。","identification":"绿斑蜂鸟与同区域内的其他相似体型的蜂鸟相比，下体斑点较为模糊，尾巴颜色较蓝的物种较少见。通过其独特的栖息地选择，可帮助辨识。","protection":"IUCN：LC（无危）","distribution":"分布于巴西西北部、厄瓜多尔东部、秘鲁东北部和哥伦比亚东南部沿亚马逊河及其支流的区域。","other":"绿斑蜂鸟的分布范围限制尚不清楚，特别是在厄瓜多尔东北部和巴西西部需要进一步的研究。"},{"name":"点斑蜂鸟","english_name":"Many-spotted Hummingbird","scientific_name":"Taphrospilus hypostictus","overview":"点斑蜂鸟（英文名：Many-spotted Hummingbird，学名：Taphrospilus hypostictus），是雨燕目蜂鸟科点斑蜂鸟属的鸟类。是蜂鸟科点斑蜂鸟属的唯一物种，分布于南美的安第斯山脉东坡，从厄瓜多尔南部至哥伦比亚、秘鲁东部至玻利维亚中部，体型较大，羽毛独特，具有白色腹部和绿色斑点，常见于云雾森林。","appearance":"点斑蜂鸟体长10.5至11.4厘米，体重6.7至9克，拥有中等大小、略微弯曲的黑色喙。雄鸟和雌鸟的上体呈草绿到铜褐色，眼后有白色斑点，下体白色，除中央腹部外被绿色厚密斑点覆盖，尾巴蓝绿色，末端灰暗。雌鸟的斑点较轻。幼鸟类似成鸟，但头部羽毛边缘呈淡黄色。","call":"其鸣唱为一系列微弱的哨音和沙哑的叽叽喳喳声，叫声包括细薄的“chit”声和沙哑的“dew dew dew”声。","habits":"栖息于海拔400至1500米的湿润山脚和低地亚热带森林，偏好小溪谷地带，以花蜜为食，包括开花灌木、陆生凤梨科植物、藤本植物和树木的花蜜，也会捕食空中昆虫。通常单独活动，但在人工喂食器附近会聚集。","breeding":"繁殖期可能为1月至5月，筑杯状巢于树干低处，约0.5米高，由细根和苔藓构成，每窝产两枚蛋，由雌鸟孵卵14至15天，小鸟约在20至22天后离巢。","identification":"与Heliodoxa属雌鸟相似，但后者有短白颊纹和通常有淡黄色腹部，在北部范围内，Heliodoxa属有蓝色冠顶。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的安第斯山脉东坡，从厄瓜多尔的纳波省向南延伸至秘鲁东部和玻利维亚中部；记录于哥伦比亚的卡奎塔省；曾有报告称出现在巴西西南部，但存疑；阿根廷西北部也有报道，但未得到证实。","other":"最近在哥伦比亚有记录，仅基于单个标本。该物种在厄瓜多尔的特纳和科卡之间，以及秘鲁的库斯科和马努之间出现。"},{"name":"白腹蜂鸟","english_name":"White-bellied Hummingbird","scientific_name":"Elliotomyia chionogaster","overview":"白腹蜂鸟（英文名：White-bellied Hummingbird，学名：Elliotomyia chionogaster），是雨燕目蜂鸟科 Elliotomyia 属的小型鸟类。分布于南美洲，从秘鲁北部至阿根廷西北部，其特征为绿色背部，白色腹部，下颚带粉色。该物种在中间和高海拔地带常见。","appearance":"白腹蜂鸟体型中等，体长9-12厘米，雄鸟体重4.9-6.7克，雌鸟体重4.5-6克。雄鸟具有中等长度的直喙，上颌黑色，下颌红褐色带暗色尖端；上体、胸部两侧及两翼边缘呈金绿至亮绿色；下体中央白色，下喉及两侧有金色绿斑点；尾羽底面白色，有时基部金绿；尾羽内侧有白色。雌鸟下喉及喉部轻奶油色，斑点更重。幼鸟喉咙的奶油色延伸到腹部，全身颜色更偏绿色。亚种hypoleuca下体奶油色更深，外侧尾羽白色部分仅覆盖内网的基部一半。","call":"白腹蜂鸟的歌声通常由一系列三声吱吱声组成，如'tseet-chew-chip ... tseet-chew-chip ...'，而亚种hypoleuca的歌声则是一系列单个高音的'pseek'音符，偶尔跟着低音更快的'tsi-tsi-tsi-tsi'。叫声包括高音的'seeek'和下降的颤音系列。","habits":"白腹蜂鸟栖息于森林边缘和灌木丛生的开阔地带，偏好相对干燥的环境，如仙人掌、龙舌兰或桤木和桉树林。它主要以各种植物家族的花蜜为食，包括豆科、吴茱萸科、锦葵科、桑寄生科、紫葳科、木棉科、西番莲科和芭蕉科，饮食中还包括小昆虫。","breeding":"繁殖季节从1月持续到3月。白腹蜂鸟筑杯状巢，由植物绒毛和苔藓制成，外表覆盖着地衣，位于灌木或小树的较低枝条上，距离地面2-5米。巢的外部直径为48-50毫米，内部直径30-32毫米，高度40-50毫米，深度25-28毫米。每窝产2枚白色蛋，尺寸为13毫米×8.5毫米。孵化期为14-15天，由雌鸟承担，幼鸟离巢时间为19-22天。","identification":"白腹蜂鸟与绿尾蜂鸟相似，但可通过白色向下延伸至尾部下方更多，以及有时较淡的粉红色下颌来区分。白腹蜂鸟通常在更开阔的生境中发现。","protection":"IUCN：LC（无危）；CITES II；在当地常见。可能因生境破坏如燃烧或放牧而受到威胁，尤其是在玻利维亚东南部和阿根廷北部的相对干旱的开放至半开放植被区域。在阿根廷胡胡伊省的Calilegua国家公园中常见。","distribution":"白腹蜂鸟的分布范围从秘鲁北部至阿根廷西北部，包括玻利维亚和巴西马托格罗索州的部分地区。在秘鲁，主要分布在安第斯山脉东坡的亚马逊和库斯科部门之间；在玻利维亚南部至阿根廷拉里奥哈省，向东进入巴西马托格罗索州。在海拔450至2000米间常见，偶尔可达2800米。","other":"白腹蜂鸟曾被归类在Leucippus、Elliotia和Amazilia等属，但在2014年基于分子系统发育研究，为了创建单系群分类，被置于新属Elliotomyia。"},{"name":"绿尾蜂鸟","english_name":"Green-and-white Hummingbird","scientific_name":"Elliotomyia viridicauda","overview":"绿尾蜂鸟（英文名：Green-and-white Hummingbird，学名：Elliotomyia viridicauda），是雨燕目蜂鸟科 Elliotomyia 属的鸟类。中等体型的蜂鸟。其特征为绿色背部和白色腹部，有时下喙呈淡红色。主要分布在秘鲁中部的安第斯山脉东坡，从Huánuco南部至Cuzco地区。","appearance":"绿尾蜂鸟体长约10至11厘米，雄鸟体重约6克，雌鸟约5.5克。它们拥有中等长度的直喙，上喙黑色，下喙红褐色带暗色尖端。成年雄鸟背部和侧翼为鲜艳的绿至青铜绿色，腹部从下巴到尾下覆羽为白色，带有绿色斑点。雌鸟相似，但下巴和喉咙为淡奶油色，斑点更多。幼鸟类似于雌鸟，喉部的奶油色延伸至腹部。","call":"绿尾蜂鸟的歌声为重复的三个尖锐音符组成的短语，类似“tseet-chew-chip … tseet-chew-chip ...”。叫声为两个上升的高音随后下降的颤音系列，‘tsee-tseeet-tsi-tsi-tsi-tsi’。","habits":"绿尾蜂鸟主要栖息在成熟的亚热带森林边缘和空地，以及次生林区，海拔高度在1000至2500米之间。它们通常定居，但可能存在局部迁移。它们以多种开花植物、灌木和树木的花蜜为食，同时也会捕食小型节肢动物。","breeding":"繁殖季节具体时间未知，但已知包含一月。绿尾蜂鸟会用植物绒毛和蜘蛛网构建杯状巢，外部覆盖苔藓，通常位于小树的水平枝条上。孵化期和雏鸟离巢时间尚未确定。","identification":"与白腹蜂鸟区分，绿尾蜂鸟尾部下方完全为深色，而白腹蜂鸟尾部下方有白色。此外，绿尾蜂鸟更倾向于森林环境。","protection":"IUCN：LC（无危）","distribution":"绿尾蜂鸟的分布限于秘鲁中部的安第斯山脉东坡，从Huánuco南部至Cuzco地区，包括Machu Picchu一带。"},{"name":"桂红蜂鸟","english_name":"Cinnamon Hummingbird","scientific_name":"Amazilia rutila","overview":"桂红蜂鸟（英文名：Cinnamon Hummingbird，学名：Amazilia rutila），是雨燕目蜂鸟科艳蜂鸟属的鸟类。中等体型的蜂鸟，常见于中美洲干燥森林地带，从墨西哥西北部至哥斯达黎加均有分布。其下体呈均匀的肉桂色，上体金属青铜绿色，独特的外观使其在干燥热带低地生态系统中独树一帜。","appearance":"成年桂红蜂鸟，雄雌相似，拥有金属青铜绿色的背部和肉桂色至肉桂赤褐色的腹部，腹部颜色较淡，尤其是下巴和喉咙上方。尾巴主要为深肉桂赤褐色，尾羽尖端有暗金属青铜色，外侧边缘同样带有暗金属青铜色。翅膀呈深棕色石板色或暗灰色。幼鸟类似成鸟，但面部、头顶和臀部羽毛边缘呈赤褐色，下体颜色通常更淡，喙全黑。","call":"其叫声多样，高音、尖细且略带吱吱声，如“si ch chi-chit”或“tsi si si-si-sit”，以及“chi chi-chi chi chi”等。叫声被描述为‘嗡嗡的、刺耳的tzip’和‘坚硬到尖锐的chik’。","habits":"桂红蜂鸟常在灌木林地、林缘、花园和开花树木的半开放区域活动，偏好干燥的热带低地。它们的活动范围从森林下层至中层，也会造访较高的开花树木。以多种花卉的花蜜为食，同时捕食昆虫。具有领地意识，会保卫食物来源不受其他蜂鸟、蜜蜂和蝴蝶的侵扰。","breeding":"繁殖季节随分布区域而异，全年都有繁殖记录。筑巢于水平树枝上，巢由植物材料和蜘蛛网构成，有时底部会有小平台由木片搭建。巢外覆盖着草、木屑和苔藓。每窝产卵两枚，但关于繁殖生态学的细节尚不多。","identification":"桂红蜂鸟下体的均匀肉桂色是其显著特征，与区域内其他蜂鸟种类明显不同。在仅从背面观察时，可能与Buff-bellied和Rufous-tailed Hummingbirds混淆，但后两者侧面或正面可见绿色喉咙和胸部。","protection":"IUCN：LC（无危）","distribution":"桂红蜂鸟分布于中美洲，从墨西哥西北部至哥斯达黎加，包括尤卡坦半岛东南部的墨西哥和伯利兹。"},{"name":"棕腹蜂鸟","english_name":"Buff-bellied Hummingbird","scientific_name":"Amazilia yucatanensis","overview":"棕腹蜂鸟（英文名：Buff-bellied Hummingbird，学名：Amazilia yucatanensis），是雨燕目蜂鸟科艳蜂鸟属的鸟类。以其红嘴、橙色尾巴和腹部淡黄色斑块而著称，性别相似，常见于墨西哥，其在美国的分布有限，仅限于南部沿海德克萨斯州。该鸟种在各种林地和灌木环境中都能生存，春季到夏季间在南德克萨斯州繁殖。","appearance":"成年棕腹蜂鸟体型中等，长度约10-11厘米，重量在2.9-4.7克之间。上半身呈金属青铜绿色，冠部较暗，尾羽橙红色，腹部有明显的淡黄色或肉桂色斑块。雌雄相似，但雌鸟背部和喉咙光泽较弱，尾羽中央为绿铜色，外侧为胸棕色，边缘和尖端带有绿铜色。亚成鸟色彩较为暗淡，喉部和胸部为灰色或淡肉桂色，两性相似。","call":"已知在德克萨斯州的棕腹蜂鸟会发出双音节的'tsi-we'叫声用于展示，进食时发出'tik'或'tik-k'声，追逐其他蜂鸟时则发出一系列快速重复的低沉叫声。","habits":"生活在从干旱灌木地带到墨西哥湾沿岸的半湿润林地等各种生境。春季至夏季在南德克萨斯州繁殖，冬季分散到墨西哥和美国东南部。以各种开花植物的花蜜为食，通过悬停采食。具有强烈的领地意识，保卫着喂食地点，包括糖水喂食器，免受其他蜂鸟和昆虫的侵扰。还捕食空中和植被上的小型节肢动物。","breeding":"繁殖季节主要在3月至8月间，筑巢期可能早于1月或晚于8月。巢由植物纤维、蜘蛛网、苔藓和其他材料制成，位于小树或灌木的分叉处，离地面1-3米高。孵化期和雏鸟成长时间未知。","identification":"与其他Amazilia属蜂鸟如绿玉蜂鸟(A. beryllina)、棕尾蜂鸟和桂红蜂鸟的区别在于腹部的淡黄色或肉桂色斑块，以及红色基部的喙。与这些种类相比，棕腹蜂鸟的尾羽更具有绿铜色的尖端。","protection":"IUCN：LC（无危）","distribution":"在中美洲，分布于墨西哥东部至尤卡坦半岛，以及美国南部。在墨西哥，它全年可见于从北伯利兹和西北危地马拉至塔巴斯科、金佩切和尤卡坦半岛的东南墨西哥。在美国，它主要分布在南德克萨斯州南部，冬季可分散至佛罗里达州和北卡罗来纳州。","other":"自1980年代以来，其种群数量似乎在增加，尽管确切的种群规模未知。"},{"name":"棕尾蜂鸟","english_name":"Rufous-tailed Hummingbird","scientific_name":"Amazilia tzacatl","overview":"棕尾蜂鸟（英文名：Rufous-tailed Hummingbird，学名：Amazilia tzacatl），是雨燕目蜂鸟科艳蜂鸟属的鸟类。中等体型的蜂鸟。其最显著的特征是拥有一条鲜明的棕红色尾巴，因而得名。分布于中美洲至南美洲西部，从墨西哥中部到委内瑞拉和厄瓜多尔西部。常见于森林边缘和花园等地。","appearance":"成年雄鸟的头部和上体主要呈绿色，胸腹部有灰褐色，尾部大部分为棕红色，边缘和尖端呈青铜绿色。喉咙、上胸部和两侧绿色，有时带有白色边缘，形成鳞片状效果。雌鸟的下胸部颜色较浅。幼鸟的下胸部和侧面略带肉桂色，背部和臀部的羽毛尖端狭窄。喙外半部黑色，内半部红色，下喙红色，尖端黑色。","call":"其鸣叫声多样，高音、尖锐、叽叽喳喳，如'tsi, tsi-tsi-tsit tsi-tsitsi tsi-si-si'。叫声为'较为响亮、清脆的tchik-tchik...或...tchi tchi...'，有时会重复不断地发出。","habits":"偏好栖息于热带低地的森林边缘、次生林、花园等开阔地带。以花蜜和小型昆虫为食，常在低至高的位置觅食，会频繁造访喂食器。在觅食地极度领地性，会驱赶其他蜂鸟和大型昆虫。","breeding":"繁殖季节因地区而异，大致在2月到11月之间。实行一雄多雌制。筑巢、孵化和抚育雏鸟全由雌鸟承担。巢由植物纤维、叶子和蜘蛛网构成，外部覆盖苔藓和地衣，通常位于离地面约6米高的细水平枝上。孵化期15至19天，雏鸟离巢需18至22天。","identification":"与棕腹蜂鸟相似，但棕腹蜂鸟的尾部稍呈叉形，中央尾羽背面主要为绿色，下体覆羽颜色与腹部一致。与绿蜂鸟和栗腹蜂鸟也有相似之处，但可通过腹部颜色和尾部特征加以区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区域涵盖墨西哥中部至南美的委内瑞拉和厄瓜多尔西部。非繁殖区域可能涉及更广泛的中美洲和南美洲地区。","other":"已知至少有五个亚种，其中A. t. handleyi曾被视为独立物种Escudo蜂鸟。"},{"name":"红树林蜂鸟","english_name":"Mangrove Hummingbird","scientific_name":"Amazilia boucardi","overview":"红树林蜂鸟（英文名：Mangrove Hummingbird，学名：Amazilia boucardi），是雨燕目蜂鸟科艳蜂鸟属的鸟类。中等体型的蜂鸟，此鸟种仅见于哥斯达黎加太平洋沿岸的红树林及其周边环境，具有蓝绿色的头部与喉咙，腹部白色，尾部叉状。雄鸟喉部与胸部闪耀着蓝绿色光泽，雌鸟上体绿色，下体主要白色，喉部及两侧有小绿斑。该物种为哥斯达黎加特有种，受到威胁。","appearance":"红树林蜂鸟是一种中等体型的青铜绿色蜂鸟。雄鸟具有蓝绿色的喉部与胸部，腹部白色，尾部叉状。头部与上体绿色，臀部与尾部带有青铜色调。喙部暗色，下颌红色。雌鸟相似，但下体主要白色，喉部与两侧有小绿斑。幼鸟外观类似雌鸟，但下体更灰。","call":"红树林蜂鸟发出一种柔和而急促的\"djt\"声，下降式的颤音。","habits":"红树林蜂鸟定居于哥斯达黎加太平洋海岸，栖息于大面积的茶红树林中，偶尔出现在邻近的次生林地。以红树林花蜜为主食，也会在近红树林的陆地森林空地进食Inga、Heliconia和Maripa的花蜜。此外，它们也捕食昆虫。","breeding":"繁殖期从十月持续至二月。巢由巴尔萨木棉和其他柔软植物纤维构成，用蜘蛛网固定，外部装饰苔藓。巢通常位于红树林枝条上，距离水面1至4米。雌鸟孵化两枚卵，但孵化期和离巢时间未知。","identification":"与迷人的蜂鸟（Amazilia decora）最为相似，但喙部较直，喉部与胸部图案不同。与白腹绿蜂鸟雌鸟相似，但红树林蜂鸟尾部深色，胸带铜绿色。与雪胸蜂鸟也有相似之处，但后者下体对比更明显，尾部黑色，臀部颜色与上体一致。","protection":"IUCN：EN（濒危）","distribution":"红树林蜂鸟仅分布于中美洲的哥斯达黎加太平洋沿岸，具体而言是在红树林及邻近的次生林地。"},{"name":"洪都拉斯蜂鸟","english_name":"Honduran Emerald","scientific_name":"Amazilia luciae","overview":"洪都拉斯蜂鸟（英文名：Honduran Emerald，学名：Amazilia luciae），是雨燕目蜂鸟科艳蜂鸟属的鸟类。仅分布于洪都拉斯干旱山谷地带。以亮蓝色的喉部和白色腹部为显著特征，全身覆以绿色羽毛，雄鸟的蓝绿色喉部和上胸闪耀着光芒，腹部呈淡灰色，两侧带有绿色斑纹。雌鸟外观相似，但色彩略显暗淡，尤其是喉部。目前，该物种在洪都拉斯东北部三个地点被发现，近期在西部也再次被记录到，然而，自1950年至1988年期间未曾有记录。最近由极度濒危降级至濒危状态。","appearance":"洪都拉斯蜂鸟体长约9至10厘米，雄鸟具有蓝色的喉部和上胸部，其颜色介于蓝绿之间，视光线角度而变。头部、颈背和上背部为深绿色，下背部和尾羽盖逐渐变为青铜色。翅膀覆羽呈黄绿色至青铜色，耳羽主要为蓝绿色。胸部中央为灰白色，两侧为绿色，向侧面渐变为青铜绿色。尾羽稍呈叉状，中央尾羽为深绿色，其余尾羽近端为青铜色，尾羽末端有紫色带。雌鸟相似，但整体色彩较淡，喉部较小，更偏绿色。幼鸟与雌鸟相似。","call":"发出坚硬、略带金属质感的连续'chik, chik-chik, chik chik...'声，以及飞行中的'zzchi ---'和'chik chi zzhi ---'的硬质嗡嗡声。","habits":"栖息于热带干燥森林，常出现在低至中等高度的林冠层，森林覆盖开敞至半封闭。在西部，栖息于半落叶林、荆棘林、松栎林以及牧场边缘；东部则在干燥的热带森林、荆棘林或半落叶木本地带活动。海拔分布范围在200至500米之间。以花蜜为食，采食多种植物，包括仙人掌、灌木、藤蔓、草本植物、寄生植物等。也会捕食小型节肢动物。","breeding":"有关繁殖行为的信息极少，已知一巢由种子绒毛、干叶和蜘蛛网构成，外表覆盖苔藓，位于尤金尼亚树约2.3米高处。繁殖季节不明。","identification":"与其他同属物种相比，洪都拉斯蜂鸟的蓝色喉部、绿色上体和青铜色尾羽是其显著特征。雌鸟与雄鸟相似，但色彩较淡。","protection":"IUCN：VU（易危）","distribution":"洪都拉斯蜂鸟分布于洪都拉斯北部的三个分离地区，包括圣巴巴拉、科尔特斯、约罗和奥兰乔部门。在东部，栖息于山谷底部，而在西部则在山谷斜坡。","other":"由于栖息地持续转化为农业用地和人类居住区，洪都拉斯蜂鸟面临严重威胁，估计其原始栖息地已丧失90%。"},{"name":"栗腹蜂鸟","english_name":"Chestnut-bellied Hummingbird","scientific_name":"Saucerottia castaneiventris","overview":"栗腹蜂鸟（英文名：Chestnut-bellied Hummingbird，学名：Saucerottia castaneiventris），是雨燕目蜂鸟科 Saucerottia 属的鸟类。这分布于哥伦比亚中北部，特别是Magdalena河谷干燥地带的罕见物种，其核心分布区位于Chicamocha、Suárez和Chucurí河谷。","appearance":"这种蜂鸟长约9厘米，两性均有黑色喙，基部带红色。成年雄鸟上体呈青铜绿色，尾部为栗色，喉部与上胸闪耀着绿色光泽，腹部与下覆羽为栗色。雌鸟相似，但腹部略淡，喉部羽毛末端有白色条纹。幼鸟类似雌鸟，但颈和臀部羽毛边缘呈红褐色。","call":"栗腹蜂鸟的歌声为短促的节奏性三音节，听起来像生锈的门铰链声，\"krey-ki-cheep ... tsew ... krey-ki-cheep ...\"。叫声包括微带颤音的\"tzee\"，高音的\"see\"和断续的高音叽叽声。","habits":"主要栖息于干燥的灌木峡谷和低海拔湿润山林边缘，常见于海拔500至1500米之间，偶尔记录于340至2200米的范围内。这种蜂鸟可能在繁殖季后从高海拔迁移到低地。","breeding":"繁殖季节似乎在8月至12月间，但关于其繁殖生态学的细节和巢穴描述仍未知。","identification":"与棕尾蜂鸟的区别在于，雌鸟和年轻个体缺乏侧翼的绿色，这是识别的关键点。","protection":"IUCN：NT（近危）","distribution":"主要分布于哥伦比亚中北部，特别是在Magdalena河谷的干燥地带，已知至少14个分布点。","other":"由于栖息地丧失和未知的季节性迁移模式，保护措施尚未得到充分实施。"},{"name":"红嘴蜂鸟","english_name":"Azure-crowned Hummingbird","scientific_name":"Saucerottia cyanocephala","overview":"红嘴蜂鸟（英文名：Azure-crowned Hummingbird，学名：Saucerottia cyanocephala），是雨燕目蜂鸟科 Saucerottia 属的鸟类。广泛分布于墨西哥至尼加拉瓜的森林地带，包括松林和常绿森林。其特征为蓝冠，白喉部，红基喙，以及棕色背部和翅膀。尽管名称为红嘴蜂鸟，整体外观可能显得较为暗淡。","appearance":"红嘴蜂鸟体型中等，成年个体拥有亮金属蓝色的冠羽，雌鸟较雄鸟略显绿色。背部呈金属青铜绿色，尾部和臀部为棕绿色。腹部白色，两侧胸部有金属青铜绿色，两翼下方略带灰色。喙部上颌黑色，下颌粉红色带黑尖。幼鸟色泽较暗，冠羽呈淡绿蓝色，尾羽端部白色，下体带有淡黄色调。","call":"红嘴蜂鸟通过一系列尖锐的'chup'声宣告其存在。","habits":"栖息于海拔600至2400米的湿润常绿森林边缘、橡树林、松林和次生林。以花蜜为食，同时也会捕食小型昆虫。飞行灵活，既会巡逻领地也会守卫食物资源。","breeding":"繁殖季节从2月持续至7月，期间会在树枝叉或横跨枝条上筑杯状巢，材料随当地环境而异。城市环境中，巢穴甚至建在电线上。","identification":"与白腹绿蜂鸟和绿额蜂鸟相似，但体型更大，具蓝冠，喙部红基黑尖，下体白色，侧胸青铜绿色。亚种chlorostephana冠羽为闪亮的绿松石色。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥东部至尼加拉瓜，包括中美洲的多个国家。亚种S. c. chlorostephana特有于洪都拉斯东海岸和尼加拉瓜东北部的低地松树草原。","other":"红嘴蜂鸟虽广泛分布，但具体限制其分布的因素尚未明确。"},{"name":"灰腹蜂鸟","english_name":"Steely-vented Hummingbird","scientific_name":"Saucerottia saucerottei","overview":"灰腹蜂鸟（英文名：Steely-vented Hummingbird，学名：Saucerottia saucerottei），是雨燕目蜂鸟科 Saucerottia 属的小型鸟类。分布于南美西北部，包括哥伦比亚和委内瑞拉的某些地区。灰腹蜂鸟具有独特的蓝黑色尾羽和钢蓝色下尾羽，其金色绿色的上体和深金色绿色的下体使它在众多蜂鸟中脱颖而出。","appearance":"灰腹蜂鸟体型介于8至11厘米之间，体重约4.4至5.0克。雄鸟拥有金色绿色的上体，蓝黑色的上尾覆羽和尾羽，下体呈暗金色绿色，下尾覆羽颜色从绿色到钢蓝色。雌鸟的喉部羽毛带有白色，下尾覆羽为灰色棕色，而幼鸟外观更接近雌鸟，但整体颜色较暗淡，喉咙部分呈暗灰色，腹部灰色棕色，背部和臀部羽毛边缘呈棕色。","call":"鸣叫声包括尖锐的高音\"tsit\"或干燥的\"chit\"声，有时以喷射式系列发出。","habits":"灰腹蜂鸟栖息于半开放到开放的景观，如灌木地、草原、成熟森林边缘、次生林、种植园和花园。它们倾向于较为干旱的环境，但在干季可能偏好湿润地带，如画廊森林边缘。在多数分布区内，它们的活动范围从海平面至海拔1500米，委内瑞拉的braccata亚种主要分布在海拔2000米左右，偶尔可达3000米。","breeding":"灰腹蜂鸟几乎全年在哥伦比亚繁殖，关于繁殖行为的细节知之甚少。已知的一个巢位于离地面约8米高的孤立树木的枝条上，呈简单的杯状。然而，关于卵、孵化期和离巢时间的描述尚未发表。","identification":"与其他Chlorostilbon或Amazilia属的蜂鸟相比较，可以通过其蓝黑色上尾覆羽、钢蓝色下尾覆羽以及金色绿色的上体加以区分。特别是与铜色腰蜂鸟(Amazilia tobaci)和白颊红嘴蜂鸟等种类存在差异。","protection":"IUCN：LC（无危）","distribution":"灰腹蜂鸟分布于南美洲西北部，具体包括哥伦比亚的苏克雷省至委内瑞拉西部的Zulia州，以及委内瑞拉的Trujillo和Mérida州的安第斯山脉。","other":"虽然通常认为是定居性的，但灰腹蜂鸟可能会因花期植物的分布而进行局部移动。"},{"name":"青顶蜂鸟","english_name":"Indigo-capped Hummingbird","scientific_name":"Saucerottia cyanifrons","overview":"青顶蜂鸟（英文名：Indigo-capped Hummingbird，学名：Saucerottia cyanifrons），是雨燕目蜂鸟科 Saucerottia 属的鸟类。中等体型的蜂鸟，主要分布于哥伦比亚中部地区。其最显著特征为全身绿色，头部拥有鲜明的蓝色冠羽，腿侧有白色绒毛，下颚基部呈红色。该鸟种在森林中层至上层活动，常见于海拔1000米至2000米之间。","appearance":"成年青顶蜂鸟体长约7至10厘米，体重约5克。雄鸟具有中等大小的黑色喙，基部三分之一红色；头部顶部为深蓝色；背部闪耀着绿色，臀部有青铜至铜色光泽；腹部呈现金色绿色闪光；尾下覆羽边缘泛白，中央颜色从青铜绿到深棕色或蓝灰色不等；尾羽上覆羽带有青铜或铜色，靠近尾端转为深蓝至蓝黑色；尾羽略呈叉状，尾羽末端深钢蓝色。雌鸟外观相似，但头部顶部向颈部方向更显蓝绿色；喉部羽毛有灰白色亚端条纹。幼鸟似雌鸟，腹部偏灰色。","call":"鸣声为重复的嗡嗡声与尖锐的‘tzuk-keee ... tsrp’，叫声包括高音尖锐的‘tsit’，有时会连续发出。","habits":"栖息于亚热带湿润森林边缘以及较干燥的开阔地带，如灌木丛、种植园和花园。主要活动于海拔1000米至2000米间，繁殖季节下至400米，偶尔可达3000米。观察到有季节性迁徙现象，可能与食物植物季节性变化有关。以花蜜和小型节肢动物为食，在树冠层活跃捕食昆虫。","breeding":"繁殖季节大概在4月至7月，筑巢记录持续至8月。巢穴类似同类，杯状，由苔藓、地衣和蜘蛛网构成。一窝产两枚白色卵，孵化由雌鸟承担，具体孵化期和离巢时间未知。","identification":"青顶蜂鸟以其独特的蓝色冠羽和红下颚基部易于识别，与同属其他物种的主要区别在于头部色彩和体型差异。","protection":"IUCN：LC（无危）；CITES II。在半开放林地中的分布较为广泛，适应人类活动区域的能力使其目前相对安全。","distribution":"主要分布于哥伦比亚北部和中部，包括Norte de Santander省、马格达莱纳河谷和上考卡河谷。在繁殖季节，可下至近海平面，偶尔在热带低地出现。","other":"青顶蜂鸟原属Amazilia属，后根据分子系统发育研究被重新分类至Saucerottia属。"},{"name":"雪胸蜂鸟","english_name":"Snowy-bellied Hummingbird","scientific_name":"Saucerottia edward","overview":"雪胸蜂鸟（英文名：Snowy-bellied Hummingbird，学名：Saucerottia edward），是雨燕目蜂鸟科 Saucerottia 属的鸟类。是中美洲特有的一种蜂鸟，主要分布在哥斯达黎加和巴拿马，少量记录出现在哥伦比亚。其最显著的外部特征是整体呈现闪耀的绿色，腹部有鲜明的白色V字形标记。","appearance":"雪胸蜂鸟体长8至11厘米，体重介于4.3至5.4克之间。喙笔直呈黑色，下颚基部带红色。成年雄鸟上半身青铜绿至铜色，背部和臀部尤为明显，尾巴铜色，有时带有紫色光泽。喉咙和胸部金绿色闪光，腹部中央有V字形白色。雌鸟相似，但上半身颜色较淡，喉部和腹部下方更偏白，尾羽外侧有浅绿色尖端。幼鸟侧面灰褐色而非纯白色。四个亚种中，niveoventer体型稍大，尾羽蓝黑至紫黑色；collata背部颜色对比不那么明显，腹部下方棕褐色；margaritarum腹部下方较淡，尾羽青铜至青铜绿色。","call":"其歌声柔和，类似“bebeebee, d’beebee”或“tseer tir tir”的声音，叫声包括轻柔的“tip”或“tsip”。","habits":"偏好半开放环境，如稀树草原、灌木丛和散落树木地带，开放林地，森林边缘，次生林，咖啡种植园，花卉灌木丛，花园和路边。海拔分布广泛，从海平面到1600米。西部种群有局部迁移行为，可能在雨季留在较为干旱地区，旱季移至河流上游。在哥斯达黎加的Buena Vista谷，种群的消失与开花期相关，可能沿大西洋海岸迁徙。主要以花蜜为食，也捕食小型节肢动物。","breeding":"繁殖季节在9月至翌年1月，筑巢于小树或灌木丛中的水平枝条上，离地面1.5至9米高，巢由棕色纤维制成，外覆苔藓和地衣。每窝产两枚卵，仅雌鸟孵卵，孵化期和育雏时间未知。","identification":"与其它蜂鸟种类相比，雪胸蜂鸟腹部的V字形白色标记是其显著特征。不同亚种在尾羽颜色和腹部下方色调上有差异。","protection":"IUCN：LC（无危）。《濒危野生动植物种国际贸易公约》CITES附录II。在巴拿马运河区是最常见的蜂鸟之一，在哥斯达黎加西南部和巴拿马西部热带至亚热带区域地方常见。","distribution":"主要分布在中美洲的哥斯达黎加和巴拿马，少量记录出现在哥伦比亚。海拔分布从海平面至1600米，不同亚种占据不同的生态位。","other":"曾被归类于Amazilia属，后根据分子系统发育研究，转移至Saucerottia属。"},{"name":"绿蜂鸟","english_name":"Berylline Hummingbird","scientific_name":"Saucerottia beryllina","overview":"绿蜂鸟（英文名：Berylline Hummingbird，学名：Saucerottia beryllina），是雨燕目蜂鸟科 Saucerottia 属的鸟类。绿蜂鸟分布于中美洲，从墨西哥西北部至洪都拉斯，常见于海拔500至1800米的干燥生境。","appearance":"绿蜂鸟体长8至10厘米，体重约4克。雄鸟头部、背部和臀部呈青铜绿至铜色，翼根部和次级飞羽基部显现出栗色斑块，下体闪烁金绿色。雌鸟相似，但喉咙和腹部较灰，喙全黑。幼鸟似雌鸟，但腹部灰肉桂色，光泽较少。不同亚种在色泽上有细微差异。","call":"绿蜂鸟的鸣声多样，包含略粗糙的高音颤音，由1至2个轻柔的前奏音节开始，整体表现为一系列复杂音调，如'ssi kirr-i-rr kirr-i-rr'，'sirrr, ki-ti ki-dik'等。此外，还发出硬朗、嗡嗡的'dzzzzir'或'drrzzzt'叫声。","habits":"绿蜂鸟栖息于多种环境，包括密林、灌木丛、落叶林、森林边缘、城市公园等。它们广泛分布于各种海拔，偏好干燥生境，偶尔在湿润地区出现。绿蜂鸟是季节性迁徙者，北界种群南迁过冬。它们在花丛中觅食，以花蜜为主食，同时捕捉昆虫。","breeding":"繁殖期主要在6月至10月，高峰在9月。巢建于树木或灌木上，离地高度可达15米，由草、植物纤维和蜘蛛网构成，外饰苔藓。巢杯状，直径和深度均为40至50毫米。每窝产卵两枚，由雌鸟孵化，孵化期未知。幼鸟约在20天后离巢。","identification":"绿蜂鸟与其他蜂鸟的区别在于其独特的色彩组合和鸣叫声。亚种间差异体现在背部和腹部的颜色以及尾羽的光泽。","protection":"IUCN：LC（无危）","distribution":"绿蜂鸟主要分布于墨西哥西北部至洪都拉斯，包括中美洲的干旱地区。在美国西南部，如亚利桑那州的Huachuca山脉和Chiricahua山脉，它们极为罕见。","other":"绿蜂鸟的亚种lichtensteini分布最有限，仅限于墨西哥西部的Cerro Brujo。"},{"name":"蓝尾蜂鸟","english_name":"Blue-tailed Hummingbird","scientific_name":"Saucerottia cyanura","overview":"蓝尾蜂鸟（英文名：Blue-tailed Hummingbird，学名：Saucerottia cyanura），是雨燕目蜂鸟科 Saucerottia 属的鸟类。体型中等的蜂鸟。其分布于中美洲热带低地至山麓地带，自墨西哥南部至哥斯达黎加，常见于林地边缘、咖啡种植园等地。","appearance":"雄性蓝尾蜂鸟整体呈深翡翠绿色，具有鲜明的蓝色尾羽、紫色臀部和小型锈色翼斑。雌鸟色彩较暗淡，腹部灰色。两性下喙基部红色，但常难以观察到。翼长平均52.9mm，尾长平均28.9mm。","call":"其鸣叫包括短促的twitter声，以及尖锐的bzzzrt声、硬脆的chip声和高音的siik！声，后者在飞行中发出。","habits":"栖息于多种半开放环境，如森林边缘、次生林、灌木丛和遮荫咖啡种植园。在所有高度层采食花蜜，偏好Inga树花。以昆虫为辅食。","breeding":"关于繁殖行为的信息有限，其筑巢和产卵细节未知。","identification":"与紫胸蜂鸟(Amazilia saucerrottei)相似，但蓝尾蜂鸟在适当光线下翼上可见锈色，而紫胸蜂鸟没有此特征。两者地理分布重叠较少。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，包括墨西哥南部至哥斯达黎加的太平洋坡地，海拔100至1,800米。","other":"蓝尾蜂鸟曾被归类于Amazilia属，后分类修订将其移至Saucerottia属。"},{"name":"蓝臀蜂鸟","english_name":"Blue-vented Hummingbird","scientific_name":"Saucerottia hoffmanni","overview":"蓝臀蜂鸟（英文名：Blue-vented Hummingbird，学名：Saucerottia hoffmanni），是雨燕目蜂鸟科 Saucerottia 属的鸟类。小型蜂鸟，主要分布在中美洲的尼加拉瓜西部至哥斯达黎加中部的干旱地区及周边环境，如灌木丛、草原、森林边缘和花园。该鸟种以前被认为是灰腹蜂鸟的一个亚种，现被认定为独立物种，","appearance":"蓝臀蜂鸟体长8到11厘米，平均体重4.45克。雄鸟拥有金色绿色的上体，铜色至紫色的臀部和尾上覆羽，下体呈深金色绿色，臀下覆羽为绿色至钢蓝色，尾巴淡钢蓝色并微叉。雌鸟相似但下胸部和腹部颜色较暗，喉部羽毛有白色亚端斑，尾羽尖端呈紫色，尾巴分叉较小。幼鸟比成鸟颜色更深，下体较暗绿，腹部灰棕色，喉咙暗灰色，背部和臀部羽毛有棕色边缘。","call":"蓝臀蜂鸟的歌声为重复的刺耳嗡嗡声“tzi-tzee-tzup”，有时会接着几个低音符“tzi-tzee-tzup ... wut-chur-up”。其叫声包括尖锐的“tsit”或干燥的“chit”，有时会连续发出。","habits":"蓝臀蜂鸟常在开花植物附近的低矮灌木和小树中觅食花蜜，通常在此建立领地。它倾向于在小树的顶部以下高度觅食，除了花蜜，还会在空中捕捉昆虫，有时也会从水面捕食昆虫。这种蜂鸟偏好相对干燥的生境，但在旱季也会出现在较湿润的区域，如画廊森林边缘。","breeding":"蓝臀蜂鸟的繁殖季节从至少12月持续到4月，具体细节知之甚少。已知它们会在枯死的Cecropia树枝或Ficus藤蔓上建造杯状的巢，由植物绒毛和蜘蛛网构成，外层装饰有苔藓。巢位于地面以上2至7米的细枝上。","identification":"蓝臀蜂鸟与灰腹蜂鸟的区别在于铜色臀部和缺乏翼上的锈色斑点，雄鸟的叫声和行为也有所不同。雌鸟的下胸和腹部颜色更暗，尾羽尖端呈紫色。","protection":"IUCN：LC（无危）。CITES II级。在较干旱地区较为常见，但尼加拉瓜和哥斯达黎加的加勒比海岸线仍较为罕见。它在哥斯达黎加的多个保护区中被发现，包括圣罗莎国家公园、巴尔韦德国家公园和巴哈洪达国家公园。","distribution":"蓝臀蜂鸟的分布范围从尼加拉瓜南部延伸至哥斯达黎加中部。它主要栖息于半开放的景观，如灌木地、草原、成熟森林边缘、次生林和花园。","other":"蓝臀蜂鸟可能受益于森林砍伐和种植园的扩张，这导致了它最近侵入哥斯达黎加中部高原的山谷。"},{"name":"绿腹蜂鸟","english_name":"Green-bellied Hummingbird","scientific_name":"Saucerottia viridigaster","overview":"绿腹蜂鸟（英文名：Green-bellied Hummingbird，学名：Saucerottia viridigaster），是雨燕目蜂鸟科 Saucerottia 属的鸟类。主要分布在南美洲的哥伦比亚北部和委内瑞拉西部。此物种曾被归入Amazilia属，后因分类修订而移至Saucerottia属。绿腹蜂鸟体型较小，长约8至10.5厘米，重约4.5到6.7克。其最显著的特征是头部和背部呈金色至绿色，腹部通常为棕色而非绿色，尾巴深蓝至紫蓝色。","appearance":"绿腹蜂鸟的雄鸟具有直而中等长度的喙，喙基部粉红至红色，头部和背部为暗金色至绿色，翅膀为深紫色至棕色，尾巴为深蓝至紫蓝色。腹部颜色从绿色过渡到灰色或棕色。雌鸟与雄鸟相似，但喉部羽毛边缘白色，尾羽边缘为青铜色或棕色。幼鸟的下体颜色为灰棕色或棕灰色。","call":"绿腹蜂鸟的鸣唱为一系列重复的节奏短语，由大约4个刺耳或嘶哑的音符组成，如“tee-djew…djidjit”，其中第二个音符音调较低。叫声包括尖锐的下降颤音和快速连续的“tsi”音。","habits":"绿腹蜂鸟栖息于安第斯山脉的半开放至开放的亚热带景观，包括林缘、种植园、灌木丛、河岛和低矮的次生林，海拔高度在400至1700米之间。它们基本保持定居状态，但会局部移动以寻找花蜜资源。","breeding":"绿腹蜂鸟的繁殖季节至少从十月持续到一月。已知的巢穴是一个由淡黄色种子绒毛制成的杯状结构，外部覆盖着苔藓。关于繁殖生物学的其他细节尚未可知。","identification":"绿腹蜂鸟与棕尾蜂鸟相似，但喙更暗且不那么红，臀部和尾巴更棕色且不那么锈色。在Tepui地区发现的个体现在被认为是独立的物种，即铜尾蜂鸟。","protection":"IUCN：LC（无危）","distribution":"绿腹蜂鸟主要分布在南美洲的哥伦比亚东部安第斯山脉东坡和委内瑞拉西部安第斯山脉。在哥伦比亚，从北中部向南至少延伸到Macarena山脉。在委内瑞拉，仅在Táchira的安第斯山脉有记录，但北部分布界限尚待确认。","other":"绿腹蜂鸟的两个亚种S. v. viridigaster和S. v. iodura仍保留在该物种中，而其他四个亚种已被划分为铜尾蜂鸟。"},{"name":"铜色腰蜂鸟","english_name":"Copper-rumped Hummingbird","scientific_name":"Saucerottia tobaci","overview":"铜色腰蜂鸟（英文名：Copper-rumped Hummingbird，学名：Saucerottia tobaci），是雨燕目蜂鸟科 Saucerottia 属的鸟类。以闪亮的绿色头部和下体，铜色臀部，蓝紫色叉状尾巴为显著特征，雄鸟拥有红色下颚基部。广泛分布于委内瑞拉、特立尼达岛和多巴哥岛，可能也见于格林纳达。雌鸟与雄鸟相似，但腹部略显暗淡。","appearance":"体长9至11厘米，雄鸟体重4.6至4.7克，雌鸟3.5至4.2克。雄鸟拥有青铜绿色上体，紫色臀部覆羽，深金色下体，红棕色下尾覆羽，及紫黑色叉状尾。雌鸟相似，但背部颜色较淡，喉部和上胸部带有白色。幼鸟的喉咙和腹部部分呈灰褐色。不同亚种在体型、色彩强度及尾部颜色上有细微差异。","call":"发出重复的三音节嗡嗡声或尖锐声，节奏分明，最后一个音较低沉。觅食时会发出高音下降的颤音。","habits":"栖息于多种森林环境，包括画廊林、云雾林和雨林，也见于次生林和空旷地带。分布海拔从海平面到1000米，部分亚种可达2000米。极端领地性，捍卫其领域免受其他鸟类侵犯，甚至比它大的种类。主要以花蜜为食，同时捕食小昆虫。","breeding":"繁殖季节在特立尼达岛几乎全年发生，峰值在一月至三月，多巴哥岛则从十一月至六月。巢形似马鞍，由植物绒毛构成，装饰以苔藓和蛛网，置于离地面1至3米的小树或灌木枝叉处，有时高达6米。每窝产两枚白色蛋，雌鸟孵化16至19天，幼鸟23天左右离巢。每年可育二至三窝。","identification":"与灰腹蜂鸟的区别在于缺乏蓝色臀部覆羽；与翡翠蜂鸟相比，其喙更长且更弯曲；与蓝颏青蜂鸟的区别在于尾部形状（叉状而非圆形）及缺少蓝调的下巴和身体。不同亚种在色彩和体型上有所不同。","protection":"IUCN：LC（无危）","distribution":"主要分布于委内瑞拉、特立尼达岛和多巴哥岛，可能在格林纳达也有记录。在特立尼达岛和多巴哥岛，铜色腰蜂鸟常见于城市区域。","other":"在特立尼达岛和多巴哥岛以及大陆亚种feliciae和caudata中，铜色腰蜂鸟数量普遍较多，特别是在城市公园和花园等人为环境中频繁出现。"},{"name":"铜尾蜂鸟","english_name":"Copper-tailed Hummingbird","scientific_name":"Saucerottia cupreicauda","overview":"铜尾蜂鸟（英文名：Copper-tailed Hummingbird，学名：Saucerottia cupreicauda），是雨燕目蜂鸟科 Saucerottia 属的鸟类。主要分布于南美的特普伊山脉，委内瑞拉南部，圭亚那西部和巴西中北部。这体型较小的蜂鸟，以其独特的铜色尾羽著称，生活在山地森林中。","appearance":"铜尾蜂鸟长度约为8至10.5厘米，体重介于3.1到5克之间。雄鸟具有闪亮的绿色羽毛，除腹部下方部分外，上体从头部到背部呈现金绿至青铜绿色，逐渐过渡到铜绿色的臀部和尾上覆羽。尾羽主要呈红铜色，尾端有暗紫色光泽。雌鸟与雄鸟相似，但下巴的羽毛基部更白，造成斑点效果，且尾羽外侧末端更偏向青铜色而非赤褐色。","call":"其鸣唱被描述为一系列重复的短小精致的音节，如'tee-djee-tee-djee'或'tee-tee-djee-ti'，同时发出短促的嗡嗡声'tzit..tzit..tzit...'以及同音调的高音颤音'tsi-tsi-tsi-tsi'。","habits":"铜尾蜂鸟主要栖息于山地森林的半开放至开阔地带，包括画廊森林边缘、种植园、灌木丛和次生林。它们基本保持定居状态，但有时会进行季节性迁移。以花蜜和小型节肢动物为食，常在多种植物家族的花朵间觅食。","breeding":"繁殖季至少包括1月至5月。已知巢穴为开放式的杯状结构，由种子绒毛构成，外部覆盖苔藓和地衣，通常位于离地面约3米高的小树细枝上。雏鸟孵化和育雏的详细信息尚未明确。","identification":"与其他Saucerottia属蜂鸟相比，铜尾蜂鸟的两色调羽毛，前部绿色和尾部赤褐色，使其易于识别。亚种duidae的臀部更显铜色，尾羽呈丰富青铜色，无赤褐色或肉桂色。亚种laireti颜色略深，尾羽上覆羽和尾羽为金色青铜至铜色。亚种pacaraimae颜色更深，背部铜色更明显，尾羽无赤褐色或肉桂色。","protection":"IUCN：LC（无危）","distribution":"主要分布于委内瑞拉南部的特普伊山脉、圭亚那西部和巴西中北部。偶尔会在低地出现，可能只是季节性访客或迷鸟。"},{"name":"艳蜂鸟","english_name":"Amazilia Hummingbird","scientific_name":"Amazilis amazilia","overview":"艳蜂鸟（英文名：Amazilia Hummingbird，学名：Amazilis amazilia），是雨燕目蜂鸟科Amazilis的鸟类。拥有绿色与栗色相间的羽毛，最显著的特点是其红嘴黑尖。分布于南美洲的厄瓜多尔和秘鲁，尤其偏爱干旱森林和灌木丛，较少见于湿润地区。","appearance":"艳蜂鸟身长9至11厘米，体重介于4.5至6.5克之间。所有性别和亚种均具有粉红色带黑色尖端的直喙。雄鸟拥有金绿色上体，栗色腹部和尾部，喉部呈金色至蓝绿色；雌鸟类似，但喉部和腹部带有白色，腹部栗色较淡。幼鸟与雌鸟相似，但上体羽毛边缘呈棕色。","call":"艳蜂鸟的鸣唱为一系列4至10个尖锐的音符，通常呈现下降趋势，间隔重复。叫声包括短暂的‘tsip’和干燥的‘zrrt’，有时会以结巴式的颤音延长。","habits":"艳蜂鸟栖息于干旱至半干旱的开放地带，包括灌木丛、荆棘林、荒漠化草原，也常见于城市公园和花园。它们主要以花蜜为食，常访问中等长度的花朵，如Erythrina、Psittacanthus、Salvia和Justicia等，同时捕食小昆虫和蜘蛛。","breeding":"繁殖季节全年皆可，但A. a. alticola亚种主要在11月至3月间繁殖。雌鸟用植物纤维、蛛网和苔藓建造杯状巢，高度约1至2.5米。每窝产两枚白色卵，孵化期为16至18天，雏鸟约在17至25天后离巢。","identification":"A. a. alticola亚种胸部栗色较少，尾部几乎无绿色。A. a. azuay亚种喙部红色较少，腹部几乎纯白，仅下侧有栗色，尾部和上尾覆羽颜色更浅。A. a. caeruleigularis亚种喉部呈闪亮的蓝紫色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的厄瓜多尔和秘鲁，不同亚种占据不同的海拔和生境，从海平面到约2,700米的云雾林边缘。","other":"该物种的A. a. alticola亚种因栖息地破坏而可能受到威胁，尤其是森林砍伐导致适宜的云雾森林生境变得越来越孤立。"},{"name":"安第斯蜂鸟","english_name":"Andean Emerald","scientific_name":"Uranomitra franciae","overview":"安第斯蜂鸟（英文名：Andean Emerald，学名：Uranomitra franciae），是雨燕目蜂鸟科 Uranomitra 属的鸟类。中等体型的蜂鸟。常见于南美洲安第斯山脉云雾森林地带，海拔高度约800至1800米。其洁净的白色下部羽毛无斑点，使它在分布区内不易混淆。雄鸟与雌鸟相似，但雄鸟冠羽呈蓝紫色，雌鸟则为绿色调。","appearance":"体长9至11厘米，体重雄鸟约5.6克，雌鸟约5.3克。雄鸟具有中等大小的直或略弯喙，上颚黑色，下颚珊瑚红色带暗尖。雄鸟冠羽闪耀蓝紫光泽，颊部与颈部金绿至翡翠绿。其余上身与两侧呈淡绿至金绿色，具铜色尾羽覆羽。腹部中心白色。雌鸟冠羽较暗，更偏向蓝绿色，光泽较弱。幼鸟似雌鸟，上身羽毛边缘褐色，侧部灰褐。","call":"鸣声多样，通常为高音反复复杂的哨声、颤音和刺耳音组成的乐句。叫声包括尖细的“tsip”声和社交互动中的刺耳叽喳。","habits":"栖息于湿林边缘、次生林与空旷地带；在秘鲁西部，亦可见于较为干旱的灌木区。海拔分布600至2100米，最常见于1000米以上，低地少见。季节性迁移，表现为不在繁殖区如哥伦比亚Anchicayá停留，且有低地记录。以花蜜为主食，活动于不同高度，偏好中至高层的花朵，如香蕉、Canna等草本植物，Psammisia藤本，Hamelia、Cavendishia灌木及Eugenia树。偶尔捕食近地或植被内的昆虫。","breeding":"繁殖几乎全年进行，例如哥伦比亚安第斯山脉记录到1月至11月的筑巢活动。巢杯状，直径约42至53毫米，深约45至47毫米，由树蕨鳞片、棉花纤维、苔藓和蜘蛛网构成，置于地面1.4至2.3米处。每窝产两枚白色蛋，大小11.8至14.1毫米×6.9至8.5毫米，间隔一天左右产下。雌鸟孵卵，自第二枚蛋开始，雏鸟粉色，带浅黄色绒毛。孵化期19至24天，平均21天；雏鸟期19天左右。监测的七巢成功率为100%。","identification":"雄鸟与雌鸟在冠羽颜色上有明显差异，雄鸟蓝紫色，雌鸟蓝绿色，且雄鸟下颚颜色独特。亚种viridiceps冠羽绿色，尾巴显著短于其他亚种。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲哥伦比亚至秘鲁北部，主要在安第斯山脉的云雾森林中。在秘鲁西部，也见于较为干旱的灌木区。","other":"曾被归入Amazilia属，后分类学研究将其移至Uranomitra属。"},{"name":"紫冠蜂鸟","english_name":"Violet-crowned Hummingbird","scientific_name":"Ramosomyia violiceps","overview":"紫冠蜂鸟（英文名：Violet-crowned Hummingbird，学名：Ramosomyia violiceps），是雨燕目蜂鸟科 Ramosomyia 属的鸟类。以其纯白的腹部、蓝紫色的冠羽和红色的喙而独特。分布于北美和中美地区，从美国西南部到墨西哥西南部。在美国，几乎仅在亚利桑那州东南部和新墨西哥州西南部的亚利桑那梧桐树上筑巢。","appearance":"紫冠蜂鸟长约10至11.5厘米，重约5.1至5.8克。雄鸟和雌鸟的外观相似，仅在细微处略有差异。成鸟的上体呈现蓝紫色的冠羽，颈部后方可能混合着蓝紫色和白色，背部、肩部和臀部呈灰褐色至绿褐色，尾巴呈灰绿色至青铜绿色，翅膀暗淡。腹部从喉咙到尾下覆羽均为纯白色，两侧和侧翼大多为橄榄色光泽，带有青铜绿色。喙红至鲜红色，尖端黑色。腿和脚为深灰色，眼睛颜色深。幼鸟比成鸟更暗淡，上喙主要是黑褐色，下喙为暗粉红色，逐渐发展成红色和黑色尖端。","call":"其鸣叫声被描述为一系列非常高亢、细弱的下降音符，类似'seew seew seew seew seew'，通常从显眼的栖木上发出。","habits":"紫冠蜂鸟偏好沿河流的河岸林地等河流环境。它们在花多的地方觅食时，与其他蜂鸟表现出较少的攻击性行为，但在花朵稀缺时会试图捍卫花丛免受较小蜂鸟的侵扰。它们通过悬停从各种开花植物和灌木中摄取花蜜，也会从栖木上捕食小昆虫，或通过悬停从植被中收集。","breeding":"紫冠蜂鸟在亚利桑那州和新墨西哥州的繁殖季节从4月持续到9月，主要在亚利桑那梧桐树上筑巢。在墨西哥，繁殖活动主要在3月至8月之间，但几乎全年都观察到筑巢行为。巢穴一般由柔软的植物绒毛和蜘蛛网构成，外部覆盖苔藓。已知的巢中每次产卵两枚。孵化期和雏鸟离巢时间尚不清楚。","identification":"紫冠蜂鸟通过纯白色的腹部和红色的喙与其他北美的蜂鸟区分开来。与墨西哥的绿额蜂鸟(A. viridifrons)相比，后者具有黑绿色的冠羽、灰色或赤褐色的侧翼和更亮的绿色上体。","protection":"IUCN：LC（无危）","distribution":"紫冠蜂鸟的分布范围从美国西南部的亚利桑那州和新墨西哥州向南延伸至墨西哥西南部，包括米却肯州和伊达尔戈州，可能远至普埃布拉州和墨西哥州。在亚利桑那州和新墨西哥州，它们主要分布在海拔1200至1700米之间。在索诺拉州，分布高度在200至1300米之间，且随着向南扩展，海拔范围进一步扩大。在米却肯州东部和南部至瓦哈卡州西北部，它们通常出现在海拔200至1400米之间，总体海拔范围可达海平面至2400米。","other":"紫冠蜂鸟在U.S.和北部墨西哥被认为是迁徙性的，但越来越多的过冬记录显示，它们似乎正在向北扩展其分布范围。"},{"name":"绿额蜂鸟","english_name":"Green-fronted Hummingbird","scientific_name":"Ramosomyia viridifrons","overview":"绿额蜂鸟（英文名：Green-fronted Hummingbird，学名：Ramosomyia viridifrons），是雨燕目蜂鸟科 Ramosomyia 属的鸟类。墨西哥西南部的特有蜂鸟。该鸟体背金属绿，腹面纯白，雄鸟尾羽铜红，雌鸟尾绿金黄，喙基部鲜红。主要栖息于干旱灌丛、松栎混交林、荆棘林、河岸林及半开阔地带，海拔60–1400 米。繁殖后部分个体向低海拔扩散。IUCN列为无危，但在墨西哥法律中被视为受威胁种。","appearance":"体长10–11.5厘米，体重约6.3克。两性腹面纯白，上体闪耀绿光。\n雄鸟：额与冠具油蓝至蓝绿金属辉，远观近黑；背至腰呈翡翠到铜绿；尾上覆羽灰褐至铜色；尾羽铜红至紫铜，边缘带铜绿；胸侧与胁呈铜绿，偶见淡肉桂点斑；尾下覆羽白色，羽中心常带肉桂或酒红细纹。\n雌鸟：似雄鸟，但冠暗绿，尾羽铜色减弱，呈铜绿至金黄绿。\n幼鸟：似雌鸟，上体羽尖及尾羽端带淡肉桂色。","call":"主要叫声为柔和的“干哑絮语”，比紫顶蜂鸟声低；亚种 wagneri 会自栖枝发出轻微的“zzzzrr’k chiuk”重复声。飞行时可闻翅振的嗡鸣。","habits":"全年留居，个别繁殖后向低海拔扩散，如格雷罗州由内陆向太平洋坡移动。栖于落叶林、荆棘林、干旱至半干旱灌丛、河岸林及半开阔带篱墙与散树的环境。多在林层中上部取食花蜜并飞捕昆虫，活动高度以中层及树冠为主。一般单独活动。","breeding":"繁殖记录见于5月与9月，10月见衔巢材。巢为典型蜂鸟杯状，由白植物绒外覆少量绿苔构成，外径约40.9 毫米，深约27.4 毫米，杯口内径约12.0 毫米，距地约1.8 米。每窝2枚纯白无斑卵，大小约13.7×8.8 毫米。","identification":"与紫顶蜂鸟相似，但后者上体绿较暗，额紫而非绿，尾羽暗绿。与蓝顶蜂鸟区别在于蓝顶蜂鸟额淡蓝，上喙黑，胁暗褐范围大，尾羽暗绿。亚种区分：指名亚种 viridifrons 胁白，wagneri 胁及体侧肉桂色，翼内基部肉桂红；rowleyi 胁肉桂范围介于二者之间，上体稍暗。","protection":"IUCN: LC（无危）。列入CITES附录Ⅱ。因分布狭窄及栖息地受严重威胁，被墨西哥法律列为受威胁物种。","distribution":"繁殖区：墨西哥南部，自格雷罗州经瓦哈卡州至恰帕斯州东部，并延伸至危地马拉西部韦韦特南戈。非繁殖期部分个体向低海拔或坡面扩散，但总体为留鸟。","other":"分类史上曾被并入紫顶蜂鸟，后因羽色差异及同域分布证据被视为独立种。属级系统学研究显示旧 Amazilia 属为多系群，本种现归入 Ramosomyia 属。栗胁蜂鸟现在为亚种。"},{"name":"栗胁蜂鸟","english_name":"Cinnamon-sided Hummingbird","scientific_name":"Ramosomyia wagneri","overview":"栗胁蜂鸟（英文名：Cinnamon-sided Hummingbird，学名：Ramosomyia wagneri），是雨燕目蜂鸟科 Ramosomyia 属的鸟类。","appearance":"栗胁蜂鸟体长10到11.5厘米（3.9到4.5英寸），体重约6.3克（0.22盎司）。其喙呈红色，尖端黑色。成年雄鸟拥有闪耀的蓝绿色冠羽，背部呈现绿宝石到青铜绿色，臀部和上尾覆羽灰褐至青铜色。尾羽铜色至紫罗兰色，边缘带青铜绿色。下体从喉至尾下覆羽纯白，两侧和侧腹为特征性的肉桂色。成年雌鸟外观相似，但冠羽暗绿，尾羽青铜绿至金绿色。","call":"栗胁蜂鸟的鸣叫声尚未被单独描述，其声音特征与绿额蜂鸟（广义）相似。","habits":"栗胁蜂鸟全年在其范围内居住。它们栖息于落叶林、荆棘林、干旱至半干旱灌木丛、河岸森林以及公园和花园。海拔高度范围在250至900米（820至3,000英尺）之间。觅食策略和所采食的开花植物尚未详细记载，但推测也以小型昆虫为食，如同其他大多数蜂鸟。","breeding":"关于栗胁蜂鸟的繁殖生态学信息有限，具体繁殖期、筑巢行为和幼鸟抚育等细节尚不清楚。","identification":"与绿额蜂鸟相比，栗胁蜂鸟最显著的区别在于其两侧和侧腹的肉桂色，以及特定的分布区域。","protection":"IUCN：LC（无危）尽管其分布范围非常有限，且种群数量未知且被认为正在减少。","distribution":"栗胁蜂鸟主要分布在中美洲的墨西哥瓦哈卡州中部和南部。"},{"name":"辉喉蜂鸟","english_name":"Glittering-throated Emerald","scientific_name":"Chionomesa fimbriata","overview":"辉喉蜂鸟（英文名：Glittering-throated Emerald，学名：Chionomesa fimbriata），是雨燕目蜂鸟科 Chionomesa 属的小型蜂鸟。分布广泛于南美洲，常见于多种开放和半开放生境，如干燥和湿润森林边缘、次生林、开阔林地、灌木丛、种植园和花园。体长8至12厘米，体重3.5至6.2克。","appearance":"辉喉蜂鸟拥有金属绿色的外观，眼后有白色斑点，下喙橙色，腹部苍白，尾部蓝黑色带绿基。雄鸟有直而中等大小的喙，上喙深色，下喙粉红色尖端暗色；背部金至青铜绿色，喉咙和胸部闪烁金色绿色光泽，下胸中部和腹部白色，尾下覆羽白带褐色中心。雌鸟类似，但喉羽有白色亚端斑，最外侧尾羽尖端绿灰色。幼鸟腹部灰褐色更明显。各亚种在喉部蓝色量、体型和尾羽颜色上有差异。","call":"辉喉蜂鸟的鸣唱是在黎明时连续重复的高音刺耳音符“tzee...tzee...tzee...”。白天飞行或领土防卫时发出连续的高音“tsee…tsi-tsi-tsitsitsi”或“tslee-tslee-tslee-tslee”。叫声包括高音“tsee”和柔和的叽叽声。","habits":"辉喉蜂鸟偏好半开放至开放环境，避免密集森林内部、大草原和城市区域。它们在各种生境中广泛分布，包括干湿森林、森林边缘、次生林、开阔林地、灌木丛、种植园和花园。在巴西中部，常见于卡廷加和卡佩拉。海拔范围从海平面到1100米，主要在500米以下活动。","breeding":"繁殖季节几乎全年都有，具体时间在圭亚那和东北巴西为8月至9月，在阿根廷、巴拉圭和乌拉圭为11月至12月，在中央巴西为11月至2月，在东部巴西为11月至4月。巢杯状，通常位于水平枝上，由植物纤维、蜘蛛网和苔藓构成，高度6至12天建成。每窝产两枚卵，孵化期14至17天，由雌鸟独自承担。雏鸟孵化后18至22天离巢，偶尔可达30天。一年可能育雏两次以上。","identification":"辉喉蜂鸟与其他蜂鸟的区别在于其独特的喉部闪光、体型、尾羽颜色和分布。各亚种之间在上尾覆羽颜色、喙长和尾羽光泽上有细微差异。","protection":"IUCN：LC（无危）","distribution":"辉喉蜂鸟广泛分布于南美洲，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、圭亚那、秘鲁、特立尼达和委内瑞拉。","other":"辉喉蜂鸟的种族tephrocephala沿大西洋海岸迁徙，其他种族可能仅做局部移动，但具体情况不明。"},{"name":"蓝喉蜂鸟","english_name":"Sapphire-spangled Emerald","scientific_name":"Chionomesa lactea","overview":"蓝喉蜂鸟（英文名：Sapphire-spangled Emerald，学名：Chionomesa lactea），是雨燕目蜂鸟科 Chionomesa 属的鸟类。小型蜂鸟。拥有闪光绿色背部，蓝紫色喉咙和胸部，绿色侧翼，以及胸部中央的白色条纹。分布于南美洲亚马逊雨林区域，从委内瑞拉东南部至阿根廷东北部，以及玻利维亚北部。","appearance":"体型小，长度约8至11厘米，体重3.6至5克。雄鸟具有笔直中等长度的喙，上颚黑色，下颚粉色至角质色，带有暗灰色或黑色尖端；冠部、颈部和侧翼青铜绿色，其余上体金绿至青铜绿色；喉咙和上胸闪耀蓝紫色，胸中央白色，腹部灰色，下尾覆羽灰白色带棕色基部条纹；中央尾羽基部闪绿或青铜绿色，远端变暗，外侧尾羽蓝黑色。雌鸟喉咙较灰色，带闪烁蓝绿色斑点，最外侧尾羽有灰色尖端。幼鸟下体有扩展的灰色区域，雄鸟幼鸟喉咙颜色与成年雌鸟相似。","call":"重复的嗡嗡声似昆虫的高音颤音，'tzee … tzitzitzee … tzitzitzee …' 或类似。也发出 'tsip' 和 'chup' 的叫声。","habits":"栖息于半开放的景观，如雨林边缘、河岸森林、次生林、河流边界和开阔地带，常在低海拔地区活动，偶尔可达1400米高度。偏好在多种本土和引进的开花植物、灌木和树木中觅食花蜜，如豆科、锦葵科、旅人蕉科、茜草科等植物家族。雄鸟建立喂食领地，捕食空中飞虫。","breeding":"南部种群在10月至1月间繁殖，委内瑞拉种群繁殖季节未知。杯状巢由植物绒毛和蜘蛛网构成，外表覆盖苔藓，高49毫米，外径41毫米，内径23毫米。每窝产两枚白色蛋，尺寸14毫米×9毫米，重0.46克，仅由雌鸟孵化，孵化期14天。雏鸟深色，背部有淡黄色绒羽，离巢期22至23天。","identification":"与同属种类的区别在于喉咙颜色和羽毛细节，雄鸟C. l. zimmeri的蓝紫色斑块较小，雌鸟的喉咙和腹部更白。幼鸟与成年雌鸟相似，但下体有更多灰色区域。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，包括委内瑞拉东南部、巴西东部至南部、玻利维亚北部、阿根廷东北部，以及秘鲁东部和东南部。在委内瑞拉，通常位于1100至1400米的高度。","other":"已知从委内瑞拉东南部到阿根廷东北部的短距离迁移模式，与开花的蜜源时间相关。"},{"name":"蓝胸蜂鸟","english_name":"Blue-chested Hummingbird","scientific_name":"Polyerata amabilis","overview":"蓝胸蜂鸟（英文名：Blue-chested Hummingbird，学名：Polyerata amabilis），是雨燕目蜂鸟科 Polyerata 属的鸟类。主要分布在中美洲至南美洲的尼加拉瓜至厄瓜多尔南部。其最显著的特征是雄鸟拥有闪亮的紫蓝色喉部，绿色背部和冠羽，腹部呈淡灰色，尾部深色。雌鸟较为低调，胸部斑点状，下喙基部粉红色。","appearance":"雄性蓝胸蜂鸟具有笔直的中等长度黑褐色喙，下颌基部红褐色，头部和面颊区闪烁着带有蓝调的绿色光泽，上体和侧翼呈暗绿至青铜绿色，下喉部和胸部有紫蓝色斑块，下腹灰棕色，覆肛羽棕色中心，尾上覆羽和尾羽青铜绿色，外侧尾羽变黑。雌鸟缺乏闪光的冠羽，喉咙散落有带宽白色边缘的蓝绿色羽毛，腹部较浅，尾羽尖端灰色。幼鸟喉部颜色似雌鸟，但下体更偏灰色，幼年雄鸟下巴暗绿色，幼年雌鸟下巴淡灰色，带有绿色斑点。","call":"鸣声多变，常为一连串尖锐的吱吱声，例如“tsip-tsew-tsew-tseek-tsew...”或更简单的“tseek-tseek-tseek-tseek...”。叫声包括金属般的“tsink”和短促的“tsit”。社交互动时发出下降的啾啾声。","habits":"栖息于森林边缘、开阔林地、灌木丛、次生植被、清理地带、河岸植被、种植园等，常见于开放区域，避免茂密森林内部。活动高度从海平面到1400米，但通常低于500米，偶尔在1000米以上，尤其在厄瓜多尔西部，主要出现在300米以下，单次记录达到1200米。季节性迁徙与开花期部分相关，个体突然出现或消失在某些地方，可能在繁殖季节后出现在较高海拔。","breeding":"在哥斯达黎加，筑巢始于旱季，从12月到5月，假设巴拿马和哥伦比亚有类似季节（在后者国家，收集到处于繁殖状态的鸟类时间在2月至5月之间）。杯状巢建在水平的叶状枝条上，位于灌木或小树2-5米高处，用淡色植物纤维和蜘蛛网固定，内部有时覆盖种子绒毛和棕色蕨类鳞片，外部饰以苔藓和地衣。每次产两枚白色卵，由雌鸟孵化。雏鸟粉红色，背部稀疏的淡黄色绒毛，关于孵化和离巢期的数据尚无。","identification":"与娇蜂鸟极其相似，但两者分布范围不重叠。雄鸟通过其独特的喉部颜色和体型区别于其他有斑点胸部的雌鸟蜂鸟，如白颈蜂鸟。","protection":"IUCN：LC（无危）。列入CITES附录II。在分布范围内相对常见，至少在局部地区，是巴拿马运河区域最常见的Trochilidae之一。在厄瓜多尔西北部普遍较少见，数量被A. rosenbergi超越。","distribution":"分布于中美洲至南美洲，从尼加拉瓜南部到哥伦比亚东北部，向南延伸至厄瓜多尔西部，安第斯山脉以西。可能还出现在洪都拉斯东南部。确切的分布范围在北部和南部极端以及可能的其他地方不确定。","other":"曾归类于Amazilia属，分子系统发育研究发现Amazilia属多系群，2014年修订分类，蓝胸蜂鸟被移至复活的Polyerata属。"},{"name":"娇蜂鸟","english_name":"Charming Hummingbird","scientific_name":"Polyerata decora","overview":"娇蜂鸟（英文名：Charming Hummingbird，学名：Polyerata decora），是雨燕目蜂鸟科 Polyerata 属的鸟类。最显著的外部特征为雄鸟的紫色闪亮喉部和绿色背部与冠部，雌鸟胸部有斑点，喙基部呈粉红色。主要分布在中美洲，哥斯达黎加西南部至巴拿马西部的森林边缘和次生植被地带。","appearance":"雄鸟体长9.6-10.4厘米，平均体重4.74克，拥有直而中等长度的黑色喙，喙基部微红，颈背及冠部闪耀着带有蓝调的绿色光泽，上体及两侧为暗绿至青铜绿色，下巴中央呈青铜色，下喉及胸部长有皇家蓝色斑块，腹部灰褐色，下尾覆羽带棕色中心，尾羽青铜绿色，偶尔泛紫。雌鸟头部顶部闪亮绿色，胸部散落着蓝绿色带宽白边的羽毛，腹部颜色较浅，尾羽末端灰白色，臀部、上尾覆羽和尾羽更绿，少有青铜紫色。幼鸟似雌鸟，头部、喉咙和胸部为暗青铜绿色，羽毛边缘宽阔淡黄色。","call":"其鸣唱多变，通常为高音的金属声短语重复，如“twee-ti-tlee … twee-ti-tlee …”或“tlwee-tit … tlwee-tit …”。叫声包括干涩的“tsik”和颤音的“trr”，在互动中会发出低沉的涟漪颤音。","habits":"栖息于森林边缘、开阔林地、灌木丛、次生植被、清理地、河岸植被、种植园等地，偏好低地及塔拉曼卡山脉和中央山脉的亚山区，常见于中海拔地区，高度可达1580米（主要在1200米以下）。它倾向于在开阔区域活动，沿河流和溪流边缘，避免密集森林内部。","breeding":"雄鸟会在2-6米高的栖木上几乎全年歌唱，除了旱季高峰期。它们形成多达12只的求偶场，集体鸣唱以吸引伴侣。","identification":"与蓝胸蜂鸟相比，娇蜂鸟具有更长更宽的喙和较短的翅膀，雄鸟的喉部和胸部色彩更为独特。","protection":"IUCN：LC（无危），CITES II。在分布范围内相对常见，尤其在哥斯达黎加，巴拿马西部较为局部。它是一种有限分布的物种，在南中美洲太平洋斜坡EBA中出现，哥斯达黎加的几个保护区中均有记录，如曼努埃尔安东尼奥国家公园、科科瓦多国家公园和戈尔菲托国家野生动物保护区。","distribution":"分布于中美洲的哥斯达黎加西南部和巴拿马西部，主要在太平洋斜坡地区。","other":"因喙长翼展及色彩差异，从蓝胸蜂鸟中独立出来成为单独物种。"},{"name":"紫胸蜂鸟","english_name":"Purple-chested Hummingbird","scientific_name":"Polyerata rosenbergi","overview":"紫胸蜂鸟（英文名：Purple-chested Hummingbird，学名：Polyerata rosenbergi），是雨燕目蜂鸟科 Polyerata 属的鸟类。主要分布于哥伦比亚西部和厄瓜多尔西北部的低地森林和山麓地带。其最显著的特征是雄鸟胸前的一块蓝紫色斑块。","appearance":"紫胸蜂鸟拥有闪亮的翠绿色羽毛，雄鸟胸前具有独特的蓝紫色斑块，这一特征在雌鸟身上可能减退或缺失。雄鸟和雌鸟在外形上相似，但可以通过胸部颜色的差异来区分。","call":"鸣唱时，紫胸蜂鸟会重复发出约7至9个‘tsee’音节的短语，首两个音节重音明显，随后音节节奏略快。叫声包括单独的‘tsee’音。","habits":"紫胸蜂鸟通常在森林边缘或空旷地带活动，偶尔会在某些地方访问喂食器。它们偏好栖息于低地森林和严重退化的前森林环境中。","breeding":"关于紫胸蜂鸟的繁殖习性的具体信息有限，但它们通常在当地定居，形成稳定的繁殖群体。","identification":"与蓝胸蜂鸟相比，紫胸蜂鸟可通过其鲜明的白色腹部特征来区分。","protection":"IUCN：LC（无危）; CITES: Appendix II（华盛顿公约附录二）","distribution":"紫胸蜂鸟的分布范围限于哥伦比亚西部（自中部Chocó省向南）和厄瓜多尔西北部（至西北Pichincha省）。在哥伦比亚西南沿海地区，记录到至少每平方公里2-3对的密度。","other":"紫胸蜂鸟曾被归类于Amazilia属，但分子系统发育研究显示Amazilia属多系群，因此紫胸蜂鸟被重新分类至Polyerata属。"},{"name":"花顶蜂鸟","english_name":"Santa Marta Blossomcrown","scientific_name":"Anthocephala floriceps","overview":"花顶蜂鸟（英文名：Santa Marta Blossomcrown，学名：Anthocephala floriceps），是雨燕目蜂鸟科花顶蜂鸟属的珍稀鸟类。仅见于哥伦比亚圣玛尔塔山脉的云雾森林，拥有独特的白尾尖和眼后大白色泪斑，雄鸟还具有栗色冠羽。","appearance":"小型蜂鸟，约8.4厘米长。雄鸟具直而黑的喙，前额淡黄色，后冠栗色，其余上部羽毛闪耀绿色，眼后有白色斑点；下部羽毛灰褐色；尾部方形，青铜绿，边缘淡黄，中央一对尾羽无黑亚端斑。雌鸟与雄鸟相似，但冠羽呈棕色。幼鸟似成年雌鸟。","call":"雄鸟发出一系列快速的‘tsip’音符，每秒约1.5个音符，形成连续的歌曲。","habits":"栖息于海拔400至1700米的湿润森林和较老的次生林。通常在低层灌木丛中觅食，以开花的香蕉等植物为食源。","breeding":"关于繁殖习性的信息极为有限，已知在9月至10月期间有成鸟处于繁殖状态，巢、蛋及繁殖行为的具体细节尚未描述。","identification":"与托利马花顶蜂鸟非常相似，但区别在于后者尾羽尖端几乎全白。","protection":"IUCN：VU（易危）, CITES II级附录。受栖息地破坏威胁，特别是在圣玛尔塔山脉的森林被清除用于毒品种植。","distribution":"仅分布于哥伦比亚东北部的圣玛尔塔山脉。","other":"曾被认为是托利马花顶蜂鸟的同种，但遗传分析证实两者分化时间约140万年前，生态位模型显示二者存在显著的气候生态位差异。"},{"name":"托利马花顶蜂鸟","english_name":"Tolima Blossomcrown","scientific_name":"Anthocephala berlepschi","overview":"托利马花顶蜂鸟（英文名：Tolima Blossomcrown，学名：Anthocephala berlepschi），是雨燕目蜂鸟科花顶蜂鸟属的鸟类。体型较小的蜂鸟，主要分布在哥伦比亚中央安第斯山脉东部斜坡，特别是在南中部的马格达莱纳河谷。曾被认为是花顶蜂鸟的一个亚种。该物种拥有直而短的喙，雄鸟具有绿色上部，前额呈淡黄色，后冠橙色，腹部灰色，雌鸟和幼鸟的头部呈棕色。","appearance":"托利马花顶蜂鸟长约8.4厘米。雄鸟具有黑色直喙，前额淡黄色，后冠红褐色，上体大部分呈绿光闪耀，背部下方和尾羽覆羽呈锈色，下体灰黄色。尾羽青铜绿色，末端宽白，除中央一对外，其余尾羽近端处有一黑斑。雌鸟和幼鸟外观类似成年雄鸟，但其整个头部呈棕色。","call":"托利马花顶蜂鸟的鸣唱为一系列重复的“tsip”音符，速度约为每秒1.5个音符。","habits":"托利马花顶蜂鸟生活在哥伦比亚上马格达莱纳河谷的云雾森林内部和边缘，以及成熟的次生林中，海拔介于1200至2500米之间。其饮食和觅食策略尚未研究，但可能类似于花顶蜂鸟，在森林下层活动。","breeding":"托利马花顶蜂鸟的繁殖生态学未被研究。","identification":"托利马花顶蜂鸟与花顶蜂鸟在遗传学和生态位上有显著差异。最明显的羽毛区别在于尾羽末端的白色宽度，托利马花顶蜂鸟的白色更宽。","protection":"IUCN：VU（易危）","distribution":"托利马花顶蜂鸟分布在哥伦比亚的中央安第斯山脉，包括卡乌卡、北胡利亚、托利马和昆迪奥省。其分布范围限于马格达莱纳河上游流域。","other":"托利马花顶蜂鸟在其分布范围内数量稀少，受农业扩张导致的栖息地破坏威胁。"},{"name":"白腹棕尾蜂鸟","english_name":"White-vented Plumeleteer","scientific_name":"Chalybura buffonii","appearance":"体长约10.5至12厘米，体重雄鸟6至7.3克，雌鸟5.9至7.9克。喙和脚均为黑色，仅intermedia亚种嘴基部粉红色，脚淡粉色至红色。雄鸟上体主要为深金属绿色，头冠和颈后部更呈青铜色，上尾覆羽铜褐色；雌鸟上体较淡金属绿，下体灰色，侧身有绿色斑点。","call":"在觅食时会发出“chip”声，具体歌曲未详述。","habits":"栖息于干湿森林、林缘、咖啡种植园、半开放和次生林，偏好较开阔的灌木丛而非森林内部。海拔分布从海平面到2000米。以各种树木、灌木和大型草本植物的花蜜为食，采用守候和领域制，极具攻击性和主导性，能驱赶其他蜂鸟。","breeding":"繁殖季节在不同地区有所变化，如巴拿马的micans亚种在至少9月繁殖，哥伦比亚的指名亚种种群在2月至7月或8月繁殖。筑巢于树上，高2.5米左右，巢由植物绒毛和蜘蛛网构成，外表装饰有苔藓和地衣。","identification":"与斑胸棕尾蜂鸟最相似，但通过尾部颜色和脚的颜色可以区分。intermedia亚种有时被归入斑胸棕尾蜂鸟，需进一步研究。","protection":"IUCN：LC（无危）。CITES II级。尽管总体数量似乎稳定，但caeruleogaster亚种可能因低地森林砍伐而下降。","distribution":"分布于巴拿马至委内瑞拉和哥伦比亚，包括中美和南美地区。","other":"已知有五个亚种，其中intermedia亚种的地位需要进一步调查。"},{"name":"斑胸棕尾蜂鸟","english_name":"Bronze-tailed Plumeleteer","scientific_name":"Chalybura urochrysia","overview":"斑胸棕尾蜂鸟（英文名：Bronze-tailed Plumeleteer，学名：Chalybura urochrysia），是雨燕目蜂鸟科棕尾蜂鸟属的鸟类。是中型蜂鸟，主要分布于中美洲和南美洲，从尼加拉瓜到厄瓜多尔西南部。其最显著的特征为红脚和粉红色下喙基部，雄鸟上体金属绿色，下体闪烁绿，尾羽青铜绿色，雌鸟下体灰色，两侧点缀绿斑，尾羽尖端灰色。在繁殖季节，该鸟主要栖息于森林边缘的花卉附近。","appearance":"斑胸棕尾蜂鸟体型中等，长度约10.5至12厘米，雄鸟平均重量约为7.1克，雌鸟约为6.1克。雄鸟上体呈现金属绿色光泽，下体闪烁着绿色，尾羽青铜绿色，尾下覆羽长而蓬松，白色；雌鸟上体绿色，下体灰白色，两侧带有绿色斑点，尾羽尖端灰色。幼鸟较成鸟色泽暗淡，冠、颈背和臀部的羽毛边缘呈肉桂色。","call":"斑胸棕尾蜂鸟的叫声包括轻柔、鼻音、刮擦式的颤音“ter-twee-ee-ee-ee-ee....ter-twee-ee-ee...”，追逐时发出延长的下降式叽叽喳喳的颤音。此外，还有响亮的“chup”和“chip”音以及短暂的叽叽声。","habits":"斑胸棕尾蜂鸟偏好生活在湿润森林的林下层和中层，偶尔出现在高大的次生林和半开放环境中，如香蕉园和花园。它们通常在海拔700米以下活动，但在哥伦比亚可达900米。该物种以花蜜为主食，尤其偏爱Heliconia等大型草本和灌木，同时也飞扑捕食小型节肢动物。","breeding":"斑胸棕尾蜂鸟在哥斯达黎加的繁殖期从12月持续至6月，高峰期为2月至4月。在哥伦比亚，繁殖期同样在2月至4月之间。巢穴为深杯状，由浅色植物绒毛和纤维构成，外覆苔藓和少量地衣，高度一般位于地面0.5至1.5米之间。","identification":"与其他蜂鸟相比，斑胸棕尾蜂鸟可通过其独特的红脚和粉红色下喙基部识别。雌鸟的下体颜色和尾羽尖端的灰色有助于区分。在不同亚种中，C. u. melanorrhoa的雄鸟上体颜色更深，腹侧呈烟灰色，尾羽呈紫黑色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲和南美洲，北起尼加拉瓜，南至厄瓜多尔西南部，包括哥斯达黎加、巴拿马、哥伦比亚和厄瓜多尔等地。","other":"该物种在某些地区遭受了严重的森林栖息地损失，但在一些地点仍保持局部常见状态。"},{"name":"蓝喉宝石蜂鸟","english_name":"Blue-throated Mountaingem","scientific_name":"Lampornis clemenciae","overview":"蓝喉宝石蜂鸟（英文名：Blue-throated Mountaingem，学名：Lampornis clemenciae），是雨燕目蜂鸟科宝石蜂鸟属的鸟类。体型庞大，为北美洲最大的蜂鸟之一。雄鸟重约10克，比常见的红喉北蜂鸟大三倍以上。分布于美国西南部至墨西哥中部，偏爱混合松林和山地橡树林的边缘地带，夏季在亚利桑那州东南部、新墨西哥州西南部和德克萨斯州西部的高山峡谷中常见。","appearance":"蓝喉宝石蜂鸟体长11.2至12.8厘米，雄鸟体重平均8.4克，雌鸟平均6.8克。雌雄相似，具中等长度的黑色喙，有明显的白色眼后条纹和较细的眼下条纹。雄鸟拥有闪亮的钴蓝色至天蓝色喉部，雌鸟喉部灰色。上体绿色至青铜色，臀部暗橄榄色至蓝黑色，下体灰褐色至淡灰色，尾羽黑色带蓝紫色光泽，外侧两对尾羽尖端白色。","call":"雄鸟会发出高音调单调的啾啾声，雌鸟偶尔也会在繁殖季节唱歌吸引雄鸟注意。","habits":"栖息于湿润森林环境，包括河岸森林、松林和混合针叶林。在繁殖季节和冬季，它们会捕食小节肢动物，以补充花蜜饮食。冬季部分个体在亚利桑那州南部的喂食站过冬。","breeding":"繁殖季节从2月开始至9月结束，雌鸟独自筑巢，巢由软植物纤维和蜘蛛丝构成，外表用苔藓伪装。每窝产卵2枚，孵化期17至19天，幼鸟24至26天离巢。","identification":"与辉紫喉宝石蜂鸟和阔嘴蜂鸟相比，蓝喉宝石蜂鸟体型更大，尾羽白色尖端更明显，雌鸟喉部颜色不同。","protection":"IUCN：LC（无危）","distribution":"分布于美国西南部至墨西哥中部，常见于亚利桑那州东南部、新墨西哥州西南部和德克萨斯州西部的高山峡谷。","other":"蓝喉宝石蜂鸟能发出超声波振动，可能用于迷惑和定位昆虫猎物。"},{"name":"辉紫喉宝石蜂鸟","english_name":"Amethyst-throated Mountaingem","scientific_name":"Lampornis amethystinus","overview":"辉紫喉宝石蜂鸟（英文名：Amethyst-throated Mountaingem，学名：Lampornis amethystinus），是雨燕目蜂鸟科宝石蜂鸟属的鸟类。是中美洲特有种，分布于墨西哥中部至洪都拉斯。以其独特的亮粉色喉咙而闻名。","appearance":"成年雄性辉紫喉宝石蜂鸟拥有深绿色的冠羽和背部，灰色耳羽，以及一条白纹从眼后延伸。喉部呈现明亮的粉紫色，胸部与腹部为暗灰色。尾羽宽而微叉，黑色基部带有灰尖。雌鸟与雄鸟相似，但喉部颜色为肉桂色。幼鸟似雌鸟，但雄鸟幼鸟喉部可能有少许粉红羽毛。","call":"鸣叫声为安静的叽喳声，由两个音节的引子后跟一系列复杂的音符组成，形成极其复杂的叫声模式。雄鸟和雌鸟都会鸣叫。","habits":"辉紫喉宝石蜂鸟栖息于常绿和松栎混交的山地森林内部及边缘，海拔高度从900米至3000米。它们主要以花蜜为食，通过串行访问不同的花蜜源而非守卫固定区域，同时也会摄食昆虫。它们在森林的低层和中层活动。","breeding":"繁殖期间，雄鸟会向雌鸟展示，进行地面平行的空中表演，包括环绕飞行、俯冲并向雌鸟发出鸣叫，然后返回栖木重复这一过程。雌鸟负责筑巢，巢呈深杯状，由植物纤维与蜘蛛丝结合而成，装饰有苔藓和地衣，通常位于离地面1.4至2.4米高的下垂枝条上。孵化期和雏鸟离巢时间未知。","identification":"与蓝喉宝石蜂鸟最为相似，但蓝喉宝石蜂鸟雄鸟的喉部为蓝色，雌鸟的喉部为灰色，且尾羽末端白色部分较大。","protection":"IUCN：LC（无危）","distribution":"主要分布在墨西哥中部至洪都拉斯的中美洲地区，包括常绿和松栎混交的山地森林。","other":"已知的五个亚种中，L. a. margaritae在外观上与其它亚种差异最大，可能被认为是独立物种。"},{"name":"绿喉宝石蜂鸟","english_name":"Green-throated Mountaingem","scientific_name":"Lampornis viridipallens","overview":"绿喉宝石蜂鸟（英文名：Green-throated Mountaingem，学名：Lampornis viridipallens），是雨燕目蜂鸟科宝石蜂鸟属的鸟类。体型较大的蜂鸟，在中美洲的墨西哥南部至萨尔瓦多的山区湿润常绿林中可见其身影。其飞行速度极快，最高可达每小时50公里，且心脏跳动速率惊人，每分钟可达615次。","appearance":"绿喉宝石蜂鸟长约11至12厘米，体重约5.4克。拥有笔直的黑色喙，眼后上方有一条白色条纹，脸颊深色，尾部略微分叉。成年雄鸟上身绿色，臀部青铜色，背部及尾羽覆羽蓝黑色，中央尾羽黑色，其余部分呈淡灰色。喉部白色，带有蓝绿色斑点，胸部白色，腹部灰白，侧翼及腹部两侧有绿色斑点，下尾羽覆羽暗灰色。雌鸟上身翠绿色，喉部白色无斑点，其余特征与雄鸟相似。幼鸟类似雌鸟，但喉部呈淡黄色。","call":"其歌声复杂，包含尖锐的音符和嘶哑的咕噜声，‘tsee-tsee-glr-tsee-glr-tsee-glugluglugluglu-glr-glr-tsee’。叫声包括硬质、嘶哑的‘zzrrt’，短促的‘tsik’和高音的细薄‘see’。","habits":"绿喉宝石蜂鸟栖息于湿润的常绿森林和松栎混交林的内部及边缘地带，海拔介于900至2700米之间。它们在森林各层觅食花蜜，同时通过捕捉昆虫为食。","breeding":"已知繁殖期在3月至7月间，但具体繁殖生态细节尚不清楚。","identification":"与其他蜂鸟相比，绿喉宝石蜂鸟最显著的区别在于飞行时尾巴侧面显现出的大量浅灰色。此外，不同亚种在颜色深度和绿色斑点分布上有细微差异。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥南部至萨尔瓦多，涵盖危地马拉、洪都拉斯等地。","other":"尽管总体上被认为常见，绿喉宝石蜂鸟的栖息地正受到森林砍伐的威胁，且其对人类制造的环境适应性有限。"},{"name":"绿胸宝石蜂鸟","english_name":"Green-breasted Mountaingem","scientific_name":"Lampornis sybillae","overview":"绿胸宝石蜂鸟（英文名：Green-breasted Mountaingem，学名：Lampornis sybillae），是雨燕目蜂鸟科宝石蜂鸟属的鸟类。中型蜂鸟，以绿色胸部和金属光泽的上体为显著特征。分布于中美洲的洪都拉斯和尼加拉瓜，主要栖息于云雾缭绕的山地森林。绿胸宝石蜂鸟与绿喉宝石蜂鸟关系密切，但两者的分布区并不重叠。","appearance":"绿胸宝石蜂鸟身长约10至11厘米，体重介于4至7克之间，雄鸟体型较雌鸟大。其头部和背部呈深绿色金属光泽，带有青铜色臀部。成年雄鸟喉咙闪烁着绿色虹彩，而雌鸟和幼鸟喉咙为白色或淡黄色。白眼线明显，尾巴暗色，外侧尾羽白色。雌鸟下巴和喉咙为淡黄色，腹部灰白色，胸部两侧金属绿色。","call":"其鸣唱为柔和、沙哑的颤音，结尾常带颤音。雄鸟通常从隐蔽的栖木上歌唱，有时在空中或开阔地带发声。觅食时，两性都会发出短暂的、嗡嗡的“shrrrt”叫声。","habits":"绿胸宝石蜂鸟生活在海拔1400至2200米的湿润常绿林和松栎混交林中，季节性地在不同高度间迁移。它们以花蜜和小型昆虫蜘蛛为食，但具体饮食细节尚未明确。这种蜂鸟在中美洲的特定环境中活动。","breeding":"绿胸宝石蜂鸟的繁殖季节大约在11月至次年2月，但关于其繁殖生态学的信息极为有限。","identification":"绿胸宝石蜂鸟与近缘种绿喉宝石蜂鸟的区别在于雄鸟胸部的绿色斑点和雌鸟的白色喉咙。幼鸟具有绿色斑点的喉咙和上体羽毛的红褐色尖端。","protection":"IUCN：LC（无危）","distribution":"绿胸宝石蜂鸟分布于中美洲的洪都拉斯和尼加拉瓜，主要栖息于云雾森林和松栎混交林中。","other":"绿胸宝石蜂鸟的自然历史信息非常有限，尤其是关于其繁殖生态学的知识。"},{"name":"白腹宝石蜂鸟","english_name":"White-bellied Mountaingem","scientific_name":"Lampornis hemileucus","overview":"白腹宝石蜂鸟（英文名：White-bellied Mountaingem，学名：Lampornis hemileucus），是雨燕目蜂鸟科宝石蜂鸟属的鸟类。中等体型的蜂鸟，雄鸟大多绿色，具紫色喉部，眼后有一条细白线，腹部亮白色；雌鸟色彩稍逊，但独特的白色腹部和眼后线同样显著。主要分布在中美洲，从哥斯达黎加北中部至巴拿马西部的加勒比海斜坡。","appearance":"体长约10-11厘米，雄鸟体重约6.2克，雌鸟约5.1克。喙黑色，脚暗粉色。雄鸟头部和面部闪烁着绿色光泽，眼后有一条白色条纹，上体青铜绿色，尾羽青铜色，外侧尾羽末端有灰暗带；喉部中央蓝紫色，其余下体白色，侧面绿斑点缀。雌鸟相似，但头部光泽较弱，喉部白色，侧面有绿色斑点。幼鸟头部、背部、臀部和侧面的羽毛边缘锈色，雄鸟喉部青铜色代替了成年雄鸟的紫色。","call":"其歌声由吱吱声、干涩或湿润的颤音和喷溅声组成。追逐时发出尖锐的喷溅颤音。其他叫声包括反复、略带鼻音的‘deep’声，有时呈连续的‘de-de-drrrrr’颤音序列。","habits":"栖息于凉爽、极度潮湿的亚热带森林的树冠层，沿边下降到灌木层，在边界、空隙和开阔的下层区域活动；偶尔出现在相邻的次生林和半开放植被中。在哥斯达黎加繁殖季节位于海拔700-1400米处。","breeding":"在哥斯达黎加，繁殖期从8月或9月至次年3月。雄鸟通过复杂的鸣唱宣告以花朵为中心的领地。巢穴尚未被描述。","identification":"与同属其他物种相比，白腹宝石蜂鸟的白色腹部和眼后白色条纹是显著的识别特征。","protection":"IUCN：LC（无危）。CITES II级。在当地非常常见，大部分栖息地保持完好，特别是在哥斯达黎加的Braulio Carrillo、Tapantí和Amistad国家公园。","distribution":"分布于中美洲，包括哥斯达黎加和巴拿马的高地，主要在加勒比海斜坡，从哥斯达黎加北中部至巴拿马西部的Veraguas省，局部出现在巴拿马太平洋斜坡。"},{"name":"紫喉宝石蜂鸟","english_name":"Purple-throated Mountaingem","scientific_name":"Lampornis calolaemus","overview":"紫喉宝石蜂鸟（英文名：Purple-throated Mountaingem，学名：Lampornis calolaemus），是雨燕目蜂鸟科宝石蜂鸟属的鸟类。分布于中美洲的尼加拉瓜南部至巴拿马西部的云雾森林。雄鸟拥有耀眼的紫色喉部、蓝色冠羽和眼后白线，而雌鸟虽色彩略逊一筹，但仍引人注目，其亮黄色下体与黑色脸颊和眼后白线相映成趣。","appearance":"雄性紫喉宝石蜂鸟展现出明亮的紫色喉部、蓝绿色的冠羽和一条白色的眼后纹。它们的上体大部分覆盖着金属光泽的绿羽，而雌鸟的上体也是绿色，但下体呈淡红褐色，缺乏雄鸟的紫色喉部。幼鸟与雌鸟相似，但喉部颜色较暗，腹侧为红褐色。","call":"鸣声高亢、尖细且干燥，由一系列喷发和颤音组成。常见的叫声被描述为‘trrrt’或类似‘zeet’的锐利、刺耳声。","habits":"紫喉宝石蜂鸟栖息于中海拔的湿润常绿森林，偏好陡峭的山坡和破碎的地形。它们主要以花蜜为食，雄鸟会守卫花区，驱赶其他蜂鸟。雌鸟较为不具领域性，常采用陷阱式觅食策略。它们还捕食昆虫，以补充营养。","breeding":"繁殖季节在雨季，即每年10月至次年4月。雌鸟独自筑巢、孵化和抚养雏鸟。巢穴为厚壁开放杯状，位于灌木丛或小树上，距地面约2米。每窝产两枚白色蛋，孵化期为17至18天，幼鸟约在22至23天后离巢。","identification":"与雌性白腹宝石蜂鸟相比，紫喉宝石蜂鸟雌鸟具有更绿的尾巴，仅通过良好观察才能安全识别。雄鸟与雌鸟在外表上有明显差异，雄鸟有紫色喉部，雌鸟则无。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从尼加拉瓜南部至巴拿马西部，主要栖息在中海拔的云雾森林中。","other":"紫喉宝石蜂鸟的三个亚种分别适应了不同的地理环境。"},{"name":"白喉宝石蜂鸟","english_name":"White-throated Mountaingem","scientific_name":"Lampornis castaneoventris","overview":"白喉宝石蜂鸟（英文名：White-throated Mountaingem，学名：Lampornis castaneoventris），是雨燕目蜂鸟科宝石蜂鸟属的鸟类。。其显著特征为雄鸟具纯白喉部与金属绿色上体，尾羽颜色因亚种而异：指名亚种呈蓝黑色带暗绿，哥斯达黎加亚种呈全灰色。雌鸟通体下体肉桂栗色，尾羽暗铜绿。本种栖于海拔1 500–3 350 m的湿润山地森林及次生林，分布范围狭窄，仅见于哥斯达黎加南部至巴拿马西部。","appearance":"体长9.3–10.8厘米，重约5–6克。雄鸟略大，头顶金属草绿色闪蓝光，上体深草绿；颏喉纯白，胸具宽阔金属绿与蓝辉带；余下体羽深灰。尾羽颜色依亚种：指名亚种尾羽蓝黑并具暗绿光泽，亚种cinereicauda尾羽全灰。雌鸟上体金属绿带铜色光泽，白色过眼纹显著；通体下体肉桂栗色，尾羽暗铜绿，外侧羽端灰白。幼鸟似成鸟但色泽暗淡，羽缘具淡棕。","call":"雄鸟鸣声为断续而带泡沫感的“噗噗”声。常见叫声包括高而尖细的“pick”或“pipipick”，以及短促的滚奏状“zeet/zeep”。互动时发出刺耳的颤音。飞行时翅振产生低沉嗡鸣。","habits":"留鸟，具微小季节性垂直移动，繁殖后偶降至1 200 米。栖于苔藓、附生植物丰富的常绿阔叶林及边缘、次生林、花园，主要活动于2 400 米。单独或松散小群觅食，从林冠至林下灌丛取食花蜜，亦食小型节肢动物与果实，偶尔盗蜜。雄鸟在花丛建立取食领域，优势大于小紫耳蜂鸟，但次于火喉蜂鸟。","breeding":"繁殖期在哥斯达黎加为8月至翌年4月，巴拿马为12–2月。巢筑于林缘、路边或花园灌木1–3 m高处，由细植物纤维与蕨鳞构成，外覆苔藓与绿色地衣。每窝2枚白色卵，卵长14 mm、宽9.3 毫米，仅雌鸟孵卵并育雏。曾记录于人工灯具上重复筑巢。","identification":"与紫喉宝石蜂鸟雌鸟极似，但后者尾羽金属绿具黑色次端斑，上体带蓝绿辉。白腹宝石蜂鸟下体白色，分布海拔较低。高地大蜂鸟体型显著较大，雄鸟具紫罗兰冠与蓝绿喉，雌鸟下体全灰。","protection":"IUCN: LC（无危）。BirdLife International将两亚种分别评为无危；然而在哥斯达黎加列为CITES附录Ⅱ，巴拿马评为易危，并列入Partners in Flight红名单关注物种。","distribution":"繁殖区：哥斯达黎加南部塔拉曼卡山脉及多塔地区，向西延伸至巴拿马西部奇里基高地。非繁殖期局部下降至较低海拔。","other":"曾与紫喉宝石蜂鸟被视为同种，亦被合并为“多变宝石蜂鸟”。二者在接触区存在杂交，雄鸟出现带紫或蓝边的白色喉羽，比例及遗传影响尚未量化。灰尾宝石蜂鸟曾为亚种。"},{"name":"灰尾宝石蜂鸟","english_name":"Grey-tailed Mountaingem","scientific_name":"Lampornis cinereicauda","overview":"灰尾宝石蜂鸟（英文名：Grey-tailed Mountaingem，学名：Lampornis cinereicauda），是雨燕目蜂鸟科宝石蜂鸟属的小型鸟类，主要分布于中美洲的哥斯达黎加南部，尤其在塔拉曼卡山脉。具有独特的灰尾和绿冠，是当地特有种。","appearance":"灰尾宝石蜂鸟长约12厘米，重约6克。它拥有中等长度的直黑喙，暗色脸颊和眼后白色条纹。雄鸟上体大多为深绿色带青铜光泽，顶冠翠绿色，尾羽灰色；下喉部和喉部白色，颈侧和上胸亮绿色，下胸至腹部区域深灰色。雌鸟全身亮绿色，尾羽灰色；喉部和腹部为深赤褐色，下尾羽覆羽灰色，边缘白或淡黄色。","call":"灰尾宝石蜂鸟发出高音调的叫声，被描述为'ziit或ziip'，同时也有'嘶嘶作响、冒泡感'的歌曲。","habits":"灰尾宝石蜂鸟在繁殖季节结束后会移动到其海拔范围的较低部分。它们主要栖息于橡树林内部、边缘和灌木丛空地，也出现在森林附近的社区花园中。其活动范围从海拔1,500米至林线。它们以多种开花植物的花蜜为食，雄鸟通常在森林内部的寄生植物上觅食，而雌鸟更常在灌木区觅食。雄鸟守护着花丛领域，对抗较小的蜂鸟种类，但在较大种类面前处于劣势，例如火喉蜂鸟。此外，它们也会从叶片上捕食小型节肢动物。","breeding":"灰尾宝石蜂鸟的繁殖季节从10月持续到次年4月。其巢穴特征尚未详细描述，但推测与近亲白喉宝石蜂鸟相似，即由细纤维构成的杯状巢，外层覆盖苔藓和一些地衣。孵化时间和雏鸟离巢时间未知。","identification":"灰尾宝石蜂鸟与白喉宝石蜂鸟在外观上有明显差异，尤其是尾羽颜色和下体色调，以及分布范围的不同。","protection":"IUCN：LC（无危）","distribution":"灰尾宝石蜂鸟仅分布于哥斯达黎加南部的塔拉曼卡山脉。","other":"尽管灰尾宝石蜂鸟被IUCN评估为无危等级，但由于其小范围的分布和未知的人口趋势，它可能受到人类活动如森林砍伐和农业扩张的威胁。现为白喉宝石蜂鸟亚种。"},{"name":"赞氏蜂鸟","english_name":"Xantus's Hummingbird","scientific_name":"Basilinna xantusii","overview":"赞氏蜂鸟（英文名：Xantus's Hummingbird，学名：Basilinna xantusii），是雨燕目蜂鸟科白耳蜂鸟属的鸟类。以匈牙利自然学家约翰·赞特斯（John Xantus de Vesey）的名字命名，主要分布于墨西哥下加利福尼亚州南部。这中等体型、结构紧凑的蜂鸟，拥有白色眼后纹和黑色面罩的鲜明特征。","appearance":"雄性赞氏蜂鸟头部和喉咙常呈黑色，但在特定光线下会闪耀出绿色光泽；雌鸟则具有淡肉桂色的下体。它们的共同特征包括黑色面具、粗厚的白色耳纹、红色嘴基和亮丽的锈色尾巴。雄鸟的冠部暗绿，下巴和前额黑色，喉咙闪烁着翠绿色，上体绿色，尾羽红铜色；雌鸟的冠部暗绿，上体金色绿，尾羽暗红铜色，喉部和下体肉桂色。","call":"雄性赞氏蜂鸟的歌唱是一串安静、粗糙、咕噜般的颤音，有时穿插着响亮的颤音和高音尖叫。物种的叫声包括快速的干燥或微湿的颤音，以及在争斗时发出的金属般尖锐的芯片声。","habits":"生活在干燥的灌木林、橡树和松橡树林中，海拔在150至1500米之间，也出现在海岸沙漠、花园和喂食器附近。它们在各种植被层中觅食花蜜，同时也会捕捉飞行中的小昆虫。","breeding":"繁殖期在北部范围从7月到9月或10月，在南部范围从2月到4月，呈现梯度变化。雌鸟用细植物纤维、蜘蛛网等材料筑杯状巢，悬挂在离地面约1至2米高的细枝末端，通常靠近水源。孵化期约为15至16天，幼鸟大约在孵化后22天离巢。","identification":"在有限的分布范围内无相似物种。其独特的脸谱图案和色彩模式使其易于识别。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥下加利福尼亚州南部，偶尔作为迷鸟出现在美国加州和加拿大不列颠哥伦比亚省。"},{"name":"白耳蜂鸟","english_name":"White-eared Hummingbird","scientific_name":"Basilinna leucotis","overview":"白耳蜂鸟（英文名：White-eared Hummingbird，学名：Basilinna leucotis），是雨燕目蜂鸟科白耳蜂鸟属的鸟类。是山地松林、松栎混交林和松常绿混合林中的常见物种，分布范围从美国西南部延伸至尼加拉瓜。其最显著的特征为黑色面罩旁的宽白色耳纹，雄鸟头部及喉部在特定光线下闪烁着紫绿色光泽。","appearance":"中等体型，雄鸟头部和喉部呈金属紫蓝色，面部两侧为黑色，眼后有一条明显的白色耳纹，上体铜绿色，臀部带锈红色。雌鸟喉部和胸部为淡色，点缀以绿色斑点。尾羽中等长度，末端钝圆或微凹。雄鸟前额和下巴为蓝紫色，喉咙闪烁着绿光，下体白色，饰以绿色斑点。","call":"发出单调的金属般‘chi’tink chi’tink chi’tink’声，或简单‘tink tink’叫声。","habits":"栖息于山地森林内部、边缘和空旷地带，主要在低至中层植被活动，以花蜜为食，也捕食小昆虫。领域性强，会驱赶同种、小型或略大型的其他蜂鸟种类。","breeding":"繁殖季节因纬度而异，北部从3月到8月，南部在10月至12月。雄鸟会在求偶场展示，筑杯状巢，外覆苔藓，通常离地面6米高。雌鸟孵化两枚蛋，孵化期14至16天，雏鸟23至28天后离巢，有时一季可育两窝。","identification":"雄鸟头部和喉部色彩鲜艳，雌鸟喉部白色，缀以绿色斑点，与阔嘴蜂鸟区分，后者体形更细长，喙较长，侧面颜色较暗，下体绿色斑点较少。","protection":"IUCN：LC（无危）","distribution":"主要分布在中美洲，从墨西哥至尼加拉瓜的山地森林中，包括松林、松栎混交林和松常绿混合林。","other":"白耳蜂鸟在繁殖季节结束后，大部分北方个体向南迁徙，南方种群可能有季节性的海拔移动。"},{"name":"红喉蜂鸟","english_name":"Garnet-throated Hummingbird","scientific_name":"Lamprolaima rhami","overview":"红喉蜂鸟（英文名：Garnet-throated Hummingbird，学名：Lamprolaima rhami），是雨燕目蜂鸟科红喉蜂鸟属的鸟类。以其独特的红褐色翅膀和闪亮的玫瑰粉色喉部著称，主要分布在墨西哥中部至洪都拉斯的山区。","appearance":"红喉蜂鸟体型较大，长度约12至12.4厘米，体重介于5.6至7.1克。成年雄鸟上体呈绿色金属光泽，面部黑色，眼后有一小白点，喉部闪耀着玫瑰粉色，胸部为蓝紫色，下体黑色，侧翼有绿斑。雌鸟下体灰暗，喉部可能带有小粉点。两性翅膀均为红褐色，尾羽深紫，外侧有灰色尖端。雄鸟幼鸟与雌鸟相似，但下体颜色更深，胸羽边缘呈淡黄色；雌鸟幼鸟头部羽毛边缘亦为淡黄色。","call":"红喉蜂鸟的鸣唱柔和而粗糙，伴有鼻音和咕噜声，叫声包括鼻音的“nyik”和“choiw”，高音的吱吱声，以及尖锐带点嗡嗡声的“tis-i-tyu-tyu”。","habits":"红喉蜂鸟栖息于热带森林、云雾林、松栎混交林及灌木丛，海拔范围在1,200至3,000米之间，偏好高度在1,500至2,300米的区域。它们在繁殖季节会向更高海拔迁移，非繁殖季则下降到较低海拔。主要以花蜜为食，偏爱Inga和Erythrina属的开花灌木和树木，也会捕食小型昆虫。","breeding":"繁殖期在大西洋沿岸为4月至5月，太平洋沿岸则在12月至次年3月。雌鸟用苔藓、树叶碎片和松针搭建杯状巢，常固定在溪流边土堤上的裸露根系。具体孵化时间和雏鸟离巢时间未知。","identification":"红喉蜂鸟最显著的特征是其红褐色翅膀和玫瑰粉色喉部，与其它蜂鸟种类相比，其翅膀在飞翔时闪烁夺目。雌雄差异明显，雌鸟下体灰暗，雄鸟下体黑色，喉部颜色鲜艳。","protection":"IUCN：LC（无危）；曾被墨西哥政府列为受威胁物种。","distribution":"分布于墨西哥中部（包括Guerrero、Puebla和Veracruz西部）至南部Oaxaca和Chiapas，南至危地马拉、萨尔瓦多和洪都拉斯。","other":"红喉蜂鸟是Lamprolaima属的唯一成员，属名结合了希腊语lampros（光辉）和laimos（喉部），种加词纪念瑞士外交官Henri-Casimir de Rham。"},{"name":"鳞斑蜂鸟","english_name":"Speckled Hummingbird","scientific_name":"Adelomyia melanogenys","overview":"鳞斑蜂鸟（英文名：Speckled Hummingbird，学名：Adelomyia melanogenys），是雨燕目蜂鸟科鳞斑蜂鸟属的鸟类。体型较小的褐色蜂鸟。其最显著的特征为黑色脸颊与淡色眉纹，喉咙斑点状，背部呈绿色，尾巴深色带淡角。广泛分布于南美洲安第斯山脉的云雾森林，常见于海拔1000-3000米之间。","appearance":"体长约8.5-9厘米，重量约3.5-4.9克，性别相似。喙短直黑，脸颊黑，眼后有淡白色条纹，上体青铜绿，喉咙有斑点，胸部绿色，下体灰白或淡黄，尾巴微叉，铜紫色，中央两根尾羽除外，末端白色或淡黄色。幼鸟头部和下背羽毛边缘棕色。亚种在大小、颜色上有细微差异。","call":"鸣唱为单调的高音‘tsee’声，约每秒两音，间或夹杂清脆的颤音。叫声包括重复的干涩颤音‘trr..tr..trrr’，以及升跌的高音系列‘tititititi.ti.ti.tsee..see..see..see...see...see’，总长3-5秒，通常只发一两次，如起飞或追逐时。","habits":"栖息于湿润森林、林缘和水边，海拔1000-2500米，常见于2000米左右。单独觅食，偏好密集灌木较低处。以开花灌木和藤本植物的花蜜为食，如龙胆、倒挂金钟、Psammisia、Palicourea和Bomarea。通过空中捕食或叶面搜寻昆虫。","breeding":"全年均可发现巢穴，主要在1月至5月中旬。巢由苔藓和蛛丝构成，内衬精细植物纤维，建于苔藓覆盖的树干或岩石峭壁，偶尔在洞口，高度1-3米。每窝产两枚白色卵，大小约为12.4mm×8.7mm。孵化期17-18天，由雌鸟承担。雏鸟黑色，背部淡灰色绒毛。孵化后7天内雌鸟持续照料。离巢期20-24天，幼鸟与母鸟共处3-4周。第二年首次繁殖。","identification":"与其他蜂鸟相比，结合小尺寸、直黑喙和方形尾巴，容易区分。亚种在大小、喉部斑点和下体颜色上有所不同。","protection":"IUCN：LC（无危）。CITES II。在安第斯山脉中海拔地区非常常见。","distribution":"分布于南美洲的委内瑞拉至阿根廷西北部，包括哥伦比亚、厄瓜多尔、秘鲁、玻利维亚，尤其在哥伦比亚卡利上方的安第斯山脉西段，密度至少10-12对/平方公里。","other":"曾因野生鸟贸易在哥伦比亚和厄瓜多尔被捕获，直到1970年代中期，现已停止。"},{"name":"厄瓜多尔斑尾蜂鸟","english_name":"Ecuadorian Piedtail","scientific_name":"Phlogophilus hemileucurus","overview":"厄瓜多尔斑尾蜂鸟（英文名：Ecuadorian Piedtail，学名：Phlogophilus hemileucurus），是雨燕目蜂鸟科斑尾蜂鸟属的鸟类。体型较小的蜂鸟，分布于南美洲安第斯山脉东坡的狭窄地带，从哥伦比亚南部延伸至秘鲁东北部。其最显著的特征是宽阔的白色颈环和尾羽上的大量白色。该鸟种绿背白腹，喙直而短。","appearance":"成鸟长约7.3至7.6厘米，体重2.2至3.7克。两性相似，具有短而直的黑色喙，基部呈淡黄色；冠部绿色偏褐，其余上体为草绿色；喉部和胸部白色，带有绿色斑点，胸中部有一白色带；腹部白色；尾羽圆形，中央一对尾羽蓝绿色，其余尾羽蓝色，基部及尖端宽幅白色。幼鸟外观与成鸟类似，但头部和颈部羽毛边缘呈淡褐色。","call":"鸣唱由一系列典型的三个高音刺耳音符组成，随后是连续的颤音“tzeeeee...tzeee.tzew..tititititi”。叫声包括一连串3至4个下降的高音“see”音符，重复的“tsik”音符和高音颤音。","habits":"主要栖息于海拔500至1200米的原始森林边缘和次生林。通常在离地面2至4米的高度觅食，以花蜜为食并从树叶上捕食小型昆虫。","breeding":"繁殖季节从12月至翌年4月。筑巢于2至3米高的地面，巢由细根和蕨叶构成，置于藤蔓或悬垂灌丛中，每窝产卵2枚。","identification":"与雌鸟长靴尾蜂鸟（Booted Racket-tail）和棕臀白尾梢蜂鸟有相似之处，但可通过白色颈环和尾羽的白色特征加以区分。","protection":"IUCN：LC（无危）。被列入《濒危野生动植物种国际贸易公约》（CITES）附录II。","distribution":"分布于南美洲，具体从哥伦比亚南部的普图马约省和卡乌卡省向南延伸至厄瓜多尔东部，直至秘鲁东北部的圣马丁和洛雷托部门。","other":"虽然分布范围有限，但在适宜的栖息地中较为常见。"},{"name":"秘鲁斑尾蜂鸟","english_name":"Peruvian Piedtail","scientific_name":"Phlogophilus harterti","overview":"秘鲁斑尾蜂鸟（英文名：Peruvian Piedtail，学名：Phlogophilus harterti），是雨燕目蜂鸟科斑尾蜂鸟属的特有种。这种小型蜂鸟以其独特的黑白条纹尾羽而得名，分布于秘鲁中部和东南部的安第斯山脉东侧山脚地带。","appearance":"成年秘鲁斑尾蜂鸟体长约7.2至7.5厘米，体重约2.2至2.7克。其特征包括短直的黑色喙，上身绿色，眼后有一白色斑点，喉部、胸部中心和腹部中心呈白色，其余下体部分淡黄色。尾羽中央一对为绿色，末端宽黑带，其余尾羽为淡黄色，带有宽阔的斜向黑色横带。幼鸟与成鸟相似，但头部和颈部羽毛边缘呈淡黄色。","call":"其叫声被描述为一系列尖锐、细薄的音符，音调依次下降，类似于'SIIII siii suuu'。","habits":"栖息于海拔750至1500米的密集苔藓森林内部，尤其常见于1000米左右的地带。主要以开花寄生植物、灌木和小树的花蜜为食，如Rubiaceae、Ericaceae或Gesneriaceae科植物。同时，它也会从叶片表面捕捉小型节肢动物。","breeding":"关于秘鲁斑尾蜂鸟的繁殖生态学信息目前尚不清楚。","identification":"与同属的厄瓜多尔斑尾蜂鸟相比，秘鲁斑尾蜂鸟的尾羽图案更为独特，且分布区域不同。","protection":"IUCN：LC（无危）","distribution":"分布于秘鲁中部和东南部的安第斯山脉东侧山脚地带，具体包括Huánuco、Pasco、Cuzco和Puno地区。","other":"尽管其自然栖息地总体保持良好，但伐木和农业转换对其构成威胁。然而，只要森林和次生林斑块得以保留，秘鲁斑尾蜂鸟能够适应人类对栖息地的改变。"},{"name":"红玉蜂鸟","english_name":"Brazilian Ruby","scientific_name":"Heliodoxa rubricauda","overview":"红玉蜂鸟（英文名：Brazilian Ruby，学名：Heliodoxa rubricauda），是雨燕目蜂鸟科辉蜂鸟属的鸟类。独特的辉蜂鸟，以其鲜艳的粉红色喉部和白色眼后斑点著称。广泛分布于巴西东部和东南部的热带雨林中，常在森林边缘的喂食器附近活动。","appearance":"体型较小，长约10.8至11.3厘米，雄鸟体重7至9.2克，雌鸟5.9至7.1克。雄鸟头部呈绿宝石光泽，背部金铜色，尾部锈色，喉部闪耀着红宝石般的色泽。雌鸟上部草绿色，下部统一肉桂色，尾羽类似雄鸟。幼鸟羽毛边缘带有淡黄色。偶尔可见黑色变异个体。","call":"鸣唱声为连续的'jig chrrrrrr....jig cherrrrrr...jig chrrrrrr'，最常听到的叫声为'jig jig jig'。","habits":"栖息于低海拔的雨林内部、灌木丛、公园和香蕉种植园，高度从海平面至1500米，尤其常见于500米以下的区域。以花蜜为食，包括本土和引进的花卉，同时捕食空中飞虫。","breeding":"繁殖季节为11月至次年3月，筑杯状巢于离地面3至10米的水平枝条上，由雌鸟孵卵，卵数两个，孵化期15至16天，雏鸟约在25天后离巢。","identification":"与其他辉蜂鸟属物种相比，红玉蜂鸟具有独特的粉红色喉部和白色眼后斑点。雄鸟和雌鸟在色彩上有明显差异。","protection":"IUCN：LC（无危）","distribution":"分布于巴西东部和东南部，从巴伊亚州向南延伸至里奥格兰德州。常见于里约热内卢的塞拉多奥尔甘索国家公园和伊塔蒂亚亚国家公园，以及埃斯皮里图圣托州的佩德拉阿祖尔州立公园。","other":"适应性强，常见于人造环境如树荫花园、公园和种植园中。"},{"name":"黑眉辉蜂鸟","english_name":"Velvet-browed Brilliant","scientific_name":"Heliodoxa xanthogonys","overview":"黑眉辉蜂鸟（英文名：Velvet-browed Brilliant，学名：Heliodoxa xanthogonys），是雨燕目蜂鸟科辉蜂鸟属的鸟类。主要分布在南美洲特普伊山脉的高地与特普伊地区，包括委内瑞拉、圭亚那、巴西北部及苏里南的部分地区。以其独特的黑眉和绿色光泽的羽毛著称。","appearance":"黑眉辉蜂鸟体长10至11厘米，体重5.5至7.5克，喙直而黑色上部，下颚橙色带暗尖。雄鸟头部中央呈金色至绿宝石色闪光，眉毛丝绒般黑色，其余面部、颈背及背部为深金色。喉部上方有一块闪光的蓝紫色斑块，胸部和腹部为深金色，尾上覆羽和中央尾羽为青铜至绿宝石色，外侧尾羽为墨绿色。雌鸟颜色较淡，缺乏金属光泽，眉毛非黑色，喉部无蓝紫色斑块，腹部白色，尾羽有白色尖端。幼鸟的头部为暗绿色，边缘带锈色，喉部斑块减小或缺失，下体尤其是喉咙和腹部中心更偏向灰褐色。","call":"发出重复的鼻音“squank”，在飞行中亦会发出高音持续的颤音，音调时高时低。","habits":"生活在南美特普伊山脉的森林内部、边缘、空地以及灌木丛中，海拔高度主要在700至2000米之间，偶尔下至500米。以多种植物的花蜜为食，如Tyleria和一些藤本植物（尤其是杜鹃花科），采用巡逻线觅食或保卫花区的方式。也会捕食昆虫，如双翅目昆虫。雄鸟和雌鸟可能在不同季节利用不同的资源。","breeding":"繁殖季节似乎至少从1月至3月，已知会建造鞍型巢，一窝产两枚白色蛋，其他繁殖信息不明。","identification":"雄鸟与雌鸟的主要区别在于雄鸟有闪光的额头和蓝紫色喉部斑块，雌鸟则无，且下体颜色较淡。亚种willardi的雄鸟翅膀和尾巴较长，雌鸟下体颜色更白，腹部无绿色斑点。","protection":"IUCN：LC（无危）。CITES II。限制分布物种，出现在特普伊生态系统关键区域（EBA）。作为特普伊地区的特有种，分布散乱，包括Duida-Marahuaca和Serranía de la Neblina国家公园（委内瑞拉/巴西）。尽管在特普伊区域内数量不多，但在某些地方如Cerro Tamacuarí和Tafelberg（苏里南东部的特普伊）较为常见。","distribution":"分布于南美洲的委内瑞拉、圭亚那、巴西北部和苏里南的特普伊山脉地区。具体分布范围尚不确定，因为仍有适合其生存的未探索区域存在数据空白。","other":"在巴西的分布范围不明确。"},{"name":"粉喉辉蜂鸟","english_name":"Pink-throated Brilliant","scientific_name":"Heliodoxa gularis","overview":"粉喉辉蜂鸟（英文名：Pink-throated Brilliant，学名：Heliodoxa gularis），是雨燕目蜂鸟科辉蜂鸟属的鸟类。分布于南美洲安第斯山脉东部云雾森林，包括哥伦比亚南部、厄瓜多尔东北部和秘鲁北部。体型较小的蜂鸟，具有绿色上体，白色腹下部，以及雄鸟独特的粉红色喉斑。","appearance":"粉喉辉蜂鸟体长约11至12厘米，雄雌外观相似，拥有几乎笔直的黑色喙，眼后有白色斑点，上体闪耀着绿色光泽，额间有绿色条纹，胸部亦为绿色光泽，腹部呈灰色，下尾覆羽白色，尾部长而叉开，呈青铜绿色。","call":"其鸣叫声被认为是一种反复的鼻音'keuw'，以大约每秒一次的速率发出，也可在飞行或觅食时单独发出。","habits":"生活在海拔250至1050米的湿润山地森林中，据观察可能为留鸟。已知以Psittacanthus和其他寄生花科植物的花朵为食，同时也摄取昆虫。","breeding":"关于繁殖习性的信息非常有限，仅有一例在11月初观察到被雌鸟照料的幼鸟。","identification":"与其他辉蜂鸟相比，体型较小，是唯一具有白色腹下部的种类，雄鸟有明显的粉红色喉斑。","protection":"IUCN：LC（无危）。根据未来亚马逊盆地森林破坏模型预测，其适宜生境在未来三代内（12年）将丧失超过40%，且种群数量预计下降30%以上。","distribution":"分布于南美安第斯山脉东部，包括哥伦比亚（考卡省、普图马约省）、厄瓜多尔（苏昆比奥斯省、纳波省）和秘鲁东北部（洛雷托、亚马逊斯、圣马丁北部）。","other":"在哥伦比亚的几个国家公园内受到保护，但在厄瓜多尔未受保护。"},{"name":"棕甲辉蜂鸟","english_name":"Rufous-webbed Brilliant","scientific_name":"Heliodoxa branickii","overview":"棕甲辉蜂鸟（英文名：Rufous-webbed Brilliant，学名：Heliodoxa branickii），是雨燕目蜂鸟科辉蜂鸟属的鸟类。主要分布于秘鲁东南部的安第斯山脉东坡，偶尔也有未经证实的记录出现在玻利维亚北部。该鸟种以绿色为主色调，雄鸟具有小而醒目的红喉斑，雌鸟则较为暗淡，腹部点缀着白色斑点。","appearance":"棕甲辉蜂鸟体长约11至11.5厘米，雄鸟平均体重约5.8克，雌鸟平均体重约5.4克。其头部丰满，喙直而强壮，颜色为黑色，基部较浅。羽毛色彩丰富，以闪烁的深绿色为主，雄鸟的前额更为亮丽，闪耀着翠绿色光泽。雄鸟还拥有粉红色的喉斑，雌鸟的喉斑较小或可能缺失，颜色更淡，偏向黄色。尾羽中央为绿色，外侧为深蓝色，尾下覆羽明亮的白色是其显著特征之一。翼内侧的飞羽基部呈现肉桂色的红褐色，飞行时尤为显眼。","call":"其鸣叫声为一系列咀嚼音，其间穿插着短暂而快速的下降颤音，叫声则为甜美而下降的‘tew’声。","habits":"栖息于湿润的山地森林内部及边缘，活动范围位于海拔650至1700米之间。主要以花蜜为食，在林下层或林缘觅食，同时也会捕食小型昆虫。关于其迁徙行为，目前尚无确切记录。","breeding":"棕甲辉蜂鸟的繁殖生态尚未被详细记录，其繁殖行为、巢穴构建、交配及育雏过程仍需进一步研究。","identification":"该物种最明显的辨识特征为其翼内侧飞羽的红褐色，这一特征在飞行中尤为突出。与之相似的物种包括紫额辉蜂鸟和粉喉辉蜂鸟，但紫额辉蜂鸟体型更大，缺乏红褐色翼斑，且雄鸟没有粉红色喉斑；粉喉辉蜂鸟与棕甲辉蜂鸟大小相近，但分布区域并不重叠，且没有红褐色的翼内侧飞羽。","protection":"IUCN：LC（无危）","distribution":"主要分布于秘鲁东南部的安第斯山脉东坡，偶尔有记录显示其出现于玻利维亚北部。","other":"虽然棕甲辉蜂鸟在部分地区被认为数量不多到相当常见，但其对栖息地破碎化、退化和干扰有一定的容忍度。然而，森林彻底清除预计会导致局部种群数量下降。"},{"name":"黑喉辉蜂鸟","english_name":"Black-throated Brilliant","scientific_name":"Heliodoxa schreibersii","overview":"黑喉辉蜂鸟（英文名：Black-throated Brilliant，学名：Heliodoxa schreibersii），是雨燕目蜂鸟科辉蜂鸟属的鸟类。体型较大，拥有粗壮的喙。雄鸟具黑色腹部和喉咙，后者边缘镶以紫色，有时仅显暗色。雌鸟金色绿下体，紫色喉部斑块，伴以显著的淡褐色髭纹。分布于南美洲亚马逊雨林东部，常被吸引至喂食器旁。其鸣唱独特，为持续五秒以上的下降颤音。","appearance":"体长11.5至13厘米，雄鸟体重约9.9克，雌鸟7.1至8.5克。喙几乎笔直，颜色深沉，长约2.8厘米。雄鸟前额闪烁绿光，头顶及背部闪耀绿色，下体黑色，喉部下方有一紫色斑点，边缘环绕绿色光泽带；尾羽极长，深叉开，呈钢蓝色。雌鸟似雄鸟，但有灰白色至锈色的髭纹，下体灰色，点缀青铜绿色斑点，中央尾羽绿色，尾叉较浅。幼鸟与雌鸟相似，但髭纹色彩更深。","call":"其鸣唱独特，为连续下降的颤音，持续约4至5秒。亦会发出单一的‘chup’声，重复频率约为每秒一次。","habits":"栖息于热带低地和山麓森林内部，海拔介于400至1000米，局部可达1450米，甚至偶尔1900米。主要在阴凉下层2至4米高度觅食，偏好吸食如杜鹃花科和锦葵科开花植物的花蜜，同时通过空中捕食昆虫。","breeding":"繁殖季节至少从二月延续至五月，但可能延至十月。雌鸟孵化两枚白色蛋，其他繁殖生物学信息未知。","identification":"雄鸟黑色喉部与紫色斑点，雌鸟独特的髭纹和青铜绿色下体，均为识别特征。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，具体包括哥伦比亚东南部、厄瓜多尔东部、秘鲁东北部至圣马丁省，以及巴西西北部亚马逊河上游流域。在秘鲁中部和东南部也有分布，包括帕斯科、胡宁至库斯科北部，以及马德雷德迪奥斯西部。","other":"黑喉辉蜂鸟的分类存在争议，两个亚种被一些权威机构视为独立物种。"},{"name":"古氏蜂鸟","english_name":"Gould's Jewelfront","scientific_name":"Heliodoxa aurescens","overview":"古氏蜂鸟（英文名：Gould's Jewelfront，学名：Heliodoxa aurescens），是雨燕目蜂鸟科辉蜂鸟属的鸟类。中等体型的蜂鸟，广泛分布于亚马逊雨林西部至中部，从哥伦比亚南至玻利维亚，东至委内瑞拉南部和巴西中部。其独特的橙色胸带和紫色前额使它在热带雨林中易于识别。该物种相对罕见，生活在成熟湿润森林的阴凉下层，偶尔造访花蜜喂食器。","appearance":"古氏蜂鸟拥有厚重的体态和粗壮的黑色喙。雄鸟拥有闪光的绿色羽毛，巨大的橙色胸斑和紫色前额，下巴为黑色；雌鸟较暗淡，缺乏黑色下巴，具有短而白色的髭纹。雄鸟的前额呈闪亮的蓝紫色，上喉和下巴为天鹅绒般的黑色，胸部有宽阔的橙色带；雌鸟相似但色泽较淡，前额蓝色减少甚至缺失，下巴为白色或淡黄色。","habits":"古氏蜂鸟偏好潮湿常绿森林的阴凉地带，如树倒处和森林溪流边缘的光斑，避开次生林和森林边缘。它们广泛分布在低地到安第斯山脉东部山脚，海拔从250米至1150米，有时高达1450米。物种具有定居性，但在某些地区有范围扩展的记录。","breeding":"关于繁殖生物学知之甚少，推测繁殖季节可能在6月至9月间，雌鸟孵化两枚蛋。雌鸟标本在2月和4月显示发达的生殖腺，但2月获得的一只雄鸟标本生殖腺较小。","identification":"古氏蜂鸟在亚马逊范围内因其明显的橙色胸带而高度独特，与其他物种明显不同。雌雄异型，雄鸟有黑色下巴和宽阔的橙色胸带，雌鸟具有短而白色的髭纹。","protection":"IUCN：LC（无危）","distribution":"古氏蜂鸟广泛分布于南美洲亚马逊雨林的西部和中部，包括哥伦比亚、委内瑞拉南部、厄瓜多尔、秘鲁、玻利维亚和巴西西北部。"},{"name":"棕胸辉蜂鸟","english_name":"Fawn-breasted Brilliant","scientific_name":"Heliodoxa rubinoides","overview":"棕胸辉蜂鸟（英文名：Fawn-breasted Brilliant，学名：Heliodoxa rubinoides），是雨燕目蜂鸟科辉蜂鸟属的鸟类。主要分布于南美洲安第斯山脉的哥伦比亚、厄瓜多尔和秘鲁。其特征是拥有温暖的肉桂色下体和绿色上体，独特的粉红色喉部斑块，雄鸟的粉红喉斑较雌鸟更为明显。","appearance":"棕胸辉蜂鸟体长约11厘米，雄鸟上体呈闪亮的铜绿色，翼覆羽更显铜色；尾羽为铜绿色，微叉状。下体主要是肉桂色，喉部和胸部散布着绿色斑点。雄鸟下喉中心有小片玫瑰紫色。雌鸟与雄鸟相似，但喉部通常为肉桂色，粉红色喉斑较小或缺失。","call":"发出两种不同的声音，一系列‘tchik’音符和常见的‘swi-swi-swi-swu’叫声。","habits":"生活在热带森林，主要栖息于海拔1,000至2,200米的云雾林内。通常单独活动，大部分时间在林下层到中层。以花蜜为主食，同时摄取昆虫和蜘蛛以补充蛋白质。","breeding":"繁殖期，雄鸟会进行U形飞行的求偶展示。雌鸟在灌木或树上建造巢穴，用植物纤维、蛛网、动物毛发和绒羽制成，外部覆盖苔藓伪装。产两枚白色蛋，孵化期约12天，雏鸟约20天离巢。","identification":"与同域内的其他蜂鸟种类区别明显，无类似体型和颜色组合的物种。雌雄差异在于雌鸟喉部粉红斑块较小或缺失。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲安第斯山脉，从哥伦比亚至秘鲁，主要在云雾森林中。"},{"name":"绿顶辉蜂鸟","english_name":"Green-crowned Brilliant","scientific_name":"Heliodoxa jacula","overview":"绿顶辉蜂鸟（英文名：Green-crowned Brilliant，学名：Heliodoxa jacula），是雨燕目蜂鸟科辉蜂鸟属的鸟类。体型较大的蜂鸟，广泛分布在中美洲南部和南美洲西北部的多个山脉，常见于森林及其边缘地带，甚至会造访人为设置的喂食器。雄鸟通体呈现璀璨的翡翠绿色，雌鸟则具有独特的白色髭纹和眼后斑点。","appearance":"雄鸟全身闪耀着翡翠绿至蓝绿色的光泽，喉部有一小块蓝色金属光泽的斑块，仅在某些角度可见。雌鸟胸部点缀着绿色斑点，显眼的白色髭纹和眼后斑点是其显著特征。成年雄鸟长约12-13厘米，雌鸟稍小，约为10.5-12厘米。幼鸟的冠部和下体呈暗铜绿色，下颚和髭区明亮的淡黄色，尾羽分叉较浅。","call":"绿顶辉蜂鸟发出响亮而尖锐的kyew或tyew叫声。在求偶展示中，雄鸟会发出tseek、tseek、tseek的叫声。追逐时，它们会发出响亮的喷嚏声和尖叫声。","habits":"绿顶辉蜂鸟栖息于多种景观，包括湿润的亚高山和高山森林内部、边缘和空地、成熟的次生林以及花园。它们主要在森林的中上层觅食，以Marcgravia藤蔓为主要蜜源，有时也会采取陷阱线觅食策略，访问一系列开花植物。通常它们会在花朵上停留吸食而非悬停。","breeding":"在哥斯达黎加，繁殖季节可能从7月或8月持续到1月，在哥伦比亚则是从5月到9月。雌鸟单独孵化两个白色的椭圆形蛋，巢由植物纤维和树蕨鳞片构成，置于离地面2至6米高的细斜枝上。","identification":"在中美洲范围内，雄性绿顶辉蜂鸟较为独特，而雌鸟的白色髭纹有助于将其与其他具有绿色斑点下体的物种区分开来。南美洲的雄性绿顶辉蜂鸟与雄性紫额辉蜂鸟通过冠部的颜色差异区分，雌鸟则通过尾巴分叉的程度来识别。","protection":"IUCN：LC（无危）","distribution":"绿顶辉蜂鸟分布在中美洲的哥斯达黎加至南美洲的厄瓜多尔。具体而言，指名亚种遍及巴拿马东部至哥伦比亚的三个安第斯山脉；H. j. henryi分布于北至哥斯达黎加，南至巴拿马的Coclé省；H. j. jamersoni分布于哥伦比亚的纳里尼奥省，可能还包括卡乌卡省北部，向南沿厄瓜多尔西部安第斯山脉至少到达埃尔奥罗省。"},{"name":"皇辉蜂鸟","english_name":"Empress Brilliant","scientific_name":"Heliodoxa imperatrix","overview":"皇辉蜂鸟（英文名：Empress Brilliant，学名：Heliodoxa imperatrix），是雨燕目蜂鸟科辉蜂鸟属的鸟类。体型较大、色彩斑斓的蜂鸟，主要分布在南美洲安第斯山脉的云雾森林中，从哥伦比亚西部至厄瓜多尔西北部。拥有厚实的喙和长长的尾巴，腹部闪耀着金色光泽。","appearance":"皇辉蜂鸟雄鸟体长约15至17厘米，重约9.3克，雌鸟略小，体长12至13.5厘米，重约8.3克。雄鸟前额、面颊、喉部和胸部主要呈深绿色闪光，喉部中央有一块淡紫色斑块；冠部和颈背深绿色，其余上体呈现暗铜绿色，腹部闪烁金绿色。雌鸟上体呈铜绿色，喉部和胸部中央灰白色，密布铜绿色斑点，侧腹固有色铜绿，腹部金绿色。幼鸟头部、喉部和胸部颜色较暗，呈暗铜绿色，喉部中间灰白色，腹部的金绿色比成年鸟更暗淡。","call":"皇辉蜂鸟会发出重复的单个“tsit”音符，大约每秒一次，也会在盘旋或觅食时单独发出。","habits":"皇辉蜂鸟偏好非常湿润的森林环境，常访问Marcgravia和Marcgraviastrum等植物的花序，以吸取花蜜为主食，同时也会捕捉小型昆虫。它们的活动范围从中层到树冠层，偶尔雌鸟会在林下层觅食。","breeding":"繁殖季节通常从1月至4月。已知的巢穴是由树蕨鳞片和其他植物材料构成的小杯状结构，内部衬有柔软的种子绒毛。巢穴可能位于森林边缘的棕榈叶上或废弃小屋下的钢筋上。","identification":"皇辉蜂鸟雄鸟的喉部中央有独特的淡紫色斑块，而雌鸟的喉部和胸部中央则为灰白色，带有铜绿色斑点。幼鸟的头部、喉部和胸部颜色较暗，呈暗铜绿色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，从哥伦比亚中西部的Chocó省向南延伸至厄瓜多尔西北部的Pichincha省。在哥伦比亚的Tatamá、Munchique和Farallones de Cali国家公园以及La Planada保护区常见，厄瓜多尔的Mindo地区也有记录。","other":"皇辉蜂鸟的非常湿润的森林栖息地目前仍保持相对完好，包括多个保护区。"},{"name":"紫额辉蜂鸟","english_name":"Violet-fronted Brilliant","scientific_name":"Heliodoxa leadbeateri","overview":"紫额辉蜂鸟（英文名：Violet-fronted Brilliant，学名：Heliodoxa leadbeateri），是雨燕目蜂鸟科辉蜂鸟属的鸟类。主要分布在南美洲的委内瑞拉至玻利维亚西北部。这体型壮实、喙粗的蜂鸟，拥有闪亮的绿宝石色羽毛，雄鸟具有蓝色或紫色的额头，雌鸟则有白色的胸前斑纹和髭纹。通常独居，生活在中海拔的云雾森林中。","appearance":"紫额辉蜂鸟身长11至13厘米，雄鸟体重7.1至8.5克，雌鸟体重6.6至7.5克。喙几乎笔直，呈黑色。雄鸟上体呈青铜绿色，颈部转为铜色，额头闪耀蓝光；雌鸟上体铜绿色，前额闪烁绿色，下体主要为白色，向腹部渐变为淡黄色，喉部和胸部密布着闪光的绿色斑点。尾羽末端有白色尖端。","call":"紫额辉蜂鸟的疑似歌声是一系列连续的尖锐“chup”或“tchep”音符，每秒约一音节。还有一种重复的、明亮的下降音调“whee-tsee-tsee-tsew”，听起来像是断断续续的啾啾声。","habits":"紫额辉蜂鸟主要栖息于热带和亚热带地区的云雾森林内部和边缘，也会出现在灌木丛、林间空地、次生林和咖啡种植园。它们偏好在森林较低至中层觅食，通常低于10米的高度，单独觅食，以花蜜和捕食的昆虫为食。","breeding":"繁殖季节从1月持续到5月，但关于其繁殖生态的详细信息尚未发表。","identification":"雄鸟parvula亚种额头更偏紫色，腹面颜色较淡；sagitta亚种雄鸟额头蓝色，胸带常有蓝色色调，雌鸟腹部近似白色；otero亚种雄鸟上体铜色较少，雌鸟腹部褐色，前额闪光绿斑几乎缺失。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，自委内瑞拉至玻利维亚西北部。"},{"name":"大蜂鸟","english_name":"Rivoli's Hummingbird","scientific_name":"Eugenes fulgens","overview":"大蜂鸟（英文名：Rivoli's Hummingbird，学名：Eugenes fulgens），是雨燕目蜂鸟科大蜂鸟属的鸟类。曾名为Magnificent Hummingbird，大型蜂鸟。体型约为11至14厘米，重量约6至10克，雄鸟比雌鸟略大。主要分布于墨西哥南部至尼加拉瓜北部，以及美国西南部。","appearance":"雄性大蜂鸟背部呈绿色青铜色，尾羽尖端黑色，冠部紫色，喉咙处的蓝绿色羽毛在阳光下闪烁，头部其余部分黑色，眼后有一小块白色斑点。胸部为绿色青铜色，腹部灰白。雌鸟背部青铜绿色，腹面颜色较暗淡，眼后有白色条纹。幼鸟外观类似雌鸟，但颜色更深、更棕色。","call":"可能的鸣叫声包括高音或响亮的‘tchik’或‘tcheep’声，另一种可能是短暂的音符串，音调起伏不定。雄鸟会发出单个或连续的‘chip’声，无论是在栖息还是飞行中。在争斗或警戒时，会发出快速连续的‘chip’声。","habits":"栖息于松栎林、云雾森林的内部、边缘和空地，海拔高度从1500米到树线附近。在墨西哥至尼加拉瓜的山地地带繁殖，夏季迁徙至美国西南部。以多种开花植物的花蜜为食，也捕食小型昆虫，昆虫在其饮食中所占比例高于其他北美的蜂鸟。","breeding":"繁殖季节在美国从五月持续至七月，可能在萨尔瓦多全年发生。筑巢材料包括柔软的羽毛、苔藓，用蜘蛛丝粘合，外部覆盖苔藓。巢通常建在水平枝条上或树叉中，常位于枫树和悬铃木上，靠近溪流，距离地面至少6米。雌鸟单独孵化两个白色蛋，孵化期约为15至19天，小鸟大约25天后离巢。","identification":"与蓝喉宝石蜂鸟相比，大蜂鸟头部更大，喙更长，尾巴末端白色斑点较小。与高地大蜂鸟相比，其喉咙处羽毛颜色更偏向蓝色，下体颜色为黑色而非深绿色。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要在墨西哥北部至尼加拉瓜北部，非繁殖区包括美国西南部的亚利桑那州和新墨西哥州，以及墨西哥的奇瓦瓦州、索诺拉州等地。夏季在德克萨斯州的奇索斯山脉有记录，但未确认繁殖。","other":"在部分范围内，大蜂鸟在地位上低于蓝喉蜂鸟。它与许多其他蜂鸟物种共存，如黑颏蜂鸟（Archilocus alexandri）、宽尾煌蜂鸟、辉紫喉宝石蜂鸟等。"},{"name":"高地大蜂鸟","english_name":"Talamanca Hummingbird","scientific_name":"Eugenes spectabilis","overview":"高地大蜂鸟（英文名：Talamanca Hummingbird，学名：Eugenes spectabilis），是雨燕目蜂鸟科大蜂鸟属的鸟类。体型庞大的蜂鸟，曾被称为Magnificent Hummingbird，后分为大蜂鸟和高地大蜂鸟两个物种。主要分布于哥斯达黎加和巴拿马西部的高山云雾森林中，雄鸟具有独特的紫冠蓝喉，雌鸟具有灰白色腹部。","appearance":"雄性高地大蜂鸟全身绿色，头部在特定光线下呈现紫色冠和蓝绿色喉部，雌鸟颜色较暗淡，腹部灰色并带有绿色侧边。两性皆有显著的白色眼后斑点。雌鸟的喙比雄鸟更长且稍微向下弯曲。体长约13厘米，雄鸟体重约10克，雌鸟约8.5克。","call":"其鸣声被描述为柔和低沉的咕噜声和刮擦般的嗡嗡音符，争斗时发出快速连串的高亢清澈液滴声，另一种叫声则较为浑厚滚动。","habits":"栖息于高山橡树林及其边缘，偏好林间空地和次生林。通常定居，部分个体可能进行规律性迁移至较低海拔。以多种开花植物的花蜜为食，雄鸟会保卫花区，而雌鸟通过巡视花丛觅食。也会捕食小型节肢动物。","breeding":"繁殖季节在哥斯达黎加从11月至3月，筑巢于竹枝末端，距地面1.5至3米，由植物纤维构成并覆盖苔藓和地衣。孵化期未知，雏鸟至少需25天才能离巢。","identification":"雄性高地大蜂鸟与大蜂鸟相似，但前者喉部更为蓝绿，胸部和腹部呈深绿色。雌性高地大蜂鸟体型较大，喙较长，与绿顶辉蜂鸟和starthroats有明显区别。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从哥斯达黎加的Cordillera Central和Cordillera de Talamanca山脉到巴拿马西部的Volcán Barú山系，主要栖息于海拔2000至2500米以上的高山森林。","other":"尽管分布广泛且相对常见，但其自然历史研究仍不充分。"},{"name":"剪尾蜂鸟","english_name":"Scissor-tailed Hummingbird","scientific_name":"Hylonympha macrocerca","overview":"剪尾蜂鸟（英文名：Scissor-tailed Hummingbird，学名：Hylonympha macrocerca），是雨燕目蜂鸟科剪尾蜂鸟属的鸟类。独特的蜂鸟，以其极长的剪刀状尾巴著称，通体绿色，喙呈弯曲状，眼后有一白色斑点。雄鸟具有蓝色额部，黑色又长又叉的尾巴，与紫额辉蜂鸟相似，但尾羽更长。雌鸟尾巴较短但仍呈叉状，喉部白色，胸部绿斑点缀，腹部淡黄色，与长尾蜂鸟雌鸟相像。仅分布于委内瑞拉东北部的帕里亚半岛，属于极度濒危物种。","appearance":"雄性剪尾蜂鸟长约19厘米，包括9至10厘米的尾部，体重约7至7.5克。雌鸟略小，12至13厘米长，体重6.5至8克。雄鸟的前额和冠中部为闪光的紫色，其余部分为深绿色接近黑色。背部金属草绿色，颈部带有金色光泽。喉咙和胸部为闪光的翡翠绿色，下体颜色较暗，变为黑色，腹部带绿色斑点。雌鸟上体为深绿色，喉部和胸部白色，带绿色斑点，腹部为红栗色，尾部中央羽毛绿色基部，钢蓝色末端，外侧羽毛为肉桂色，尖端为米色。","call":"剪尾蜂鸟发出短暂的脉冲式叫声，重复每2至2.5秒一次，听起来像是'tsi-si-sip...tsi-si-sip...'","habits":"剪尾蜂鸟栖息于潮湿的苔藓森林和云雾林，高度在500至1200米之间，偶尔出现在森林边缘和小片开阔地带。以花蜜为主食，偏好凤梨科植物，其次为Heliconia和Costus属植物。雌鸟会建立采食领地。它们也会从植被上捕食节肢动物或在空中捕捉。","breeding":"关于剪尾蜂鸟的繁殖生态知之甚少。","identification":"雄性剪尾蜂鸟与紫额辉蜂鸟类似，但其尾羽更长且更叉；雌鸟与长尾蜂鸟雌鸟相似，但尾部形状和颜色有别。","protection":"IUCN：EN（濒危）","distribution":"剪尾蜂鸟仅分布于委内瑞拉东北部的帕里亚半岛，包括从胡莫山、帕塔奥山、遗忘山和阿祖尔山向东的地区。","other":"剪尾蜂鸟是该地区的特有种，依赖于原始的云雾林环境。"},{"name":"紫罗兰胸蜂鸟","english_name":"Violet-chested Hummingbird","scientific_name":"Sternoclyta cyanopectus","overview":"紫罗兰胸蜂鸟（英文名：Violet-chested Hummingbird，学名：Sternoclyta cyanopectus），是雨燕目蜂鸟科紫罗兰胸蜂鸟属的鸟类。单型属。其体型中等偏大，分布于南美洲委内瑞拉北部至哥伦比亚东北部的特定区域，偏好湿润的山地森林与次生林。该鸟种以其独特的紫罗兰色胸部斑块和绿色光泽的羽毛著称。","appearance":"紫罗兰胸蜂鸟身长11.4至13厘米，体重雄鸟7至9.4克，雌鸟4至10.3克。头部略向下弯曲的黑色喙，雄鸟较长。雄鸟上体呈闪光草绿色，喉咙闪烁着翡翠绿，胸部有一片闪耀的紫罗兰蓝色斑块，其余腹部灰褐色带金色绿点，两胁有金绿色斑点；尾巴青铜色，最外侧羽毛尖端有白色。雌鸟上体类似雄鸟，下体主要灰白，胸部有绿色斑点，腹部中心赤褐色。幼鸟似雌鸟。","call":"发出一系列尖锐重复的“chit!”音符，节奏约每秒一次，有时连续10至20秒或更长，偶尔混合“chip”和“weet”音符，以及短促的吱吱声。觅食时会发出响亮的断奏式叽叽声。","habits":"栖息于低地湿润的山地森林和林地，尤其偏爱滑坡或老树倒下的开阔地带，也见于成熟的次生林和咖啡种植园。活动范围从海平面到2000米，但低于700米较为罕见。通常在森林深处密集植被中觅食，很少上升至树冠层，不会与其他蜂鸟群聚于大规模开花事件。偶尔访问人工喂食器。","breeding":"繁殖季节在委内瑞拉西北部为3月至7月，在委内瑞拉北部为11月至12月。杯状巢置于离地平均1.9米高的细藤或小蕨上，由柔软植物纤维构成，外层覆盖苔藓、树蕨鳞片和地衣。每次产两枚白色蛋，孵化期约20.4天，由雌鸟独自完成。雏鸟异步孵化，孵化后15至17天开始发育主羽，喂养频率平均每小时3.3次，平均离巢体重7.23克。","identification":"与棕尾刀翅蜂鸟区别在于后者尾部有锈色；与紫额辉蜂鸟区别在于后者较小，喙直，雄鸟下部紫色彩斑较小；雌鸟与金尾星额蜂鸟雌鸟相比，后者喙较长直，尾部主要为金色锈色。","protection":"IUCN：LC（无危）；CITES II级；限制分布物种，出现在委内瑞拉特定生态区。在当地常见，但在安第斯山脉范围内稀少且分布零散。适应次生林和人为环境。","distribution":"主要分布在委内瑞拉北部和西部，包括沿海山脉至Miranda州，向西南延伸至Lara、Mérida和Táchira州的安第斯山脉，稍入哥伦比亚Norte de Santander省。","other":"直到最近才被确认在哥伦比亚的存在，之前被认为是委内瑞拉特有种。"},{"name":"褐颊白尾蜂鸟","english_name":"Rufous-gaped Hillstar","scientific_name":"Urochroa bougueri","overview":"褐颊白尾蜂鸟（英文名：Rufous-gaped Hillstar，学名：Urochroa bougueri），是雨燕目蜂鸟科白尾蓝胸蜂鸟属的鸟类。别名源于脸部的红褐色条纹与独特的白色尾羽。分布于南美洲安第斯山脉西侧，自哥伦比亚西南部至厄瓜多尔西北部。此鸟体型较大，色彩独特。","appearance":"体长13-14厘米，体重8.5-12.5克。两性相似，拥有长而直的黑色喙。上体呈铜绿色，脸部有红褐条纹，喉部和胸部为虹彩蓝色，腹部灰暗。中央及最外侧尾羽黑色，其余白色边缘灰暗。幼鸟头部羽毛带淡黄色边缘。","call":"鸣声被描述为一系列连续的单个“swit”或“tsit”音符，速率约为每秒1-2个音符。警戒时发出流利的“twit”声，以长序列重复。","habits":"栖息于成熟的山地森林内部及边缘，偏好靠近溪流的环境。主要以开花的Inga树、Bomarea、Psammisia和Cavendishia植物的花蜜为食，同时在溪流上方或森林空地上捕食昆虫。","breeding":"繁殖季节为12月至翌年3月，巢为杯状，由苔藓和地衣构建，通常位于高树的垂直枝上，距地面8-12米。每窝产两枚白色蛋，孵化期16-18天，由雌鸟承担，雏鸟黑色，背部稀疏覆盖淡色绒毛，离巢期为23-25天。","identification":"与紫冕蜂鸟相比，其体型更大，喙更长，虹彩蓝色仅限于喉部，且尾羽具有明显的白色部分。","protection":"IUCN：LC（无危）。被列入CITES II。在哥伦比亚较为常见，在厄瓜多尔则较为罕见。","distribution":"分布于南美洲安第斯山脉西侧，从哥伦比亚西南部（Chocó省南部）到厄瓜多尔西北部（Pichincha省南部）。","other":"能适应人为环境，如牧场，只要周围保留有森林斑块。在哥伦比亚的Río Ñambi和La Planada保护区定期被记录。"},{"name":"铜腰白尾蜂鸟","english_name":"Green-backed Hillstar","scientific_name":"Urochroa leucura","overview":"铜腰白尾蜂鸟（英文名：Green-backed Hillstar，学名：Urochroa leucura），是雨燕目蜂鸟科白尾蓝胸蜂鸟属的鸟类。曾在分类上与安第斯山脉西坡的褐颊白尾蜂鸟视为同一物种。其显著特征为整体呈现铜绿色，喉部闪耀着蓝色光泽，拥有非常长且直的黑色喙。分布于南美洲的哥伦比亚南部、厄瓜多尔东部及秘鲁东北部的安第斯山脉东坡，常在海拔1100至2000米处活动。","appearance":"体长约13至14厘米，喙长约为3厘米，体重约8.7克。两性相似，雌鸟可能略显暗淡。上体为青铜绿色，尾羽中央为青铜色，其余部分为白色，边缘带有灰色。幼鸟与成鸟相似，但头部羽毛边缘带有点缀的淡黄色。","call":"发出连续的单音节“tseee”、“tsing”或“seeuw”声，每秒约1至1.5个音节。还有一种液态的“twit”声，有时会重复成一系列长序列。","habits":"栖息于成熟的山地森林内部和边缘，偶尔在灌木斜坡上活动，通常靠近溪流。在哥伦比亚和厄瓜多尔，常见于海拔1600至2800米之间，而在秘鲁则限于800至1500米。通常在森林较低和中间层次觅食，偶尔到达树冠层。","breeding":"繁殖生态尚未详尽研究，但在9月于秘鲁东北部收集到一只处于繁殖状态的个体。","identification":"与棕尾刀翅蜂鸟或那波刀翅蜂鸟相比，具有更直的喙和明显的白色尾羽。","protection":"IUCN：LC（无危）。在哥伦比亚相对常见，在厄瓜多尔则罕见至非常见，在秘鲁东北部则稀少且局部分布。","distribution":"分布于哥伦比亚南部（纳里尼奥省，卡奎塔省有一目击记录）、厄瓜多尔东部和秘鲁东北部（圣马丁省北部）。"},{"name":"黄尾冕蜂鸟","english_name":"Buff-tailed Coronet","scientific_name":"Boissonneaua flavescens","overview":"黄尾冕蜂鸟（英文名：Buff-tailed Coronet，学名：Boissonneaua flavescens），是雨燕目蜂鸟科冕蜂鸟属的鸟类。主要分布在南美洲，自委内瑞拉至厄瓜多尔的云雾森林地带，海拔高度约在1,500至2,400米之间。体型中等，羽毛大多呈深绿色，下翼和尾巴显著带有黄褐色。","appearance":"体长约11至12厘米，体重7.3至8.8克。喙短而直，呈黑色，两性相似。雄鸟上身闪耀着绿色光泽，喉部和胸部亦为绿色，其余腹部为黄褐色，带绿色斑点，翅膀下覆羽为肉桂色，飞行时尤为显眼。中央尾羽为青铜色，其余尾羽为黄褐色，边缘和尖端带有青铜色。雌鸟下体更偏黄褐色，尾羽青铜色部分较窄。幼鸟似雌鸟，但臀部羽毛边缘呈棕色。","call":"发出连续的高音‘tsit’音符，频率约为每秒0.6至1个音符。此外，还发出吱吱声，伴随上升的笛音和断续的颤音，尤其在社交互动中。","habits":"栖息于湿润至潮湿的山地森林、云雾林和矮林，以及上亚热带和低温带的开阔和灌木丛生地带，海拔在2,000至3,500米之间。通常在树木的中上层觅食，以Cavendishia、Palicourea、Disterigma和Huilaea等植物为主食。捕食昆虫时，会从高处的栖息点快速出击。具有强烈的领土意识，好斗。","breeding":"繁殖期在哥伦比亚为4月至8月，在某些地区可能为11月至3月。巢穴为杯状，主要由苔藓和地衣构成，通常悬挂在离地面3至10米高的树枝上。一窝产卵2枚，由雌鸟孵化。","identification":"与同属其他物种如栗胸冕蜂鸟和紫冕蜂鸟相比，黄尾冕蜂鸟的下翼和尾巴颜色更为显著。亚种tinochlora的黄褐色部分带有独特的肉桂色调，尾羽尖端的青铜色比指名亚种更宽。","protection":"IUCN：LC（无危）","distribution":"分布于委内瑞拉至厄瓜多尔的安第斯山脉区域，包括哥伦比亚的三个安第斯山脉。在西南哥伦比亚向南延伸至厄瓜多尔的西坡，以及中部厄瓜多尔的东坡。","other":"黄尾冕蜂鸟在某些地区如厄瓜多尔西部的Mindo旧路沿线较为常见，密度至少达到1至2对/km²。"},{"name":"栗胸冕蜂鸟","english_name":"Chestnut-breasted Coronet","scientific_name":"Boissonneaua matthewsii","overview":"栗胸冕蜂鸟（英文名：Chestnut-breasted Coronet，学名：Boissonneaua matthewsii），是雨燕目蜂鸟科冕蜂鸟属的鸟类。广泛分布于南美洲的安第斯山脉，自哥伦比亚东南部至秘鲁南部，同时在厄瓜多尔西部和秘鲁西北部的安第斯山脉西侧也有分布。这种蜂鸟体型健壮，拥有相对较短的喙，最显著的特征是其绿色的上体和兜帽状头部，以及醒目的栗色胸部、腹部和尾巴。","appearance":"成年栗胸冕蜂鸟体长约10.5至13厘米，体重约6.5至8.3克。性别相似，具有一身金属绿色的上体，带有眼后白色斑点，尾部呈微凹状。雄鸟的喉部有黄绿色斑点，下体为红栗色，两侧有少许绿色斑点；中央尾羽为青铜色，其余尾羽为红栗色，带青铜色尖端。雌鸟与雄鸟类似，但下体颜色略淡，喉部绿斑较少，露出底色。","call":"据描述，其鸣叫声包括高亢、清澈的液体音节，快速甜美的颤音，以及各种吱吱声。","habits":"生活在潮湿的山地森林内部及边缘，有时出现在靠近森林的花园中。活动范围在海拔1,600至3,300米之间，偏好在中层至树冠层觅食。高度领地性，会保卫花丛免受其他吸蜜鸟类侵扰。通过悬停并抓住花朵摄取花蜜，偶尔也会从栖息处捕捉小昆虫。","breeding":"关于繁殖行为的信息有限，但推测其繁殖方式与近缘物种相似，会筑造杯状巢穴。","identification":"与同属其他物种如黄尾冕蜂鸟和紫冕蜂鸟相比，栗胸冕蜂鸟具有独特的栗色下体和较短的喙，易于区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的安第斯山脉东侧，从哥伦比亚东南部至秘鲁南部，以及安第斯山脉西侧的厄瓜多尔中部至秘鲁西北部。","other":"虽然分布广泛，但对其自然历史了解甚少。"},{"name":"紫冕蜂鸟","english_name":"Velvet-purple Coronet","scientific_name":"Boissonneaua jardini","overview":"紫冕蜂鸟（英文名：Velvet-purple Coronet，学名：Boissonneaua jardini），是雨燕目蜂鸟科冕蜂鸟属的鸟类。此物种在光照不佳时全身呈现深黑色，但在特定角度下，其腹部和冠羽会闪耀出紫色光芒，翅膀覆盖羽呈绿色，侧翼为蓝绿色，下翼的肉桂色在飞行中尤为显眼。分布于哥伦比亚西南部至厄瓜多尔西北部的湿润云雾林边缘。","appearance":"紫冕蜂鸟体长11至12.7厘米，体重8.0至8.5克。喙短直而黑，眼后有白色斑点。雄鸟头部丝绒般黑色，冠羽和胸腹部闪现耀眼的蓝紫色，上体呈闪亮的蓝绿色；雌鸟颜色较暗淡，胸腹羽毛边缘泛着黄褐色至灰褐色。幼鸟似雌鸟，但侧面带有灰色至棕色色彩。","call":"其求偶鸣唱为一系列交替的刺耳和柔和的哨声，'si, siii, si, siii, si, siii...'。","habits":"栖息于热带和亚热带湿润森林及边缘地带，高度范围从350至2200米。主要以花蜜为食，同时在空中捕捉昆虫。领土性较强，通常在低层至树冠处觅食。","breeding":"繁殖季节从1月至3月，巢为杯状，外饰苔藓和地衣，置于水平枝或细叉中，由雌鸟独自孵化两枚卵。雏鸟喂养频率高。","identification":"与其他冠蜂鸟相比，紫冕蜂鸟的雄鸟具有独特的蓝紫色腹部和冠羽，雌鸟下体羽毛边缘呈黄褐色至灰褐色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，具体为哥伦比亚西南部至厄瓜多尔西北部的安第斯山脉西侧。"},{"name":"闪羽蜂鸟","english_name":"Shining Sunbeam","scientific_name":"Aglaeactis cupripennis","appearance":"闪羽蜂鸟身长约为12到13厘米（4.7到5.1英寸），雄鸟体重介于7.6到8.1克（0.27到0.29盎司），而雌鸟略轻，约6.9到7.5克（0.24到0.26盎司）。两性均具有黑色的短而直的喙，没有白色羽毛。雄鸟头部上部呈深棕色，下背和臀部为紫金色，逐渐变为银绿色的尾上覆羽。尾巴通常为暗褐色至赤褐色，边缘常带有青铜色。喉咙部分为赤褐色，点缀着灰暗的颜色，胸部为斑驳的浅黄色，腹部为红棕色。雌鸟的下背部和臀部的金色和绿色较暗淡或缺失。","call":"闪羽蜂鸟的鸣唱由一连串高音的‘tsip...chew...chew...tseep.....tsip..chew...’构成，叫声包括类似‘suweet’的上扬音符和单个尖锐的‘see’音。","habits":"闪羽蜂鸟栖息于安第斯山脉的亚高山和高山草甸，以及云雾林和半干旱山脊，高度范围从2,500米至4,300米（8,200至14,100英尺）。它们会季节性地进行垂直迁移。以花蜜为食，从地面到树冠各层都能觅食，偏好各种凤梨科植物、藤蔓和树木，如Embothrium、Puya和Fuchsia，雄鸟会守护花丛区域。此外，它们也会通过飞扑的方式捕食小型节肢动物。","breeding":"闪羽蜂鸟的繁殖季节因地域而异，哥伦比亚从3月至9月，厄瓜多尔在2月至4月间，秘鲁可能在11月至4月之间。它们用苔藓和蛛网建造紧凑的杯状巢，内部铺垫柔软的植物纤维，有时外部装饰树皮或地衣，巢置于树枝或附生植物上，高度通常在4到10米（10到30英尺）之间，最高可达15米（50英尺）。雌鸟单独孵化两个白色的卵，孵化期为16到18天；幼鸟离巢发生在孵化后的24到27天。","identification":"闪羽蜂鸟最显著的辨识特征是其独特的紫金色下背部和臀部，以及没有白色羽毛的特点。与同属其他种类相比，其喙较为短小。","protection":"IUCN：LC（无危）","distribution":"闪羽蜂鸟主要分布于南美洲的哥伦比亚、厄瓜多尔和秘鲁。在哥伦比亚，它遍布安第斯山脉的三大山系，向南延伸至秘鲁的La Libertad和Huánuco部门。在秘鲁，从哥伦比亚南部边界向南至Lima和Cuzco部门均有分布。"},{"name":"紫背闪羽蜂鸟","english_name":"Purple-backed Sunbeam","scientific_name":"Aglaeactis aliciae","overview":"紫背闪羽蜂鸟（英文名：Purple-backed Sunbeam，学名：Aglaeactis aliciae），是雨燕目蜂鸟科羽蜂鸟属的鸟类。一种珍稀的蜂鸟科鸟类，仅见于秘鲁北部安第斯山脉的狭窄地带。其最显著的特征是雄鸟的紫色背部，而雌鸟和幼鸟的这一特征较为模糊或缺失。分布区域极其有限，主要在拉利伯塔德省的马腊翁河上游流域。","appearance":"体长约12至13厘米，体重约7.3至8.3克。雄鸟具有短而直的黑色喙，头部与肩部呈土褐色，下背部与臀部呈现虹彩般的紫罗兰色至金绿色，上覆羽亦可见金色光泽。面颊、喉部、胸部中央及胸毛为白色，其余部分呈深棕色。雌鸟与雄鸟相似，但虹彩部位缩小至尾上覆羽或完全缺失。幼鸟似成年雌鸟，但面颊、喉部、腹部中央有淡黄色斑点，有时喉部甚至完全呈淡黄色。","call":"鸣声与闪羽蜂鸟极为相似，其假定的歌声由3至5个高音的啁啾声组成，如‘tsip .. tsee .. chew .. chew ....... tsip .. tsee .. tsee .. chew-chew...’。","habits":"栖息于海拔3000至3500米的半开阔的安第斯山坡，常见于Alnus acuminata树和Oreocallis grandiflora灌木丛中。以Oreocallis grandiflora灌木丛的花蜜、寄生槲寄生Tristerix longebrachteatum（寄生于Alnus acuminata树上）的花蜜及小昆虫为食。其食谱和觅食行为尚不明确。","breeding":"关于繁殖的信息较少。繁殖季节不明，曾记录到5月时的雌鸟在筑巢，6月时的雄鸟睾丸稍有增大，2月、3月和6月收集到幼鸟样本。","identification":"雄鸟独特的紫色背部是与同类物种区别的关键特征。雌鸟和幼鸟的识别较为困难，需结合分布区域和其他形态特征。","protection":"IUCN：VU（易危）。由于栖息地的丧失，尤其是为了增加牛牧场而燃烧森林，导致其生存受到严重威胁。","distribution":"秘鲁北部，具体在马腊翁河上游流域的拉利伯塔德省，最近记录显示其分布已延伸至相邻的安卡什省南部。","other":"由于栖息地的快速消失，紫背闪羽蜂鸟的数量可能比先前估计的更为稀少。"},{"name":"辉胸闪羽蜂鸟","english_name":"White-tufted Sunbeam","scientific_name":"Aglaeactis castelnaudii","overview":"辉胸闪羽蜂鸟（英文名：White-tufted Sunbeam，学名：Aglaeactis castelnaudii），是雨燕目蜂鸟科羽蜂鸟属的鸟类。分布于秘鲁高海拔地区的半湿润灌木丛中。体长约12厘米，重7-8.5克，以其独特的金色尾巴、紫色背部和胸前显眼的白色羽毛簇而著称。","appearance":"成年辉胸闪羽蜂鸟具有直而黑的喙，胸部有明显的白色羽毛簇。雄鸟上背呈暗黑色，带有紫罗兰色反光，尾部叉开，腹部、侧翼和颈部为暗褐色，喉部和胸部有黑色带纹。雌鸟相似，但背部光泽较弱，尾部叉开较小。幼鸟外表均匀棕色，无金属光泽羽毛。","call":"发出重复的“tzit”声，追逐时会发出一系列类似“titi-tsreet-tsreet-tsreet”的啾啾声，还能发出尖细的下滑音“seeeuuu”。","habits":"栖息于亚热带或热带湿润山地森林及高海拔灌木地带，偏好干燥的常绿山地森林、山间谷地和开阔灌木。在闪羽蜂鸟同域时，它们倾向于隐藏在较低的树枝和茂密植被中。","identification":"与闪羽蜂鸟相比，辉胸闪羽蜂鸟头部和身体颜色更深，胸部白色斑块更亮。","protection":"IUCN：NT（近危）；CITES: II级。","distribution":"主要分布于秘鲁中部和南部中央地区，尤其在Apurímac、Cordillera Vilcanota和Vilcabamba地区有记录。","other":"虽然确切数量未知，但该物种被描述为‘常见但分布零散’，主要威胁是持续的栖息地丧失和森林砍伐。"},{"name":"黑头闪羽蜂鸟","english_name":"Black-hooded Sunbeam","scientific_name":"Aglaeactis pamela","overview":"黑头闪羽蜂鸟（英文名：Black-hooded Sunbeam，学名：Aglaeactis pamela），是雨燕目蜂鸟科羽蜂鸟属的鸟类。独特的蜂鸟，主要栖息于玻利维亚安第斯山脉上部的湿润森林地带。其羽毛以黑色为主，胸部有醒目的白色羽毛，臀部闪耀着蓝色光泽。","appearance":"黑头闪羽蜂鸟的羽毛大部分为紫黑色，背部下方和臀部呈现出金绿至蓝绿色的闪光，尾巴呈红褐色，胸中央有一撮白色的羽毛。雄鸟和雌鸟外观相似，但雌鸟的闪光臀部较为减淡。幼鸟颜色略带棕色，胸羽可能不太明显。","call":"关于黑头闪羽蜂鸟的鸣叫声报道有限，已知会发出高音的'zeet-zeet-zeet'声，以及在对抗性遭遇中的其他叫声。","habits":"这种大型蜂鸟主要栖息于云雾森林和湿润至半湿润的高山灌木丛中，海拔范围大约在1,800到4,200米之间。它们以花蜜和小节肢动物为食，常贴紧花朵吸食花蜜而非悬停。","identification":"黑头闪羽蜂鸟在其地理范围内非常独特，不易与其他物种混淆。它具有白色的胸羽、闪烁的蓝绿色臀部和红褐色的尾巴，这些特征在它的范围内是独一无二的。","protection":"IUCN：LC（无危）","distribution":"黑头闪羽蜂鸟仅分布于玻利维亚北部的安第斯山脉，主要在拉巴斯和科恰班巴部门之间。","other":"黑头闪羽蜂鸟属于蜂鸟科，‘brilliants’族，Heliantheini支系，是该物种的唯一代表。"},{"name":"紫巾山蜂鸟","english_name":"Ecuadorian Hillstar","scientific_name":"Oreotrochilus chimborazo","overview":"紫巾山蜂鸟（英文名：Ecuadorian Hillstar，学名：Oreotrochilus chimborazo），是雨燕目蜂鸟科山蜂鸟属的鸟类。分布于安第斯山脉高海拔地区的大型蜂鸟，主要见于厄瓜多尔，极南端延伸至哥伦比亚南部。雄鸟拥有引人注目的紫蓝色头部和绿色下喉，以及黑色腹纹；雌鸟和幼鸟颜色较为暗淡，主要为灰绿色，喉部有斑点。","appearance":"雄鸟上体为深橄榄绿色，头部和上喉覆盖着闪亮的紫蓝色羽毛，下喉为绿色，腹部中央有黑色细纹，尾羽中央深色，其余部分白色，末端有深色边缘。雌鸟上身铜绿色，尾羽深绿色，下体淡灰色，喉部有褐色斑点。幼鸟似雌鸟，但雄鸟幼鸟胸前有浅色区域，未成熟雄鸟有深青色头罩。","call":"发出重复的短促‘tsit’声和尖锐的‘tseek’声，还有快速旋律的颤音，音调起伏，可能是追逐叫声。","habits":"栖息于海拔3500至5200米的高山草甸，偏好干燥的 puna 类草地环境，有时也会出现在潮湿的安地斯高山草甸。常在 Chuquiraga 灌木丛附近活动，积极守护其喜欢的花丛，以橙色花朵为食源，同时捕食昆虫。","breeding":"繁殖期主要在10月至翌年2月，巢由苔藓、干草、羽毛等材料构成，建于洞穴、沟壑或悬崖壁，以抵御恶劣天气。每窝产两枚白色蛋，孵化和育雏期较长。","identification":"与蓝喉山蜂鸟没有重叠分布，可通过紫色头巾和黑色腹纹辨别雄鸟。亚种 jamesonii 的雄鸟喉部全为紫色，外侧尾羽白色较少。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，从哥伦比亚南部至厄瓜多尔中部的安第斯山脉，包括 Chimborazo 和 Quilotoa 火山周围地区。","other":"紫巾山蜂鸟的两个亚种可能与安第斯山脉复杂的地形和历史气候变化有关，显示了地理隔离导致的分化。"},{"name":"安第斯山蜂鸟","english_name":"Andean Hillstar","scientific_name":"Oreotrochilus estella","overview":"安第斯山蜂鸟（英文名：Andean Hillstar，学名：Oreotrochilus estella），是雨燕目蜂鸟科山蜂鸟属的鸟类。南美洲高海拔地区特有的小型蜂鸟。常见于岩石和灌木山谷、村庄及开放和半开放地带，特别是有花卉的地方。其最显著的特征是尾部大部分为白色，雄鸟拥有闪亮的绿喉和腹部锈色条纹，而雌鸟较为暗淡，但具有略向下弯的喙，喉部斑点和尾羽模式。","appearance":"体型小巧，长度约为13至15厘米，雄鸟体重约8.8克，雌鸟约8.0克。雄鸟拥有中等长度略向下弯曲的黑色喙，背部暗褐色，绿喉带有黑色边框，胸部和腹部主要为白色，腹部中央有一条锈色线。尾羽呈叉状，中央羽毛对及外侧边缘和尖端为青铜黑色，其余部分为白色。雌鸟整体颜色较暗淡，喉部有细小斑点，尾羽绿色带黑色，外侧3至4根尾羽基部和尖端为白色。幼鸟更灰，雄鸟幼鸟具有深蓝绿色喉部。","call":"发出重复的短促“tsip”或“swit”声，追逐时会发出快速、悦耳类似雀鸟的鸣叫。","habits":"栖息于普纳草原，尤其在岩石露头和各种开花灌木丛附近最为常见。常出现在房屋周边，Puya raimondii丛生区，以及Polylepis森林边缘。在繁殖季节，雌雄会分别占据不同的栖息地，雌鸟在岩石附近的灌木峡谷中建立领地，雄鸟则在开阔的草原上游荡。在寒冷夜晚和冬季，会进入类似冬眠的状态以降低代谢率，藏身于洞穴和深裂缝中躲避天敌。食性以花蜜为主，常在Chuquiragua spinosa灌木和其他开花植物上取食，同时也会从植被中捕食节肢动物。","breeding":"繁殖季从9月至翌年2月，雌鸟在岩石附近的灌木峡谷中持有领地，常在特别适宜的地方半殖民地式筑巢，有时会在Puya raimondii植物裙部下筑巢。巢为大型羊毛状杯形，粘贴于岩石表面。每窝产两枚卵，孵化期约20天，雏鸟离巢期38天，视温度可能缩短。可能在温暖地方一年产两窝。","identification":"与同属其他种类相比，安第斯山蜂鸟的白尾极为显著，雄鸟的绿喉和腹部锈色条纹是识别特征，雌鸟的暗淡色彩和尾羽模式有助于辨认。","protection":"IUCN：LC（无危）。受CITES II保护。在多个保护区得到保护，如Calipuy国家保护区、Huascaran国家公园、Salinas y Aguada Blanca国家保护区（秘鲁）、Ulla-Ulla和Sajama国家公园（玻利维亚）、Lauca国家公园（智利）。","distribution":"分布于南美洲高海拔区域，从秘鲁西南部至阿根廷西北部，主要在2400至5000米之间，尤以3500至4500米高度最为常见。"},{"name":"白胁山蜂鸟","english_name":"White-sided Hillstar","scientific_name":"Oreotrochilus leucopleurus","overview":"白胁山蜂鸟（英文名：White-sided Hillstar，学名：Oreotrochilus leucopleurus），是雨燕目蜂鸟科山蜂鸟属的小型蜂鸟。分布于南美安第斯山脉，从玻利维亚南部经阿根廷至智利中部。在岩石和灌木丛生的山谷、村落以及开放或半开放的花丛地带发现。通常在建筑物或桥梁下筑巢，以抵御寒冷夜晚。普遍常见。","appearance":"体长约13-15厘米，体重约7.9-8.4克。喙稍弯，黑色。雄鸟上部呈暗褐色，具闪亮绿色喉盾，边缘有黑色界限，与白色胸腹相隔；腹部有一条宽的蓝黑色中线延伸至肛周区；尾羽圆形，外侧有基部白色的羽毛。雌鸟上部和下部皆为灰褐色，喉部淡色并有细小暗斑点；尾部绿黑，外侧三至四对羽毛基尖部有大量白色。幼鸟整体较灰，雄鸟具暗蓝绿色喉盾。","call":"发出重复的短促‘tsit’声，追逐或展示时有快速的啾啾声，与近似种相似。","habits":"栖息于海拔1200-4000米的普纳草原，伴生矮灌木、柱状仙人掌和Puya。冬季通常离开其在智利的领地，向低海拔迁移。以花蜜为食，取食于Barnadesia、Berberis和Chuquiragua灌木、大型Puya种类和其他一些草本植物。","breeding":"繁殖期在11月至12月，将大型杯状巢粘附于垂直岩壁上的隐蔽处，一窝产两枚蛋，关于繁殖生态的其他信息有限。","identification":"雄鸟与安第斯山蜂鸟相似，但具宽蓝黑色中腹纹，尾部更圆，外侧尾羽较短窄且向内弯曲，仅基部白色。雌鸟和幼鸟与安第斯山蜂鸟难以区分，但外侧尾羽狭窄，有完整的均匀宽度深绿色横带。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲安第斯山脉，自玻利维亚塔里哈省至智利比奥比奥区和阿根廷圣克鲁斯省。在阿根廷，分布范围远超先前所知，向南延伸。","other":"白胁山蜂鸟曾被认为可能是安第斯山蜂鸟的亚种，但现在被视为独立物种。"},{"name":"黑胸山蜂鸟","english_name":"Black-breasted Hillstar","scientific_name":"Oreotrochilus melanogaster","overview":"黑胸山蜂鸟（英文名：Black-breasted Hillstar，学名：Oreotrochilus melanogaster），是雨燕目蜂鸟科山蜂鸟属的鸟类。主要分布在南美洲秘鲁中部的安第斯山脉高海拔地区。其最显著的特征是雄鸟的蓝绿色喉部和黑色胸部，雌鸟则具有斑点状喉部和白色尾羽尖端。","appearance":"黑胸山蜂鸟体长13至14厘米，体重约8.4克。雄鸟上身呈暗绿褐色，拥有闪亮的翡翠绿喉部，腹部和腹侧黑色，两翼侧面灰褐色，尾部稍呈叉状，颜色为蓝黑色。雌鸟上身和下身色泽较淡，喉部有细小的暗色斑点，尾羽绿色带黑色，外侧三到四对尾羽尖端白色。","call":"鸣叫声了解不多，但在追逐时会发出快速的吱吱声，音调有升有降。","habits":"栖息于安第斯山脉的普纳草甸，常见于Chuquiragua spinosa灌木丛和低矮的仙人掌附近，偶尔在花园中出现。食物以Chuquiragua spinosa的花蜜为主，也会在红色花朵中觅食，同时捕食空中飞虫。","breeding":"繁殖期在2月至3月，会在垂直的岩壁或建筑物檐下粘贴大型杯状巢，每窝产两枚白色蛋，关于繁殖生态的其他细节尚不清楚。","identification":"雄鸟与安第斯山蜂鸟相比，上身更暗，喉部颜色更鲜明，雌鸟区别在于尾羽基部无白色。与同属的Andean和Green-headed Hillstars雌鸟区别明显，后者尾羽基部有白色。","protection":"IUCN：LC（无危）","distribution":"分布于秘鲁中部的安第斯山脉，包括Junín和Huancavelica，局部延伸至Ancash、Lima、Pasco和Ayacucho。在海拔3500至4400米的范围内活动。"},{"name":"楔尾山蜂鸟","english_name":"Wedge-tailed Hillstar","scientific_name":"Oreotrochilus adela","overview":"楔尾山蜂鸟（英文名：Wedge-tailed Hillstar，学名：Oreotrochilus adela），是雨燕目蜂鸟科山蜂鸟属的独特而美丽的鸟类，分布于南美洲中部玻利维亚至阿根廷西北部的高安第斯山脉，主要栖息于Polylepis木地及邻近灌丛。此鸟体型较小，长约11至13厘米，重约7.4至8.3克。","appearance":"雄鸟拥有独特的亮绿色喉部羽毛，胸腹部呈栗色，中央有一显著黑色条纹；尾羽大部分为蓝黑色，除中央羽毛外，其余均带有肉桂色内侧。雌鸟喉部白色带灰色及绿色斑点，其余下体淡红褐色；尾羽蓝黑色，外侧三至四对尾羽尖端为白色。幼鸟与成年雌鸟相似。","call":"雄鸟的展示鸣唱是一系列强烈的啾啾声，间以明显的下降音调。","habits":"主要栖息于海拔2600至4000米的半干旱到暂时湿润地带，常见于有Polylepis树的沟壑与盆地，树上寄生有多种槲寄生（Tristerix）和Barnadesia灌木丛。也会出现在退化环境，只要有Dodonea灌木、柱状仙人掌和一些较高的灌木即可。","breeding":"繁殖季节大致从10月至次年2月，雄鸟会在公开的栖木上交替唱歌和展示，进行深U形飞行。巢穴为大杯状，粘贴于岩石表面。","identification":"雄鸟是其分布区内唯一具有锈色侧面、黑色胸部和绿色喉部的蜂鸟。雌鸟可以通过橙色下体与同属其他物种区分开。","protection":"IUCN：LC（无危）","distribution":"分布于玻利维亚南部拉巴斯至波托西省和楚基萨卡，以及阿根廷极西北部（胡胡伊省）。","other":"虽然全球不受威胁，但在其分布范围内人类密集，需建立保护区以覆盖其核心栖息地。"},{"name":"绿头山蜂鸟","english_name":"Green-headed Hillstar","scientific_name":"Oreotrochilus stolzmanni","overview":"绿头山蜂鸟（英文名：Green-headed Hillstar，学名：Oreotrochilus stolzmanni），是雨燕目蜂鸟科山蜂鸟属的鸟类。分布于南美的安第斯山脉，包括厄瓜多尔南部和秘鲁北部及中部地区。其显著特征为雄鸟拥有一抹亮绿色的喉部羽毛，以及一条黑色条纹贯穿腹部至白色下体。雌鸟色彩较为朴素，但拥有略弯的喙、斑点喉咙和独特的尾羽模式。","appearance":"绿头山蜂鸟体型小巧，长度约13至14厘米，体重介于7.9至8.4克之间。雄鸟上身呈绿色带青铜光泽，喉部为闪亮的翡翠绿色，中央腹部有一条细黑线，尾羽白色，中央尾羽为暗淡的青铜色。雌鸟整体偏白，喉部点缀着灰色斑点，尾羽为绿黑色，外侧尾羽基部和尖端带有白色网状图案。幼鸟外观与成年雌鸟相似。","call":"鸣叫特征包括重复的短促‘tseep’声，以及追逐或展示时的快速、悦耳、类似雀鸟的颤音，与安第斯山蜂鸟的声音非常相似或完全相同。","habits":"绿头山蜂鸟偏好高海拔环境，常栖息于岩石和灌木丛生的山谷，村庄及开放或半开放地带的花丛中。它们能在寒冷的夜间生存，通过在建筑物或桥梁下筑巢来抵御低温。这种蜂鸟广泛分布于南美安第斯山脉，常见于岩石草甸、牧场和以Puya和Polylepsis为主的灌木丛中。它们在3,600到4,200米的海拔高度活动，季节性下降至较低海拔。","breeding":"繁殖季节通常从2月持续到6月，有时延续至8月。雌鸟会在岩石洞穴、屋檐下或旧建筑内使用植物纤维和苔藓建造杯状巢。每窝产两枚白色蛋，孵化期为19至21天。雏鸟孵化后约36至40天离巢。雄鸟在求偶时会展示各种姿势以突出其翠绿色的喉部羽毛，伴随着悦耳的颤音。","identification":"绿头山蜂鸟通过其独特的羽毛颜色和尾羽特征与同属其他物种区分开来，雄鸟的绿色喉部和腹部的黑色条纹尤其明显。雌鸟虽然较为朴素，但可以通过略弯的喙和尾羽上的斑点加以识别。","protection":"IUCN：LC（无危）","distribution":"绿头山蜂鸟主要分布于南美洲的安第斯山脉，具体包括秘鲁北部和中部，以及厄瓜多尔南部。","other":"绿头山蜂鸟曾被认为是安第斯山蜂鸟的亚种，但基于遗传学和羽毛颜色的差异，现被视为独立物种。"},{"name":"蓝喉山蜂鸟","english_name":"Blue-throated Hillstar","scientific_name":"Oreotrochilus cyanolaemus","overview":"蓝喉山蜂鸟（英文名：Blue-throated Hillstar，学名：Oreotrochilus cyanolaemus），是雨燕目蜂鸟科山蜂鸟属的鸟类。仅分布于南美洲厄瓜多尔西南部一小片区域内。2017年被科学界发现，其独特之处在于雄鸟拥有一抹耀眼的深蓝色喉咙，与绿色头部和上身形成鲜明对比。","appearance":"雄性蓝喉山蜂鸟头部至后冠区闪耀着翠绿的光泽，伴有蓝绿色反光。颈部、肩部、下背、翼上覆羽及臀部呈明亮的翡翠绿至蓝绿色，具细窄蓝绿边缘。尾上覆羽蓝绿色金属光泽，中央尾羽钢蓝色至金属蓝绿色。下体白色，中央腹部有黑色条纹，两胁及臀部橄榄绿至灰绿。雌鸟上体翠绿，下喉部灰橄榄色，两侧较白，两胁及臀部灰黄褐色，带些微绿色光泽。","habits":"该物种栖息于安第斯山脉的高海拔草甸环境，偏好有灌木丛的草地。它们会侧身或倒挂于枝头觅食，主要以Chuquiraga花蜜为食，偶尔也会捕食苍蝇。","breeding":"关于蓝喉山蜂鸟的繁殖信息目前尚未收集到。","identification":"蓝喉山蜂鸟与同属的紫巾山蜂鸟和绿头山蜂鸟最为相似，但可通过其独特的深蓝色喉咙和绿色上体区分。雌鸟则以其暗灰色下巴和上喉部以及稀疏的金属绿色斑点区别于其他同类。","protection":"IUCN：CR（极危）","distribution":"蓝喉山蜂鸟仅分布于厄瓜多尔西南部，具体位于El Oro和Loja省边界附近的Cerro de Arcos山区。","other":"蓝喉山蜂鸟的数量估计不超过750只，面临火灾、放牧和金矿开采的威胁。Nature and Culture International正与当地机构合作，计划建立一个新的保护区，保护其全部栖息地。"},{"name":"绒胸蜂鸟","english_name":"Mountain Velvetbreast","scientific_name":"Lafresnaya lafresnayi","overview":"绒胸蜂鸟（英文名：Mountain Velvetbreast，学名：Lafresnaya lafresnayi），是雨燕目蜂鸟科绒胸蜂鸟属的唯一物种，分布于南美洲，从委内瑞拉西部至秘鲁中部。该鸟以长而弯曲的喙和大部分白色的尾巴著称，主要栖息于高海拔森林边缘和灌木斜坡。","appearance":"体长11.5至12厘米，包括2.7至3.2厘米的喙，体重4.5至6.3克。雄鸟主要为绿色，腹部黑色，具长而细薄的弯曲黑喙；雌鸟下方为灰白或淡黄色，密布绿色斑点。幼鸟类似雌鸟，但头部羽毛边缘呈褐色，雄鸟幼鸟开始显现黑色腹部。喙的形状和长度是区分亚种的主要诊断特征。","call":"发出重复的高音“tseee”或“pseeuw”，有时后跟一连串颤音，还包括柔和的“tek”声和细小的颤音。","habits":"生活在1800米至3400米的湿润山地森林边界和灌木斜坡，偶尔在厄瓜多尔东部达到3700米。主要在低层0.5至3米处觅食，偏好花蜜，如Centropogon、Castilleja、Siphocampylus、Salvia、Pentadenia、Loranthaceae、Ericaceae和Gesneriaceae的花，以及捕食空中或植物表面的小型节肢动物。","breeding":"繁殖季节因地理而异，但除六月外每月都有可能繁殖。雄鸟占据富含花蜜的领地，雌鸟通过巡回访问分散的花丛觅食。巢由苔藓、地衣和蜘蛛丝构成的厚实杯状巢，通常位于陡峭岩石面或土岸上的植被中，离地面1至3米，有时在树干上。雌鸟孵化两枚蛋约16至19天，幼鸟在孵化后23至26天离巢。","identification":"雄鸟的长而弯曲的喙、绿色上部、翡翠绿色喉部和胸部、黑色腹部以及铜绿色中央尾羽（仅限某些亚种）为显著特征。雌鸟下方颜色从灰白到白色，带有绿色斑点。亚种间在喙的长度和曲度、尾羽颜色上有细微差异。","protection":"IUCN：LC（无危）。被列入CITES II附录。在圣玛尔塔山脉常见，安第斯山脉分布较少且零散，委内瑞拉和厄瓜多尔不常见。在厄瓜多尔的几个保护区如Pasochoa森林保护区、Las Cajas国家休闲区和Podocarpus国家公园内出现。","distribution":"分布于南美洲，从委内瑞拉西部至秘鲁中部，主要栖息于1800至3400米的高海拔地区，偶尔在厄瓜多尔东部达到3700米。"},{"name":"铜色星额蜂鸟","english_name":"Bronzy Inca","scientific_name":"Coeligena coeligena","overview":"铜色星额蜂鸟（英文名：Bronzy Inca，学名：Coeligena coeligena），是雨燕目蜂鸟科星额蜂鸟属的鸟类。其最显著的外部特征是全身覆盖着暗淡的青铜色羽毛，缺乏光泽和色彩。分布于南美洲，从委内瑞拉北部到玻利维亚东南部的安第斯云雾森林，海拔介于1000米至2500米之间。","appearance":"体型较大，长约14厘米，雄鸟体重约7.3克，雌鸟约6.2克。雄鸟拥有长而直的黑色喙，基部常带黄色，头部及背部呈深青铜色，略带紫红光泽，下背绿色；眼后有白色斑点；喉部和胸部有白色斑点和灰褐色条纹，腹部为红棕色，尾羽叉开，呈青铜色。雌鸟相似，但尾羽分叉程度较小，喙稍长。幼鸟外观类似雌鸟。","call":"其假定的歌声为连续的单个甜美‘tseet’音符，每秒约1-1.6个音符。另有高音的‘tsit-sit-it-it’声，结尾变得尖细。叫声包括单个‘tsee’或‘tzeet’音，通常在飞行中发出。","habits":"栖息于安第斯山脉的云雾森林边缘，亦可见于分散树木的开阔地带和咖啡种植园。有季节性迁徙行为，具体细节尚未完全明确。以花蜜为主食，通过巡游的方式觅食，访问各种开花植物。同时捕食小昆虫，采用悬停捕食和空中捕食的方式。","breeding":"繁殖季节从11月至次年3月。雌鸟单独筑巢，使用苔藓和植物纤维构建杯状巢，通常离地面1至1.5米，隐藏于植被中。每次产卵两枚，孵化期15至16天，雏鸟在22至24天后离巢。","identification":"与其他星额蜂鸟属成员相比，铜色星额蜂鸟的羽毛颜色较为暗淡，缺乏鲜艳色彩。不同亚种间存在细微差异，如zuliana亚种的羽毛略显绿色，columbiana亚种体型更小，ferruginea亚种的下体带有更多赭石色。","protection":"IUCN：LC（无危）；CITES II（华盛顿公约附录二）","distribution":"主要分布于南美洲，繁殖区域从委内瑞拉北部延伸至玻利维亚东南部，包括哥伦比亚、厄瓜多尔、秘鲁等地。栖息地包括多个受保护区域，如委内瑞拉的Henri Pittier国家公园和哥伦比亚的Cueva de los Guácharos国家公园。","other":"尽管原始栖息地受到森林砍伐的影响，但由于该物种能适应人类改变的环境，如咖啡种植园等，因此并未受到严重影响。过去几十年欧洲野鸟贸易中的进口对该物种数量未造成显著负面影响。"},{"name":"褐星额蜂鸟","english_name":"Brown Inca","scientific_name":"Coeligena wilsoni","overview":"褐星额蜂鸟（英文名：Brown Inca，学名：Coeligena wilsoni），是雨燕目蜂鸟科星额蜂鸟属的鸟类。主要分布在南美洲的哥伦比亚西部至厄瓜多尔西部，常见于安第斯山脉的云雾森林中。其特征为长而直的黑色喙，上体呈红铜色，背部逐渐转为橄榄绿色，喉部有紫色斑块，雌鸟斑块较小。","appearance":"体长约11至13厘米，体重雄鸟约7克，雌鸟约6.5克。雄鸟上体红铜色，背部偏绿橄榄色，尾羽青铜色，叉状；下体暗褐色，喉部有紫晶色斑块，胸部两侧有白色斑点。雌鸟相似，但喙较长，喉部斑块更小，尾部叉度较小。幼鸟外观与雌鸟相似。","call":"可能的歌声由三个音符组成：“tsip-tzreeew-tzrew”。叫声包括尖锐的单音“tsit”或双音“tsi-tsit”，以及一系列延长的“tsitsitsitsitsit…tsitsitsi...tsitsitsit...”。飞行时会发出短促的颤音“trrr”，短暂的啾啾声和高音调的“tzree...tzee...tzee...tzee”。","habits":"栖息于云雾森林的边缘和内部，海拔高度从700米至1900米，偏好低层植被。以吸食花蜜为主，常访问各种开花植物如Psammisia、Macleania、Cavendishia和Fuchsia等，也会捕食小型节肢动物。","breeding":"繁殖季节从1月持续到6月。杯状巢由苔藓和柔软的种子纤维构成，建在年轻树木的分叉处，离地面2至3米。每窝产2枚卵，孵化期为15至16天，仅由雌鸟承担；幼鸟黑色，背部有两行浅黄色绒毛；22至26天后离巢。","identification":"与（可能指铜色星额蜂鸟）类似，但喉部斑块更小，尾部叉度不同，雌鸟特征更为明显。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，从哥伦比亚的Chocó省向南延伸至厄瓜多尔的Loja省，主要在太平洋沿岸的安第斯山脉。","other":"物种的种小名纪念了美国自然学家Thomas Bellerby Wilson。"},{"name":"黑星额蜂鸟","english_name":"Black Inca","scientific_name":"Coeligena prunellei","overview":"黑星额蜂鸟（英文名：Black Inca，学名：Coeligena prunellei），是雨燕目蜂鸟科星额蜂鸟属的鸟类。独特的中型蜂鸟，分布于哥伦比亚东部山区的特定区域，主要栖息于海拔1200至2800米的湿润山地森林，尤其是橡树为主的林区。全球保护状况被评为易危（VU），在哥伦比亚国内则被列为濒危（EN）。","appearance":"黑星额蜂鸟身长约14厘米，体重约6.6至7克。其显著特征为紫黑色的羽毛，肩部呈现暗金属蓝色，尾部分叉。雄鸟的喉咙闪耀着蓝绿色光泽，两侧胸部有白色斑块。雌鸟较雄鸟颜色略暗，肩部蓝色较少，尾巴分叉程度较小，喙较长。幼鸟色彩较暗淡，无喉部光泽。","call":"黑星额蜂鸟通常保持安静，偶尔会发出短促的‘ick’或‘pip’声。","habits":"该蜂鸟主要通过巡游式觅食，访问多种开花植物以吸食花蜜，偏好红黄色彩的管状花朵，如倒挂金钟属、炮仗花属等。它也会在植被上捕捉小型节肢动物。活动范围包括森林中层及边缘低层，可能进行局部迁移。","breeding":"繁殖季节不详，可能从6月持续到次年2月。已知的巢为树蕨鳞片制成，内部铺有植物绒毛，放置于1.5至1.8米高的地面。具体孵化时间和雏鸟离巢时间未知。","identification":"与同属的其他种类如领星额蜂鸟相比，黑星额蜂鸟具有独特的两侧胸部白色斑块和几乎全黑的尾羽。","protection":"IUCN：VU（易危）；哥伦比亚：EN（濒危）。约90%的栖息地已被清除，剩余的栖息地碎片化严重。","distribution":"黑星额蜂鸟仅分布于哥伦比亚中北部，具体在Santander、Boyacá和Cundinamarca地区的东部安第斯山脉西侧，以及Serranía de los Yariguíes的双坡。","other":"历史上，蜂鸟的羽毛曾被用于装饰，导致其生存受到威胁。现今，栖息地破坏是其面临的最大挑战。"},{"name":"领星额蜂鸟","english_name":"Collared Inca","scientific_name":"Coeligena torquata","overview":"领星额蜂鸟（英文名：Collared Inca，学名：Coeligena torquata），是雨燕目蜂鸟科星额蜂鸟属的鸟类。大而华丽的蜂鸟，广泛分布于安第斯山脉，从委内瑞拉到秘鲁南部。其显著特征为白色胸斑与长直喙，雄鸟头部具紫罗兰色前冠斑，雌鸟喉部呈白色带绿色斑点。","appearance":"领星额蜂鸟体型约14.5厘米，雄鸟体重约为7.1克，雌鸟约6.6克。雄鸟有长而直的黑色喙，头部黑色带紫罗兰色前冠斑，上半身黑绿色，下半身背部和臀部闪耀深绿色，有大而显眼的白色胸带，尾部中央绿黑色，外部羽毛白色带黑色尖端。雌鸟相似，但黑色区域被深绿色取代，喉部白色带绿色斑点，胸带不甚突出，下半身灰绿色带小绿色圆盘状斑点。","call":"常见的叫声是一种刺耳的喋喋声，通常重复如'tsi-tsi-tsiririt...'，也有单独的'tsit'声或高音的'see'。","habits":"栖息于湿润的安第斯山云雾林，高度在1800至3000米间，偶尔低至1500米。以花蜜为食，偏好长管状花朵，如Cavendishia、Fuchsia和多种Ericaceae，同时捕食昆虫和其他小型节肢动物。通常独自觅食，飞行速度快。","breeding":"繁殖季节为11月至3月（哥伦比亚）、8月至12月（厄瓜多尔东部）、3月（秘鲁中部）。巢杯状，隐藏于岩石悬崖下的蕨类植物中，离地面1.5至2米，由植物纤维构成，外表装饰有苔藓和枯叶，直径约30毫米，深30至35毫米。每窝产两枚白色蛋，孵化期18天，雏鸟孵化同步，育雏期21至22天。","identification":"与同属物种相比，领星额蜂鸟具有更广泛的白色胸带和尾部白色标记。雄鸟的头部颜色比雌鸟深，喉部色彩更为鲜艳。与其他Coeligena物种相比，它在花丛中的行为更为领土性。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，从委内瑞拉西北部和哥伦比亚至秘鲁南部，主要栖息于1800至3000米海拔的湿润云雾林。","other":"目前没有已知的特定威胁，但由于其生境——湿润的安第斯山云雾林正遭受严重破坏，未来可能面临风险。"},{"name":"白尾星额蜂鸟","english_name":"White-tailed Starfrontlet","scientific_name":"Coeligena phalerata","overview":"白尾星额蜂鸟（英文名：White-tailed Starfrontlet，学名：Coeligena phalerata），是雨燕目蜂鸟科星额蜂鸟属的鸟类。大型、长喙的蜂鸟，特有于哥伦比亚东北部的圣玛尔塔山脉，拥有引人注目的白色尾羽，是该地区独有的物种。","appearance":"成年白尾星额蜂鸟体长约14厘米（5.5英寸），两性皆具有长而直的黑色喙，雌鸟的喙较雄鸟稍长。雄鸟拥有闪亮的暗绿色上体，冠羽呈现璀璨的蓝绿色，尾羽全白，新羽时带有青铜色尖端。雌鸟冠羽呈深蓝绿色，上体闪耀绿色，尾羽带青铜色，羽尖呈淡黄色，下体为红肉桂色。幼鸟外观与成年雌鸟相似。","call":"其叫声包括高音的‘tsee-tsee-tsi-tsi-tsirrrrr’和低音的短促颤音。","habits":"白尾星额蜂鸟栖息于圣玛尔塔山脉的湿润森林中，海拔介于1,400至3,700米之间，偏好在林间空地觅食，同时也在林缘活动。它们以多种花朵的花蜜为食，也捕食昆虫和其他节肢动物。","breeding":"繁殖季节大致从2月持续至4月，但具体繁殖生态细节未知。","identification":"雄性白尾星额蜂鸟的白色尾羽是显著的识别特征，而雌鸟的红肉桂色下体和长喙亦易于辨认。","protection":"IUCN：NT（近危）","distribution":"仅分布于南美洲哥伦比亚东北部的圣玛尔塔山脉。","other":"此物种被列为CITES附录II，且在圣玛尔塔山脉的自然栖息地正遭受严重的森林砍伐威胁，需要紧急的保护措施。"},{"name":"金腹星额蜂鸟","english_name":"Golden-bellied Starfrontlet","scientific_name":"Coeligena bonapartei","overview":"金腹星额蜂鸟（英文名：Golden-bellied Starfrontlet，学名：Coeligena bonapartei），是雨燕目蜂鸟科星额蜂鸟属的鸟类。中型蜂鸟，拥有长而直的黑色喙。雄鸟呈现耀眼的绿色前额，腹部色彩从金色橙色到闪耀的金色不等；雌鸟则为光泽的绿色，逐渐变为金色橙色的臀部，下方为肉桂色。分布于南美洲哥伦比亚东部至委内瑞拉西部的安第斯山脉中高海拔区域（1400-3200米）。栖息在湿润森林边缘，以中高灌木上的管状花朵花蜜为食。","appearance":"金腹星额蜂鸟体型中等，喙长且直。雄鸟的前额闪耀着绿色光芒，头部其余部分为黑色，背部为光泽的绿色，臀部及下腹部呈金色橙色至红色或铜色，尾羽稍分叉，为金色青铜绿。雌鸟前额为绿色，上半身颜色与雄鸟相似但较暗淡，喉部为肉桂色，胸部斑驳的绿色与肉桂色相间，下腹部主要为肉桂色，腹部为闪烁的红色金色，尾羽为青铜色，有时尖端带肉桂色。幼鸟外观与成年雌鸟相似。","call":"关于金腹星额蜂鸟的鸣叫特征，目前记录有限，已知其声音包括短暂的啾啾声和音调起伏复杂的叽叽喳喳声。","habits":"金腹星额蜂鸟全年居住在哥伦比亚东部安第斯山脉的湿润山地森林内部和边缘，偶尔出现在矮树森林和零散植被的开放景观中。它们以管状花的花蜜为主食，通常在低至中等高度的花丛中觅食，采用陷阱线觅食策略，沿着一系列开花植物移动。此外，它们通过从树叶中捕食小型节肢动物、悬停捕食和飞扑来补充营养。","breeding":"金腹星额蜂鸟的繁殖季节尚不明确，可能从1月持续到7月。其筑巢、孵化期和雏鸟成长期等繁殖细节尚未被详细描述。","identification":"与蓝喉星额蜂鸟相比，金腹星额蜂鸟雄鸟具有金色而非紫色的腹部，雌鸟缺乏两侧的紫罗兰色，臀部为青铜色而非蓝色。佩里星额蜂鸟和Merida星额蜂鸟被认为是金腹星额蜂鸟在Perijá山脉和委内瑞拉安第斯山脉的独立物种。","protection":"IUCN：LC（无危）","distribution":"金腹星额蜂鸟分布于哥伦比亚东部安第斯山脉，从博亚卡省至波哥大都会区，海拔1400至3200米之间。","other":"金腹星额蜂鸟的分类地位曾一度与Helianthea属中的其他种类一起，自20世纪中期以来归入Coeligena属。"},{"name":"暗星额蜂鸟","english_name":"Dusky Starfrontlet","scientific_name":"Coeligena orina","overview":"暗星额蜂鸟（英文名：Dusky Starfrontlet，学名：Coeligena orina），是雨燕目蜂鸟科星额蜂鸟属的鸟类。又称闪光星额蜂鸟，极为罕见的蜂鸟，仅分布于哥伦比亚西部安第斯山脉的少数特定区域。其显著特征为雄鸟的蓝绿色至金色前额，以及雌鸟的肉桂色喉部和金色腹部。这种蜂鸟主要栖息于高海拔的湿润森林与苔藓矮林生态交错带。","appearance":"暗星额蜂鸟体长约14厘米，雄鸟体重介于6.9至7.2克之间，雌鸟略轻。雄鸟拥有丝绒般黑色的冠、头部两侧和背部，额头上的前额饰片色彩由蓝绿至金绿变化，背部和翼上覆羽为绿色，上背部混合黑色，下背部变为亮丽的金绿色。尾巴颜色较淡的绿色，喉咙和胸部呈深绿色，带有黑色调，中央下喉处有一大块钴蓝色斑点。腹部和下尾羽覆羽与臀部颜色相同。雌鸟的冠、头部两侧、肩部和翼上覆羽为绿色，带有黑色尖端，形成鳞状外观。臀部、上尾羽覆羽和尾巴类似雄鸟，但光泽稍逊。喉咙为亮肉桂色，两侧有绿色斑点，腹部为金绿色，带有暗色基部和肉色条纹，下尾羽覆羽色泽较暗，边缘肉色。","call":"发出高音的金属声，开始时为'zseeririrrr'的颤音，随后是单独的'tsee'声，以及较低沉的尖锐'tsip'声。","habits":"暗星额蜂鸟栖息于海拔约3100至3500米的高海拔湿润森林、苔藓矮林和森林-草原过渡地带。已知它们访问过多种植物的花朵，如猫须花、Bejaria、Bomarea、Cavendishia和Centropogon。此外，其胃内容物显示，它们也会捕食小型寄生黄蜂、苍蝇、可能的啮虫目昆虫和蜘蛛。","breeding":"关于繁殖的了解甚少。在塔塔马国家自然公园发现过两个巢穴，都位于接近水源的岩石面上，由细根悬挂，距地面约3米，每个巢中有两枚蛋。幼鸟的记录出现在一月和八月。","identification":"暗星额蜂鸟与同属的其他种类如金腹星额蜂鸟有明显区别，尤其是雄鸟的前额饰片和雌鸟的肉桂色喉部。在同域分布的物种中，通过体型、色彩和分布区可以有效区分。","protection":"IUCN：EN（濒危）","distribution":"分布于哥伦比亚中北部，具体包括帕拉莫德弗龙蒂诺、拉斯奥尔奇德亚斯国家自然公园、法拉隆内斯德尔西塔拉、加尔迪恩、塞罗蒙特苏马等地，栖息于海拔3100至3500米的湿润森林、苔藓矮林和森林-草原过渡地带，以及在塞罗蒙特苏马的一次记录来自海拔2500米的原始森林。","other":"暗星额蜂鸟曾一度被认为是金腹星额蜂鸟的亚种，直到2004年在帕拉莫德弗龙蒂诺和法拉隆内斯德尔西塔拉被重新发现，才确认其独立物种的地位。"},{"name":"蓝喉星额蜂鸟","english_name":"Blue-throated Starfrontlet","scientific_name":"Coeligena helianthea","overview":"蓝喉星额蜂鸟（英文名：Blue-throated Starfrontlet，学名：Coeligena helianthea），是雨燕目蜂鸟科星额蜂鸟属的鸟类。壮观的蜂鸟，分布于南美洲的哥伦比亚东北部至委内瑞拉西部山区，具有独特的暗黑头部和胸脯，配以绿色前额、蓝色喉部斑块和闪烁的紫色腹部。","appearance":"雄鸟拥有约13厘米的身长，重7.1至7.6克；雌鸟稍轻，重6至6.5克。雄鸟特征鲜明，黑色长而直的喙，头部黑色，前额深绿色，带有白色耳后斑点，上体略带绿宝石光泽，下背部和臀部呈深蓝色，带有紫色调。下体灰色带绿宝石光泽，紫罗兰色喉部斑块，腹部和尾下覆羽闪耀玫瑰色。雌鸟头部灰绿色，上体金色绿渐变为蓝紫色臀部，喉部赤褐色，胸部赤褐色带绿色斑点，腹部玫瑰色，尾下覆羽颜色较浅。幼鸟与成年雌鸟相似。","call":"蓝喉星额蜂鸟较为沉默，其声音知之甚少，已知叫声包括尖锐的单音节‘chit’声。","habits":"栖息于云雾林、森林边缘、灌木斜坡以及偶尔出现在高山草原的边缘地带，也常光顾开花的花园。以花蜜为食，通过在低层植被间穿梭的方式觅食，同时捕食小型节肢动物。","breeding":"繁殖季节从5月持续到10月，关于其繁殖生态的详细信息尚不明确。","identification":"雄鸟以其独特的蓝色喉部斑块和闪烁的紫色腹部易于识别。雌鸟与雄鸟相比，头部颜色更偏灰绿色，腹部色彩更为柔和。","protection":"IUCN：LC（无危）","distribution":"主要分布在哥伦比亚东北部和委内瑞拉西部的安第斯山脉区域，具体包括哥伦比亚北部和东部的安第斯山脉，以及委内瑞拉塔奇拉州的塔马山脊。"},{"name":"黄翅星额蜂鸟","english_name":"Buff-winged Starfrontlet","scientific_name":"Coeligena lutetiae","overview":"黄翅星额蜂鸟（英文名：Buff-winged Starfrontlet，学名：Coeligena lutetiae），是雨燕目蜂鸟科星额蜂鸟属的鸟类。体型较大，长喙的蜂鸟种类，分布于哥伦比亚南部至秘鲁西北部的安第斯山脉。以绿色为主色调，具有显著的淡黄色翼斑，雄鸟喉部有紫色斑点，雌鸟喉部淡黄色。常见于云雾森林、高山矮林和亚高山地带。","appearance":"长约14厘米，雄鸟体重6.9-7.2克，雌鸟约6.6克。雄鸟具长而微翘的黑色喙，上半身为天鹅绒般黑色，前额有绿色光泽，眼后有白色斑点；下半身深绿色，紫色喉部斑点；翅膀深色，次级飞羽呈肉桂黄色；尾巴分叉，铜黑色。雌鸟上半身深绿色带光泽，翅膀肉桂黄色斑点明显，喉咙肉桂黄色，下半身金绿色，有浅色羽毛边缘；尾巴较圆，偏铜绿色。幼鸟似雌鸟。亚种albimaculata雄鸟翅膀几近白色，对比强烈，雌鸟颏部和喉咙色泽偏淡，下体有更多浅黄色斑纹。","call":"发出细薄、金属质感的颤音，伴有咔嗒声，通常在空中高速追逐时听到。喂食时会重复发出鼻音的‘unk’声。","habits":"栖息于海拔2,600至4,800米的云雾森林、矮林和亚高山地带，最常见于3,000米左右。通常在林缘和空旷地活动，领地性强，常在花丛间盘旋觅食，偶尔停歇。以花蜜为主食，也会捕捉小昆虫。","breeding":"繁殖期在哥伦比亚为8月至9月，筑杯状巢于树叉间，离地2至4米，由雌鸟孵化两枚白色蛋，孵化期15至17天。","identification":"与其他Coeligena属蜂鸟相比，黄翅星额蜂鸟最显著的特征是其翼斑的色彩。亚种albimaculata的雄鸟翅膀颜色更为独特，雌鸟下体颜色有别。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲安第斯山脉，自哥伦比亚中部向南延伸至厄瓜多尔，直至秘鲁最北端。在哥伦比亚、厄瓜多尔和秘鲁均有记录。","other":"在Podocarpus国家公园（厄瓜多尔）有分布。过去曾因野生鸟类贸易而被引入欧洲，但现已因国际法规而停止。"},{"name":"紫喉星额蜂鸟","english_name":"Violet-throated Starfrontlet","scientific_name":"Coeligena violifer","overview":"紫喉星额蜂鸟（英文名：Violet-throated Starfrontlet，学名：Coeligena violifer），是雨燕目蜂鸟科星额蜂鸟属的鸟类。此物种分布在南美洲，包括秘鲁北部至玻利维亚西北部，拥有绿色头部与青铜色身体，雄鸟特征明显，拥有虹彩般的紫色喉部和蓝色前额，雌雄体重差异显著。","appearance":"紫喉星额蜂鸟体型介于13至14.5厘米，雄鸟体重通常在5至13克之间，雌鸟在4至7克之间。雄鸟具有黑色长而直的喙，额头呈绿松石色，冠部深绿色，喉部有紫色斑点，腹部金绿色。雌鸟相似但缺乏前额和喉部斑点。幼鸟似雌鸟成鸟。","call":"发出一系列快速的‘tchit’音符，每秒约1.6个音符，亦会发出断断续续的尖锐音符和咔哒声。其歌声被描述为连续的、尖锐的节奏性短语，伴随高音调的叽叽喳喳。","habits":"栖息于云雾林边缘、精灵森林和次生林，海拔高度在1900至3700米间。以花蜜为主食，同时捕食小节肢动物，有季节性垂直迁徙习性。","breeding":"繁殖季节开始于7月至8月，具体繁殖行为细节尚不清楚。","identification":"与同属其他物种的区别在于其独特的喉部和前额色彩，以及尾部的鲜明图案。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲北部秘鲁至西北部玻利维亚，可能延伸至厄瓜多尔。"},{"name":"彩虹星额蜂鸟","english_name":"Rainbow Starfrontlet","scientific_name":"Coeligena iris","overview":"彩虹星额蜂鸟（英文名：Rainbow Starfrontlet，学名：Coeligena iris），是雨燕目蜂鸟科星额蜂鸟属的鸟类。南美洲安第斯山脉南部（厄瓜多尔南部和秘鲁北部）特有的壮观大型蜂鸟。其羽毛色彩斑斓，随地理位置而异，但所有个体均具有明亮的栗色下背、尾巴、腹部和翅膀，以及绿色胸羽。头部颜色从锈色至璀璨的绿蓝色，喉部斑块可能呈紫色或蓝色，大小不一。","appearance":"雄鸟拥有一根长直的黑色喙，头部黑色，前额闪烁着黄绿色，逐渐过渡至金色黄色再到蓝色，具白色眼后斑点，背部黑色带有微弱的绿色光泽，下背部栗色；喉咙闪耀着翠绿色，带有小块紫罗兰色喉斑，下腹及尾下覆羽栗色；尾巴叉开，统一栗色。雌鸟比雄鸟暗淡，缺乏喉部斑块和金属光泽。幼鸟与成年雌鸟相似。","call":"发出细薄、金属质感的叽喳声，音调起伏，伴有颤音和尖锐音符，常在高速空中追逐时发出。亦会发出单个‘tsit’或‘tip’声。","habits":"栖息于湿润和较干燥的云雾森林边缘、花园和河岸灌木丛，海拔1700至3300米，曾记录在秘鲁Huascarán国家公园高达4000米处。觅食活动低矮，离地面2至4米。以花蜜为食，访问各种花朵，包括Embothrium、Fuchsia等，偶尔在引进的桉树上觅食。通过悬停捕食空中昆虫。","breeding":"繁殖季节为11月至1月。杯状巢由苔藓、地衣和小枝条构成，内衬柔软的植物材料，置于小枝分叉处。关于繁殖生态的详细信息尚缺。","identification":"与同属其他物种相比，雄鸟具有独特的前额色彩和深叉的尾巴，雌鸟较为暗淡，尾部较不叉开。不同亚种在头冠颜色、背部色调、喉部斑点和下体颜色上有显著差异。","protection":"IUCN：LC（无危）。CITES II。此物种为南方中央安第斯山脉特有种，局部常见，但因其分布范围极窄而可能面临威胁。自然栖息地遭受森林砍伐威胁，且高度破碎化。人类制造的环境，如花园和公园景观，被该物种接受到一定程度。","distribution":"繁殖区域位于南美洲的厄瓜多尔和秘鲁。在厄瓜多尔，可见于Las Cajas国家休闲区和北Podocarpus国家公园。","other":"该物种有六个亚种，历史上曾将其中三个亚种视为独立物种。"},{"name":"绿星额蜂鸟","english_name":"Green Inca","scientific_name":"Coeligena conradii","overview":"绿星额蜂鸟（英文名：Green Inca，学名：Coeligena conradii），是雨燕目蜂鸟科星额蜂鸟属的鸟类。主要分布于南美洲安第斯山脉的云雾森林中，从委内瑞拉西北部的特鲁希略至塔奇拉北部，以及哥伦比亚北部的桑坦德省。这种蜂鸟体型较大，拥有醒目的白色胸带和尾羽标记，雄鸟的喉咙上方呈绿色，而雌鸟的喉咙则是淡黄色。其自然历史研究较少，繁殖习性至今不明。","appearance":"绿星额蜂鸟体长约14.5厘米，雄鸟几乎全身闪耀着草绿色，仅上胸处有宽阔的白色胸带，尾羽外侧大部为白色，尖端绿色；翅膀呈褐色。雌鸟相似，但腹部灰暗，喉咙带有锈色并点缀以绿色斑点，胸带较窄。它们拥有长而直的黑色喙，尾部分叉。","call":"绿星额蜂鸟最常见的叫声是一种刺耳的叽喳声，还发出柔和低沉的芦苇哨音“tu-tee”，一系列低音的笛音“pip..pip..pip...”，以及觅食时短暂的“spit”或“tsit”。兴奋时，会发出一连串的口哨和柔和音符。","habits":"绿星额蜂鸟栖息于湿润的高山云雾林内部和边缘，海拔主要在1800至3000米之间，偶尔低至1500米。它们以花蜜为食，偏爱Cavendishia、Fuchsia和杜鹃花科植物的花朵，同时也捕食昆虫。通常采取陷阱线喂食的方式，即沿着固定路线访问一系列开花植物。","identification":"绿星额蜂鸟与铜色星额蜂鸟在较低海拔和更湿润的森林中生态位相似，但两者可以共存。主要通过白色胸带和尾部标记来区分。","protection":"IUCN：LC（无危）","distribution":"绿星额蜂鸟分布于南美安第斯山脉的委内瑞拉西北部（特鲁希略至塔奇拉北部）和哥伦比亚北部的桑坦德省。","other":"绿星额蜂鸟曾被认为是领星额蜂鸟的一个亚种。"},{"name":"锈胸星额蜂鸟","english_name":"Gould's Inca","scientific_name":"Coeligena inca","overview":"锈胸星额蜂鸟（英文名：Gould's Inca，学名：Coeligena inca），是雨燕目蜂鸟科星额蜂鸟属的大型蜂鸟。分布于南美洲东南部秘鲁至玻利维亚的安第斯山脉云雾森林地带，拥有醒目的橙色颈环和白色尾羽边缘。雄鸟头部黑色，前额呈蓝宝石色斑点；雌鸟可能与紫喉星额蜂鸟雌鸟混淆，但橙色颈环和白色（非淡黄色）尾纹明显。此物种曾被归类为领星额蜂鸟的亚种群。","appearance":"锈胸星额蜂鸟体型健壮，长约14.5厘米，体重6.8至7.2克。喙长而直，尾部分叉。雄鸟头部深黑，前额绿宝石色，眼后有小白斑，上体暗绿色，下背光泽更甚。中央尾羽青铜绿，其余尾羽白底绿尖。喉部黑色，橙色颈环突出，腹部闪烁着绿色，下尾覆羽金绿带白边。雌鸟头部比雄鸟略浅的黑色，有金色绿斑，上体闪金绿色，颈环红棕色，通常侧边带绿斑，下腹绿色，带有红棕色晕染和大金绿斑。幼鸟与成年雌鸟相似。","call":"锈胸星额蜂鸟的叫声特征未作描述。","habits":"栖息于湿润的山地森林，尤其偏爱茂密多苔藓的林区和灌木丛边缘。偏好长而下垂的管状花朵，常悬停其下吸食花蜜。活动范围在海拔1,600至3,200米之间，可能进行季节性短距离迁移和繁殖后扩散。以捕食昆虫和其他节肢动物为辅食。","breeding":"筑巢类似于领星额蜂鸟，巢杯状，由苔藓构成，内衬蕨类鳞片，直径约45毫米，外部直径75至82毫米，深度31毫米。巢置于岩石悬崖下的苔藓遮蔽处，高2至11米。每窝产1至2枚卵，卵白色，呈药丸状，大小约为15x9毫米，重0.75克。孵化期未知，雏鸟离巢期约23天。仅雌鸟负责孵化和照料雏鸟。","identification":"锈胸星额蜂鸟与领星额蜂鸟有明显区别，特别是雄鸟头部的蓝宝石色前额和雌鸟的橙色颈环。亚种omissa与指名亚种相似，但额头蓝色，喉部更绿，上下体颜色更暗绿而非金绿。","protection":"IUCN：LC（无危）","distribution":"分布于秘鲁东南部至玻利维亚的安第斯山脉。在玻利维亚的拉巴斯和科恰班巴部门以及秘鲁库斯科和普诺部门之间的安第斯山脉均有发现。","other":"锈胸星额蜂鸟在某些地区访问喂食器，是当地常见物种。"},{"name":"佩里星额蜂鸟","english_name":"Perija Starfrontlet","scientific_name":"Coeligena consita","overview":"佩里星额蜂鸟（英文名：Perija Starfrontlet，学名：Coeligena consita），是雨燕目蜂鸟科星额蜂鸟属的鸟类。生活在南美洲佩里哈山脉（横跨哥伦比亚东北部和委内瑞拉西部）的中型、长喙蜂鸟。其独特之处在于拥有金色腹部、蓝色喉斑和闪烁绿色前额，雌鸟则具有淡黄色喉部。过去被视为金腹星额蜂鸟的一个亚种。","appearance":"佩里星额蜂鸟体长约11厘米，喙长3厘米，呈直线状，黑色。雄鸟的前额闪耀着绿色，头部其余部分为黑色，上背部为深绿色，向金橙色臀部过渡。喉咙和胸部为闪光绿色，中央有一小片深蓝色。腹部至下部的羽毛颜色从铜色到火红或红金色不等。翅膀较暗，具有醒目的红褐色翼盖。尾巴略呈叉状，呈金青铜绿色。雌鸟的前额为平淡绿色，眼后有白色至橙色的斑点，上半身颜色似雄鸟但较为暗淡。喉咙为淡黄色，带绿色斑点，胸部混杂着淡黄色和绿色，下半身主要为肉桂色，腹部为火红色，铜色的下腹部。幼鸟外观与雌鸟相似。","call":"目前尚无关于佩里星额蜂鸟叫声的录音资料。","habits":"佩里星额蜂鸟栖息于高海拔的云雾森林，常在低至中高度的花朵上悬停采蜜，同时也会捕捉小型昆虫。它在1400米至3200米的范围内活动，偏好湿润森林内部和边缘，以及更高海拔的矮林和一些开阔地带。","identification":"佩里星额蜂鸟最易与金腹星额蜂鸟和金尾星额蜂鸟混淆，但前者在翅膀上有红褐色的翼盖，而后者则主要具有红褐色的尾巴。在分布范围内不会与这两种蜂鸟重叠。","protection":"IUCN：EN（濒危）","distribution":"佩里星额蜂鸟仅限于南美洲的佩里哈山脉，该山脉位于哥伦比亚东北部和委内瑞拉西部。","other":"过去曾被认为是金腹星额蜂鸟的亚种，现已确认为独立物种。"},{"name":"金尾星额蜂鸟","english_name":"Golden-tailed Starfrontlet","scientific_name":"Coeligena eos","overview":"金尾星额蜂鸟（英文名：Golden-tailed Starfrontlet，学名：Coeligena eos），是雨燕目蜂鸟科星额蜂鸟属的鸟类。仅分布在委内瑞拉安第斯山脉。体型较大，喙长，拥有独特的橙色翼斑，雄鸟有紫罗兰色喉部饰羽、绿色前额及金色腹部。栖息于高海拔云雾森林，偏好长管状花的蜜源。","appearance":"雄性金尾星额蜂鸟拥有闪光绿前额，黑色冠部，上背闪亮绿色至金色，臀部及下体呈火热的金橙色。腹部及下体有铜红色至火红金色的变化。雌鸟较为暗淡，前额绿色，喉部至胸侧有绿色斑点，胸部混合绿色和肉桂色，下体大多肉桂色，腹部有金色闪烁，下腹部铜金色。喙长而直，黑白色眼后斑。","habits":"栖息于湿润森林内部及边缘，海拔1400至3200米，也见于矮树森林及开阔地带的零散植被中。以长管状花为食，如杜鹃花科、Centropogon及倒挂金钟属植物。在雨季可能向更高海拔迁移。","breeding":"繁殖季节大约从一月至三月。筑杯形巢，由苔藓、地衣和根须构成，内衬柔软植物材料，通常位于垂直枝条上。其繁殖生态细节未知。","identification":"与金腹星额蜂鸟和佩里星额蜂鸟相似，但金尾星额蜂鸟具有翼上的赤褐色羽片，尾部主要为赤褐色，末端有青铜绿色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲委内瑞拉西部的安第斯山脉，从Lara州到Táchira州之间。"},{"name":"剑嘴蜂鸟","english_name":"Sword-billed Hummingbird","scientific_name":"Ensifera ensifera","overview":"剑嘴蜂鸟（英文名：Sword-billed Hummingbird，学名：Ensifera ensifera），是雨燕目蜂鸟科剑嘴蜂鸟属的独特物种。该鸟拥有世界上相对其体型最长的喙，这一特征令人难以忘怀。体羽呈柔和的绿色，头部泛着青铜光泽。剑嘴蜂鸟分布于南美洲安第斯山脉温带区，从委内瑞拉延伸至玻利维亚北部，常出现在海拔2500至3500米的地带。它利用其非凡的喙从细长的花朵中汲取花蜜。","appearance":"剑嘴蜂鸟体长介于17至22.8厘米，包括9至11厘米的喙长，体重在10至15克之间。雄鸟喙稍短，但翅膀和尾部更长且分叉更深。拥有蜂鸟中最长的喙，略向上弯曲，色泽黑亮。雄鸟通体呈深绿色，头部铜色，眼后有白色斑点；喉咙暗色，下体闪耀翡翠绿，腹部灰暗；尾巴叉开，近黑色。雌鸟与雄鸟相似，但喉部和腹部颜色较浅，尾部分叉较小。幼鸟外观与雌鸟相近。","call":"会发出低沉、略带颤音的“trrr”声。","habits":"栖息于湿润至半湿润的高海拔山地森林及其边缘，有时出现在矮树丛和花园中，海拔高度从1700至3500米，最常见于2500至3000米。通常在固定路线觅食，偏好有长垂花冠的花朵，如Aethanthus、Brugmansia、Fuchsia等，以悬停的方式从下方探入花朵吸食花蜜。也会像燕子般张口捕食昆虫。","breeding":"繁殖期从2月至3月，巢穴呈杯状，由苔藓构成，通常挂在高处的树根纤维中。","identification":"与其他蜂鸟相比，剑嘴蜂鸟的喙异常长，使其在形态上很容易区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲安第斯山脉，自委内瑞拉西部至玻利维亚东北部，包括哥伦比亚、厄瓜多尔和秘鲁的部分地区。","other":"已适应人造环境，在某些地方，如委内瑞拉的Los Frailes酒店附近，当有合适的花卉时，会在花园中觅食。"},{"name":"蓝翅大蜂鸟","english_name":"Great Sapphirewing","scientific_name":"Pterophanes cyanopterus","overview":"蓝翅大蜂鸟（英文名：Great Sapphirewing，学名：Pterophanes cyanopterus），是雨燕目蜂鸟科蓝翅大蜂鸟属的鸟类。是南美洲特有的一种大型蜂鸟，分布于哥伦比亚至玻利维亚北部的安第斯山脉地区。雄鸟拥有闪耀的翡翠绿上羽和明亮的蓝翼，而雌鸟则呈现绿色背部与肉桂色下部。作为世界上最大的蜂鸟种类之一，在栖息地中通常是最庞大的。该物种主要栖息于热带云雾森林、小矮林边缘和灌木斜坡。","appearance":"雄性蓝翅大蜂鸟长达19-20厘米，体重9.6-11.2克，具有深邃的蓝绿色上羽，翅膀闪耀着蓝色光泽，尾部深叉状，下部呈蓝绿色。雌鸟体型略小，长约16-17厘米，重8.4-11克，其上羽为金属绿色，下部为肉桂红褐色，翼覆羽为蓝色，初级飞羽蓝度较低，下部有绿色斑点。幼鸟外观类似雌鸟，但绿斑较少。","call":"蓝翅大蜂鸟发出类似啾啾的高音鸣叫，常在领地展示和空中追逐中听到。","habits":"蓝翅大蜂鸟偏好栖息于安第斯山脉的潮湿热带云雾森林、小矮林边缘和灌木斜坡，海拔高度从2,600米至3,700米不等。它们以多种开花植物的花蜜为食，同时也会捕食小型节肢动物。在觅食时，它们会盘旋或停歇在植物边缘，有时会进行花区守护，有时则沿着固定的觅食路径移动。","breeding":"蓝翅大蜂鸟的繁殖季节不固定，至少包括2月至5月。已知的巢穴构造奇特，由苔藓构成，内部铺有柔软纤维，分为三个隔间，其中一个隔间曾发现有雌鸟正在孵育两只雏鸟。","identification":"蓝翅大蜂鸟与阔嘴蜂鸟和金胸毛腿蜂鸟相似，但体型更大，蓝绿色更为鲜艳，嘴喙较长。与这两者相比，蓝翅大蜂鸟的脚为粉红色。","protection":"IUCN：LC（无危）","distribution":"蓝翅大蜂鸟分布于南美洲的哥伦比亚至玻利维亚北部，覆盖了安第斯山脉的东部和西部地区，包括哥伦比亚、厄瓜多尔、秘鲁和玻利维亚的部分地区。","other":"尽管对森林损失或碎片化敏感，但由于能够容忍森林边缘环境，蓝翅大蜂鸟的脆弱程度低于许多其他山地森林物种。"},{"name":"巨蜂鸟","english_name":"Giant Hummingbird","scientific_name":"Patagona gigas","overview":"巨蜂鸟（英文名：Giant Hummingbird，学名：Patagona gigas），是雨燕目蜂鸟科巨蜂鸟属的鸟类。独特的体型弥补了羽毛较为暗淡的外观，无相似物种。分布于南美洲，从哥伦比亚南部至智利中部。","appearance":"巨蜂鸟体长可达21.5厘米，体重介于18.5至20.2克之间，部分个体可能超过23克。羽毛上部为暗淡橄榄棕色，臀部显眼的白色与青铜绿色尾羽覆羽形成对比；叉状楔形尾巴呈青铜橄榄色，尾羽基部较浅色，最外侧羽毛中央部分为灰白色；下部及颈部侧面为暗肉桂色，尾下覆羽为白色。雌鸟上部似雄鸟，但下部通常带有不同程度的暗灰色斑点；幼鸟下方呈红褐色，喉部有时点缀灰色，上部似有细鳞状纹路，飞羽边缘为白色。","call":"巨蜂鸟能发出响亮尖锐的叫声，混合着刺耳的哨音和颤音，听起来略似雀鸟。","habits":"偏爱干燥开阔的环境，从灌木丛到花园和安第斯山脉的灌木丛，常在灌木顶或路边电线杆上显眼地栖息。飞行时翼拍缓慢有力，偶尔滑翔，捕食时会突然加速。主要在低植被地带活动，高度不超过10米。在厄瓜多尔和北秘鲁，常见于龙舌兰主导的区域和灌木峡谷，靠近小溪；在南美南部，偏好Puya和桉树林以及Polylepis和Buddleia树林，同时出现在村庄附近的篱笆和花园中。","breeding":"繁殖季节主要在12月至次年3月（厄瓜多尔）、9月至次年3月（秘鲁）或10月至次年1月（智利）和2月（阿根廷西北部）。巢宽约10厘米，深6厘米，由苔藓和地衣组成，用蜘蛛网固定，内部铺以羊毛或少量羽毛。巢通常位于大树或灌木枝条上，或仙人掌茎顶，高度多在2至4米。每窝产卵两枚，偶尔一枚；孵化期12至13天，仅由雌鸟承担。","identification":"巨蜂鸟以其显著的体型和缓慢的翼拍飞行方式与其它蜂鸟区分，尤其是雄鸟的白色臀部和青铜绿色尾羽覆羽。","protection":"IUCN：LC（无危）。CITES II。在其广泛分布范围内，巨蜂鸟一般并不罕见，不局限于受威胁的生境类型，常在人类影响的环境中出现。在多个保护区中存在，例如厄瓜多尔的科托帕希国家公园和智利的塞罗拉卡姆帕纳国家公园。","distribution":"巨蜂鸟分布于南美洲，自哥伦比亚南部至智利中部，包括厄瓜多尔、北秘鲁、秘鲁、玻利维亚、阿根廷北部和智利南部。"},{"name":"绿背火冠蜂鸟","english_name":"Green-backed Firecrown","scientific_name":"Sephanoides sephaniodes","overview":"绿背火冠蜂鸟（英文名：Green-backed Firecrown，学名：Sephanoides sephaniodes），是雨燕目蜂鸟科火冠蜂鸟属的鸟类。是南美洲南部常见的蜂鸟种类。体长约10.5厘米，雄鸟体重约5.5克，雌鸟约5克。雄鸟具独特的火红黄色额冠，雌鸟冠部不具虹彩。分布于智利中部至南端，阿根廷中部及西部，以及胡安·费尔南德斯群岛。","appearance":"绿背火冠蜂鸟体型较为壮实，喙直而尖锐，眼后有白色斑点。雄鸟的额头和冠部有虹彩般的火红黄色，上体呈青铜绿色，下体淡黄褐色，两侧融合黑色和绿色斑点；翅膀和尾巴为板岩绿色。雌鸟类似，但缺乏虹彩冠部。幼鸟头部羽毛边缘锈色，下体更偏肉桂色。","call":"其典型鸣唱是一系列高音调的音符，间杂沙哑的颤音和尖叫声，‘pseee...pseee...krrr.skee.skee.skee....psee...’。叫声为单一的‘psee’或‘skee’。","habits":"栖息于森林边缘、桉树种植园、开阔地、灌木丛和花园，偏好海拔从海平面到2000米以上的地区。迁徙发生在南部大陆区域，冬季迁往阿根廷低地，包括东至楚布特的太平洋沿岸。","breeding":"筑巢季节在南美洲大陆从9月至11月，胡安·费尔南德斯群岛则可能从9月至12月。巢为小杯状，有时建在水面上方。一窝产两枚白色蛋。关于繁殖生态的其他信息未知。","identification":"雄鸟具有明显的火红黄色额冠，与雌鸟相比，雄鸟体型较大，喙较短。胡安·费尔南德斯火冠蜂鸟是其近亲，但仅限于胡安·费尔南德斯群岛。","protection":"IUCN：LC（无危）","distribution":"分布于智利中部至南端，阿根廷中部及西部，以及胡安·费尔南德斯群岛。在智利，分布从阿塔卡马以南直至南美洲最南端；在阿根廷，分布于南部及中部，东至大西洋海岸。","other":"绿背火冠蜂鸟在人类改造的环境中如城市公园和花园中表现良好，是重要的传粉者。"},{"name":"火冠蜂鸟","english_name":"Juan Fernandez Firecrown","scientific_name":"Sephanoides fernandensis","overview":"火冠蜂鸟（英文名：Juan Fernandez Firecrown，学名：Sephanoides fernandensis），是雨燕目蜂鸟科火冠蜂鸟属的独特物种，仅在智利胡安·费尔南德斯群岛的罗宾逊·克鲁索岛发现。雄鸟以其鲜艳的橙色锈红全身和炫目的火冠闻名，而雌鸟外观截然不同，上部为蓝绿色，头冠蓝色，尾侧白色，下部雪白带黑绿斑点。","appearance":"雄性火冠蜂鸟体长11.5至12厘米，体重约10.9克，具直而黑色的喙，头部前额和冠部闪耀着火红色光泽，全身及尾巴为肉桂橙色，翅膀呈深铜灰色。雌鸟体长约10.5厘米，体重约6.8克，冠部呈现蓝紫金属光泽，上体蓝绿色，下体雪白间杂黑色圆点，翅膀灰绿色，尾羽中央及外侧基部蓝绿色，内侧基部白色。幼鸟随年龄增长，雄鸟的冠部逐渐增大并增强光泽，雌鸟下体颜色较成鸟更偏淡黄褐色。","call":"火冠蜂鸟的鸣唱是一系列高音调的吱吱声、干涩的沙哑颤音和下降的叽叽喳喳声。","habits":"栖息于森林、种植园、灌木丛和花园，偏好阴凉避风的环境，尤其在耕作区数量最多。夏季时，雄性火冠蜂鸟在圣胡安巴蒂斯塔主街附近大量出现，此时Dendroseris树开花。火冠蜂鸟以多种花卉的花蜜为食，偏好本地特有植物Dendroseris littoralis和Rhaphithamnus venustus，也会利用外来植物如Abutilon和Eucalyptus globulus作为食物来源。它们偏爱地面以上的阴影花朵，两性都会保卫觅食领地，雄鸟尤其会激烈守卫最富饶的植物。昆虫也是其饮食的一部分，尤其是在育雏期间比例增加。","breeding":"繁殖季节从9月至11月中旬，巢小而杯状，位于地面约4米高的隐蔽处，通常在Myrceugenia、Cupressus或Blechnum的枝梢，由蕨类纤维、Lophosoria绒毛、Weymouthia苔藓和蜘蛛茧网构成。巢外部直径55至75毫米，内部直径23至32毫米，深度20至30毫米。每窝产两个白色蛋，尺寸约为18毫米×11毫米。部分巢穴遭受南美鸫的掠食。","identification":"雄性火冠蜂鸟具有独特的外观，难以混淆；而雌鸟可能与较小、颜色较浅、腹部较暗且喉部斑点较稀疏的绿背火冠蜂鸟混淆，后者在相同地区也有分布。","protection":"IUCN：CR（极危）。被列入《濒危野生动植物种国际贸易公约》（CITES）附录II。该物种分布局限于智利胡安·费尔南德斯群岛，目前估计成熟个体数量为1700至2000只，仅限于罗宾逊·克鲁索岛。历史上曾广泛分布于群岛两大岛屿，19世纪时估计数量达数千，最后一次在亚历山大·塞尔克里克岛上记录到是在1908年。自1830年首次记录以来，绿背火冠蜂鸟数量估计已达到4000至6000只。","distribution":"火冠蜂鸟的分布仅限于南美洲的智利胡安·费尔南德斯群岛，具体而言，仅在罗宾逊·克鲁索岛上繁殖。","other":"人类活动导致的自然植被破坏、外来物种入侵以及捕食者的引入对其生存构成了威胁。"},{"name":"橙喉领蜂鸟","english_name":"Orange-throated Sunangel","scientific_name":"Heliangelus mavors","overview":"橙喉领蜂鸟（英文名：Orange-throated Sunangel，学名：Heliangelus mavors），是雨燕目蜂鸟科领蜂鸟属的鸟类。是南美洲特有的领蜂鸟属物种，主要分布在委内瑞拉西北部和哥伦比亚东部安第斯山脉地区。其最显著的特征是雄鸟的铜橙色喉部和绿色体羽。","appearance":"体型中等，长度约10至11厘米，体重3.9至4.4克。雄鸟具有发亮的绿色头部和背部，喉部及上胸呈闪耀的铜橙色，下胸为肉桂色，带有金色绿斑点。雌鸟的喉部和上胸为红棕色，带有淡色斑点，与雄鸟相似，但更柔和。幼鸟类似雌鸟，年轻雄鸟喉部呈暗褐色。","call":"发出连续的高音、类似蟋蟀的微弱颤音，音调约为6千赫兹，持续时间约0.3至1秒，既可在栖息处也可在飞行中发出。","habits":"栖息于云雾森林边缘、牧场、花园和开阔地带，常单独活动或在花丛附近与其他个体争斗。主要以花蜜为食，常停在花朵上吸食，同时也会从栖息处捕捉昆虫。","breeding":"繁殖季节从12月至翌年3月，巢穴未被描述，雌鸟孵卵，通常在第二年首次繁殖，孵化期和离巢时间未知。","identification":"与雌性紫喉领蜂鸟相似，但后者胸部有一白色带状标记；与雌鸟泰里安金属尾蜂鸟区别在于体型更大，尾羽颜色不同。","protection":"IUCN：LC（无危）","distribution":"分布于委内瑞拉的拉腊州至塔奇拉州，以及哥伦比亚北部桑坦德省至博亚卡省。"},{"name":"辉喉领蜂鸟","english_name":"Amethyst-throated Sunangel","scientific_name":"Heliangelus amethysticollis","overview":"辉喉领蜂鸟（英文名：Amethyst-throated Sunangel，学名：Heliangelus amethysticollis），是雨燕目蜂鸟科领蜂鸟属的鸟类。主要栖息于安第斯山脉的云雾森林中，从厄瓜多尔东南部至玻利维亚。其最显著特征为大胆的白色颈弯月纹。体型中等，羽色华丽。","appearance":"雄性辉喉领蜂鸟拥有闪光的紫罗兰色喉咙和绿松石色前额，上体呈深绿色，下体由闪烁的绿色至淡黄色，具黑色边界的紫水晶色喉部。雌鸟大多缺乏虹彩，喉部常带有橙色或肉色。幼鸟外观类似雌鸟。","call":"鸣叫表现为短促、嗡嗡的干颤音，间隔重复。","habits":"偏好湿润的山地森林内部，包括云雾林和矮树丛，偶尔出现在森林边缘和开阔的灌木地带。通常在高达3700米的海拔范围内活动，以花蜜和高比例的昆虫为食，善于守卫密集的蜜源地。","breeding":"繁殖期在秘鲁为2月至3月，雌鸟使用细小植物纤维、苔藓和地衣构建巢穴，一般离地面约1.5米，置于遮蔽处。每窝产两枚卵，由雌鸟独自孵化，首次繁殖发生在其第二年，孵化期和雏鸟离巢时间未知。","identification":"与暗绿领蜂鸟不重叠分布，通过白色的颈带与其它领蜂鸟区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于南美，自厄瓜多尔南部至玻利维亚西北部。","other":"物种分类尚存争议，涉及多个亚种的归属问题。"},{"name":"龙氏领蜂鸟","english_name":"Longuemare's Sunangel","scientific_name":"Heliangelus clarisse","overview":"龙氏领蜂鸟（英文名：Longuemare's Sunangel，学名：Heliangelus clarisse），是雨燕目蜂鸟科领蜂鸟属的鸟类。是中等体型的云林蜂鸟，主要分布在南美洲的哥伦比亚东部安第斯山脉和委内瑞拉西部，包括相邻的Perijá山脉。其最显著的特征为雄鸟拥有一片闪耀的紫罗兰色或紫色喉咙，下方边缘以细窄的白色新月形带环绕。雌鸟喉咙斑驳，呈绿色与棕色交织，缺乏金属光泽。","appearance":"龙氏领蜂鸟体长9至10厘米，体重介于5.0至6.0克。具有短而直的黑色喙，长度不足2厘米。雄鸟成鸟头部前端有一片狭窄的蓝绿色闪光区，冠部暗淡，上体呈深青铜绿色。喉咙及上胸部有闪亮的玫瑰色饰羽，下方有白色的胸带，腹部余下部分为暗淡的米色，带有圆形绿斑。尾内侧羽毛深青铜绿色，外侧羽毛黑色，偶尔可见淡色尖端。雌鸟喉咙羽毛呈暗褐色，带有红铜色或青铜绿色斑点，腹部斑点少于雄鸟。幼鸟羽毛与成年雌鸟相似。","call":"龙氏领蜂鸟的叫声为重复的干燥、上扬的‘tsik’或‘tsit’声。","habits":"龙氏领蜂鸟主要栖息于湿润的云林边缘和矮林地带，也能在较开阔的景观中发现，如散布着灌木和树木的田野、开放的树林、杂草丛生的溪谷及高海拔的草地。它们的活动范围在海拔1,800至3,600米之间。以花蜜为食，同时摄入昆虫，会捍卫富含花蜜源的领地，通常在高达6米的位置觅食，常沿溪流活动。捕食昆虫时，会从栖息处捕捉。","breeding":"繁殖季节至少从5月至8月。巢穴由苔藓和细小植物材料构成，通常悬挂在叶片下或提供避雨结构的其他物体下。每窝产两枚卵，仅由雌鸟孵化，孵化期和雏鸟离巢时间未知。","identification":"与暗绿领蜂鸟相比，龙氏领蜂鸟雄鸟的腹部略带米色。与橙喉领蜂鸟的区别在于喉咙颜色和颈部的白色（而非米色）带状图案。","protection":"IUCN：LC（无危）","distribution":"龙氏领蜂鸟主要分布在哥伦比亚东部安第斯山脉和相邻的委内瑞拉西部，包括Serranía del Perijá山脉以及Tamá Massif山地，后者位于两国边境的哥伦比亚东安第斯山脉延伸部分。","other":"过去被认为是辉喉领蜂鸟的一个亚种。"},{"name":"梅里达领蜂鸟","english_name":"Merida Sunangel","scientific_name":"Heliangelus spencei","overview":"梅里达领蜂鸟（英文名：Merida Sunangel，学名：Heliangelus spencei），是雨燕目蜂鸟科领蜂鸟属的鸟类。仅见于委内瑞拉安第斯山脉梅里达附近的云雾森林，以其所在城市命名。雄鸟具闪耀紫罗兰色喉部，绿色前额，及白色颈带；雌鸟喉部斑驳，缺乏金属光泽。曾被认为是辉喉领蜂鸟的一个亚种。","appearance":"梅里达领蜂鸟体长10至11厘米，拥有直而黑的喙。成年雄鸟的前额呈淡蓝色，冠羽深绿，上体闪烁着绿色光泽，面颊有黑色耳羽，喉部及上胸为耀眼的紫色，缀以粉红鳞片，其下有一白色胸带，余下腹面呈黄色到淡黄褐色，点缀着圆形绿斑。尾羽中央为深绿色，外侧黑色，偶尔可见淡色尖端。雌鸟面部黑色较少，喉部呈赤褐色，饰以白绿相间的斑点，腹部较雄鸟更显黄色，绿斑稀少。幼鸟特征似雌鸟。","call":"发出重复的、高音、类似蟋蟀的短颤音，无论在栖息或飞行时均可听到。","habits":"梅里达领蜂鸟定居于梅里达州西北部的安第斯山脉，偏好较为开阔的环境，如灌木林边缘、森林中的空地及多草牧场，海拔范围在2000至3600米之间。其饮食习惯与近亲隆格马尔领蜂鸟相似，以花蜜为主，同时摄食昆虫。它会捍卫密集的花蜜源地盘，通常在高达6米的地方觅食，常沿溪流活动，通过蹲伏捕获昆虫。","breeding":"已知唯一巢穴发现于六月，为绒毛状杯状巢，位于道路切口下的小根上，内含两枚白色卵。关于繁殖季节的其他信息未知。","identification":"与橙喉领蜂鸟区别在于喉部颜色、白色而非橙色的颈带及绿色腹部。雌鸟与雄鸟在外形上有显著差异。","protection":"IUCN：LC（无危）","distribution":"梅里达领蜂鸟分布局限于委内瑞拉西北部梅里达州的安第斯山脉。","other":"约三分之二的分布区位于受保护区域内，主要威胁为农业扩张和栖息地碎片化。"},{"name":"领蜂鸟","english_name":"Gorgeted Sunangel","scientific_name":"Heliangelus strophianus","overview":"领蜂鸟（英文名：Gorgeted Sunangel，学名：Heliangelus strophianus），是雨燕目蜂鸟科领蜂鸟属的小型鸟类，以其独特的粉紫色闪亮喉部和明显的白色胸带著称。主要分布在南美洲的哥伦比亚西南部和厄瓜多尔西北部。","appearance":"领蜂鸟体型中等，长度约10至11厘米，体重约5.3克，喙短而直，呈黑色。雄鸟拥有小片绿色闪光前额，喉部及上胸部为玫瑰至紫罗兰色，下方有一条白色胸带。雌鸟的下巴为暗灰褐色，羽毛边缘泛白，偶尔可见闪光的玫瑰色羽毛。幼鸟类似雌鸟，但白色胸带较窄。","call":"鸣唱为一系列重复的2至3个高音'pseee'音符，随后是略微低沉的'tsip'音符。叫声为干燥的颤音，后跟柔和的'kr..krr..krr..whee..'音。","habits":"栖息于湿润至湿热的山麓森林，也见于森林边缘灌丛和密林地带，偏好潮湿的溪谷环境。活动范围在海拔1,200至2,800米之间，但较高海拔较为罕见。通常单独活动，可能具有领地性，以花蜜为主食，有时在树冠下层觅食。","breeding":"繁殖季节主要在10月至12月间，雌鸟孵育两枚白色卵。关于繁殖生态的其他细节尚不清楚。","identification":"与紫喉林星蜂鸟相似，但领蜂鸟体型更大，飞行风格明显不同。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的哥伦比亚西南部纳里诺省至厄瓜多尔西北部，主要栖息地为湿润至湿热的山麓森林。"},{"name":"暗绿领蜂鸟","english_name":"Tourmaline Sunangel","scientific_name":"Heliangelus exortis","overview":"暗绿领蜂鸟（英文名：Tourmaline Sunangel，学名：Heliangelus exortis），是雨燕目蜂鸟科领蜂鸟属的鸟类。这种深色蜂鸟具有相对较短且直的喙。雄鸟拥有亮紫色喉斑和蓝绿色前冠，而雌鸟喉部呈白色。其尾部覆羽为白色，尾巴较长且呈凹状。常见于哥伦比亚和厄瓜多尔安第斯山脉的高海拔森林及边缘地带。","appearance":"暗绿领蜂鸟体长10-11厘米，雄鸟体重3.5-8.5克，雌鸟4-5.2克。喙直且中等大小，颜色接近黑色。雄鸟上半身为深绿色，具有一条狭窄的绿色前胸带；下巴深紫蓝色，逐渐过渡至下胸的闪亮玫瑰粉色；领部下方环绕着翠绿色边界；下半身呈暗灰色，有绿色斑点；尾部覆羽为白色；尾巴较长且分叉，中央尾羽呈深铜色，其余部分黑色。雌鸟类似雄鸟，但缺乏绿色前胸带；下巴偏黑，喉咙偏白，偶尔带有几根闪亮的玫瑰色羽毛；尾巴分叉程度较低。幼鸟似雌鸟，雄鸟下巴白色而非黑色。","call":"假定的歌曲为一系列单音节重复，约每秒一个音符，通常由几个高音上升音符后接稍微低音下降音符组成，发音为“suwee....suwee..tsew...suwee...tsew...”。叫声为短促干涩的碎石般的颤音“trrr”，间歇重复，或连续干涩的叽喳声。","habits":"暗绿领蜂鸟几乎完全定居，但在哥伦比亚偶尔会移动到热带区域。它在多种开花植物中获取花蜜，偏好地面附近的花朵，无论是在半开阔景观还是森林内部。它通常在花朵上停留以进食，而非悬停。它通过在枝头守望捕捉昆虫，以及从植被中觅食昆虫。","breeding":"繁殖季节大约从3月持续至8月。雌鸟孵化两个白色的蛋。关于该物种繁殖生态的其他细节尚不清楚。","identification":"暗绿领蜂鸟与同属其他种类的区别在于其独特的色彩组合，尤其是雄鸟的紫色喉斑和蓝绿色前冠。雌鸟与雄鸟的差异主要体现在喉部的颜色和尾部的分叉程度。","protection":"IUCN：LC（无危）。暗绿领蜂鸟的种群数量未知，但被认为稳定。在当地较为常见，分布于多个保护区，如哥伦比亚的Munchique国家公园和厄瓜多尔的北Podocarpus国家公园。","distribution":"分布于南美的哥伦比亚所有三个安第斯山脉区域，以及厄瓜多尔西北部，向南延伸至莫罗纳-圣地亚哥省的东坡。","other":"曾有时被视为与小领蜂鸟同种，但现在认为是独立物种。"},{"name":"小领蜂鸟","english_name":"Flame-throated Sunangel","scientific_name":"Heliangelus micraster","overview":"小领蜂鸟（英文名：Flame-throated Sunangel，学名：Heliangelus micraster），是雨燕目蜂鸟科领蜂鸟属的鸟类。体型小巧、色彩艳丽的鸟类。其最显著的特征是橙色喉部斑点，雄鸟和雌鸟相似，但雌鸟的喉部斑点较小，腹部略显灰暗。主要分布于南美洲的安第斯山脉东坡，自厄瓜多尔南部至秘鲁北部，海拔约2,400至3,100米。","appearance":"小领蜂鸟体长约10至11厘米，体重3.6至4.1克。喙直而黑。雄鸟上体呈深金属绿色，胸前有闪亮蓝绿色饰片，下体金属绿色，带有紫蓝色下巴，逐渐过渡到高光泽黄橙色喉部，边缘环绕着翠绿色；腹部灰色，接近腹股沟处几乎为白色，下尾羽覆羽白色；尾巴叉状，深钢蓝色。雌鸟下颌黑色，喉部白色，点缀着绿色至暗灰色圆盘，有时可见几个虹彩红橙色圆盘。幼鸟似雌鸟，但年轻雄鸟缺乏黑色下颌。cutervensis亚种具有虹彩红橙色喉部。","call":"发出重复的干涩‘djit’声或更粗糙的‘drrt’声。","habits":"小领蜂鸟主要在森林边界低处或开阔地带活动，有时在开花灌木顶部或外部栖息。以花蜜为主食，偶尔从空中捕捉昆虫或从叶片上捕获。活动范围包括森林内部较低和中层高度。","breeding":"繁殖季节在厄瓜多尔从1月持续到5月，具体在秘鲁的时间未知。雌鸟孵化两个白色蛋，其余繁殖生态细节不明。","identification":"小领蜂鸟的橙色喉部斑点是辨识关键，雄鸟与雌鸟的差异在于喉部斑点大小和腹部颜色。","protection":"IUCN：LC（无危）","distribution":"分布于南美的厄瓜多尔和秘鲁，主要栖息于安第斯山脉东部斜坡，从厄瓜多尔的Morona-Santiago省延伸至秘鲁北部。"},{"name":"紫喉领蜂鸟","english_name":"Purple-throated Sunangel","scientific_name":"Heliangelus viola","overview":"紫喉领蜂鸟（英文名：Purple-throated Sunangel，学名：Heliangelus viola），是雨燕目蜂鸟科领蜂鸟属的鸟类。这中等体型的蜂鸟，主要分布在南美洲的厄瓜多尔和秘鲁地区，以森林边缘和灌木地带为栖息地。","appearance":"紫喉领蜂鸟身长约11至12厘米，体重介于5.1到6.6克。拥有直而黑的喙，雄鸟上体呈闪光绿色，前额蓝绿闪耀，喉咙深紫色，下方有蓝绿色胸带，腹部绿色，尾羽中央对为绿色，两侧黑色。雌鸟与雄鸟相似，但喉咙颜色从黄褐色至接近白色，带有青铜绿色斑点。幼鸟外形似雌鸟。","call":"紫喉领蜂鸟的叫声包括一系列松散的干燥颤音“trr..tr..trr....trr..”，以及重复的、拉长的、干燥的嗡嗡声“bzzzrrr”。","habits":"紫喉领蜂鸟栖息于安第斯山脉西侧，从厄瓜多尔中部向南延伸至秘鲁的云林内部和边缘、次生林、桤木林及灌木丛，海拔高度在2,150至3,000米之间。它们以花蜜和昆虫为食，依赖于引进的桉树Eucalyptus globulus。它们通常从栖木捕食昆虫，也会从植被中获取食物。","breeding":"繁殖季节从十月持续到一月，雌鸟会孵化两枚白色的卵。关于繁殖生态的其他细节尚不清楚。","identification":"紫喉领蜂鸟最显著的特点是其深紫色的喉咙和蓝绿色的前额，以及较为短直的喙。雌鸟和幼鸟缺乏雄鸟的鲜艳色彩，通过这些特征可与其他蜂鸟区分开来。","protection":"IUCN：LC（无危）","distribution":"紫喉领蜂鸟分布于南美洲的厄瓜多尔和秘鲁，具体在安第斯山脉西侧，从北中部的厄瓜多尔向南延伸至秘鲁的Cajamarca和Amazonas部门。"},{"name":"皇领蜂鸟","english_name":"Royal Sunangel","scientific_name":"Heliangelus regalis","overview":"皇领蜂鸟（英文名：Royal Sunangel，学名：Heliangelus regalis），是雨燕目蜂鸟科领蜂鸟属的鸟类。是南美洲秘鲁北部和厄瓜多尔东南部特有的濒危物种。其显著特征为深蓝色的羽毛，雄鸟尤为独特，全身暗蓝，尾羽深叉，雌鸟则上部绿色，下部肉桂色。栖息于特定的云雾林环境，偏好矮小的森林和灌木丛。","appearance":"皇领蜂鸟体型小，长度约10至12厘米，体重介于3.4到4.5克之间。喙短而直，呈黑色。雄鸟成鸟全身深蓝，带有金属光泽，尾羽长且深叉。雌鸟成鸟背部深绿，腹部肉桂色，胸部有淡黄色带状斑纹，尾羽较短，全蓝。幼鸟类似雌鸟，但喉部有灰色斑点。","call":"雄鸟在空中展示时发出一系列强调的“tseep”音符，频率约为每秒4个音符，有时更快。争斗时，雄鸟会发出连续快速的高音“jijijit’jijit’jijit’jijiji…”。喂食时，会发出重复的短促而有力的“tsik”或“tsawk”。","habits":"偏好生活在安第斯山脉东坡的矮小云雾林中，常见于“精灵灌丛”，一种由苔藓覆盖的矮树和灌木组成的特殊生境。海拔分布范围从1250米至2200米，最密集的区域在1500米以上。以花蜜和昆虫为食，雄鸟高度领地性，围绕开花灌木活动。","breeding":"繁殖季节估计在7月至9月间，雌鸟筑巢并孵化两枚白色蛋，关于繁殖生态的其他细节未知。","identification":"雄鸟与其他领蜂鸟属物种相比，具有独特的全蓝体色和深叉尾羽。雌鸟和幼鸟与属内其他物种相似，但喉部斑纹和尾羽颜色可作区分依据。","protection":"IUCN：NT（近危）","distribution":"分布于秘鲁北部的Cordillera del Cóndor和Cordillera Azul，以及厄瓜多尔东南部的Zamora-Chinchipe省。在秘鲁，位于Cajamarca和Amazonas部门，以及San Martín和Loreto部门的东部山坡。","other":"该物种的栖息地受到农业扩张和森林砍伐的威胁，种群数量估计不足10,000只，分布区面积小于2100平方公里。"},{"name":"黑胸毛腿蜂鸟","english_name":"Black-breasted Puffleg","scientific_name":"Eriocnemis nigrivestis","overview":"黑胸毛腿蜂鸟（英文名：Black-breasted Puffleg，学名：Eriocnemis nigrivestis），是雨燕目蜂鸟科毛腿蜂鸟属的鸟类。小型的蜂鸟，主要分布在厄瓜多尔西北部，仅限于基多周边几座山的特定高海拔森林。雄鸟呈深蓝绿色，具白色腿羽和蓝色腹面；雌鸟更显绿色，带金色光泽，有蓝色喉部和腹面。全球数量极为稀少，濒临灭绝。","appearance":"成鸟体长8-9厘米，体重4.3-4.6克。雄鸟有直而黑的喙，全身几乎黑色，在某些光线下可见微弱绿光，尾羽覆盖着闪耀的深蓝色，下身黑色，带有发光的蓝紫色喉部和下尾羽覆盖物；尾羽呈暗钢蓝色，适度分叉；腿羽白色。雌鸟上半身闪亮青铜绿色，向臀部和尾羽覆盖物渐变为蓝绿色；下半身金绿色，有淡蓝色喉部；尾羽、下尾羽覆盖物和腿羽与雄鸟相似；幼鸟似成年雌鸟，但头部羽毛边缘有淡黄色。","call":"声音特征了解不多，飞行时会发出单调的金属声“tzeet...tzeet...tzeet...”。","habits":"栖息于基多周围山脉的脊顶，依赖特定类型的植被环境，包括矮小密集的森林，平均树冠高度8-10米，有大量杜鹃科植物和附生植物。主要分布于温带地区，海拔从2400米到4600米，季节性迁移依赖于植物开花。以花蜜为主食，偏好Palicourea huigrensis的明亮蓝花，也采食多种灌木、草本和藤本植物的花蜜，偶尔捕食昆虫。","breeding":"繁殖期为10月至次年3月，每次产两枚白色蛋，孵化和育雏由雌鸟独自承担。巢穴通常位于低矮的水平枝上，由苔藓、纤维、动物毛发和羽毛构成，有时利用蜘蛛网和其他粘性物质，使巢能随雏鸟成长而伸展。","identification":"与蓝臀毛腿蜂鸟相比，缺乏蓝色头冠，尾巴较短。雌鸟与紫颏毛腿蜂鸟类似，但下方更金绿而非肉桂色，腹部有白色边缘，尾羽覆盖物更蓝，光泽较弱。","protection":"IUCN：EN（濒危）","distribution":"分布于厄瓜多尔西北部，主要在皮钦查火山的西北脊顶和可能的阿塔卡索火山，以及因塔格山谷上方的托伊桑山脊（埃斯梅拉达斯和因巴布拉省）。","other":"在非繁殖季节，雄鸟通常出现在比雌鸟更高的海拔。"},{"name":"伊莎毛腿蜂鸟","english_name":"Gorgeted Puffleg","scientific_name":"Eriocnemis isabellae","overview":"伊莎毛腿蜂鸟（英文名：Gorgeted Puffleg，学名：Eriocnemis isabellae），是雨燕目蜂鸟科毛腿蜂鸟属的罕见且濒危的物种。仅在南美洲哥伦比亚西南部的安第斯山脉发现，其分布范围极小，仅限于Serranía del Pinche地区。雄鸟具有独特的双色喉颈羽，中央为闪光蓝紫色，两侧为绿色，以及白色腿部绒毛。雌鸟多呈绿褐色，腹部带有淡黄色色调，喉部斑纹较淡，颈部较少呈现淡黄色。该鸟种于2005年首次被发现，2007年确认为新物种。","appearance":"体型较小，长度约8至9厘米，体重约4.5克。雄鸟上半身黑色带金色橄榄绿光泽，背部略显绿色光泽，尾巴为深钢蓝色，喉颈中央为耀眼的蓝紫色，两侧为绿色，腹部为黑色带绿色光泽，腿部有白色绒毛。雌鸟上半身为青铜绿色，渐变为臀部的蓝色，下腹部羽毛边缘带有红棕色并反射出青绿色。","call":"领土叫声为频繁重复的单音节尖锐“twek”，音调比同类较低。","habits":"栖息于高海拔的云雾林，偏好陡峭山坡上的潮湿环境，以花蜜为食，常在密集植被中的开花灌木上觅食。已知的食物来源包括Bejaria resinosa、Cavendishia bracteata、Cinchona pubescens和Faramea flavicans。","breeding":"关于繁殖行为的信息尚不清楚。","identification":"雄性伊莎毛腿蜂鸟的独特双色喉颈羽使其容易与同类区分开来，雌鸟与紫颏毛腿蜂鸟雌鸟相似，但喉部斑纹较淡，颈部淡黄色较少。","protection":"IUCN：CR（极危）","distribution":"仅分布于哥伦比亚西南部的Serranía del Pinche地区。","other":"其栖息地正受到非法古柯种植的压力，尽管其栖息地名义上已被列为Serranía del Pinche保护森林储备区。"},{"name":"紫颏毛腿蜂鸟","english_name":"Glowing Puffleg","scientific_name":"Eriocnemis vestita","appearance":"雄鸟主要呈现绿色，喉部蓝色，腹部闪烁着翡翠和蓝色光泽。下尾覆羽蓝色，具有强烈的虹彩效果。最显著的特征是其腿基部的大型白色绒毛，比黄尾冕蜂鸟的白色绒毛大得多。雌鸟颜色较淡，下方呈淡黄色，带有斑点状外观。幼鸟与雌鸟相似。","call":"已知唯一的叫声是单个金属音“tseek”或成对的“tsi-tseek”，以不规则间隔重复，无论是在栖息还是悬停时都会发出。","habits":"栖息于安第斯山脉的温带区域，常出现在云雾林和矮树丛的森林边缘。也会出现在灌木斜坡、过度生长的牧场和潮湿的高海拔草原上。食性包括花蜜和昆虫，尤其偏好有短花管的植物，如Palicourea、Clusia multiflora等。","breeding":"具体繁殖季节不明确，但在哥伦比亚东部安第斯山脉似乎每月都有筑巢现象，除了7月。巢通常建在草丛中，雌鸟负责孵化两个白色的蛋，首次繁殖发生在第二年。","identification":"与其它种类蜂鸟相比，紫颏毛腿蜂鸟的白色腿绒毛最为显著，雄鸟的紫色喉部斑块周围有一圈金色绿边，雌鸟喉部有少量蓝紫色斑点。","protection":"IUCN：LC（无危）；CITES II；在一些国家公园中常见，如哥伦比亚的Puracé国家公园、厄瓜多尔的Pasochoa森林保护区和Podocarpus国家公园。","distribution":"分布于南美洲，包括委内瑞拉西北部至秘鲁北部，常见于安第斯山脉的温带区域。","other":"紫颏毛腿蜂鸟对次生林和过度生长的牧场适应良好，显示出较强的生态弹性。"},{"name":"黑脚毛腿蜂鸟","english_name":"Black-thighed Puffleg","scientific_name":"Eriocnemis derbyi","overview":"黑脚毛腿蜂鸟（英文名：Black-thighed Puffleg，学名：Eriocnemis derbyi），是雨燕目蜂鸟科毛腿蜂鸟属的鸟类。分布于南美洲的哥伦比亚和厄瓜多尔西北部，偏好中央安第斯山脉的高海拔地区。雄鸟呈现深绿色光泽，臀部和腹部更为明亮，黑色腿羽不显眼；雌鸟则拥有更加鲜艳的绿色羽毛，前额蓝色，喉咙和胸部点缀白色鳞片状花纹，腿羽混杂黑白灰三色。","appearance":"体长约10厘米，喙笔直呈黑色。雄鸟全身闪耀金色绿光，特定光照下可见黑色部分，尾上覆羽和尾下覆羽闪烁着孔雀绿光芒，尾叉尖锐且黑色；雌鸟及幼鸟下体更多为白色，点缀以绿色闪光斑点，腿羽黑灰白相间，雌鸟前额泛蓝。","call":"已知的唯一叫声是一连串短暂的嗡嗡颤音'tzzrr'，间隔不规律，无论停歇还是悬停飞行时都会发出，与同属其它种类的叫声截然不同。","habits":"栖息于湿润森林边缘和灌木丛生的牧场，偏好开阔地带。在哥伦比亚至厄瓜多尔北部的中央安第斯山脉，海拔2,500至3,600米间活动，常见于2,900米以上高度。季节性迁徙至不同海拔。","breeding":"对其繁殖生态了解甚少，已知繁殖季包含二月，雌鸟筑巢并孵化两枚白色卵，具体孵化期和雏鸟离巢时间未知。","identification":"雄鸟与雌鸟在外形上有明显差异，雄鸟深绿色光泽显著，雌鸟下体白色且带绿色斑点。与同属其它种类相比，叫声独特。","protection":"IUCN：LC（无危）","distribution":"分布在哥伦比亚南部至厄瓜多尔西北部的中央安第斯山脉地区。","other":"适应人类环境，如牧场和花园，被评估为局部常见。"},{"name":"绿喉毛腿蜂鸟","english_name":"Turquoise-throated Puffleg","scientific_name":"Eriocnemis godini","overview":"绿喉毛腿蜂鸟（英文名：Turquoise-throated Puffleg，学名：Eriocnemis godini），是雨燕目蜂鸟科毛腿蜂鸟属的鸟类。主要分布于厄瓜多尔西北部的蜂鸟。其特征为全身绿色，下体带蓝绿色光泽，尾下覆羽呈蓝紫色，雄鸟有蓝紫色喉斑，两性皆有白色绒毛形成的腿羽。自19世纪以来，仅发现少量标本，确切分布与生存状况不明。","appearance":"绿喉毛腿蜂鸟总长约为10-11厘米，雄鸟的羽毛以绿色为主，带有绿松石色的喉咙，上身及下身的主要部分呈现金绿色。尾底羽为紫蓝色，喙笔直且呈黑色。雌鸟的喉咙上无斑纹，羽毛颜色较淡，腹部更显金色。两性均有显著的白色绒毛形成的腿羽。","habits":"绿喉毛腿蜂鸟的生活习性知之甚少。据唯一有记录的标本收集地，它可能生活在干燥的山谷中，原生环境为山地干林和灌丛，但现在大部分已消失，仅存零星残片。海拔高度约在2100至2300米之间。","identification":"绿喉毛腿蜂鸟与其它Eriocnemis属的物种相比，可通过其独特的绿松石色喉咙和白色腿羽加以区分。","protection":"IUCN：CR (PE)（极危（可能已灭绝））","distribution":"绿喉毛腿蜂鸟的分布限于南美厄瓜多尔西北部，具体为北皮钦查省的Guayllabamba地区。可能存在极少数个体于隐蔽地带，但确切分布范围不确定。","other":"绿喉毛腿蜂鸟的分类地位存在争议，有学者认为可能是紫颏毛腿蜂鸟与未知Eriocnemis物种的杂交后代，也有观点将其视为紫颏毛腿蜂鸟的亚种。"},{"name":"铜腹毛腿蜂鸟","english_name":"Coppery-bellied Puffleg","scientific_name":"Eriocnemis cupreoventris","overview":"铜腹毛腿蜂鸟（英文名：Coppery-bellied Puffleg，学名：Eriocnemis cupreoventris），是雨燕目蜂鸟科毛腿蜂鸟属的鸟类。闪耀着绿光的中型蜂鸟，腹部呈铜色，腿基部有蓬松的白色羽毛，尾羽下覆羽亮蓝宝石色，分布于南美洲北部的安第斯山脉区域，包括哥伦比亚和委内瑞拉。该物种属于‘辉煌蜂鸟’类群。","appearance":"体型约为9至10厘米，体重介于4.4到5.6克之间。雄鸟上体闪烁着绿色光泽，逐渐变为蓝绿色的上尾覆羽；下体熠熠生辉的绿色，腹部中央转变为金铜色，尾下覆羽闪烁着紫罗兰色，与叉状蓝黑色尾巴形成鲜明对比，腿基部有白色的绒毛。雌鸟相似，但喉部带有灰色斑点，腹部铜色较淡。幼鸟胸部为黑色，腹部缺乏铜色光泽。","call":"已知唯一的叫声为单一金属音“tseek”，以不规则间隔重复发出，无论是在栖息还是悬停飞行时都会发出。","habits":"主要栖息于高山森林边缘、灌木地带和帕拉莫地带的较低区域，偶尔也会出现在潮湿森林内部。海拔分布范围在2000至3000米间，但在2500米以上最为常见。生活方式主要是定居，但会进行季节性的高度迁移。以花蜜为食，偏好花冠短的灌木和小树，如Palicourea、Cavendishia和Pernettya属植物，同时捕食昆虫。","breeding":"繁殖季节为9月至次年1月。巢穴位置和构造尚未被详细描述，通常建在密集植被中。雌鸟孵化两枚白色蛋，但孵化期和幼鸟离巢时间未知。","identification":"其独特的铜色腹部、腿基部的白色绒毛和亮蓝宝石色的尾下覆羽是与其他蜂鸟种类区分的关键特征。","protection":"IUCN：LC（无危）","distribution":"分布于委内瑞拉的安第斯山脉（Mérida州）和哥伦比亚东部安第斯山脉，南至Cundinamarca省。","other":"该物种在CITES II附录中，为受限制的地理分布物种，存在于Cordillera de Mérida和Colombian East Andes生态区。"},{"name":"蓝臀毛腿蜂鸟","english_name":"Sapphire-vented Puffleg","scientific_name":"Eriocnemis luciani","overview":"蓝臀毛腿蜂鸟（英文名：Sapphire-vented Puffleg，学名：Eriocnemis luciani），是雨燕目蜂鸟科毛腿蜂鸟属的鸟类。广泛分布于安第斯山脉高海拔地区，从哥伦比亚南部延伸至秘鲁。其主要特征为绿色体羽，蓝色腹部，白色腿羽蓬松，以及相对较长的分叉蓝黑色尾巴。这种蜂鸟栖息于湿润的山地森林边缘，积极保卫花丛领地。","appearance":"蓝臀毛腿蜂鸟体型较大，羽毛呈金属草绿色，头顶前部闪耀着深蓝色，腹部金绿发光，尾下覆羽紫光闪烁，腿部有大而显眼的白色蓬松羽毛。雄雌相似，但雌鸟稍小，南方种群的雌鸟腹部可能呈现白色。尾羽深蓝黑，分叉明显。","call":"蓝臀毛腿蜂鸟发出尖锐的‘tirr tirr’叫声。","habits":"它们居住在湿润的山地环境中，偏好开阔植被区，如湿高山森林的边缘或草地旁的灌木丛。以低矮处小花的花蜜为食，同时也会摄取小型昆虫。飞行时会在花朵上停留。","breeding":"关于繁殖行为的信息有限。已知它们会用苔藓、地衣、蕨类叶片和蜘蛛网构建吊挂式的巢，巢内通常有两枚白色蛋。","identification":"与同属的其他种类相比，蓝臀毛腿蜂鸟体型更大，尾羽更长且分叉更深，喙也更长。在特定区域内，通过颜色差异和腹部特征可以区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美，具体从哥伦比亚西南部至秘鲁南部，可能覆盖委内瑞拉，但在玻利维亚的记录尚待证实。","other":"尽管分布广泛，但其生物学细节仍不为人所熟知，且存在分布空白地带，原因不明。"},{"name":"金胸毛腿蜂鸟","english_name":"Golden-breasted Puffleg","scientific_name":"Eriocnemis mosquera","overview":"金胸毛腿蜂鸟（英文名：Golden-breasted Puffleg，学名：Eriocnemis mosquera），是雨燕目蜂鸟科毛腿蜂鸟属的鸟类。特征是胸部呈现明显的金色光泽，腿部有白色的羽毛蓬松簇。广泛分布于哥伦比亚和厄瓜多尔的安第斯山脉高海拔森林地带。","appearance":"金胸毛腿蜂鸟体长约11至13厘米，体重约5.3克。全身大部分羽毛为闪烁的绿色，胸部和颈部两侧呈铜绿色，腹部上部为铜褐色。尾羽深叉状，中央尾羽蓝绿色，外侧两对尾羽暗绿至蓝黑色。雌雄羽毛相似，雌鸟略小，尾下覆羽更显绿色。","call":"其叫声为\"trit notes\"。","habits":"金胸毛腿蜂鸟栖息于高海拔的山地森林边缘，常在矮树丛和树线附近的灌木区活动。它们主要以花蜜为食，同时也会捕捉小型昆虫。这种蜂鸟在觅食时非常活跃且具有攻击性，会捍卫自己的领地。","breeding":"关于金胸毛腿蜂鸟的繁殖习性知之甚少。在哥伦比亚发现的一个巢穴是由苔藓和树枝制成，内部铺垫植物绒毛，位于岩石悬垂下的细枝末端。繁殖期具体时间未知。","identification":"金胸毛腿蜂鸟与其他Eriocnemis属的蜂鸟相比，胸部和腹部颜色独特，尾羽色彩和形状也有所不同。与其他种类的Puffleg相比，其胸腹颜色并非蓝色或紫色，尾羽也不是蓝黑色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的哥伦比亚西部至厄瓜多尔西北部，主要栖息在安第斯山脉的高海拔地区。"},{"name":"蓝顶毛腿蜂鸟","english_name":"Blue-capped Puffleg","scientific_name":"Eriocnemis glaucopoides","overview":"蓝顶毛腿蜂鸟（英文名：Blue-capped Puffleg，学名：Eriocnemis glaucopoides），是雨燕目蜂鸟科毛腿蜂鸟属的鸟类。在南美洲分布的物种，主要见于玻利维亚中部至阿根廷西北部的安第斯山脉东侧。其显著特征为雄鸟的蓝色头顶和白色的腿羽蓬，以及雌鸟的橙色下腹部和金属蓝色下尾覆羽。","appearance":"蓝顶毛腿蜂鸟体长9到13厘米，体重4.0至4.5克。雄鸟上体暗绿色，前额闪耀着深蓝色光泽，下体大部分为金绿色，胸部下方转为蓝绿色，下尾覆羽呈闪亮的紫蓝色。雌鸟上体同样暗绿，但无蓝色前额，喉、胸和腹为明亮的肉桂色，下尾覆羽边缘淡黄色，尾巴较雄鸟更少分叉。幼年雄鸟前额缺乏闪光蓝色。","call":"蓝顶毛腿蜂鸟的鸣声被描述为高音的“zee-zee”。","habits":"蓝顶毛腿蜂鸟栖息于海拔1500至3400米的温带地带，常见于2000至2500米间，偏好湿润的山坡，覆盖有草丛和浓密灌木的云雾林边缘。在阿根廷部分地区，它们也会出现在较为干燥的环境中，以Myrtaceae为主的植被和矮树丛。在阿根廷北部和玻利维亚某些地区，它们表现出季节性垂直迁移的习性。","breeding":"蓝顶毛腿蜂鸟的繁殖行为知之甚少，但在11月的玻利维亚曾有繁殖记录。雌鸟负责孵育两枚蛋，但孵化期和雏鸟离巢时间尚不清楚。","identification":"蓝顶毛腿蜂鸟雄鸟以其独特的蓝色前额和白色腿羽蓬，以及雌鸟的橙色下体和金属蓝色下尾覆羽区别于其他同类。在体型上，雄鸟翅膀和尾巴较长，而雌鸟喙和中央尾羽较长，使雄鸟的尾巴看起来更加分叉。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的玻利维亚中部至阿根廷西北部，具体包括玻利维亚的拉巴斯和科恰班巴部门，以及阿根廷的萨尔塔和图库曼省份。"},{"name":"彩毛腿蜂鸟","english_name":"Colorful Puffleg","scientific_name":"Eriocnemis mirabilis","overview":"彩毛腿蜂鸟（英文名：Colorful Puffleg，学名：Eriocnemis mirabilis），是雨燕目蜂鸟科毛腿蜂鸟属的鸟类。是蜂鸟科毛腿蜂鸟属的独特物种，仅见于哥伦比亚西部安第斯山脉西坡的一个狭小区域内，尤其是卡乌卡省的蒙奇克国家公园附近。这种罕见的蜂鸟以其独特的色彩和腿上的白色羽毛蓬松而闻名。","appearance":"彩毛腿蜂鸟体型小巧，长度约8至9厘米。雄鸟拥有闪耀的绿色上体，头部前额处呈翠绿色，腹部为蓝紫色，下体为红色和铜色，尾羽叉状，上方暗绿带青铜光泽，下方金绿闪光。雌鸟下体主要为白色，喉咙和胸部两侧有绿色斑点，两胁和腹部侧面有红铜色斑点。两性均有白色腿蓬，雄鸟的较为显著。","call":"关于彩毛腿蜂鸟的声音信息有限，其疑似歌声为重复的金属质感短音'茨特'，频率约为每秒1.5至2次。","habits":"栖息于相对未受干扰的云雾森林，偏好海拔2200至2440米的湿润森林边缘和小片空地。彩毛腿蜂鸟以低层活动为主，常在地面以上2至4米的高度觅食，食物包括多种植物的花蜜。","breeding":"彩毛腿蜂鸟的繁殖生态细节未知，需要更多研究。","identification":"彩毛腿蜂鸟最显著的辨识特征是其腿部的白色蓬松羽毛，雄鸟的多彩下体和雌鸟的白底绿斑点下体。","protection":"IUCN：EN（濒危）, CITES: II级附录。在哥伦比亚国内被列为国家级濒危物种。由于栖息地的破坏和非法作物的种植，其生存状况堪忧。","distribution":"主要分布在哥伦比亚西部安第斯山脉的西坡，包括蒙奇克国家公园和Pinche山脉，已知的分布点集中于卡乌卡省。","other":"彩毛腿蜂鸟的已知分布区面积极小，估计总范围不超过680平方千米，而适合其生存的生境仅占其中一小部分。"},{"name":"翠腹毛腿蜂鸟","english_name":"Emerald-bellied Puffleg","scientific_name":"Eriocnemis aline","overview":"翠腹毛腿蜂鸟（英文名：Emerald-bellied Puffleg，学名：Eriocnemis aline），是雨燕目蜂鸟科毛腿蜂鸟属的小型蜂鸟，常见于南美洲安第斯山脉东坡的云雾森林中。其体羽闪耀着绿色光泽，腿部拥有独特的白色羽毛簇。分布于哥伦比亚、厄瓜多尔和秘鲁，偏好湿润的中海拔森林。","appearance":"体长8-9厘米，体重约4-4.5克，是最小的毛腿蜂鸟种类。头部至背部为深绿色，闪烁着金属光泽，额头部分在特定光线下呈现蓝绿色。胸部有显著的白色斑块，边缘散布绿点，其余腹部区域则闪耀着蓝绿色。尾巴短而微叉，下方具明显的虹彩效果。两性相似，但雌鸟的额头无蓝绿色，翅膀和尾巴略短。腿上白色的羽毛簇极大。","call":"叫声特征知之甚少，已知的是当悬停时会发出单一的、略带嗡嗡声的金属音'茨特'，以不规律的间隔重复。","habits":"常居于热带和亚热带的山地森林，尤其偏爱湿润的云雾森林环境，通常在森林内部或小片开阔地带活动，较少出现在森林边缘或更为开放的地方。活动高度一般介于地面1到3米之间，主要以花蜜为食，偶尔捕食小型昆虫。","breeding":"关于繁殖生态学的细节目前未知。","identification":"与近缘种彩毛腿蜂鸟相比，翠腹毛腿蜂鸟的羽毛色彩有明显差异，尤其是腹部的绿色闪光和较大的白色腿羽簇。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，从哥伦比亚的中央和东部安第斯山脉，向南延伸至厄瓜多尔和秘鲁中部，主要在安第斯山脉东侧的热带和亚热带山地森林。","other":"物种系统发育历史显示，翠腹毛腿蜂鸟与彩色毛腿蜂鸟关系密切，两者曾被视为姐妹种或超种。"},{"name":"淡绿蓬腿蜂鸟","english_name":"Greenish Puffleg","scientific_name":"Haplophaedia aureliae","overview":"淡绿蓬腿蜂鸟（英文名：Greenish Puffleg，学名：Haplophaedia aureliae），是雨燕目蜂鸟科蓬腿蜂鸟属的鸟类。分布于中美洲和南美洲的巴拿马东部、哥伦比亚和厄瓜多尔。其特征在于腿基部的小白绒毛，整体呈现较为沉闷的绿色，头部略带铜色光泽。","appearance":"体长9至11.6厘米，体重4至6.5克。雄鸟上体绿色，头颈具铜色光泽，下体较暗淡的绿色，羽缘灰白色，腿上的绒毛外侧白色，内侧淡黄色；尾部稍叉开，蓝黑色。雌鸟相似，但下体鳞状斑纹更明显，腿绒毛全白。幼鸟似雌鸟。亚种caucensis上体草绿色，头部和臀部铜色更浓，腹部有白色斑块；floccus亚种雄鸟下体颜色较浅，上体铜色减弱，而雌鸟前颈和胸部有显著的白色边缘；galindoi亚种上下体颜色更深，雌鸟下体鳞纹更不显眼；russata亚种喙较长，上体铜色更亮，下体呈棕色而非灰白色；cutucuensis亚种下体有厚重的灰白色鳞纹。","call":"雄鸟常聚集在高枝上反复鸣唱，发出双音节的“tur seet”或“tskut”，频率约为每秒一音，贯穿大部分白天。","habits":"栖息于安第斯山脉云雾森林，海拔1500至2500米，通常在林下层活动，偶尔在开花的印加树冠层觅食。领地性强，以短花管的花朵为中心建立觅食领域，也从叶片上捕获昆虫。","breeding":"繁殖季节主要为12月至次年3月，但也有5月至8月和9月的筑巢记录。杯形巢由苔藓和蜘蛛网构成，内衬精细植物材料，通常建在大叶蕨或Heliconia叶下，离地面0.5至2米。每窝产两枚卵，仅由雌鸟孵化，初次繁殖年龄为两岁。","identification":"与其他蓬腿蜂鸟属物种相比，淡绿蓬腿蜂鸟的腿绒毛特征明显，各亚种在色彩和下体鳞纹上有细微差异。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括巴拿马东部、哥伦比亚、厄瓜多尔和秘鲁东北部。在哥伦比亚的卡利上方，密度至少达到3至5对/平方公里。在厄瓜多尔东北部，种族russata仅在孤立的山脊上普遍。","other":"物种分类仍在讨论中，一些亚种曾被视为独立物种或合并到其他亚种中。"},{"name":"黄腿蓬腿蜂鸟","english_name":"Buff-thighed Puffleg","scientific_name":"Haplophaedia assimilis","overview":"黄腿蓬腿蜂鸟（英文名：Buff-thighed Puffleg，学名：Haplophaedia assimilis），是雨燕目蜂鸟科蓬腿蜂鸟属的小型绿色蜂鸟。其腿部被覆以奶油色的绒毛，尾部呈现深蓝色金属光泽。雌雄相似，但腹部颜色略灰。该物种分布于南美洲的秘鲁和玻利维亚。","appearance":"黄腿蓬腿蜂鸟体型介于9至10厘米，体重约5到6克。拥有笔直的黑色喙。成年鸟体羽深绿，尾羽蓝黑并略带叉状，腿上覆盖着奶油色至白色的绒毛。H. a. affinis亚种颜色更深，尾羽偏蓝，腿部绒毛呈淡红褐色。幼鸟与成鸟类似，但头部和颈部的羽毛边缘带有棕色。","call":"其鸣唱为一连串尖锐的单音“tsuk...tsuk...tsuk...”，每秒约1.5至2个音符，偶尔穿插双音“tsi-tsuk”。此外，还发出干燥的颤音和一系列叽喳声。","habits":"黄腿蓬腿蜂鸟栖息于湿润的山地森林的下层和中层。季节性地向海拔较低的地方扩散。主要在近地面觅食，偏好小簇花朵的花蜜，同时捕食树叶上的昆虫，有时从栖木出击捕猎。","breeding":"关于黄腿蓬腿蜂鸟的繁殖习性知之甚少。已知的是雌鸟单独孵化两个白色蛋的窝卵。","identification":"与相似的淡绿蓬腿蜂鸟相比，黄腿蓬腿蜂鸟的喙较短。H. a. affinis亚种与指名亚种为H. a. assimilis的个体在色彩和尾羽色调上有细微差别。","protection":"IUCN：LC（无危）","distribution":"黄腿蓬腿蜂鸟的分布范围覆盖了秘鲁的北部和中部地区，以及玻利维亚的东部安第斯山脉斜坡，最远至Cochabamba部门。栖息于1,500至3,000米（4,900至9,800英尺）的海拔高度，但很少出现在2,500米（8,200英尺）以上。","other":"曾一度被视为淡绿蓬腿蜂鸟的亚种，后恢复为独立物种。目前再次考虑将其重新归入淡绿蓬腿蜂鸟，但这一提议支持度不高。"},{"name":"苍蓬腿蜂鸟","english_name":"Hoary Puffleg","scientific_name":"Haplophaedia lugens","overview":"苍蓬腿蜂鸟（英文名：Hoary Puffleg，学名：Haplophaedia lugens），是雨燕目蜂鸟科蓬腿蜂鸟属的鸟类。主要分布在南美洲的安第斯山脉云雾森林中，具体包括哥伦比亚西南部至厄瓜多尔西北部。其体长9至10厘米，体重5至6克，具有独特的白边灰暗下体和铜色的冠部及臀部。","appearance":"雄性苍蓬腿蜂鸟上身呈青铜绿色，冠部和臀部带有铜色光泽，下体深灰色，喉咙和胸部羽毛边缘白色，侧腹带绿光，尾羽黑色稍叉，腿上有显眼的白色蓬毛。雌鸟相似但色彩略暗淡，翅膀略短，腿上的蓬毛全白。幼鸟似雌鸟。","call":"已知的叫声为单声尖锐的“tzik”或双音节“tsi-tsik”，间歇性重复，无论在停歇还是飞行中都会发出。","habits":"苍蓬腿蜂鸟全年居住在其分布范围内，偏好低矮密集的植被区，常靠近溪流，活动高度通常在1.5至2米之间，以花蜜为食，偶尔在树冠觅食，会保护自己的花丛领地。","breeding":"繁殖季节记录在五月和八月，巢穴由苔藓和蜘蛛网构成，悬挂于蕨类植物或大叶植物下方，高0.5至2米，每窝产两枚白色蛋，孵化期15至17天，由雌鸟负责，小鸟约20至24天离巢。","identification":"与同类相比，苍蓬腿蜂鸟的独特之处在于其灰色下体带白色边缘和铜色头部，雄鸟的白色腿蓬尤其明显。","protection":"IUCN：NT（近危），其小范围分布区正因大规模的森林砍伐而迅速消失。","distribution":"分布于南美，自哥伦比亚西南部（纳里尼奥省）至厄瓜多尔西北部（至皮钦查省），在哥伦比亚海拔1200至2000米，局部高达2500米；在厄瓜多尔记录于1525至2100米之间。"},{"name":"白尾梢蜂鸟","english_name":"Purple-bibbed Whitetip","scientific_name":"Urosticte benjamini","overview":"白尾梢蜂鸟（英文名：Purple-bibbed Whitetip，学名：Urosticte benjamini），是雨燕目蜂鸟科白尾梢蜂鸟属的物种，分布于哥伦比亚西部和厄瓜多尔西北部安第斯山脉西坡的云雾森林中。雄鸟具有醒目的紫色喉斑和白色尾羽尖端，雌鸟和幼鸟则以绿色和白色斑点为主。此鸟种在蒙特内森林中常见。","appearance":"成年白尾梢蜂鸟体长约8至9厘米，体重约3.8至4.2克。雄鸟具有中等长度的黑色直喙，眼后有一条显眼的白色纹路。上体闪烁着绿色光泽，下体则呈绿色带紫晕，胸腹部白色，腹侧灰绿色，密布绿色斑点。尾羽深褐色，中央尾羽宽幅白色尖端形成明显的圆形斑点。雌鸟上体与雄鸟相似，眼后条纹白色，下体白色并带有大量绿色斑点；尾羽深褐色，末端紫色，外侧尾羽宽幅白色尖端。幼鸟与雌鸟类似，但头部羽毛边缘呈棕色。","call":"发出柔和、鼻音浓重的快速啁啾声，描述为‘tweetweetweetwee...’，有时听似欢笑声。在飞行觅食时，还会发出单一低沉的刮擦音‘chrrrrr’，以及非常高音的‘pseee’。","habits":"栖息于海拔700至1600米的蒙特内森林及边缘地带，独居，主要在林内从地面至亚冠层活动。在厄瓜多尔，数量最多出现在1200至1400米高度。繁殖期后，个体在哥伦比亚保持定居，而在厄瓜多尔会迁移到较低海拔。","breeding":"繁殖季节在厄瓜多尔为1月至4月，哥伦比亚繁殖期未知。营建苔藓和蕨类纤维构成的紧凑杯状巢，位于陡峭峡谷中的灌木或藤蔓中，距地面约2至4米。每窝产卵两枚，由雌鸟孵卵，孵化期16至18天。雏鸟背部黑色，有淡色绒毛，离巢时间未知。","identification":"与盘尾蜂鸟相比，后者较小，且下体绿色斑点较少。雄鸟的紫色喉斑和白色的尾羽尖端是显著的辨识特征。","protection":"IUCN：LC（无危）","distribution":"分布于哥伦比亚西部至厄瓜多尔西北部的安第斯山脉西坡，从哥伦比亚乔科省南部向南延伸至厄瓜多尔皮钦查省。"},{"name":"棕臀白尾梢蜂鸟","english_name":"Rufous-vented Whitetip","scientific_name":"Urosticte ruficrissa","overview":"棕臀白尾梢蜂鸟（英文名：Rufous-vented Whitetip，学名：Urosticte ruficrissa），是雨燕目蜂鸟科白尾梢蜂鸟属的唯一物种。分布于南美的安第斯山脉东部斜坡，从哥伦比亚南部至秘鲁东北部。雄鸟主要呈绿色，喉部较暗，尾羽内侧有白色尖端形成圆形斑点；雌鸟喉部有绿色鳞状斑纹，腹部白色，尾羽角落白色，臀部带浅褐色调。雌鸟与雌鸟靴尾蜂鸟相似，但前者喉部鳞纹更重，大腿部位为白色。","appearance":"棕臀白尾梢蜂鸟长约9至10厘米，体重4至4.2克。两性皆有中等长度的直黑喙和眼后显著的白色条纹。雄鸟上体光泽绿，下体亦为绿色，尾羽中央部分宽白尖，尾羽呈叉状，雌鸟下体白色带绿色斑点，尾羽外侧有白色尖端。幼鸟似雌鸟，头部羽毛边缘棕色。","call":"发出柔和而快速的啾啾声“tweetweetweetwee...”，有时被描述为类似笑声的叽喳声。在飞行觅食时还会发出单个低音的刮擦声“tzrrrrr”。","habits":"生活在半开放的山地森林和云雾林中，海拔高度介于1600至2400米之间。通常在地面附近至森林中层活动，以多种开花植物的花蜜为食，如凤梨科植物、Clusia和Palicourea属植物。同时捕食昆虫，通过从栖木上猎捕或从植被中采集。","breeding":"繁殖季节从1月至4月，雌鸟用苔藓筑杯状巢，置于离地2至4米高的藤蔓中。孵化期15至18天，幼鸟在22至24天后离巢。","identification":"与靴尾蜂鸟雌鸟相似，但棕臀白尾梢蜂鸟雌鸟喉部的绿色鳞纹更明显，且大腿部位白色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的哥伦比亚（Huila、Nariño）、厄瓜多尔和秘鲁（San Martín）。","other":"自21世纪初以来，共识认为棕臀白尾梢蜂鸟和白尾梢蜂鸟是各自独立的物种。"},{"name":"盘尾蜂鸟","english_name":"White-booted Racket-tail","scientific_name":"Ocreatus underwoodii","overview":"盘尾蜂鸟（英文名：White-booted Racket-tail，学名：Ocreatus underwoodii），是雨燕目蜂鸟科盘尾蜂鸟属的鸟类。主要分布在南美洲的哥伦比亚、厄瓜多尔和委内瑞拉。其最显著的特征是雄鸟的长尾羽和独特的腿毛，而雌鸟则缺少这些特征。盘尾蜂鸟在云雾森林中常见，常在林缘和开阔地带的小花上觅食。","appearance":"盘尾蜂鸟具有明显的性别二型性，雄鸟拥有长达7到8厘米的外侧尾羽，尾羽末端有长椭圆形的旗状物，雌鸟则没有长尾和旗状物。雄鸟体长11到15厘米，体重2.5到2.7克，喉部呈绿灰色，腹部绿色。雌鸟体长7.6到9厘米，体重2.6到3.2克，胸部和腹部白色，带有绿色斑点。两者皆有绿色的上体和白色的腿毛。","call":"盘尾蜂鸟的鸣叫包括下降的细甜颤音'ti-tlee-ee-ee'以及单个的'tsit'和'trrt'音符。","habits":"盘尾蜂鸟栖息于温带和亚热带的安第斯山脉森林边缘，偏好湿润至潮湿的环境，偶尔出现在次生林中。它们的活动范围通常在地面以上6至18米处，以多种植物如Palicourea、Clusia、Inga和Cavendishia的花蜜为食，也会捕食小昆虫。它们在繁殖季节后会进行季节性的高度迁移。","breeding":"盘尾蜂鸟的繁殖期在哥伦比亚至少在1月至4月，可能全年均可繁殖。雌鸟用植物纤维和苔藓筑成小杯状巢，通常位于离地6至8米高的水平枝条上。雌鸟孵化两枚卵约16至17天，幼鸟在出生后19至22天离巢。","identification":"雌性盘尾蜂鸟与雌性白尾梢蜂鸟相似，但前者喙较短，胸部清晰无斑，眼后有白色斑点而非线条。与秘鲁盘尾蜂鸟在哥伦比亚南部安第斯山脉东部可能重叠，但可通过其两性均有的白色腿毛和雌鸟的无标记清洁胸部加以区分。","protection":"IUCN：LC（无危）","distribution":"盘尾蜂鸟主要分布于南美洲，北起委内瑞拉北部，南至厄瓜多尔西部。"},{"name":"秘鲁盘尾蜂鸟","english_name":"Peruvian Racket-tail","scientific_name":"Ocreatus peruanus","overview":"秘鲁盘尾蜂鸟（英文名：Peruvian Racket-tail，学名：Ocreatus peruanus），是雨燕目蜂鸟科盘尾蜂鸟属的鸟类。分布自哥伦比亚南部至秘鲁中部。其最显著的特征是雄鸟的直尾末端带有类似球拍的结构，以及雌鸟的白色腹部饰以绿色鳞片状图案。","appearance":"秘鲁盘尾蜂鸟展现出明显的性别二态性。雄鸟长度介于11至15厘米之间，包括7至8厘米长的外侧尾羽，这些尾羽呈直线状，末端有狭长的椭圆形旗帜。体重约2.5至2.7克。雌鸟稍小，长度在7.6至9厘米之间，体重2.6至3.2克。两性皆有绿色上体，眼后有一白色斑点，以及肉桂色的腿羽。雄鸟喉部为灰绿色，腹部全绿，尾羽旗帜为绿黑色；雌鸟喉部和胸部为白色，布满绿色斑点。","call":"秘鲁盘尾蜂鸟的鸣声由雄鸟和雌鸟共同发出，包括下降的甜美颤音‘ti-tlee-ee-ee’，以及单个‘tsit’和‘trrt’音符。","habits":"秘鲁盘尾蜂鸟在繁殖季节后会进行季节性垂直迁移。它们通常在地面以上6至18米的高度觅食，偏好湿润至湿热森林边缘，但也出现在森林内部和较为开阔的次生林中。食物主要包括多种植物的花蜜，如Palicourea、Clusia、Inga和Cavendishia属植物，同时通过从栖木上捕捉的方式获取小型昆虫。","breeding":"虽然繁殖季节尚未得到详细研究，可能覆盖全年大部分时间。它们使用植物纤维和苔藓制作微型杯状巢穴，通常位于距地面6至8米高的水平枝条上。雌鸟孵化一窝两个蛋，孵化期为16至17天；雏鸟在孵化后19至22天离巢。","identification":"雌性秘鲁盘尾蜂鸟与雌性棕臀白尾梢蜂鸟相似，但前者腿部颜色为肉桂色而非白色，且喉部标记较少。与棕靴盘尾蜂鸟在分布范围南端有重叠，但雄性秘鲁盘尾蜂鸟的中央尾羽是直的，不会交叉。","protection":"IUCN：LC（无危）","distribution":"秘鲁盘尾蜂鸟分布在南美洲东部厄瓜多尔和秘鲁东北部，栖息于温带和亚热带安第斯山脉，常见于海拔1,600至2,200米之间，但可低至600米，高至4,000米。","other":"关于秘鲁盘尾蜂鸟分类地位存在争议，国际鸟类学委员会（IOC）和克莱门茨分类法将其视为独立物种，而《世界鸟类手册》（HBW）将其作为的一个亚种。"},{"name":"棕靴盘尾蜂鸟","english_name":"Rufous-booted Racket-tail","scientific_name":"Ocreatus addae","overview":"棕靴盘尾蜂鸟（英文名：Rufous-booted Racket-tail，学名：Ocreatus addae），是雨燕目蜂鸟科盘尾蜂鸟属的鸟类。小型的云森林中的蜂鸟。分布于南美洲，自秘鲁中部至玻利维亚的东部安第斯山脉。其显著特征为雄鸟的独特尾羽，呈V字形交叉散开。","appearance":"雄性棕靴盘尾蜂鸟体型微小，上体绿色，下体白色带斑点（annae亚种整体绿色），具有独特的V字形尾羽，尾羽外侧延长，末端为裸露的杆状结构。雌鸟体型较小，大腿和腹部淡黄色，下体具斑点，有白色的颊须。雌雄均有肉色腿毛，尾部深叉，雄鸟尾羽外侧延长，形成绿色黑色的旗状结构。","call":"雄鸟和雌鸟都会发出下降的细甜颤音，类似'ti-tlee-ee-ee'，以及单独的'tsit'和'trrt'音符。","habits":"栖息于湿润至湿热的森林边缘，偏好海拔1600至2200米的高度，但也可见于低至600米高至4000米的地区。常在6至18米的高度觅食，以多种植物的花蜜为食，如Palicourea、Clusia、Inga和Cavendishia属植物，也会从栖息处捕食小型昆虫。","breeding":"繁殖季节不详，可能覆盖大部分年份。筑杯状巢，由植物纤维和苔藓构成，通常位于离地面6至8米高的水平枝条上。雌鸟孵卵期约16至17天，幼鸟在孵化后19至22天离巢。","identification":"雄鸟与秘鲁盘尾蜂鸟的区别在于尾羽的形状，前者尾羽外侧扭曲而非直线型。雌鸟两者几乎无法区分，但annae亚种雄鸟尾羽的旗帜部分呈暗铜紫色。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，具体而言，annae亚种见于秘鲁中部至南部安第斯山脉的东坡，addae亚种则见于玻利维亚安第斯山脉的东坡。","other":"该物种会进行季节性垂直迁移，于繁殖后改变高度分布。"},{"name":"黑带尾蜂鸟","english_name":"Black-tailed Trainbearer","scientific_name":"Lesbia victoriae","overview":"黑带尾蜂鸟（英文名：Black-tailed Trainbearer，学名：Lesbia victoriae），是雨燕目蜂鸟科带尾蜂鸟属的鸟类。独特的蜂鸟，以其异常长的尾巴著称。主要分布在南美洲的哥伦比亚东北部至秘鲁东南部，海拔介于2500至3800米之间，偏好半开放环境而非密林。","appearance":"雄性黑带尾蜂鸟身长可达21至24厘米，包括其显著的长尾，全身呈现绿色光泽，拥有黑色长尾羽及胸部、喉咙处的虹彩绿斑块。雌鸟体长约13.5至14.5厘米，尾部较短，腹部为白色并带有绿色斑点。与绿带尾蜂鸟相比，黑带尾蜂鸟具有更长且更弯曲的喙及尾部，整体颜色略显暗淡。","call":"鸣声包括重复的粗糙嘶哑声“skreee...skreee...”以及类似变化，还有上滑音“tseep”和一系列加速进入颤音的高音符“tseee...tseee...tseee..tsi-tsititititrrr-tsi-tsi”。展示时，通过尾部或翅膀产生机械式的咔嚓声。","habits":"黑带尾蜂鸟主要在开花的Bignoniaceae、Fabaceae、Gesneriaceae、Leguminosaceae、Puya及引进的桉树等中到高层觅食花蜜，同时以空中捕捉昆虫为食。适应性强，能在城市生态系统如公园和花园中生存。","breeding":"繁殖期在哥伦比亚的基多为10月至次年3月，在玻利瓦尔为9月至10月，在纳里尼奥为6月至8月。巢呈杯状，内部由细小的植物纤维构成，外表覆盖苔藓和地衣，置于岩石下方或蕨类植物中，有时悬挂在树枝上。孵化期18至19天，仅由雌鸟负责；雏鸟粉红色，背部有两行浅棕色绒毛；离巢时间在29至31天左右。雏鸟发育期较长。","identification":"与绿带尾蜂鸟相比，黑带尾蜂鸟的喙更为弯曲，尾部更长且通常略微弯曲，整体颜色稍暗淡。亚种juliae喙和尾部较短，整体呈金色光泽；berlepschi亚种喙更弯曲，喉部虹彩呈草绿色，下体及臀部羽毛锈色。","protection":"IUCN：LC（无危）","distribution":"广泛分布于南美的中央和北部安第斯山脉，从哥伦比亚到厄瓜多尔，直至秘鲁，主要在2500至3800米的海拔范围内。","other":"共有三种亚种被确认，分别是L. v. victoriae、L. v. juliae和L. v. berlepschi。"},{"name":"绿带尾蜂鸟","english_name":"Green-tailed Trainbearer","scientific_name":"Lesbia nuna","overview":"绿带尾蜂鸟（英文名：Green-tailed Trainbearer，学名：Lesbia nuna），是雨燕目蜂鸟科带尾蜂鸟属的鸟类。体型较小的蜂鸟，以拥有非常长的尾巴而著称。分布于南美洲，自哥伦比亚东北部至玻利维亚北部，常见于森林边缘、灌木丛生地带，偶尔也出现在较干燥开阔的区域。","appearance":"雄性绿带尾蜂鸟全长约15.3至17厘米，包括10.6至13.6厘米的长尾；雌鸟较短，约11.6厘米，尾长约4.5至6.2厘米。体重介于3.1至4.3克之间。全身闪耀着鲜艳的翠绿色，喙短直且黑色。雄鸟的长尾引人注目，尾羽黑底绿尖，叉状。雌鸟下腹有白色斑点，尾较短。幼鸟与成年雌鸟相似，雄鸟幼鸟喉部有绿色斑点。存在多个亚种，如gouldii、gracilis、pallidiventris、huallagae和aureliae，它们在体型、颜色深浅和尾部特征上有所不同。","call":"绿带尾蜂鸟的疑似歌声为重复的沙哑音“drrrt...drrrt...”，还有类似的变化。叫声包括连续的嗡嗡声“bzzzzt”和一系列加速的高音“tseee...tseee...tseee..tsee-tsi-tsi”。展示时，会用尾巴或翅膀制造机械般的啪嗒声。","habits":"绿带尾蜂鸟在低至中等高度处觅食花蜜，如Castilleja fissifolia、Cavendishia cordifolia、Rubus、Cuphea dipetala和Palicourea angustifolia等植物的花朵。它会捍卫小范围的觅食领地。通过空中捕捉昆虫，如在长时间飞行中猎食蓟马等小型昆虫。常被观察到在Espeletia花朵中寻找昆虫。","breeding":"繁殖季节从11月持续至次年4月。它用苔藓和根须筑成杯状巢，内部铺垫柔软的植物材料，通常建在斜坡下的遮蔽处，离地面2至4米高。每窝产两枚蛋，孵化和雏鸟成长的时间记录尚缺。","identification":"与黑带尾蜂鸟非常相似，但绿带尾蜂鸟的喙更短更直，尾部更短且更直，整体呈现更明亮的翡翠绿色。不同亚种在体型、色彩和尾部长度上有细微差异。","protection":"IUCN：LC（无危）；CITES: II级附录。在当地较为常见，目前没有已知的直接威胁，但Polylepis森林的砍伐、牧场经营和农业活动可能构成潜在威胁。","distribution":"绿带尾蜂鸟广泛分布于南美洲，包括哥伦比亚、厄瓜多尔、秘鲁、玻利维亚北部。在繁殖季节，主要分布在1700至3800米的海拔范围内。","other":"过去曾因野鸟贸易被捕获，但近年来由于国家和国际法规的实施，进口已被停止。"},{"name":"红尾彗星蜂鸟","english_name":"Red-tailed Comet","scientific_name":"Sappho sparganurus","overview":"红尾彗星蜂鸟（英文名：Red-tailed Comet，学名：Sappho sparganurus），是雨燕目蜂鸟科红尾慧星蜂鸟属的鸟类。是南美洲特有的蜂鸟，分布于玻利维亚北部至阿根廷北部，以及阿根廷的孤立山脉。其雄鸟拥有闪耀的绿金色背部和引人注目的长红尾，而雌鸟亦有独特的红尾。该物种偏好干旱或开阔地带，常出现在树线以上，接近Cardon仙人掌和树烟草的开花区。","appearance":"雄鸟的背部为绿金色，逐渐过渡到一条闪耀的红色长尾，尾羽末端呈黑色宽带。雌鸟相似，但颜色较暗淡，尾部较短。幼鸟上身呈暗绿色，臀部略带铜色，尾羽外侧有白色延伸至内侧。成年雄鸟头部和上背为绿色，与红紫色的背和臀形成鲜明对比；尾羽上表面在特定角度下显现出草莓红或橙红色，每根尾羽尖端有黑色宽带。雌鸟上体绿色，仅臀部红紫色，下体淡黄色，微斑点绿色。","call":"据描述，红尾彗星蜂鸟的鸣声包括短暂快速的混乱叽喳声，以及单调重复的、间隔超过一秒的‘tjrrrt’和较为刺耳的‘tsha’或‘zack’音符。","habits":"栖息于安第斯山脉东坡的干旱灌木丛和山谷内的灌木丛，海拔高度主要在1500至4200米之间。它以花蜜为主食，偶尔捕食小型节肢动物，通过悬停和站立的方式采食花蜜，同时在飞行中捕捉昆虫。雄鸟会保卫花区作为觅食领地。","breeding":"繁殖季节在阿根廷为10月至12月，在玻利维亚可能包括4月至6月。雌鸟独自筑巢，孵化蛋并照顾幼鸟。巢通常位于岩石壁的凹处或树木中，由苔藓、地衣和动物毛发构成。每次产卵两枚，孵化期约19至20天，雏鸟在孵化后31至32天离巢。有记录显示，雌鸟在首次孵化的雏鸟离巢前就开始第二次筑巢。","identification":"红尾彗星蜂鸟的独特之处在于其红紫色背部和上尾，以及雄鸟的长尾。这种特征在其他蜂鸟种类中极为罕见，使得识别相对容易。","protection":"IUCN：LC（无危）","distribution":"分布于南美的安第斯山脉，从玻利维亚北部向南延伸至阿根廷北部，以及阿根廷的Córdoba孤立山脉。","other":"红尾彗星蜂鸟的本地名称在Quechua语言中为Q'ori Kenti，意为“金色的蜂鸟”。"},{"name":"铜尾彗星蜂鸟","english_name":"Bronze-tailed Comet","scientific_name":"Polyonymus caroli","overview":"铜尾彗星蜂鸟（英文名：Bronze-tailed Comet，学名：Polyonymus caroli），是雨燕目蜂鸟科铜尾彗星蜂鸟属的鸟类。特有种蜂鸟，仅分布于秘鲁的安第斯山脉的干旱至半干旱山地灌丛和小片山林中。雄鸟拥有闪亮的绿色羽毛，带玫瑰色喉部，尾羽外侧具青铜色尖端。雌鸟及幼鸟则为灰色腹部，饰以绿色斑点，喉部较小，边缘有淡色髭纹。其尾羽展开时呈叉状。","appearance":"铜尾彗星蜂鸟体型中等，尾羽较长，尤其在雄鸟中更甚，尾羽深叉，上表面青铜绿色。雄鸟上体呈暗青铜绿色，具有白色眼后斑，玫瑰紫色喉部覆盖整个下巴和喉咙，下体青铜绿色，胫部有小白簇毛。雌鸟较雄鸟暗淡，喉部较小且更偏橙色，腹部灰白色，点缀着绿色斑点，尾羽比雄鸟短且叉度较小。","call":"其叫声被描述为一段音调先升后降的短颤音，觅食时会发出快速而干燥的‘tcht’或‘tchtcht’声。","habits":"铜尾彗星蜂鸟主要栖息于秘鲁太平洋坡面及干涸的安第斯山谷中的干旱至半干旱山地灌木丛和小片山林。它们全年留居于同一区域，以昆虫为主要食物，偶尔也会摄取小型节肢动物，觅食高度多近地面。","breeding":"繁殖季节至少涵盖11月和12月，但关于繁殖生态的详细信息仍知之甚少，巢穴特征尚未被描述。","identification":"与本地的灰嘴彗星蜂鸟相比，铜尾彗星蜂鸟体型较小，尾羽更短且叉度较小，雄鸟的喉部颜色为玫瑰紫色而非淡蓝色，雌雄两性下体均为青铜绿色而非均匀的淡灰色。","protection":"IUCN：LC（无危）","distribution":"铜尾彗星蜂鸟分布于秘鲁中部至南部，包括卡哈马卡大区南至阿雷基帕大区的太平洋斜坡和干燥的安第斯山谷。"},{"name":"黑背刺嘴蜂鸟","english_name":"Black-backed Thornbill","scientific_name":"Ramphomicron dorsale","overview":"黑背刺嘴蜂鸟（英文名：Black-backed Thornbill，学名：Ramphomicron dorsale），是雨燕目蜂鸟科刺嘴蜂鸟属的鸟类。仅分布于南美洲哥伦比亚东北部的圣塔玛尔塔山脉，主要栖息于高海拔的森林边缘和paramo地带。其最显著的特征是雄鸟拥有黑色背部和绿色喉咙，而雌鸟则有斑点状的下体和白色尾端。","appearance":"黑背刺嘴蜂鸟体型小巧，长度约为9至10厘米，体重约3.5克。其喙极短，呈黑色，雄鸟的喙稍向下弯曲。雄鸟上半身覆以天鹅绒般的黑色羽毛，尾羽上覆有紫色，眼后有一白色斑点，喉咙橄榄绿，下体混有暗灰色和锈色，点缀着绿色斑点。雌鸟上半身为闪亮的草绿色，同样有紫色尾羽上覆和眼后白色斑点，下体为带绿色斑点的淡黄色，尾羽较短，外侧尾羽尖端白色。","call":"其鸣叫特征包括短促干燥的颤音‘trrr’，以及从高音至低音的长下降颤音，开始和结束时带有单个音符‘tsee-tttrrrrrrrr-tsee’，同时也会发出单独的‘tsee’音。","habits":"黑背刺嘴蜂鸟活动范围广泛，从地面到树冠都能见到它们采食花蜜的身影。它们会访问Ericaceae、Lobeliaceae、Melastomataceae和Rubiaceae科植物的花朵，具体而言，包括Erythrina、Puya和Salvia属的花朵。此外，它们还会在空中捕捉昆虫，或从花朵上获取虫子。","breeding":"关于黑背刺嘴蜂鸟的繁殖习性，目前尚无确切信息。","identification":"与同属的紫背刺嘴蜂鸟相比，黑背刺嘴蜂鸟的背部颜色和下体斑点是主要的区别点。","protection":"IUCN：NT（近危），濒危）","distribution":"黑背刺嘴蜂鸟的分布局限于南美洲哥伦比亚东北部的圣塔玛尔塔山脉。"},{"name":"紫背刺嘴蜂鸟","english_name":"Purple-backed Thornbill","scientific_name":"Ramphomicron microrhynchum","overview":"紫背刺嘴蜂鸟（英文名：Purple-backed Thornbill，学名：Ramphomicron microrhynchum），是雨燕目蜂鸟科刺嘴蜂鸟属的鸟类。其分布区域从委内瑞拉北部延伸至玻利维亚，拥有独特的紫蓝色上部羽毛，下部呈绿色，是安第斯山脉中引人注目的小型鸟类。","appearance":"成年雄性紫背刺嘴蜂鸟具有极短而直的喙，上部羽毛呈现耀眼的紫蓝色光泽，下部为绿金色，腹部铜色并带有锈色边缘。雌鸟上部羽毛为绿色，下部白色并点缀以绿色斑点，尤其在两胁处更为密集。幼鸟外观似雌鸟，但雄鸟幼鸟背部开始显现紫色。成鸟尾部长而略叉开，雌鸟的尾羽末端有白色尖端。","call":"紫背刺嘴蜂鸟的鸣唱为一系列轻柔的刮擦音，间杂着短促的嗡嗡声或干燥的颤音。叫声包括短暂的干燥噼啪声‘trrr’，粗糙的‘krr-kit’，以及绵长的颤音。","habits":"栖息于湿润山地森林边缘，波利莱比斯森林，以及安第斯山脉的亚高山草地和高山草地，海拔高度从1700米至3600米。季节性迁徙模式尚不明确，但在雨季会从低海拔向高海拔移动。以吸食花蜜为主，常从Ericaceae、Lobeliaceae等植物中获取食物，同时也会在空中捕捉昆虫。","breeding":"繁殖期可能从五月持续至十二月，具体时间因地区而异。巢穴为杯状，由细小的植物纤维构成，外表装饰有苔藓和地衣，置于水平树枝上。一窝通常产两个蛋，孵化期约为16天。","identification":"紫背刺嘴蜂鸟以其独特的紫蓝色上部羽毛和极短的喙易于识别。与黑背刺嘴蜂鸟相比，其体型较小，且上部羽毛颜色更偏向紫蓝。","protection":"IUCN：LC（无危）","distribution":"繁殖区域从委内瑞拉北部延伸至玻利维亚，非繁殖季节偶尔下降到较低海拔。分布区包括哥伦比亚、厄瓜多尔、秘鲁以及玻利维亚的特定地区。","other":"紫背刺嘴蜂鸟的四个亚种中，R. m. andicola 和 R. m. albiventre 的差异性存在争议，而R. m. bolivianum 在上部羽毛颜色和下部羽毛的质地上有显著区别。"},{"name":"须蜂鸟","english_name":"Bearded Mountaineer","scientific_name":"Oreonympha nobilis","overview":"须蜂鸟（英文名：Bearded Mountaineer，学名：Oreonympha nobilis），是雨燕目蜂鸟科须蜂鸟属的大型蜂鸟，主要分布在秘鲁中部，以其独特的面部图案和长尾著称。雄鸟具有虹彩绿紫喉部饰羽，而雌鸟相似但色彩较淡。","appearance":"须蜂鸟体型较大，上体棕色，下体白色，头部棕色，尾巴黑色和白色相间，呈深叉状。雄鸟拥有虹彩绿紫的喉部饰羽，某些亚种头部有蓝色前额；雌鸟外观类似但颜色较为暗淡。全长约14至16.5厘米，体重7至9克，喙长约2.3厘米，尾部长且深叉，中央羽毛呈青铜色，两侧逐渐增加白色，最外侧几乎全白。成年雄鸟喉部饰羽基部翠绿色，尖端蓝紫色；雌鸟喉部饰羽较小，多为白色基底，尾部叉度较小。幼鸟色泽较暗，具黄色下颚。","call":"须蜂鸟发出下降的、尖锐的一系列叫声，随后是丰富的叽喳声，如'swee swee chew-chew-chew'以及'dzzrt'的干燥声。","habits":"栖息于干燥的山地灌丛，常在岩石峭壁、灌木覆盖的地带和轻度林木区域活动。海拔分布范围为2,500至3,900米。以花蜜为主食，尤其是Agave、仙人掌、Nicotiana和Eucalyptus的花蜜，通过悬停和翅膀张开的方式吸食花蜜，也会抓住花朵进食。对大多数其他蜂鸟表现顺从。活动范围包括本土植物群落，也常见于树烟草和桉树种植区，甚至在道路旁和城镇内。","breeding":"须蜂鸟的繁殖生态尚未详细记录，但可能在河流上方的洞穴中筑巢繁殖。","identification":"与安第斯山蜂鸟区别明显，后者尾部较短且圆，且不具备须蜂鸟的显著苍白眉纹。","protection":"IUCN：LC（无危）","distribution":"秘鲁中部，具体在Apurímac和Cuzco部门的Urubamba和上Apurímac河流域，以及Huancavelica、Ayacucho和Apurímac部门的Mantaro、Pampas和Chalhuanca河流域。","other":"其分类地位正在重新考虑，未来可能需修订其属的划分，或将Oreonympha和Chalcostigma合并入Oxypogon。"},{"name":"髯蜂鸟","english_name":"Green-bearded Helmetcrest","scientific_name":"Oxypogon guerinii","overview":"髯蜂鸟（英文名：Green-bearded Helmetcrest，学名：Oxypogon guerinii），是雨燕目蜂鸟科髯蜂鸟属的特有种鸟类。仅分布于哥伦比亚东部安第斯山脉。其最显著特征为雄鸟的绿色胡须状羽毛和尖锐的黑色冠羽。","appearance":"髯蜂鸟体长介于11.2至12.7厘米，雄鸟重约5.7克，雌鸟约4.8克。拥有短而直的黑色喙。雄鸟头部暗棕色至黑色，具白色尖顶冠羽，上身呈铜色，胸前有一片闪耀的绿色胡须状羽毛，边缘为白色，形成独特的\"胡须\"。下体灰铜色，尾部中等长度，叉状，颜色由铜色至绿铜色，外侧尾羽带有宽阔的白色条纹。雌鸟外观与雄鸟相似，但缺乏显著的冠羽和胡须，下体更呈淡黄白色，略带绿色斑点。幼鸟与成年雌鸟相似，但雄鸟幼鸟会发展出部分冠羽和胡须。","call":"已知的鸣声为雄鸟追逐雌鸟时发出的坚持的\"tii…tii…\"叫声。","habits":"髯蜂鸟全年居住在潮湿的帕拉莫草原，偏好Espeletia植被环境，有时会在波利普里斯森林边缘活动。雌鸟常出现在峡谷地带，而雄鸟更倾向于开阔的山坡。海拔分布范围为3000至5200米。在旱季（11月至次年2月），可能部分离开帕拉莫草原，迁往相邻的高海拔森林。","breeding":"繁殖季节与Espeletia开花季节紧密相关，一般在5月至9月中旬。筑巢行为和繁殖生态学细节尚待更多研究，但据信与近亲白胡须盔蜂鸟类似。","identification":"与同属其他物种相比，髯蜂鸟可通过其绿色胡须状羽毛和雄鸟的白色尖顶冠羽来识别。","protection":"IUCN：LC（无危）；CITES II；本地常见，分布在多个保护区，如Chingaza、Sumapaz和El Cocuy国家公园。","distribution":"主要分布于哥伦比亚东部安第斯山脉，南至Cundinamarca省。"},{"name":"蓝髯蜂鸟","english_name":"Blue-bearded Helmetcrest","scientific_name":"Oxypogon cyanolaemus","overview":"蓝髯蜂鸟（英文名：Blue-bearded Helmetcrest，学名：Oxypogon cyanolaemus），是雨燕目蜂鸟科髯蜂鸟属的极为罕见且濒危的鸟类，仅见于南美洲哥伦比亚圣玛尔塔山脉的高海拔地区。其独特的绿蓝色胡须、黑白相间的头部图案以及蓬松的冠羽使其在同类中脱颖而出。该鸟种曾一度失踪近71年，直到2015年才被重新发现。","appearance":"成年雄性蓝髯蜂鸟约11.5厘米长，上体橄榄绿色，具有黑色和白色的长冠羽，脸部深色，带有宽阔的淡黄白色颈环。喉部有一条薄而白色的‘胡须’，中央有一条蓝紫色的条纹。下体暗淡呈黄褐色，胸部有灰色斑点，逐渐变为黄白色。尾部适度长且微叉，中央尾羽橄榄青铜色，其余尾羽白色，边缘和尖端呈红铜色，下部奶油色带宽橄榄色尖端。雌鸟和未成年雄鸟缺少冠羽和胡须，整体较为暗淡，喉部白色。","call":"关于蓝髯蜂鸟的鸣叫特征知之甚少，但在2015年的观察中，听到了类似绿紫蜂鸟的飞行叫声。","habits":"蓝髯蜂鸟栖息于高海拔的草甸环境，海拔高度介于3000至4800米之间。它以花蜜为食，尤其是Libanothamnus occultus的花蜜，采取悬停或攀附花朵的方式进食。","breeding":"目前关于蓝髯蜂鸟的繁殖信息非常有限，尚无具体报道。","identification":"蓝髯蜂鸟的特征在于其独特的胡须、冠羽以及大小、短喙和白颈环，这些特征有助于将其与同属其他物种区分开来。","protection":"IUCN：EN（濒危）","distribution":"蓝髯蜂鸟仅分布于南美洲哥伦比亚的圣玛尔塔山脉，具体在东北部的Santa Marta Mts.区域。","other":"蓝髯蜂鸟曾被认为已灭绝，直到2015年才被重新发现，这使得它成为全球关注的焦点。"},{"name":"白髯蜂鸟","english_name":"White-bearded Helmetcrest","scientific_name":"Oxypogon lindenii","overview":"白髯蜂鸟（英文名：White-bearded Helmetcrest，学名：Oxypogon lindenii），是雨燕目蜂鸟科髯蜂鸟属的鸟类。委内瑞拉西北部安第斯山脉的特有种，以其独特的短喙和白髯著称。栖息在潮湿的高山草甸，以Espeletia植被为伴。","appearance":"这种蜂鸟长约11.5厘米，体重约4.8克。其特征为非常短的喙，雄鸟拥有闪亮的青铜绿色上身，带灰色鳞状斑点，黑色脸庞上有尖锐的黑白色冠羽和长而蓬松的黑白相间‘胡须’，颈背有宽大的白色项圈，下体灰暗，尾部略叉开。雌鸟类似但较暗淡，无冠羽和‘胡须’，下体呈密集的绿褐色斑点。","call":"发出重复的、高音且略带嗡嗡声的单一音符‘tzee’或‘peek’，通常在繁殖季节从矮灌木顶上连续数分钟歌唱。","habits":"常见于有巨石和水源的高海拔潮湿开阔的高山草甸，依赖Espeletia植被。在干燥季节会迁移到较低海拔的Polylepis森林边缘或更茂密的高山草甸。","breeding":"繁殖季节与Espeletia开花期紧密相关，通常在6月至11月。巢由Espeletia纤维构成，建在河岸、瀑布附近的洞穴或悬垂植物下，巢内产两枚白色的蛋，孵化期21至23天，小鸟在35至38天后离巢。","identification":"与其它种类蜂鸟区别明显，雄鸟的黑白色冠羽和‘胡须’是显著标志，无相似物种在同一范围内。","protection":"IUCN：LC（无危）。CITES II。在委内瑞拉的Sierra Nevada和Sierra La Culata国家公园得到保护。","distribution":"分布于委内瑞拉西北部安第斯山脉的梅里达州和特鲁希略州，主要栖息于3600至4500米的海拔高度。","other":"白髯蜂鸟曾被认为是髯蜂鸟的一个亚种，后基于2013年的研究被提升为独立物种。"},{"name":"黄髯蜂鸟","english_name":"Buffy Helmetcrest","scientific_name":"Oxypogon stuebelii","overview":"黄髯蜂鸟（英文名：Buffy Helmetcrest，学名：Oxypogon stuebelii），是雨燕目蜂鸟科髯蜂鸟属的鸟类。体型较大，拥有短喙，仅在哥伦比亚中央安第斯山脉的极高海拔地区发现。雄性黄髯蜂鸟的绿色与蓝色胡须、黑色及淡褐色头部图案、蓬松的冠羽使其在狭窄的分布范围内极易识别。雌鸟和未成年雄鸟缺少冠羽和胡须，颜色较为暗淡，但其体型较大和短喙仍使它们容易辨认。","appearance":"雄性黄髯蜂鸟长11.2至12.7厘米，包括适度长的尾巴。具有约1.5厘米长的短直黑喙。头部深棕色至黑色，顶有较短的肉桂色冠羽，背部呈青铜色。白色细长的下巴和喉部羽毛形成“胡须”，中央夹杂着绿色和蓝色的羽毛。淡褐色的颈环与深色头部形成对比，其余下体呈灰青铜色，点缀以肉桂色斑点，向后逐渐加宽，下尾覆羽纯肉桂色。尾巴叉状，上部铜色至青铜绿，边缘宽阔的白色条纹覆盖至外侧尾羽的轴，下部红褐色，带有乳白色至淡肉桂色的外缘。雌鸟与雄鸟相似，但缺少显眼的冠羽和“胡须”，下体呈不均匀的赤褐色或棕褐色，混有深色斑点，模糊的绿色调。幼鸟类似成年雌鸟；雄鸟幼鸟开始发展部分冠羽和“胡须”。","call":"鸣唱为连续的高音单音节“tsee”，音高约为7千赫兹，音符长度约0.11秒，每3至5秒重复一次。","habits":"黄髯蜂鸟栖息于湿润开阔的帕拉莫地带，偏好Espeletia植被。它常在Espeletia schultzii的花朵中觅食，即使在干燥的老花中寻找充满昆虫幼虫的食物源。它紧贴花朵吸取花蜜而非悬停，使用尾巴支撑，类似于啄木鸟。它还会在地上栖息，拾取受惊的节肢动物；通过悬停跳跃或从地面或栖木上猛扑捕捉昆虫。","identification":"黄髯蜂鸟可通过其独特的绿色和蓝色胡须、黑色与淡褐色头部图案、蓬松的冠羽以及相对较大的体型和短喙与其他蜂鸟区分。","protection":"IUCN：VU（易危）","distribution":"黄髯蜂鸟仅在哥伦比亚中部的内华达德尔鲁伊斯火山周边的托利马和卡尔达斯省边界地区发现。","other":"黄髯蜂鸟的种群估计少于1000个成熟个体，且数量被认为正在减少。大部分分布区位于洛斯内瓦多斯国家公园内，但其帕拉莫栖息地在公园之外正迅速退化。"}];
